            {/* ── FALLBACK: gradient bg + overlay ── */}
            {!hasPoster && <div className="event-hero-overlay" />}

            {/* Fallback icon */}
            {!hasPoster && (
                <div className="event-hero-poster-icon">{bgIcon}</div>
