                                        <><Loader2 className="w-4 h-4 mr-2 animate-spin" />Joining...</>
                                    ) : (
                                        <><UserPlus className="w-4 h-4 mr-2" />Join Club</>
                                    )}
                                </Button>
                            ) : (
                                <Button className="event-hero-btn-primary" disabled>
