                                </Button>
                            )}
                            <Button
                                variant="outline"
                                className="event-hero-btn-secondary"
                                onClick={() => onExploreClub(cl)}
                            >
                                <Info className="w-4 h-4 mr-2" />
                                More Info
                            </Button>
                        </div>
                    );
                })()}
            </div>

            {/* Progress dots */}
            <div className="event-hero-dots">
                {heroItems.map((_, i) => (
                    <button
                        key={i}
                        className={cn("event-hero-dot", i === activeIndex && "active")}
                        onClick={() => goTo(i)}
                    />
                ))}
            </div>

        </div>
    );
