        department?: string;
    };
    status: 'Scheduled' | 'Ongoing' | 'Completed' | 'Postponed' | 'Cancelled';
    createdAt: string;
    updatedAt: string;
    postedBy: string;
}

interface ExamContextType {
    exams: Exam[];
    upcomingExams: Exam[];
    loading: boolean;
    error: string | null;
    fetchExams: () => Promise<void>;
    fetchUpcomingExams: () => Promise<void>;
    addExam: (examData: Omit<Exam, '_id' | 'createdAt' | 'updatedAt'>) => Promise<void>;
    updateExam: (id: string, examData: Partial<Exam>) => Promise<void>;
    updateExamStatus: (id: string, status: Exam['status']) => Promise<void>;
    deleteExam: (id: string) => Promise<void>;
}

const ExamContext = createContext<ExamContextType | undefined>(undefined);

export const useExams = () => {
    const context = useContext(ExamContext);
    if (!context) {
        throw new Error('useExams must be used within an ExamProvider');
    }
    return context;
};

export const ExamProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [exams, setExams] = useState<Exam[]>([]);
    const [upcomingExams, setUpcomingExams] = useState<Exam[]>([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Fetch all exams
    const fetchExams = useCallback(async () => {
        try {
            setLoading(true);
            setError(null);
            const data = await api.get('/exams');
            setExams(data);
        } catch (err: any) {
            console.error('Error fetching exams:', err);
            setError(err.message || 'Failed to fetch exams');
        } finally {
            setLoading(false);
        }
    }, []);

    // Fetch upcoming exams (for students)
    const fetchUpcomingExams = useCallback(async () => {
        try {
            setLoading(true);
            setError(null);
            const data = await api.get('/exams/upcoming');
            setUpcomingExams(data);
        } catch (err: any) {
            console.error('Error fetching upcoming exams:', err);
            setError(err.message || 'Failed to fetch upcoming exams');
        } finally {
            setLoading(false);
        }
    }, []);

    // Add new exam
    const addExam = async (examData: Omit<Exam, '_id' | 'createdAt' | 'updatedAt'>) => {
        try {
            setError(null);
            const newExam = await api.post('/exams', examData);
            setExams(prev => [newExam, ...prev]);

            // Also update upcoming exams if applicable
            const examDate = new Date(examData.date);
            const today = new Date();
            today.setHours(0, 0, 0, 0);
            if (examDate >= today && examData.status !== 'Cancelled' && examData.status !== 'Completed') {
                setUpcomingExams(prev => [...prev, newExam].sort((a, b) =>
                    new Date(a.date).getTime() - new Date(b.date).getTime()
                ));
            }
        } catch (err: any) {
            console.error('Error adding exam:', err);
            setError(err.message || 'Failed to add exam');
            throw err;
        }
    };

    // Update exam
    const updateExam = async (id: string, examData: Partial<Exam>) => {
        try {
            setError(null);
            const updatedExam = await api.put(`/exams/${id}`, examData);
            setExams(prev => prev.map(exam => exam._id === id ? updatedExam : exam));
            setUpcomingExams(prev => prev.map(exam => exam._id === id ? updatedExam : exam));
        } catch (err: any) {
            console.error('Error updating exam:', err);
            setError(err.message || 'Failed to update exam');
            throw err;
        }
    };

    // Update exam status
    const updateExamStatus = async (id: string, status: Exam['status']) => {
        try {
            setError(null);
            const updatedExam = await api.patch(`/exams/${id}/status`, { status });
            setExams(prev => prev.map(exam => exam._id === id ? updatedExam : exam));

            // Remove from upcoming if completed or cancelled
            if (status === 'Completed' || status === 'Cancelled') {
                setUpcomingExams(prev => prev.filter(exam => exam._id !== id));
            } else {
                setUpcomingExams(prev => prev.map(exam => exam._id === id ? updatedExam : exam));
            }
        } catch (err: any) {
            console.error('Error updating exam status:', err);
            setError(err.message || 'Failed to update exam status');
            throw err;
        }
    };

    // Delete exam
    const deleteExam = async (id: string) => {
        try {
            setError(null);
            await api.delete(`/exams/${id}`);
            setExams(prev => prev.filter(exam => exam._id !== id));
            setUpcomingExams(prev => prev.filter(exam => exam._id !== id));
        } catch (err: any) {
            console.error('Error deleting exam:', err);
            setError(err.message || 'Failed to delete exam');
            throw err;
        }
    };

    const value = {
        exams,
        upcomingExams,
        loading,
        error,
        fetchExams,
        fetchUpcomingExams,
        addExam,
        updateExam,
        updateExamStatus,
        deleteExam,
    };

    return (
        <ExamContext.Provider value={value}>
            {children}
        </ExamContext.Provider>
    );
};

export default ExamContext;

import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import { ref, push, onValue, set, remove, query, orderByChild, limitToLast, off } from 'firebase/database';
import { signInAnonymously } from 'firebase/auth';
import { auth, database, firebaseReady } from '@/lib/firebase';
import { useAuth } from './AuthContext';
import { useToast } from '@/hooks/use-toast';

// Notification interface
export interface Notification {
    id: string;
    title: string;
    message: string;
    urgency: 'normal' | 'important' | 'critical';
    targetAudience: {
        type: 'all' | 'students' | 'faculty' | 'custom' | 'faculty_alert';
        branches?: string[];
        sections?: string[];
        years?: string[];
        groups?: string[];
        specificRoles?: string[];
        courseCode?: string;
        semester?: string;
    };
    postedBy: {
        name: string;
        role: string;
        collegeId: string;
    };
    createdAt: number;
    expiresAt?: number;
    isRead?: boolean;
    category?: 'general' | 'academic' | 'placement' | 'event' | 'emergency';
}

interface NotificationContextType {
    notifications: Notification[];
    unreadCount: number;
    loading: boolean;
    error: string | null;
    sendNotification: (notification: Omit<Notification, 'id' | 'createdAt' | 'postedBy'>) => Promise<void>;
    markAsRead: (notificationId: string) => Promise<void>;
    markAllAsRead: () => Promise<void>;
    deleteNotification: (notificationId: string) => Promise<void>;
    fetchNotifications: () => void;
    allNotifications: Notification[];
}

const NotificationContext = createContext<NotificationContextType | undefined>(undefined);

// LocalStorage key for notifications
const NOTIFICATIONS_STORAGE_KEY = 'campverse_notifications';

// Helper to get notifications from localStorage
const getLocalNotifications = (): Notification[] => {
    try {
        const stored = localStorage.getItem(NOTIFICATIONS_STORAGE_KEY);
        return stored ? JSON.parse(stored) : [];
    } catch {
        return [];
    }
};

// Helper to save notifications to localStorage
const saveLocalNotifications = (notifications: Notification[]) => {
    try {
        localStorage.setItem(NOTIFICATIONS_STORAGE_KEY, JSON.stringify(notifications));
    } catch (err) {
        console.error('Error saving notifications to localStorage:', err);
    }
};

export const useNotifications = () => {
    const context = useContext(NotificationContext);
    if (!context) {
        throw new Error('useNotifications must be used within a NotificationProvider');
    }
    return context;
};

export const NotificationProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { currentUser, userData } = useAuth();
    const { toast } = useToast();
    const [notifications, setNotifications] = useState<Notification[]>([]);
    const [allNotifications, setAllNotifications] = useState<Notification[]>([]);
    const [unreadCount, setUnreadCount] = useState(0);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [useLocalStorage, setUseLocalStorage] = useState(true); // Default to localStorage
    const previousUnreadCount = useRef(0);

    // Check if notification is relevant to current user
    const isNotificationRelevant = useCallback((notification: Notification, user: any): boolean => {
        if (!user) return false;

        const target = notification.targetAudience;

        // If target is 'all', everyone sees it
        if (target.type === 'all') return true;

        // If target is 'students' and user is a student
        if (target.type === 'students' && user.role === 'student') return true;

        // If target is 'faculty' and user is faculty
        if (target.type === 'faculty' && user.role === 'faculty') return true;

        // Admin sees all notifications
        if (user.role === 'admin') return true;

        // For custom targeting
        if (target.type === 'custom') {
            if (target.specificRoles?.includes(user.role)) return true;

            if (target.branches && target.branches.length > 0) {
                const userBranch = extractBranchFromId(user.collegeId);
                if (target.branches.includes(userBranch)) return true;
            }

            if (target.years && target.years.length > 0) {
                const userYear = extractYearFromId(user.collegeId);
                if (target.years.includes(userYear)) return true;
            }

            if (target.sections && target.sections.length > 0) {
                const userSection = user.section || extractSectionFromId(user.collegeId);
                if (target.sections.includes(userSection)) return true;
            }
        }

        // For Faculty Alerts
        if (target.type === 'faculty_alert') {
            const userYear = extractYearFromId(user.collegeId);
            const userSection = user.section || extractSectionFromId(user.collegeId);
            const userSemester = user.semester || "Semester I"; // Default if not parsed
            
            if (target.years?.[0] === userYear && target.semester === userSemester && target.sections?.[0] === userSection) {
                return true; 
            }
        }

        return false;
    }, []);

    // Helper functions to extract info from college ID
    const extractBranchFromId = (collegeId: string): string => {
        if (!collegeId) return '';
        const branchCode = collegeId.substring(5, 8);
        const branchMap: { [key: string]: string } = {
            'A05': 'CSE',
            'A04': 'ECE',
            'A03': 'EEE',
            'A01': 'CIVIL',
            'A02': 'MECH',
        };
        return branchMap[branchCode] || branchCode;
    };

    const extractYearFromId = (collegeId: string): string => {
        if (!collegeId) return '';
        const yearCode = collegeId.substring(0, 2);
        const currentYear = new Date().getFullYear();
        const admissionYear = parseInt('20' + yearCode);
        // Correct mathematical bounds; 2026 - 2022 yields 4 for 4th years
        // Bound calculation between 1 and 4.
        const yearInt = currentYear - admissionYear;
        const boundedYear = Math.max(1, Math.min(4, yearInt));
        return boundedYear.toString();
    };

    const extractSectionFromId = (collegeId: string): string => {
        if (!collegeId) return '';
        return collegeId.charAt(collegeId.length - 2).toUpperCase();
    };

    // Process notifications for current user
    const processNotifications = useCallback((notificationsList: Notification[]) => {
        // Sort by createdAt descending
        notificationsList.sort((a, b) => b.createdAt - a.createdAt);

        // Store all notifications for admin view
        setAllNotifications(notificationsList);

        // Filter notifications relevant to current user
        if (userData) {
            const relevantNotifications = notificationsList.filter(n =>
                isNotificationRelevant(n, userData)
            );
            setNotifications(relevantNotifications);

            // Count unread
            const unread = relevantNotifications.filter(n => !n.isRead).length;
            setUnreadCount(unread);

            // Show toast on login if there are new notifications (only once per session)
            const toastShown = sessionStorage.getItem('campverse_notif_toast_shown');
            if (!toastShown && unread > 0) {
                sessionStorage.setItem('campverse_notif_toast_shown', 'true');
                toast({
                    title: `🔔 You have ${unread} new notification${unread > 1 ? 's' : ''}!`,
                    description: "Click the bell icon to view your notifications.",
                });
            }
        }

        setError(null);
    }, [userData, isNotificationRelevant, toast]);

    // Fetch notifications from localStorage
    const fetchLocalNotifications = useCallback(() => {
        setLoading(true);
        const localNotifications = getLocalNotifications();
        processNotifications(localNotifications);
        setLoading(false);
    }, [processNotifications]);

    // Fetch and listen to notifications
    const fetchNotifications = useCallback(async () => {
        setLoading(true);
        setError(null);

        // Try Firebase RTDB
        if (firebaseReady && database && auth) {
            try {
                // Ensure we have some Firebase Auth (anonymous if needed)
                // so we satisfy "auth != null" RTDB rules
                if (!auth.currentUser) {
                    try {
                        await signInAnonymously(auth);
                        console.log('[Notifications] Anonymous sign-in successful for reading');
                    } catch (anonErr) {
                        console.warn('[Notifications] Anonymous sign-in failed, trying direct read:', anonErr);
                    }
                }

                const notificationsRef = ref(database, 'notifications');
                const recentNotificationsQuery = query(
                    notificationsRef,
                    orderByChild('createdAt'),
                    limitToLast(100)
                );

                onValue(recentNotificationsQuery, (snapshot) => {
                    const data = snapshot.val();
                    setUseLocalStorage(false);
                    if (data) {
                        const notificationsList: Notification[] = Object.entries(data).map(([id, value]: [string, any]) => ({
                            id,
                            ...value,
                        }));
                        processNotifications(notificationsList);
                    } else {
                        setNotifications([]);
                        setAllNotifications([]);
                        setUnreadCount(0);
                    }
                    setLoading(false);
                }, (err) => {
                    console.error('Error fetching notifications from Firebase:', err);
                    setUseLocalStorage(true);
                    fetchLocalNotifications();
                });
                return;
            } catch (firebaseErr) {
                console.warn('[Notifications] Firebase RTDB read failed:', firebaseErr);
                // Fall through to localStorage
            }
        }

        // Use localStorage (fallback when Firebase is not available)
        fetchLocalNotifications();
    }, [processNotifications, fetchLocalNotifications, userData?.role]);

    // Subscribe to notifications when user logs in
    useEffect(() => {
        if (currentUser && userData) {
            fetchNotifications();

            return () => {
                if (database && firebaseReady && !useLocalStorage) {
                    const notificationsRef = ref(database, 'notifications');
                    off(notificationsRef);
                }
            };
        }
    }, [currentUser, userData]);

    // Send a new notification
    const sendNotification = async (notificationData: Omit<Notification, 'id' | 'createdAt' | 'postedBy'>) => {
        if (!userData) {
            throw new Error('User not authenticated');
        }

        const newNotification: Notification = {
            ...notificationData,
            id: `notif_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            postedBy: {
                name: userData.name || 'Admin',
                role: userData.role || 'admin',
                collegeId: userData.collegeId || 'admin',
            },
            createdAt: Date.now(),
            isRead: false,
        };

        try {
            setError(null);

            // Try Firebase first if available
            if (firebaseReady && database) {
                try {
                    // Ensure Firebase Auth for write operations
                    if (!auth?.currentUser && auth) {
                        try {
                            await signInAnonymously(auth);
                        } catch { /* ignore, push might still fail */ }
                    }
                    const notificationsRef = ref(database, 'notifications');
                    const { id, ...notificationWithoutId } = newNotification;
                    await push(notificationsRef, notificationWithoutId);
                    console.log('Notification sent successfully via Firebase');
                    setUseLocalStorage(false);
                    return;
                } catch (firebaseErr: any) {
                    console.warn('Firebase push failed:', firebaseErr.message);
                    setUseLocalStorage(true);
                }
            }

            // Use localStorage
            const existingNotifications = getLocalNotifications();
            const updatedNotifications = [newNotification, ...existingNotifications];
            saveLocalNotifications(updatedNotifications);
            processNotifications(updatedNotifications);
            console.log('Notification saved to localStorage');
        } catch (err: any) {
            console.error('Error sending notification:', err);
            setError(err.message || 'Failed to send notification');
            throw err;
        }
    };

    // Delete a notification
    const deleteNotification = async (notificationId: string) => {
        try {
            if (!useLocalStorage && firebaseReady && database) {
                const notificationRef = ref(database, `notifications/${notificationId}`);
                await remove(notificationRef);
            } else {
                // Delete from localStorage
                const existingNotifications = getLocalNotifications();
                const updatedNotifications = existingNotifications.filter(n => n.id !== notificationId);
                saveLocalNotifications(updatedNotifications);
                processNotifications(updatedNotifications);
            }
        } catch (err) {
            console.error('Error deleting notification:', err);
            throw err;
        }
    };

    // Mark a notification as read
    const markAsRead = async (notificationId: string) => {
        if (useLocalStorage || !firebaseReady || !database) {
            const existingNotifications = getLocalNotifications();
            const updatedNotifications = existingNotifications.map(n =>
                n.id === notificationId ? { ...n, isRead: true } : n
            );
            saveLocalNotifications(updatedNotifications);
            processNotifications(updatedNotifications);
            return;
        }

        try {
            const notificationRef = ref(database, `notifications/${notificationId}/isRead`);
            await set(notificationRef, true);
        } catch (err) {
            console.error('Error marking notification as read:', err);
        }
    };

    // Mark all notifications as read
    const markAllAsRead = async () => {
        if (useLocalStorage || !firebaseReady || !database) {
            const existingNotifications = getLocalNotifications();
            const updatedNotifications = existingNotifications.map(n => ({ ...n, isRead: true }));
            saveLocalNotifications(updatedNotifications);
            processNotifications(updatedNotifications);
            return;
        }

        try {
            for (const n of notifications) {
                await set(ref(database, `notifications/${n.id}/isRead`), true);
            }
        } catch (err) {
            console.error('Error marking all as read:', err);
        }
    };

    const value = {
        notifications,
        unreadCount,
        loading,
        error,
        sendNotification,
        markAsRead,
        markAllAsRead,
        deleteNotification,
        fetchNotifications,
        allNotifications,
    };

    return (
        <NotificationContext.Provider value={value}>
            {children}
        </NotificationContext.Provider>
    );
};

export default NotificationContext;

import React, {
  createContext,
  useContext,
  useState,
  useEffect,
  ReactNode,
  useCallback,
} from "react";
import { api } from "@/lib/api";
import { useAuth } from "./AuthContext";

export interface PlacementJob {
  _id?: string;
  job_id: string;
  title: string;
  company: string;
  type: string;
  ctc: string;
  stipend: string;
  deadline: string;
  status: string;
  eligibility?: string[];
  eligibleBranches?: string[];
  degree?: string;
  year?: string;
  semester?: string;
  section?: string;
  allowedRollNumbers?: string[] | string;
  appliedCount: number;
  shortlistedCount: number;
  selectedCount: number;
  postedDate?: string;
  createdAt?: string;
  attachments: string[] | { filename: string; url: string }[];
  description?: string;
  bond?: string;
  rounds?: string | string[];
  applied?: boolean;
  eligible?: boolean;
  canApply?: boolean;
  applicationStatus?: string | null;
  location?: string;
  filters?: {
    branch?: string;
    degree?: string;
    year?: string;
    semester?: string;
    section?: string;
  };
  selectedStudents?: string[];
  requirements?: string[];
  benefits?: string[];
}

interface PlacementContextType {
  jobs: PlacementJob[];
  loading: boolean;
  error: string | null;
  addJob: (
    job: Omit<
      PlacementJob,
      | "_id"
      | "appliedCount"
      | "shortlistedCount"
      | "selectedCount"
      | "postedDate"
      | "createdAt"
      | "status"
      | "applied"
      | "eligible"
      | "canApply"
      | "applicationStatus"
    >
  ) => Promise<void>;
  updateJob: (jobId: string, updates: Partial<PlacementJob>) => Promise<void>;
  deleteJob: (jobId: string) => Promise<void>;
  applyToJob: (jobId: string, studentId: string) => Promise<void>;
  refreshJobs: () => Promise<void>;
}

const PlacementContext = createContext<PlacementContextType | undefined>(
  undefined
);

export const PlacementProvider: React.FC<{ children: ReactNode }> = ({
  children,
}) => {
  const [jobs, setJobs] = useState<PlacementJob[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const { currentUser } = useAuth();

  // Fetch jobs from MongoDB API
  const fetchJobs = useCallback(async () => {
    if (!currentUser) {
      setLoading(false);
      return;
    }

    try {
      setLoading(true);
      setError(null);
      console.log("Fetching jobs from MongoDB API...");

      const response = await api.get("/placements?limit=100");
      console.log("API Response:", response);

      // Handle the response structure from the backend
      const jobsData = response.jobs || response;

      if (Array.isArray(jobsData)) {
        // Normalize job data for frontend compatibility
        const normalizedJobs = jobsData.map((job: any) => ({
          ...job,
          // Ensure consistent field names
          postedDate: job.postedDate || job.createdAt,
          attachments: job.attachments || [],
          // Set eligibility flags for students
          eligible: job.canApply !== undefined ? job.canApply : true,
          applied: job.applied || false,
        }));

        setJobs(normalizedJobs);
        console.log("Jobs loaded from MongoDB:", normalizedJobs.length);
      } else {
        console.warn("Unexpected response format:", response);
        setJobs([]);
      }
    } catch (err: any) {
      console.error("Error fetching jobs from API:", err);
      setError(err.message || "Failed to load jobs");
      // Don't clear jobs on error, keep the last known state
    } finally {
      setLoading(false);
    }
  }, [currentUser]);

  // Fetch jobs when user logs in
  useEffect(() => {
    if (currentUser) {
      fetchJobs();
    } else {
      setJobs([]);
      setLoading(false);
    }
  }, [currentUser, fetchJobs]);

  // Add a new job via API
  const addJob = async (
    newJobData: Omit<
      PlacementJob,
      | "_id"
      | "appliedCount"
      | "shortlistedCount"
      | "selectedCount"
      | "postedDate"
      | "createdAt"
      | "status"
      | "applied"
      | "eligible"
      | "canApply"
      | "applicationStatus"
    >
  ) => {
    try {
      setError(null);
      console.log("Adding new job to MongoDB:", newJobData);

      // Prepare job data for API
      const jobPayload = {
        ...newJobData,
        status: "Open",
        // Ensure eligibility is an array
        eligibility: Array.isArray(newJobData.eligibility)
          ? newJobData.eligibility
          : newJobData.eligibility
            ? [newJobData.eligibility as any]
            : ["All Branches"],
        eligibleBranches: newJobData.eligibleBranches || [],
        // Ensure rounds is an array
        rounds: Array.isArray(newJobData.rounds)
          ? newJobData.rounds
          : newJobData.rounds
            ? (newJobData.rounds as string).split(",").map((r) => r.trim())
            : [],
      };

      const response = await api.post("/placements", jobPayload);
      console.log("Job created successfully:", response);

      // Refresh jobs list to get the new job from MongoDB
      await fetchJobs();
    } catch (err: any) {
      console.error("Error adding job:", err);
      setError(err.message || "Failed to add job");
      throw err;
    }
  };

  // Update a job via API
  const updateJob = async (jobId: string, updates: Partial<PlacementJob>) => {
    try {
      setError(null);
      console.log("Updating job:", jobId, updates);

      // Find the job's MongoDB _id
      const job = jobs.find((j) => j.job_id === jobId || j._id === jobId);
      if (!job?._id) {
        throw new Error("Job not found");
      }

      const response = await api.put(`/placements/${job._id}`, updates);
      console.log("Job updated successfully:", response);

      // Refresh jobs list
      await fetchJobs();
    } catch (err: any) {
      console.error("Error updating job:", err);
      setError(err.message || "Failed to update job");
      throw err;
    }
  };

  // Delete a job via API
  const deleteJob = async (jobId: string) => {
    try {
      setError(null);
      console.log("Deleting job:", jobId);

      // Find the job's MongoDB _id
      const job = jobs.find((j) => j.job_id === jobId || j._id === jobId);
      if (!job?._id) {
        throw new Error("Job not found");
      }

      await api.delete(`/placements/${job._id}`);
      console.log("Job deleted successfully");

      // Remove job from local state immediately for better UX
      setJobs((prevJobs) =>
        prevJobs.filter((j) => j.job_id !== jobId && j._id !== jobId)
      );
    } catch (err: any) {
      console.error("Error deleting job:", err);
      setError(err.message || "Failed to delete job");
      throw err;
    }
  };

  // Apply to a job via API
  const applyToJob = async (jobId: string, studentId: string) => {
    try {
      setError(null);
      console.log("Applying to job:", jobId);

      // Find the job's MongoDB _id
      const job = jobs.find((j) => j.job_id === jobId || j._id === jobId);
      if (!job?._id) {
        throw new Error("Job not found");
      }

      const response = await api.post(`/placements/${job._id}/apply`, {
        notes: `Applied by ${studentId}`,
      });
      console.log("Application submitted:", response);

      // Update local state to reflect the application
      setJobs((prevJobs) =>
        prevJobs.map((j) =>
          j.job_id === jobId || j._id === jobId
            ? { ...j, applied: true, appliedCount: j.appliedCount + 1 }
            : j
        )
      );
    } catch (err: any) {
      console.error("Error applying to job:", err);
      setError(err.message || "Failed to apply to job");
      throw err;
    }
  };

  // Manual refresh function
  const refreshJobs = async () => {
    await fetchJobs();
  };

  return (
    <PlacementContext.Provider
      value={{
        jobs,
        loading,
        error,
        addJob,
        updateJob,
        deleteJob,
        applyToJob,
        refreshJobs,
      }}
    >
      {children}
    </PlacementContext.Provider>
  );
};

export const usePlacement = () => {
  const context = useContext(PlacementContext);
  if (context === undefined) {
    throw new Error("usePlacement must be used within a PlacementProvider");
  }
  return context;
};

import React, { createContext, useContext, useState, useEffect, ReactNode, useCallback } from "react";
import { placementAPI, type PlacementJob as APIPlacementJob, type JobApplication } from "../services/api";
import { useAuth } from "./AuthContext";
import { toast } from "@/hooks/use-toast";

// Extended interface with frontend-specific fields
export interface PlacementJob extends Omit<APIPlacementJob, '_id' | 'postedBy' | 'createdAt' | 'updatedAt'> {
  _id?: string;
  applied?: boolean;
  applicationStatus?: string | null;
  canApply?: boolean;
  application?: JobApplication | null;
  postedBy?: {
    _id: string;
    name: string;
    collegeId: string;
    email?: string;
  };
  createdAt?: Date;
  updatedAt?: Date;
}

interface PlacementContextType {
  jobs: PlacementJob[];
  loading: boolean;
  error: string | null;
  pagination: {
    current: number;
    pages: number;
    total: number;
  };
  filters: {
    status?: string;
    company?: string;
    type?: string;
    eligibility?: string;
  };

  // Actions
  fetchJobs: (page?: number, filters?: any) => Promise<void>;
  addJob: (jobData: Partial<PlacementJob>) => Promise<PlacementJob | null>;
  updateJob: (jobId: string, updates: Partial<PlacementJob>) => Promise<PlacementJob | null>;
  deleteJob: (jobId: string) => Promise<boolean>;
  applyToJob: (jobId: string, applicationData?: any) => Promise<boolean>;
  getJobById: (jobId: string) => Promise<PlacementJob | null>;

  // Filters and pagination
  setFilters: (filters: any) => void;
  clearFilters: () => void;
  setPage: (page: number) => void;

  // Real-time updates
  refreshJobs: () => Promise<void>;

  // Student specific
  getStudentApplications: () => Promise<JobApplication[]>;

  // Admin/Faculty specific
  getJobApplications: (jobId: string) => Promise<JobApplication[]>;
  updateApplicationStatus: (jobId: string, applicationId: string, status: string) => Promise<boolean>;
  getPlacementStats: () => Promise<any>;
}

const PlacementContext = createContext<PlacementContextType | undefined>(undefined);

export const PlacementProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const { userData, currentUser } = useAuth();
  const [jobs, setJobs] = useState<PlacementJob[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [pagination, setPagination] = useState({
    current: 1,
    pages: 1,
    total: 0,
  });
  const [filters, setFiltersState] = useState({});

  // Fetch jobs from API (with fallback to localStorage)
  const fetchJobs = useCallback(async (page: number = 1, customFilters: any = {}) => {
    if (!currentUser) return;

    setLoading(true);
    setError(null);

    try {
      // Try localStorage first (for offline/development mode)
      const savedJobs = localStorage.getItem('placement_jobs');

      if (savedJobs) {
        const parsedJobs = JSON.parse(savedJobs);
        setJobs(parsedJobs);
        setPagination({ current: 1, pages: 1, total: parsedJobs.length });
        setLoading(false);
        return;
      }

      // Fallback to mock data if no API and no saved jobs
      const mockJobs = [
        {
          _id: "1",
          job_id: "TCS2025",
          title: "Assistant System Engineer",
          company: "TCS",
          type: "Full Time",
          ctc: "3.36 LPA",
          deadline: "2025-06-15T23:59:00",
          status: "Open",
          eligibility: ["All Branches"],
          appliedCount: 156,
          shortlistedCount: 45,
          selectedCount: 8,
          postedDate: "2025-01-15T09:00:00",
          attachments: [],
          applied: false,
          canApply: true,
        },
        {
          _id: "2",
          job_id: "WIPRO2025",
          title: "Project Engineer",
          company: "Wipro",
          type: "Full Time",
          ctc: "4.50 LPA",
          deadline: "2025-05-20T18:00:00",
          status: "Open",
          eligibility: ["CSE", "IT"],
          appliedCount: 89,
          shortlistedCount: 25,
          selectedCount: 15,
          postedDate: "2025-01-10T14:00:00",
          attachments: [],
          applied: false,
          canApply: true,
        }
      ];

      setJobs(mockJobs);
      setPagination({ current: 1, pages: 1, total: mockJobs.length });
      localStorage.setItem('placement_jobs', JSON.stringify(mockJobs));

    } catch (err) {
      // Silently handle errors and use fallback data
      console.warn('API not available, using local data');
      setError(null); // Don't show error to user
    } finally {
      setLoading(false);
    }
  }, [currentUser, filters]);

  // Add new job
  const addJob = useCallback(async (jobData: Partial<PlacementJob>): Promise<PlacementJob | null> => {
    if (!currentUser || !['admin', 'faculty'].includes(userData?.role || '')) {
      toast({
        title: "Error",
        description: "You don't have permission to add jobs",
        variant: "destructive",
      });
      return null;
    }

    try {
      setLoading(true);

      // Create new job with mock data
      const newJob: PlacementJob = {
        _id: Date.now().toString(),
        job_id: jobData.job_id || '',
        title: jobData.title || '',
        company: jobData.company || '',
        type: jobData.type || 'Full Time',
        ctc: jobData.ctc || '',
        deadline: jobData.deadline || '',
        status: 'Open',
        eligibility: jobData.eligibility || ['All Branches'],
        appliedCount: 0,
        shortlistedCount: 0,
        selectedCount: 0,
        postedDate: new Date().toISOString(),
        attachments: [],
        applied: false,
        canApply: true,
        description: jobData.description,
        rounds: jobData.rounds || [],
        postedBy: {
          _id: userData?._id || '',
          name: userData?.name || '',
          collegeId: userData?.collegeId || '',
        },
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      // Add to local state and localStorage
      const updatedJobs = [newJob, ...jobs];
      setJobs(updatedJobs);
      localStorage.setItem('placement_jobs', JSON.stringify(updatedJobs));

      toast({
        title: "Success",
        description: "Job posted successfully",
      });

      return newJob;
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to add job';
      toast({
        title: "Error",
        description: errorMessage,
        variant: "destructive",
      });
      return null;
    } finally {
      setLoading(false);
    }
  }, [currentUser, userData, jobs]);

  // Update job
  const updateJob = useCallback(async (jobId: string, updates: Partial<PlacementJob>): Promise<PlacementJob | null> => {
    if (!currentUser || !['admin', 'faculty'].includes(userData?.role || '')) {
      toast({
        title: "Error",
        description: "You don't have permission to update jobs",
        variant: "destructive",
      });
      return null;
    }

    try {
      setLoading(true);

      // Update local state and localStorage
      const updatedJobs = jobs.map(job =>
        job._id === jobId ? { ...job, ...updates, updatedAt: new Date() } : job
      );

      setJobs(updatedJobs);
      localStorage.setItem('placement_jobs', JSON.stringify(updatedJobs));

      const updatedJob = updatedJobs.find(job => job._id === jobId);

      toast({
        title: "Success",
        description: "Job updated successfully",
      });

      return updatedJob || null;
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to update job';
      toast({
        title: "Error",
        description: errorMessage,
        variant: "destructive",
      });
      return null;
    } finally {
      setLoading(false);
    }
  }, [currentUser, userData, jobs]);

  // Delete job
  const deleteJob = useCallback(async (jobId: string): Promise<boolean> => {
    if (!currentUser || userData?.role !== 'admin') {
      toast({
        title: "Error",
        description: "Only administrators can delete jobs",
        variant: "destructive",
      });
      return false;
    }

    try {
      setLoading(true);

      // Remove from local state and localStorage
      const updatedJobs = jobs.filter(job => job._id !== jobId);
      setJobs(updatedJobs);
      localStorage.setItem('placement_jobs', JSON.stringify(updatedJobs));

      toast({
        title: "Success",
        description: "Job deleted successfully",
      });

      return true;
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to delete job';
      toast({
        title: "Error",
        description: errorMessage,
        variant: "destructive",
      });
      return false;
    } finally {
      setLoading(false);
    }
  }, [currentUser, userData, jobs]);

  // Apply to job
  const applyToJob = useCallback(async (jobId: string, applicationData: any = {}): Promise<boolean> => {
    if (!currentUser || userData?.role !== 'student') {
      toast({
        title: "Error",
        description: "Only students can apply to jobs",
        variant: "destructive",
      });
      return false;
    }

    try {
      setLoading(true);

      // Update local state and localStorage
      const updatedJobs = jobs.map(job =>
        job._id === jobId ? {
          ...job,
          applied: true,
          appliedCount: (job.appliedCount || 0) + 1,
          applicationStatus: 'Applied'
        } : job
      );

      setJobs(updatedJobs);
      localStorage.setItem('placement_jobs', JSON.stringify(updatedJobs));

      toast({
        title: "Success",
        description: "Application submitted successfully",
      });

      return true;
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to apply to job';
      toast({
        title: "Error",
        description: errorMessage,
        variant: "destructive",
      });
      return false;
    } finally {
      setLoading(false);
    }
  }, [currentUser, userData, jobs]);

  // Get job by ID
  const getJobById = useCallback(async (jobId: string): Promise<PlacementJob | null> => {
    if (!currentUser) return null;

    try {
      const job = jobs.find(j => j._id === jobId);
      return job || null;
    } catch (err) {
      console.error('Error fetching job:', err);
      return null;
    }
  }, [currentUser, jobs]);

  // Student applications
  const getStudentApplications = useCallback(async (): Promise<JobApplication[]> => {
    if (!currentUser || userData?.role !== 'student') return [];

    try {
      // Mock applications for demo
      const mockApplications = jobs
        .filter(job => job.applied)
        .map(job => ({
          _id: `app_${job._id}`,
          jobId: job._id!,
          studentId: userData._id || '',
          status: job.applicationStatus || 'Applied',
          appliedDate: new Date(),
          documents: [],
        })) as JobApplication[];

      return mockApplications;
    } catch (err) {
      console.error('Error fetching applications:', err);
      return [];
    }
  }, [currentUser, userData, jobs]);

  // Get applications for a job (admin/faculty)
  const getJobApplications = useCallback(async (jobId: string): Promise<JobApplication[]> => {
    if (!currentUser || !['admin', 'faculty'].includes(userData?.role || '')) return [];

    try {
      // Mock applications for demo
      const job = jobs.find(j => j._id === jobId);
      if (!job) return [];

      const mockApplications = Array.from({ length: job.appliedCount || 0 }, (_, i) => ({
        _id: `app_${jobId}_${i}`,
        jobId,
        studentId: `student_${i}`,
        status: 'Applied',
        appliedDate: new Date(),
        documents: [],
      })) as JobApplication[];

      return mockApplications;
    } catch (err) {
      console.error('Error fetching job applications:', err);
      return [];
    }
  }, [currentUser, userData, jobs]);

  // Update application status
  const updateApplicationStatus = useCallback(async (
    jobId: string,
    applicationId: string,
    status: string
  ): Promise<boolean> => {
    if (!currentUser || !['admin', 'faculty'].includes(userData?.role || '')) return false;

    try {
      toast({
        title: "Success",
        description: "Application status updated successfully",
      });

      return true;
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to update application status';
      toast({
        title: "Error",
        description: errorMessage,
        variant: "destructive",
      });
      return false;
    }
  }, [currentUser, userData]);

  // Get placement statistics
  const getPlacementStats = useCallback(async () => {
    if (!currentUser || !['admin', 'faculty'].includes(userData?.role || '')) return null;

    try {
      const totalJobs = jobs.length;
      const activeJobs = jobs.filter(job => job.status === 'Open').length;
      const totalApplications = jobs.reduce((sum, job) => sum + (job.appliedCount || 0), 0);

      return {
        overview: {
          totalJobs,
          activeJobs,
          totalApplications,
        },
        applicationsByStatus: [
          { _id: 'Applied', count: totalApplications },
          { _id: 'Shortlisted', count: Math.floor(totalApplications * 0.3) },
          { _id: 'Selected', count: Math.floor(totalApplications * 0.1) },
        ],
        topCompanies: jobs.slice(0, 5).map(job => ({
          _id: job.company,
          jobCount: 1,
          totalApplications: job.appliedCount || 0,
        })),
      };
    } catch (err) {
      console.error('Error fetching placement stats:', err);
      return null;
    }
  }, [currentUser, userData, jobs]);

  // Filter and pagination functions
  const setFilters = useCallback((newFilters: any) => {
    setFiltersState(newFilters);
    setPagination(prev => ({ ...prev, current: 1 }));
  }, []);

  const clearFilters = useCallback(() => {
    setFiltersState({});
    setPagination(prev => ({ ...prev, current: 1 }));
  }, []);

  const setPage = useCallback((page: number) => {
    setPagination(prev => ({ ...prev, current: page }));
  }, []);

  const refreshJobs = useCallback(() => {
    return fetchJobs(pagination.current, filters);
  }, [fetchJobs, pagination.current, filters]);

  // Load jobs when context mounts or auth changes
  useEffect(() => {
    if (currentUser && userData) {
      fetchJobs(1);
    }
  }, [currentUser, userData, fetchJobs]);

  // Auto-refresh jobs every 5 minutes
  useEffect(() => {
    const interval = setInterval(() => {
      if (currentUser && userData) {
        refreshJobs();
      }
    }, 5 * 60 * 1000); // 5 minutes

    return () => clearInterval(interval);
  }, [currentUser, userData, refreshJobs]);

  const value: PlacementContextType = {
    jobs,
    loading,
    error,
    pagination,
    filters,

    fetchJobs,
    addJob,
    updateJob,
    deleteJob,
    applyToJob,
    getJobById,

    setFilters,
    clearFilters,
    setPage,

    refreshJobs,

    getStudentApplications,
    getJobApplications,
    updateApplicationStatus,
    getPlacementStats,
  };

  return (
    <PlacementContext.Provider value={value}>
      {children}
    </PlacementContext.Provider>
  );
};

