        });
        if (!response.ok) {
            if (response.status === 401) {
                console.warn("Unauthorized API call - token may be expired or missing");
                clearAuthToken();
                localStorage.removeItem("dev-user");
                window.location.href = "/login";
            }
            throw new Error(`API Error: ${response.statusText}`);
