export default Index;

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { useNavigate } from "react-router-dom";
import { useAuth } from "@/contexts/AuthContext";
import { validateCollegeId } from "@/lib/auth";
import { AlertCircle, Eye, EyeOff } from "lucide-react";

const Login = () => {
  const [userType, setUserType] = useState<"Student" | "Faculty">("Student");
  const [userId, setUserId] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [resetEmailSent, setResetEmailSent] = useState(false);
  const navigate = useNavigate();
  const { login } = useAuth();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userId || !password) {
      setError("Please fill in all fields");
      return;
    }

    // Validate college ID format (except for admin)
    if (userId !== "admin" && !validateCollegeId(userId)) {
      setError("Invalid ID format");
      return;
    }

    setLoading(true);
    setError("");

    try {
      await login(userId, password);
      // Redirect to homepage - DynamicHomepage will show the appropriate dashboard
      navigate("/", { replace: true });
    } catch (error: any) {
      console.error("Login error:", error);

      // Handle specific Firebase errors
      if (error.code === "auth/user-not-found") {
        setError("User not found. Please check your ID or contact admin.");
      } else if (error.code === "auth/wrong-password") {
        setError("Incorrect password. Try again or reset your password.");
      } else if (error.code === "auth/invalid-email") {
        setError("Invalid email format.");
      } else if (error.code === "auth/too-many-requests") {
        setError("Too many failed attempts. Please try again later.");
      } else {
        setError(error.message || "Login failed. Please try again.");
      }
    } finally {
      setLoading(false);
    }
  };

  const handlePasswordReset = async () => {
    if (!userId) {
      setError("Please enter your User ID first");
      return;
    }

    if (userId === "admin") {
      setError("Admin password cannot be reset");
      return;
    }

    if (!validateCollegeId(userId)) {
      setError("Please enter a valid User ID");
      return;
    }

    setLoading(true);
    setError("");

    try {
      const { resetPassword } = await import("@/lib/auth");
      await resetPassword(userId);
      setResetEmailSent(true);
    } catch (error: any) {
      if (error.code === "auth/user-not-found") {
        setError("No account found for this ID. Please login first to create your account.");
      } else {
        setError(error.message || "Failed to send reset email. Please try again.");
      }
    } finally {
      setLoading(false);
    }
  };

  // Auto-detect user type based on college ID
  const handleUserIdChange = (value: string) => {
    let normalized = value.trim().toUpperCase();
    if (normalized === "ADMIN") normalized = "admin";

    setUserId(normalized);
    setError("");
    setResetEmailSent(false);

    // Auto-detect role based on section (6th character)
    if (normalized.length >= 6 && normalized !== "admin") {
      const section = normalized.charAt(5);
      if (section === "Z") {
        setUserType("Faculty");
      } else if (section.match(/[A-F]/)) {
        setUserType("Student");
      }
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-primary/20 via-purple-500/10 to-background flex items-center justify-center p-4">
      <div className="w-full max-w-6xl grid lg:grid-cols-2 gap-8 items-center">
        {/* Left side - Welcome message */}
        <div className="hidden lg:block relative">
          <div className="relative h-[600px] bg-gradient-to-br from-primary/10 to-purple-500/10 rounded-2xl overflow-hidden">
            <div className="absolute inset-0 bg-gradient-to-br from-primary/30 to-purple-500/20"></div>
            <div className="relative z-10 p-12 flex flex-col justify-center h-full text-center">
              <h1 className="text-4xl font-bold text-foreground mb-4">
                Welcome to
                <br />
                CampVerse
              </h1>
              <p className="text-lg text-muted-foreground">
                Simplifying campus life, one feature at a time.
              </p>
            </div>
          </div>
        </div>

        {/* Right side - Login form */}
        <div className="w-full max-w-md mx-auto">
          <Card className="shadow-2xl border-border/50">
            <CardHeader className="text-center pb-2">
              <CardTitle className="text-3xl font-bold">Login</CardTitle>
            </CardHeader>
            <CardContent className="space-y-6">
              {/* Error Alert */}
              {error && (
                <Alert variant="destructive">
                  <AlertCircle className="h-4 w-4" />
                  <AlertDescription>{error}</AlertDescription>
                </Alert>
              )}

              {/* Success Alert */}
              {resetEmailSent && (
                <Alert className="border-green-200 bg-green-50 text-green-800">
                  <AlertCircle className="h-4 w-4" />
                  <AlertDescription>
                    Password reset email sent to {userId}@cvr.ac.in
                  </AlertDescription>
                </Alert>
              )}

              {/* User Type Toggle */}
              <div className="flex bg-muted rounded-lg p-1">
                <button
                  type="button"
                  onClick={() => setUserType("Student")}
                  className={`flex-1 py-2 px-4 rounded-md text-sm font-medium transition-all ${userType === "Student"
                    ? "bg-primary text-primary-foreground shadow-sm"
                    : "text-muted-foreground hover:text-foreground"
                    }`}
                >
                  Student
                </button>
                <button
                  type="button"
                  onClick={() => setUserType("Faculty")}
                  className={`flex-1 py-2 px-4 rounded-md text-sm font-medium transition-all ${userType === "Faculty"
                    ? "bg-primary text-primary-foreground shadow-sm"
                    : "text-muted-foreground hover:text-foreground"
                    }`}
                >
                  Faculty
                </button>
              </div>

              {/* Login Form */}
              <form onSubmit={handleLogin} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">
                    User ID
                  </label>
                  <Input
                    type="text"
                    placeholder="Enter your User ID"
                    value={userId}
                    onChange={(e) => handleUserIdChange(e.target.value)}
                    className="h-12"
                    autoComplete="username"
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-foreground mb-2">
                    Password
                  </label>
                  <div className="relative">
                    <Input
                      type={showPassword ? "text" : "password"}
                      placeholder="Enter your password"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      className="h-12 pr-10"
                      autoComplete="current-password"
                      required
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-3 top-1/2 transform -translate-y-1/2 text-muted-foreground hover:text-foreground"
                    >
                      {showPassword ? (
                        <EyeOff className="h-4 w-4" />
                      ) : (
                        <Eye className="h-4 w-4" />
                      )}
                    </button>
                  </div>
                </div>

                <Button
                  type="submit"
                  className="w-full h-12 text-lg font-semibold"
                  size="lg"
                  disabled={loading}
                >
                  {loading ? (
                    <div className="flex items-center">
                      <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin mr-2"></div>
                      Signing in...
                    </div>
                  ) : (
                    "Login"
                  )}
                </Button>

                {/* Forgot Password */}
                <div className="text-center">
                  <button
                    type="button"
                    onClick={handlePasswordReset}
                    className="text-sm text-primary hover:text-primary/80 transition-colors"
                    disabled={loading}
                  >
                    Forgot Password?
                  </button>
                </div>
              </form>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
};

export default Login;

import { useState, useEffect } from "react";
import AdminLayout from "@/components/AdminLayout";
import { useAuth } from "@/contexts/AuthContext";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogFooter,
} from "@/components/ui/dialog";
import { CalendarDays, Plus, Trash2, Edit } from "lucide-react";
import { toast } from "sonner";
import { format } from "date-fns";

interface AcademicEvent {
  _id: string;
  title: string;
  semester: string;
  degree?: string;
  year?: string;
  type: string;
  startDate: string;
  endDate: string;
  color: string;
  tagLabel: string;
}

const DEGREES = [
  { value: "All", label: "All Degrees" },
  { value: "Major", label: "Major" },
  { value: "Minor", label: "Minor" },
];

const YEARS = [
  { value: "All", label: "All Years" },
  { value: "I Year", label: "I Year" },
  { value: "II Year", label: "II Year" },
  { value: "III Year", label: "III Year" },
  { value: "IV Year", label: "IV Year" },
];

const SEMESTERS = [
  { value: "All", label: "All Semesters" },
  { value: "1", label: "Semester I" },
  { value: "2", label: "Semester II" },
];

const AdminAcademicCalendar = () => {
  const { userData } = useAuth();
  const [events, setEvents] = useState<AcademicEvent[]>([]);
  const [selectedDegree, setSelectedDegree] = useState<string>("All");
  const [selectedYear, setSelectedYear] = useState<string>("All");
  const [selectedSemester, setSelectedSemester] = useState<string>("All");
  
  // Dialog State
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  
  // Form State
  const [formData, setFormData] = useState({
    title: "",
    degree: "All",
    year: "All",
    semester: "All",
    type: "Academic",
    startDate: "",
    endDate: "",
    color: "",
    tagLabel: ""
  });

  const fetchEvents = async () => {
    if (!userData?.collegeId) return;
    try {
      const apiBaseUrl = import.meta.env.VITE_API_BASE_URL || "http://localhost:5000/api";
      const res = await fetch(`${apiBaseUrl}/academic-calendar?collegeId=${userData.collegeId}&semester=${selectedSemester}&degree=${selectedDegree}&year=${selectedYear}`);
      if (res.ok) {
        const data = await res.json();
        setEvents(data);
      }
    } catch (error) {
      console.error("Failed to fetch events:", error);
      toast.error("Failed to load academic calendar");
    }
  };

  useEffect(() => {
    fetchEvents();
  }, [userData?.collegeId, selectedSemester, selectedDegree, selectedYear]);

  const handleSave = async () => {
    if (!formData.title || !formData.startDate || !formData.endDate || !formData.semester || !formData.type) {
      toast.error("Please fill all required fields");
      return;
    }

    try {
      const apiBaseUrl = import.meta.env.VITE_API_BASE_URL || "http://localhost:5000/api";
      const method = editingId ? "PUT" : "POST";
      const url = editingId 
        ? `${apiBaseUrl}/academic-calendar/${editingId}`
        : `${apiBaseUrl}/academic-calendar`;

      // Derive auto-color if not explicitly selected
      const getColorForType = (type: string) => {
        if (type === "Academic") return "bg-green-500";
        if (type === "Exam") return "bg-blue-500";
        if (type === "Holiday") return "bg-yellow-500";
        return "bg-slate-500";
      };

      const finalColor = (!formData.color || formData.color === "none") 
        ? getColorForType(formData.type) 
        : formData.color;

      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          collegeId: userData?.collegeId,
          ...formData,
          color: finalColor
        })
      });

      if (res.ok) {
        toast.success(editingId ? "Event updated successfully" : "Event created successfully");
        setIsDialogOpen(false);
        setEditingId(null);
        setFormData({ title: "", degree: "All", year: "All", semester: "All", type: "Academic", startDate: "", endDate: "", color: "", tagLabel: "" });
        fetchEvents();
      } else {
        const err = await res.json();
        toast.error(err.error || "Failed to save event");
      }
    } catch (error) {
      console.error("Error saving event:", error);
      toast.error("An error occurred");
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this event?")) return;
    try {
      const apiBaseUrl = import.meta.env.VITE_API_BASE_URL || "http://localhost:5000/api";
      const res = await fetch(`${apiBaseUrl}/academic-calendar/${id}`, {
        method: "DELETE"
      });
      if (res.ok) {
        toast.success("Event deleted");
        fetchEvents();
      }
    } catch (error) {
      console.error("Error deleting event:", error);
      toast.error("Failed to delete event");
    }
  };

  const openEdit = (event: AcademicEvent) => {
    setEditingId(event._id);
    setFormData({
      title: event.title,
      degree: event.degree || "All",
      year: event.year || "All",
      semester: event.semester || "All",
      type: event.type,
      startDate: format(new Date(event.startDate), "yyyy-MM-dd"),
      endDate: format(new Date(event.endDate), "yyyy-MM-dd"),
      color: event.color || "",
      tagLabel: event.tagLabel || ""
    });
    setIsDialogOpen(true);
  };

  const resetForm = () => {
    setEditingId(null);
    setFormData({ title: "", degree: selectedDegree, year: selectedYear, semester: selectedSemester, type: "Academic", startDate: "", endDate: "", color: "", tagLabel: "" });
  };

  const formatDateLabel = (start: string, end: string) => {
    const sDate = new Date(start);
    const eDate = new Date(end);
    if (sDate.getTime() === eDate.getTime()) {
      return format(sDate, "dd.MM.yyyy");
    }
    return `${format(sDate, "dd.MM.yyyy")} to ${format(eDate, "dd.MM.yyyy")}`;
  };

  return (
    <AdminLayout>
      <div className="max-w-7xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
              <CalendarDays className="w-8 h-8 text-primary" />
              Academic Calendar
            </h1>
            <p className="text-muted-foreground mt-1">
              Manage semester-wise academic events, exams, and holidays
            </p>
          </div>
        </div>

        {/* Controls */}
        <Card>
          <CardContent className="p-4 flex flex-col sm:flex-row gap-4 justify-between items-center">
            <div className="flex items-center gap-4 w-full sm:w-auto">
              <div className="w-32">
                <Label className="sr-only">Filter by Degree</Label>
                <Select value={selectedDegree} onValueChange={setSelectedDegree}>
                  <SelectTrigger>
                    <SelectValue placeholder="Degree" />
                  </SelectTrigger>
                  <SelectContent>
                    {DEGREES.map(deg => (
                      <SelectItem key={deg.value} value={deg.value}>{deg.label}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="w-32">
                <Label className="sr-only">Filter by Year</Label>
                <Select value={selectedYear} onValueChange={setSelectedYear}>
                  <SelectTrigger>
                    <SelectValue placeholder="Year" />
                  </SelectTrigger>
                  <SelectContent>
                    {YEARS.map(yr => (
                      <SelectItem key={yr.value} value={yr.value}>{yr.label}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="w-48">
                <Label className="sr-only">Filter by Semester</Label>
                <Select value={selectedSemester} onValueChange={setSelectedSemester}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select Semester" />
                  </SelectTrigger>
                  <SelectContent>
                    {SEMESTERS.map(sem => (
                      <SelectItem key={sem.value} value={sem.value}>{sem.label}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
              <DialogTrigger asChild>
                <Button onClick={resetForm} className="w-full sm:w-auto flex items-center gap-2">
                  <Plus className="w-4 h-4" /> Add Event
                </Button>
              </DialogTrigger>
              <DialogContent className="sm:max-w-[425px]">
                <DialogHeader>
                  <DialogTitle>{editingId ? "Edit Event" : "Create Event"}</DialogTitle>
                </DialogHeader>
                <div className="grid gap-4 py-4">
                  <div className="space-y-2">
                    <Label>Title</Label>
                    <Input 
                      placeholder="e.g., I Mid Examinations"
                      value={formData.title}
                      onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                    />
                  </div>
                  <div className="grid grid-cols-3 gap-4">
                    <div className="space-y-2">
                      <Label>Degree</Label>
                      <Select value={formData.degree} onValueChange={(v) => setFormData({ ...formData, degree: v })}>
                        <SelectTrigger><SelectValue /></SelectTrigger>
                        <SelectContent>
                          {DEGREES.map(deg => (
                            <SelectItem key={deg.value} value={deg.value}>{deg.label}</SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="space-y-2">
                      <Label>Year</Label>
                      <Select value={formData.year} onValueChange={(v) => setFormData({ ...formData, year: v })}>
                        <SelectTrigger><SelectValue /></SelectTrigger>
                        <SelectContent>
                          {YEARS.map(yr => (
                            <SelectItem key={yr.value} value={yr.value}>{yr.label}</SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="space-y-2">
                      <Label>Semester</Label>
                      <Select value={formData.semester} onValueChange={(v) => setFormData({ ...formData, semester: v })}>
                        <SelectTrigger><SelectValue /></SelectTrigger>
                        <SelectContent>
                          {SEMESTERS.map(sem => (
                            <SelectItem key={sem.value} value={sem.value}>{sem.label}</SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="space-y-2">
                      <Label>Type</Label>
                      <Select value={formData.type} onValueChange={(v) => setFormData({ ...formData, type: v })}>
                        <SelectTrigger><SelectValue /></SelectTrigger>
                        <SelectContent>
                          <SelectItem value="Academic">Academic</SelectItem>
                          <SelectItem value="Exam">Exam</SelectItem>
                          <SelectItem value="Holiday">Holiday</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label>Start Date</Label>
                      <Input 
                        type="date"
                        value={formData.startDate}
                        onChange={(e) => setFormData({ ...formData, startDate: e.target.value })}
                      />
                    </div>
                    <div className="space-y-2">
                      <Label>End Date</Label>
                      <Input 
                        type="date"
                        value={formData.endDate}
                        onChange={(e) => setFormData({ ...formData, endDate: e.target.value })}
                      />
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label>Color Tag (Optional)</Label>
                      <Select value={formData.color} onValueChange={(v) => setFormData({ ...formData, color: v })}>
                        <SelectTrigger>
                          <SelectValue placeholder="Auto (Based on Type)" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="none">Auto (Based on Type)</SelectItem>
                          <SelectItem value="bg-green-500">Green</SelectItem>
                          <SelectItem value="bg-blue-500">Blue</SelectItem>
                          <SelectItem value="bg-yellow-500">Yellow</SelectItem>
                          <SelectItem value="bg-red-500">Red</SelectItem>
                          <SelectItem value="bg-purple-500">Purple</SelectItem>
                          <SelectItem value="bg-indigo-500">Indigo</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="space-y-2">
                      <Label>Tag Label (Optional)</Label>
                      <Input 
                        placeholder="e.g., 1 Week (Auto if left blank)"
                        value={formData.tagLabel}
                        onChange={(e) => setFormData({ ...formData, tagLabel: e.target.value })}
                      />
                    </div>
                  </div>
                </div>
                <DialogFooter>
                  <Button variant="outline" onClick={() => setIsDialogOpen(false)}>Cancel</Button>
                  <Button onClick={handleSave}>Save Event</Button>
                </DialogFooter>
              </DialogContent>
            </Dialog>
          </CardContent>
        </Card>

        {/* Calendar View */}
        <Card className="border-border/50 shadow-lg">
          <CardHeader>
            <CardTitle className="text-lg">Academic Calendar - {SEMESTERS.find(s => s.value === selectedSemester)?.label}</CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            {events.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                <CalendarDays className="w-12 h-12 mx-auto mb-3 opacity-20" />
                <p>No Academic Events Available</p>
              </div>
            ) : (
              events.map((event) => (
                <div
                  key={event._id}
                  className="flex items-center space-x-3 p-2 rounded-lg bg-muted/30 hover:bg-muted/50 transition-colors group relative pr-20"
                >
                  <div
                    className={`w-3 h-3 rounded-full ${event.color}`}
                  ></div>
                  <div className="flex-1 overflow-hidden">
                    <div className="text-sm font-medium text-foreground truncate">
                      {event.title}
                    </div>
                    <div className="text-xs text-muted-foreground">
                      {formatDateLabel(event.startDate, event.endDate)}
                    </div>
                  </div>
                  <Badge variant="secondary" className="text-xs shrink-0 mr-2">
                    {event.tagLabel}
                  </Badge>
                  
                  {/* Action buttons appear on hover in large screens, or just positioned absolute right */}
                  <div className="absolute right-2 opacity-0 group-hover:opacity-100 transition-opacity flex gap-1">
                    <Button variant="ghost" size="icon" className="h-8 w-8 text-blue-500" onClick={() => openEdit(event)}>
                      <Edit className="w-4 h-4" />
                    </Button>
                    <Button variant="ghost" size="icon" className="h-8 w-8 text-red-500" onClick={() => handleDelete(event._id)}>
                      <Trash2 className="w-4 h-4" />
                    </Button>
                  </div>
                </div>
              ))
            )}
          </CardContent>
        </Card>
      </div>
    </AdminLayout>
  );
};

export default AdminAcademicCalendar;

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
    AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import AdminLayout from "@/components/AdminLayout";
import { useAuth } from "@/contexts/AuthContext";
import { useNotifications } from "@/contexts/NotificationContext";
import { useToast } from "@/hooks/use-toast";
import {
    Bell,
    RefreshCw,
    Loader2,
    Search,
    AlertTriangle,
    CheckCircle,
    User,
    Users,
    Clock,
    Trash2,
    Plus,
    Send,
} from "lucide-react";

const AdminAlerts = () => {
    const { userData } = useAuth();
    const { allNotifications, loading, error, fetchNotifications, deleteNotification, sendNotification } = useNotifications();
    const { toast } = useToast();
    const [searchTerm, setSearchTerm] = useState("");
    const [urgencyFilter, setUrgencyFilter] = useState("all");
    const [categoryFilter, setCategoryFilter] = useState("all");
    const [deletingId, setDeletingId] = useState<string | null>(null);

    // Notification Form State (Matching Dashboard)
    const [isNotificationModalOpen, setIsNotificationModalOpen] = useState(false);
    const [isNotificationSubmitting, setIsNotificationSubmitting] = useState(false);
    const [notificationForm, setNotificationForm] = useState({
        title: "",
        message: "",
        urgency: "normal" as "normal" | "important" | "critical",
        targetType: "all" as "all" | "students" | "faculty" | "custom",
        category: "general" as "general" | "academic" | "placement" | "event" | "emergency",
        branches: [] as string[],
        sections: [] as string[],
        years: [] as string[],
    });

    const handleNotificationSubmit = async () => {
        if (!notificationForm.title.trim() || !notificationForm.message.trim()) {
            toast({
                title: "Missing Fields",
                description: "Please fill in Title and Message.",
                variant: "destructive",
            });
            return;
        }

        try {
            setIsNotificationSubmitting(true);
            const targetAudience: any = { type: notificationForm.targetType };
            
            if (notificationForm.targetType === 'custom') {
                if (notificationForm.branches.length > 0) targetAudience.branches = notificationForm.branches;
                if (notificationForm.sections.length > 0) targetAudience.sections = notificationForm.sections;
                if (notificationForm.years.length > 0) targetAudience.years = notificationForm.years;
            }

            await sendNotification({
                title: notificationForm.title,
                message: notificationForm.message,
                urgency: notificationForm.urgency,
                targetAudience,
                category: notificationForm.category,
            });

            toast({ title: "Success!", description: "Notification sent successfully." });
            
            setNotificationForm({
                title: "",
                message: "",
                urgency: "normal",
                targetType: "all",
                category: "general",
                branches: [],
                sections: [],
                years: [],
            });
            setIsNotificationModalOpen(false);
            fetchNotifications(); // Refresh the list
        } catch (err: any) {
            toast({
                title: "Error",
                description: err.message || "Failed to send notification.",
                variant: "destructive",
            });
        } finally {
            setIsNotificationSubmitting(false);
        }
    };

    // Fetch notifications when component mounts
    useEffect(() => {
        fetchNotifications();
    }, []);

    const formatDate = (timestamp: number) => {
        return new Date(timestamp).toLocaleString("en-IN", {
            day: "2-digit",
            month: "short",
            year: "numeric",
            hour: "2-digit",
            minute: "2-digit",
        });
    };

    const getUrgencyBadge = (urgency: string) => {
        switch (urgency) {
            case "critical":
                return <Badge className="bg-red-500">Critical</Badge>;
            case "important":
                return <Badge className="bg-amber-500">Important</Badge>;
            default:
                return <Badge variant="secondary">Normal</Badge>;
        }
    };

    const getCategoryBadge = (category?: string) => {
        const colors: { [key: string]: string } = {
            general: "bg-gray-500",
            academic: "bg-blue-500",
            placement: "bg-green-500",
            event: "bg-purple-500",
            emergency: "bg-red-500",
        };
        return (
            <Badge className={colors[category || "general"] || "bg-gray-500"}>
                {(category || "general").charAt(0).toUpperCase() + (category || "general").slice(1)}
            </Badge>
        );
    };

    const getTargetAudienceText = (target: any) => {
        if (!target) return "All Users";
        if (target.type === "all") return "All Users";
        if (target.type === "students") return "All Students";
        if (target.type === "faculty") return "All Faculty";
        if (target.type === "custom") {
            const parts = [];
            if (target.branches?.length) parts.push(`Branches: ${target.branches.join(", ")}`);
            if (target.sections?.length) parts.push(`Sections: ${target.sections.join(", ")}`);
            if (target.years?.length) parts.push(`Years: ${target.years.join(", ")}`);
            return parts.length > 0 ? parts.join(" | ") : "Custom";
        }
        return "Unknown";
    };

    const handleDelete = async (notificationId: string) => {
        try {
            setDeletingId(notificationId);
            await deleteNotification(notificationId);
            toast({
                title: "Deleted!",
                description: "Notification has been deleted successfully.",
            });
        } catch (err) {
            toast({
                title: "Error",
                description: "Failed to delete notification.",
                variant: "destructive",
            });
        } finally {
            setDeletingId(null);
        }
    };

    const filteredNotifications = allNotifications.filter((notification) => {
        const matchesSearch =
            notification.title?.toLowerCase().includes(searchTerm.toLowerCase()) ||
            notification.message.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesUrgency =
            urgencyFilter === "all" || notification.urgency === urgencyFilter;
        const matchesCategory =
            categoryFilter === "all" || notification.category === categoryFilter;
        return matchesSearch && matchesUrgency && matchesCategory;
    });

    return (
        <AdminLayout>
            <div className="max-w-7xl mx-auto space-y-6">
                {/* Header */}
                <div className="flex items-center justify-between">
                    <div>
                        <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
                            <Bell className="w-8 h-8 text-primary" />
                            Notification History
                        </h1>
                        <p className="text-muted-foreground mt-1">
                            View and manage all notifications sent via the system
                        </p>
                    </div>
                    <Button 
                        onClick={() => setIsNotificationModalOpen(true)}
                        className="bg-blue-600 hover:bg-blue-700 text-white flex items-center gap-2 border-none px-6 py-2 rounded-xl transition-all duration-300 shadow-lg hover:shadow-blue-500/20 active:scale-95"
                    >
                        <Plus className="w-5 h-5" />
                        Send Alert
                    </Button>
                </div>

                {/* Stats Cards */}
                <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <Card>
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-lg bg-primary/10 flex items-center justify-center">
                                <Bell className="w-6 h-6 text-primary" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Total Alerts</p>
                                <p className="text-2xl font-bold">{allNotifications.length}</p>
                            </div>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-lg bg-red-500/10 flex items-center justify-center">
                                <AlertTriangle className="w-6 h-6 text-red-500" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Critical</p>
                                <p className="text-2xl font-bold">
                                    {allNotifications.filter((n) => n.urgency === "critical").length}
                                </p>
                            </div>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-lg bg-amber-500/10 flex items-center justify-center">
                                <AlertTriangle className="w-6 h-6 text-amber-500" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Important</p>
                                <p className="text-2xl font-bold">
                                    {allNotifications.filter((n) => n.urgency === "important").length}
                                </p>
                            </div>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-lg bg-green-500/10 flex items-center justify-center">
                                <CheckCircle className="w-6 h-6 text-green-500" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Normal</p>
                                <p className="text-2xl font-bold">
                                    {allNotifications.filter((n) => n.urgency === "normal").length}
                                </p>
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* Filters */}
                <Card>
                    <CardContent className="p-4">
                        <div className="flex flex-col md:flex-row gap-4">
                            <div className="flex-1">
                                <div className="relative">
                                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground w-4 h-4" />
                                    <Input
                                        placeholder="Search notifications..."
                                        value={searchTerm}
                                        onChange={(e) => setSearchTerm(e.target.value)}
                                        className="pl-10"
                                    />
                                </div>
                            </div>
                            <Select value={urgencyFilter} onValueChange={setUrgencyFilter}>
                                <SelectTrigger className="w-full md:w-[180px]">
                                    <SelectValue placeholder="Urgency" />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">All Urgency</SelectItem>
                                    <SelectItem value="normal">Normal</SelectItem>
                                    <SelectItem value="important">Important</SelectItem>
                                    <SelectItem value="critical">Critical</SelectItem>
                                </SelectContent>
                            </Select>
                            <Select value={categoryFilter} onValueChange={setCategoryFilter}>
                                <SelectTrigger className="w-full md:w-[180px]">
                                    <SelectValue placeholder="Category" />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">All Categories</SelectItem>
                                    <SelectItem value="general">General</SelectItem>
                                    <SelectItem value="academic">Academic</SelectItem>
                                    <SelectItem value="placement">Placement</SelectItem>
                                    <SelectItem value="event">Event</SelectItem>
                                    <SelectItem value="emergency">Emergency</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </CardContent>
                </Card>

                {/* Error Display */}
                {error && (
                    <Card className="border-destructive bg-destructive/10">
                        <CardContent className="p-4 text-destructive">
                            {error}
                        </CardContent>
                    </Card>
                )}

                {/* Loading State */}
                {loading && allNotifications.length === 0 && (
                    <Card>
                        <CardContent className="py-12 text-center">
                            <Loader2 className="w-12 h-12 text-primary mx-auto mb-4 animate-spin" />
                            <p className="text-muted-foreground">Loading notifications...</p>
                        </CardContent>
                    </Card>
                )}

                {/* Notifications List */}
                {!loading && filteredNotifications.length === 0 ? (
                    <Card>
                        <CardContent className="py-12 text-center">
                            <Bell className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                            <h3 className="text-lg font-medium text-foreground mb-2">
                                No notifications found
                            </h3>
                            <p className="text-muted-foreground">
                                {allNotifications.length === 0
                                    ? "No notifications have been sent yet. Send one from the Dashboard!"
                                    : "Try adjusting your search or filters."}
                            </p>
                        </CardContent>
                    </Card>
                ) : (
                    <div className="space-y-4">
                        {filteredNotifications.map((notification) => (
                            <Card
                                key={notification.id}
                                className={`hover:shadow-lg transition-shadow ${notification.urgency === "critical"
                                    ? "border-l-4 border-l-red-500"
                                    : notification.urgency === "important"
                                        ? "border-l-4 border-l-amber-500"
                                        : ""
                                    }`}
                            >
                                <CardContent className="p-6">
                                    <div className="flex items-start justify-between gap-4">
                                        <div className="flex-1 space-y-3">
                                            {/* Title and Badges */}
                                            <div className="flex items-start gap-3 flex-wrap">
                                                <h3 className="text-lg font-bold text-foreground">
                                                    {notification.title || "Notification"}
                                                </h3>
                                                {getUrgencyBadge(notification.urgency)}
                                                {getCategoryBadge(notification.category)}
                                            </div>

                                            {/* Message */}
                                            <p className="text-muted-foreground">
                                                {notification.message}
                                            </p>

                                            {/* Meta Info */}
                                            <div className="flex flex-wrap items-center gap-4 text-sm text-muted-foreground">
                                                <span className="flex items-center gap-1">
                                                    <Clock className="w-4 h-4" />
                                                    {formatDate(notification.createdAt)}
                                                </span>
                                                <span className="flex items-center gap-1">
                                                    <User className="w-4 h-4" />
                                                    {notification.postedBy?.name || "Admin"} ({notification.postedBy?.role || "admin"})
                                                </span>
                                                <span className="flex items-center gap-1">
                                                    <Users className="w-4 h-4" />
                                                    {getTargetAudienceText(notification.targetAudience)}
                                                </span>
                                            </div>
                                        </div>

                                        {/* Delete Button */}
                                        <AlertDialog>
                                            <AlertDialogTrigger asChild>
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    className="text-destructive hover:text-destructive hover:bg-destructive/10"
                                                    disabled={deletingId === notification.id}
                                                >
                                                    {deletingId === notification.id ? (
                                                        <Loader2 className="w-4 h-4 animate-spin" />
                                                    ) : (
                                                        <Trash2 className="w-4 h-4" />
                                                    )}
                                                </Button>
                                            </AlertDialogTrigger>
                                            <AlertDialogContent>
                                                <AlertDialogHeader>
                                                    <AlertDialogTitle>Delete Notification?</AlertDialogTitle>
                                                    <AlertDialogDescription>
                                                        Are you sure you want to delete this notification? This action cannot be undone.
                                                    </AlertDialogDescription>
                                                </AlertDialogHeader>
                                                <AlertDialogFooter>
                                                    <AlertDialogCancel>Cancel</AlertDialogCancel>
                                                    <AlertDialogAction
                                                        onClick={() => handleDelete(notification.id)}
                                                        className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                                                    >
                                                        Delete
                                                    </AlertDialogAction>
                                                </AlertDialogFooter>
                                            </AlertDialogContent>
                                        </AlertDialog>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                )}

                {/* Notification Modal (Reused from Dashboard) */}
                <Dialog
                    open={isNotificationModalOpen}
                    onOpenChange={setIsNotificationModalOpen}
                >
                    <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                        <DialogHeader>
                            <DialogTitle className="flex items-center gap-2 text-xl">
                                <Bell className="w-6 h-6 text-primary" />
                                Send Notification Alert
                            </DialogTitle>
                        </DialogHeader>
                        <div className="space-y-5 py-4">
                            {/* Title */}
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">
                                    Alert Title <span className="text-destructive">*</span>
                                </Label>
                                <Input
                                    value={notificationForm.title}
                                    onChange={(e) =>
                                        setNotificationForm({ ...notificationForm, title: e.target.value })
                                    }
                                    placeholder="e.g., Important: Exam Schedule Update"
                                />
                            </div>

                            {/* Message */}
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">
                                    Message <span className="text-destructive">*</span>
                                </Label>
                                <Textarea
                                    value={notificationForm.message}
                                    onChange={(e) =>
                                        setNotificationForm({ ...notificationForm, message: e.target.value })
                                    }
                                    placeholder="Enter your notification message..."
                                    rows={4}
                                />
                            </div>

                            {/* Category */}
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">Category</Label>
                                <Select
                                    value={notificationForm.category}
                                    onValueChange={(value: "general" | "academic" | "placement" | "event" | "emergency") =>
                                        setNotificationForm({ ...notificationForm, category: value })
                                    }
                                >
                                    <SelectTrigger>
                                        <SelectValue />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="general">General</SelectItem>
                                        <SelectItem value="academic">Academic</SelectItem>
                                        <SelectItem value="placement">Placement</SelectItem>
                                        <SelectItem value="event">Event</SelectItem>
                                        <SelectItem value="emergency">Emergency</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>

                            {/* Target Audience */}
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">Target Audience</Label>
                                <Select
                                    value={notificationForm.targetType}
                                    onValueChange={(value: "all" | "students" | "faculty" | "custom") =>
                                        setNotificationForm({ ...notificationForm, targetType: value })
                                    }
                                >
                                    <SelectTrigger>
                                        <SelectValue />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="all">All Users</SelectItem>
                                        <SelectItem value="students">All Students</SelectItem>
                                        <SelectItem value="faculty">All Faculty</SelectItem>
                                        <SelectItem value="custom">Custom (Specific Branches/Sections)</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>

                            {/* Custom Targeting Options */}
                            {notificationForm.targetType === "custom" && (
                                <div className="space-y-4 p-4 border border-border rounded-lg bg-muted/20">
                                    <p className="text-sm font-medium text-foreground">Custom Targeting Options</p>

                                    {/* Branches */}
                                    <div className="space-y-2">
                                        <Label className="text-sm">Branches (comma-separated)</Label>
                                        <Input
                                            value={notificationForm.branches.join(", ")}
                                            onChange={(e) =>
                                                setNotificationForm({
                                                    ...notificationForm,
                                                    branches: e.target.value.split(",").map((b) => b.trim()).filter((b) => b),
                                                })
                                            }
                                            placeholder="e.g., CSE, ECE, EEE"
                                        />
                                        <p className="text-xs text-muted-foreground">Leave empty to include all branches</p>
                                    </div>

                                    {/* Sections */}
                                    <div className="space-y-2">
                                        <Label className="text-sm">Sections (comma-separated)</Label>
                                        <Input
                                            value={notificationForm.sections.join(", ")}
                                            onChange={(e) =>
                                                setNotificationForm({
                                                    ...notificationForm,
                                                    sections: e.target.value.split(",").map((s) => s.trim()).filter((s) => s),
                                                })
                                            }
                                            placeholder="e.g., A, B, C"
                                        />
                                        <p className="text-xs text-muted-foreground">Leave empty to include all sections</p>
                                    </div>

                                    {/* Years */}
                                    <div className="space-y-2">
                                        <Label className="text-sm">Years (comma-separated)</Label>
                                        <Input
                                            value={notificationForm.years.join(", ")}
                                            onChange={(e) =>
                                                setNotificationForm({
                                                    ...notificationForm,
                                                    years: e.target.value.split(",").map((y) => y.trim()).filter((y) => y),
                                                })
                                            }
                                            placeholder="e.g., 1, 2, 3, 4"
                                        />
                                        <p className="text-xs text-muted-foreground">Leave empty to include all years</p>
                                    </div>
                                </div>
                            )}

                            {/* Form Actions */}
                            <div className="flex justify-end gap-3 pt-4 border-t">
                                <Button
                                    variant="outline"
                                    onClick={() => setIsNotificationModalOpen(false)}
                                    disabled={isNotificationSubmitting}
                                >
                                    Cancel
                                </Button>
                                <Button
                                    onClick={handleNotificationSubmit}
                                    disabled={isNotificationSubmitting}
                                    className="min-w-[140px] bg-blue-600 hover:bg-blue-700 rounded-xl"
                                >
                                    {isNotificationSubmitting ? (
                                        <>
                                            <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                            Sending...
                                        </>
                                    ) : (
                                        <>
                                            <Send className="w-4 h-4 mr-2" />
                                            Send Alert
                                        </>
                                    )}
                                </Button>
                            </div>
                        </div>
                    </DialogContent>
                </Dialog>
            </div>
        </AdminLayout>
    );
};

export default AdminAlerts;

import { useState, useEffect } from "react";
import AdminLayout from "@/components/AdminLayout";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from "@/components/ui/dialog";
import { Megaphone, Plus, Trash2, Calendar as CalendarIcon, Loader2, Search } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";
import { format } from "date-fns";

const API_BASE = import.meta.env.VITE_API_URL || "http://localhost:5000/api";

interface Announcement {
  _id: string;
  title: string;
  message: string;
  priority: "Important" | "Normal" | "Low";
  audience: "Students" | "Faculty" | "Both";
  createdBy: string;
  createdAt: string;
  expiryDate: string | null;
  image?: string;
}

const AdminAnnouncements = () => {
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [addDialogOpen, setAddDialogOpen] = useState(false);

  const [title, setTitle] = useState("");
  const [message, setMessage] = useState("");
  const [priority, setPriority] = useState<"Important" | "Normal" | "Low">("Important");
  const [audience, setAudience] = useState<"Students" | "Faculty" | "Both">("Both");
  const [expiryDate, setExpiryDate] = useState("");
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreviewUrl, setImagePreviewUrl] = useState<string>("");
  const [uploadProgress, setUploadProgress] = useState(0);

  const fetchAnnouncements = async () => {
    try {
      setLoading(true);
      const res = await fetch(`${API_BASE}/announcements`);
      if (res.ok) {
        const data = await res.json();
        setAnnouncements(data);
      }
    } catch (error) {
      console.error("Failed to fetch announcements:", error);
      toast.error("Failed to load announcements");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAnnouncements();
  }, []);

  const resetForm = () => {
    setTitle("");
    setMessage("");
    setPriority("Important");
    setAudience("Both");
    setExpiryDate("");
    setImageFile(null);
    setImagePreviewUrl("");
    setUploadProgress(0);
  };

  const handleSubmit = async () => {
    if (!title.trim() || !message.trim()) {
      toast.error("Title and message are required.");
      return;
    }

    try {
      setSubmitting(true);
      let imageBase64 = "";

      if (imageFile) {
        // Validate file size (max 5MB)
        if (imageFile.size > 5 * 1024 * 1024) {
          toast.error("Image must be smaller than 5MB.");
          setSubmitting(false);
          return;
        }
        // Convert to base64 data URL
        imageBase64 = await new Promise<string>((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => resolve(reader.result as string);
          reader.onerror = () => reject(new Error("Failed to read image file."));
          reader.readAsDataURL(imageFile);
        });
      }

      const payload = {
        title: title.trim(),
        message: message.trim(),
        priority,
        audience,
        expiryDate: expiryDate ? new Date(expiryDate).toISOString() : null,
        image: imageBase64 || undefined,
      };

      const res = await fetch(`${API_BASE}/announcements`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (res.ok) {
        toast.success("Announcement published successfully!");
        setAddDialogOpen(false);
        resetForm();
        fetchAnnouncements();
      } else {
        toast.error("Failed to publish announcement.");
      }
    } catch (error) {
      console.error("Failed to post announcement:", error);
      toast.error("Failed to publish announcement.");
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this announcement?")) return;

    try {
      const res = await fetch(`${API_BASE}/announcements/${id}`, { method: "DELETE" });
      if (res.ok) {
        toast.success("Announcement deleted successfully");
        fetchAnnouncements();
      } else {
        toast.error("Failed to delete announcement.");
      }
    } catch (error) {
      toast.error("Failed to delete announcement.");
    }
  };

  const filteredAnnouncements = announcements.filter(
    (a) =>
      a.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      a.message.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <AdminLayout>
      <div className="max-w-7xl mx-auto space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
              <Megaphone className="w-8 h-8 text-primary" />
              Announcements Management
            </h1>
            <p className="text-muted-foreground mt-1">
              Publish official announcements to Student and Faculty dashboards.
            </p>
          </div>
        </div>

        <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
          <div className="relative w-full md:w-80">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground w-4 h-4" />
            <Input
              placeholder="Search announcements..."
              className="pl-10"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>

          <Dialog open={addDialogOpen} onOpenChange={(open) => {
            setAddDialogOpen(open);
            if (open) resetForm();
          }}>
            <DialogTrigger asChild>
              <Button className="w-full md:w-auto">
                <Plus className="w-4 h-4 mr-2" />
                Publish Announcement
              </Button>
            </DialogTrigger>
            <DialogContent className="max-w-xl">
              <DialogHeader>
                <DialogTitle className="flex items-center gap-2">
                  <Megaphone className="w-5 h-5 text-primary" />
                  New Announcement
                </DialogTitle>
              </DialogHeader>

              <div className="space-y-4 py-4">
                <div className="space-y-2">
                  <Label>Title *</Label>
                  <Input
                    placeholder="e.g. Mid Semester Examination Schedule"
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                  />
                </div>

                <div className="space-y-2">
                  <Label>Message *</Label>
                  <Textarea
                    placeholder="Enter the announcement message..."
                    rows={4}
                    value={message}
                    onChange={(e) => setMessage(e.target.value)}
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label>Target Audience</Label>
                    <Select value={audience} onValueChange={(val: any) => setAudience(val)}>
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="Both">Both (Students & Faculty)</SelectItem>
                        <SelectItem value="Students">Students Only</SelectItem>
                        <SelectItem value="Faculty">Faculty Only</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label>Priority</Label>
                    <Select value={priority} onValueChange={(val: any) => setPriority(val)}>
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="Important">Important</SelectItem>
                        <SelectItem value="Normal">Normal</SelectItem>
                        <SelectItem value="Low">Low</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="space-y-2">
                  <Label>Expiry Date (Optional)</Label>
                  <Input
                    type="date"
                    value={expiryDate}
                    onChange={(e) => setExpiryDate(e.target.value)}
                  />
                  <p className="text-xs text-muted-foreground">
                    Leave empty if this announcement shouldn't expire automatically.
                  </p>
                </div>

                <div className="space-y-2">
                  <Label>Image Upload (Optional)</Label>
                  <Input
                    type="file"
                    accept="image/jpeg,image/png,image/jpg"
                    onChange={(e) => {
                      const file = e.target.files?.[0];
                      if (file) {
                        setImageFile(file);
                        setImagePreviewUrl(URL.createObjectURL(file));
                      }
                    }}
                  />
                  {imagePreviewUrl && (
                    <div className="relative mt-2 rounded-lg overflow-hidden border border-border/50 max-h-48 group">
                      <img src={imagePreviewUrl} alt="Preview" className="w-full h-full object-scale-down bg-black/20" />
                      <Button
                        type="button"
                        variant="destructive"
                        size="icon"
                        className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity"
                        onClick={() => {
                          setImageFile(null);
                          setImagePreviewUrl("");
                          setUploadProgress(0);
                        }}
                      >
                         <Trash2 className="w-4 h-4" />
                      </Button>
                    </div>
                  )}
                  {uploadProgress > 0 && uploadProgress < 100 && (
                     <div className="w-full bg-secondary h-1.5 rounded-full mt-2 overflow-hidden">
                       <div className="bg-primary h-full transition-all" style={{ width: `${uploadProgress}%` }}></div>
                     </div>
                  )}
                </div>
              </div>

              <DialogFooter>
                <Button variant="outline" onClick={() => setAddDialogOpen(false)}>Cancel</Button>
                <Button onClick={handleSubmit} disabled={submitting}>
                  {submitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                  Publish
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        </div>

        <Card>
          <CardHeader>
            <CardTitle>Published Announcements</CardTitle>
            <CardDescription>Manage and view all platform announcements.</CardDescription>
          </CardHeader>
          <CardContent>
            {loading ? (
              <div className="flex justify-center py-12">
                <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
              </div>
            ) : filteredAnnouncements.length === 0 ? (
              <div className="text-center py-12">
                <Megaphone className="w-12 h-12 mx-auto text-muted-foreground/40 mb-4" />
                <p className="text-lg font-medium text-muted-foreground">No announcements found</p>
                <p className="text-sm text-muted-foreground/60">Upload your first announcement to reach users.</p>
              </div>
            ) : (
              <div className="space-y-4">
                {filteredAnnouncements.map((ann) => {
                  const isExpired = ann.expiryDate && new Date(ann.expiryDate) < new Date();

                  return (
                  <div key={ann._id} className="p-4 rounded-xl border border-border/50 bg-card hover:bg-muted/20 transition-colors">
                    <div className="flex justify-between items-start gap-4">
                      <div className="space-y-1">
                        <div className="flex flex-wrap items-center gap-2">
                          <h3 className="font-semibold text-lg text-foreground">{ann.title}</h3>
                          {ann.priority === "Important" && (
                            <Badge variant="destructive" className="px-1.5 py-0 text-[10px]">Important</Badge>
                          )}
                          <Badge variant="outline" className="px-1.5 py-0 text-[10px]">
                            {ann.audience}
                          </Badge>
                          {isExpired && (
                            <Badge variant="secondary" className="px-1.5 py-0 text-[10px]">Expired</Badge>
                          )}
                        </div>
                        <p className="text-sm text-muted-foreground mt-2 whitespace-pre-wrap">{ann.message}</p>
                        {ann.image && (
                          <div className="mt-4 rounded-xl overflow-hidden border border-border/50 bg-black/20 w-full sm:w-[80%]">
                            <img 
                              src={ann.image} 
                              alt={ann.title} 
                              className="w-full max-h-[400px] object-contain cursor-pointer hover:opacity-90 transition-opacity" 
                              loading="lazy" 
                              onClick={() => window.open(ann.image, '_blank')}
                            />
                          </div>
                        )}
                        <div className="flex items-center gap-4 text-xs text-muted-foreground mt-4 pt-2 border-t border-border/50">
                          <span className="flex items-center gap-1">
                            <CalendarIcon className="w-3 h-3" />
                            Posted {format(new Date(ann.createdAt), "MMM d, yyyy")}
                          </span>
                          <span className="flex items-center gap-1 text-primary">
                            By {ann.createdBy}
                          </span>
                          {ann.expiryDate && (
                            <span className="flex items-center gap-1 text-orange-500/80">
                              Expires {format(new Date(ann.expiryDate), "MMM d, yyyy")}
                            </span>
                          )}
                        </div>
                      </div>
                      <Button variant="ghost" size="icon" className="text-destructive shrink-0" onClick={() => handleDelete(ann._id)}>
                        <Trash2 className="w-4 h-4" />
                      </Button>
                    </div>
                  </div>
                )})}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </AdminLayout>
  );
};

export default AdminAnnouncements;

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import {
    Tabs,
    TabsContent,
    TabsList,
    TabsTrigger,
} from "@/components/ui/tabs";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import AdminLayout from "@/components/AdminLayout";
import {
    CheckCircle2,
    XCircle,
    Clock,
    Shield,
    Users,
    Calendar,
    Search,
    Filter,
    Download,
    Upload,
    RefreshCw,
    AlertTriangle,
    FileText,
    Building2,
    Trophy,
    Briefcase,
    Sparkles,
    TrendingUp,
    BarChart3,
    UserCheck,
    UserX,
    Pencil,
    Trash2,
    UsersRound,
} from "lucide-react";
import { useState, useEffect, useCallback } from "react";
import { useAuth } from "@/contexts/AuthContext";
import { cn } from "@/lib/utils";
import { toast } from "sonner";
import {
    AttendanceRecord,
    AttendanceStatus,
    AttendanceCategory,
    AttendanceStudent,
    TimeSlot,
    StudentAttendanceSummary,
    ATTENDANCE_THRESHOLDS,
} from "@/types/attendance";
import {
    getServerTime,
    formatDate,
    formatTime,
    adminOverrideAttendance,
    getStudentsForSection,
    calculateFourWeekAttendance,
} from "@/services/attendanceService";
import { AdminClassAttendance } from "@/components/AdminClassAttendance";

interface StudentWithSelection extends AttendanceStudent {
    selected: boolean;
    attendancePercentage?: number;
}

const AdminAttendance = () => {
    const { userData } = useAuth();

    // Tab state
    const [activeTab, setActiveTab] = useState("class");

    // Filter state
    const [selectedYear, setSelectedYear] = useState("22");
    const [selectedBranch, setSelectedBranch] = useState("05");
    const [selectedSection, setSelectedSection] = useState("B");
    const [selectedCategory, setSelectedCategory] = useState<AttendanceCategory>("ACADEMIC");
    const [searchQuery, setSearchQuery] = useState("");

    // Student selection state
    const [students, setStudents] = useState<StudentWithSelection[]>([]);
    const [selectAll, setSelectAll] = useState(false);

    // Override form state
    const [overrideSlot, setOverrideSlot] = useState("");
    const [overrideDate, setOverrideDate] = useState(formatDate(new Date()));
    const [overrideStatus, setOverrideStatus] = useState<AttendanceStatus>("PRESENT");
    const [overrideReason, setOverrideReason] = useState("");

    // UI state
    const [isLoading, setIsLoading] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [showConfirmDialog, setShowConfirmDialog] = useState(false);
    const [serverTime, setServerTime] = useState<Date>(new Date());

    // Statistics
    const [stats, setStats] = useState<{
        totalStudents: number | null;
        averageAttendance: number | null;
        belowThreshold: number | null;
        perfectAttendance: number | null;
    }>({
        totalStudents: null,
        averageAttendance: null,
        belowThreshold: null,
        perfectAttendance: null,
    });

    // Available slots
    const availableSlots: TimeSlot[] = [
        { id: "slot_1", slotNumber: 1, startTime: "09:00", endTime: "10:00", subjectCode: "CS101", subjectName: "Linux Programming", facultyId: "", section: "A", branch: "05", year: "22" },
        { id: "slot_2", slotNumber: 2, startTime: "10:00", endTime: "11:00", subjectCode: "CS102", subjectName: "Business Economics", facultyId: "", section: "A", branch: "05", year: "22" },
        { id: "slot_3", slotNumber: 3, startTime: "11:15", endTime: "12:15", subjectCode: "CS103", subjectName: "Professional Elective III", facultyId: "", section: "A", branch: "05", year: "22" },
        { id: "slot_4", slotNumber: 4, startTime: "14:00", endTime: "15:00", subjectCode: "CS104", subjectName: "Professional Elective IV", facultyId: "", section: "A", branch: "05", year: "22" },
    ];

    // Override reasons presets
    const reasonPresets = [
        { label: "Placement Drive", value: "Student attending placement drive/interview" },
        { label: "CDC Drive", value: "Student participating in CDC activities" },
        { label: "Technical Event", value: "Student participating in technical event" },
        { label: "Sports Event", value: "Student representing in sports competition" },
        { label: "Medical Emergency", value: "Medical emergency - verified" },
        { label: "Other", value: "" },
    ];

    // Sync server time
    useEffect(() => {
        const syncTime = async () => {
            const time = await getServerTime();
            setServerTime(time);
        };

        syncTime();
        const interval = setInterval(syncTime, 60000);
        return () => clearInterval(interval);
    }, []);

    // Load students when filters change
    useEffect(() => {
        loadStudents();
    }, [selectedYear, selectedBranch, selectedSection]);

    const loadStudents = async () => {
        setIsLoading(true);
        try {
            // Fetch students from Firebase using the centralized service
            const firebaseStudents = await getStudentsForSection(selectedYear, selectedBranch, selectedSection);

            if (firebaseStudents.length > 0) {
                // Transform to StudentWithSelection format with mock attendance percentages
                const studentStates: StudentWithSelection[] = firebaseStudents.map((student, index) => ({
                    rollNumber: student.rollNumber,
                    name: student.name,
                    section: selectedSection,
                    branch: selectedBranch,
                    year: selectedYear,
                    selected: false,
                    attendancePercentage: 70 + Math.floor(Math.random() * 30), // Mock percentage
                }));

                setStudents(studentStates);
                console.log(`Loaded ${studentStates.length} students from Firebase for Section ${selectedSection}`);

                // Calculate stats
                const total = studentStates.length;
                const avgAttendance = studentStates.reduce((sum, s) => sum + (s.attendancePercentage || 0), 0) / total;
                const belowThreshold = studentStates.filter(s => (s.attendancePercentage || 0) < ATTENDANCE_THRESHOLDS.SATISFACTORY).length;
                const perfect = studentStates.filter(s => (s.attendancePercentage || 0) === 100).length;

                setStats({
                    totalStudents: total,
                    averageAttendance: Math.round(avgAttendance),
                    belowThreshold,
                    perfectAttendance: perfect,
                });
            } else {
                // No students found
                setStudents([]);
                toast.info(`No students found for Section ${selectedSection}. Check Firebase database.`);
                setStats({ totalStudents: 0, averageAttendance: 0, belowThreshold: 0, perfectAttendance: 0 });
            }
        } catch (error) {
            console.error("Error loading students:", error);
            toast.error("Failed to load students from Firebase");
            setStudents([]);
        } finally {
            setIsLoading(false);
        }
    };

    const handleSelectAll = (checked: boolean) => {
        setSelectAll(checked);
        setStudents(prev => prev.map(s => ({ ...s, selected: checked })));
    };

    const handleSelectStudent = (rollNumber: string, checked: boolean) => {
        setStudents(prev => prev.map(s =>
            s.rollNumber === rollNumber ? { ...s, selected: checked } : s
        ));

        // Update selectAll state
        const updatedStudents = students.map(s =>
            s.rollNumber === rollNumber ? { ...s, selected: checked } : s
        );
        setSelectAll(updatedStudents.every(s => s.selected));
    };

    const handleReasonPreset = (preset: string) => {
        if (preset) {
            setOverrideReason(preset);
        }
    };

    const getSelectedStudents = () => students.filter(s => s.selected);

    const filteredStudents = students.filter(s =>
        s.rollNumber.toLowerCase().includes(searchQuery.toLowerCase()) ||
        s.name.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const handleSubmitOverride = async () => {
        if (!overrideSlot) {
            toast.error("Please select a slot");
            return;
        }
        if (!overrideReason.trim()) {
            toast.error("Please provide a reason for override");
            return;
        }

        const selectedStudentIds = getSelectedStudents().map(s => s.rollNumber);
        if (selectedStudentIds.length === 0) {
            toast.error("Please select at least one student");
            return;
        }

        setShowConfirmDialog(true);
    };

    const confirmOverride = async () => {
        setIsSubmitting(true);
        try {
            const selectedStudentIds = getSelectedStudents().map(s => s.rollNumber);

            const result = await adminOverrideAttendance(
                selectedStudentIds,
                overrideSlot,
                overrideDate,
                overrideStatus,
                overrideReason,
                userData?.collegeId || "admin",
                availableSlots.find(s => s.id === overrideSlot)?.subjectCode || "OVERRIDE",
                availableSlots.find(s => s.id === overrideSlot)?.subjectName || "Admin Override",
                selectedSection,
                selectedBranch,
                selectedYear
            );

            if (result.success) {
                toast.success(`Successfully marked attendance for ${result.markedCount} students`);

                // Reset form
                setStudents(prev => prev.map(s => ({ ...s, selected: false })));
                setSelectAll(false);
                setOverrideReason("");
                setOverrideSlot("");
            } else {
                toast.error(`Failed to mark ${result.failedCount} students`);
            }
        } catch (error) {
            console.error("Error submitting override:", error);
            toast.error("Failed to submit attendance override");
        } finally {
            setIsSubmitting(false);
            setShowConfirmDialog(false);
        }
    };

    const getAttendanceStatusColor = (percentage: number) => {
        if (percentage >= ATTENDANCE_THRESHOLDS.SATISFACTORY) return "text-green-500";
        if (percentage >= ATTENDANCE_THRESHOLDS.WARNING) return "text-yellow-500";
        return "text-red-500";
    };

    const getAttendanceStatusBadge = (percentage: number) => {
        if (percentage >= ATTENDANCE_THRESHOLDS.SATISFACTORY) {
            return <Badge className="bg-green-500/20 text-green-500 border-green-500/30">Good</Badge>;
        }
        if (percentage >= ATTENDANCE_THRESHOLDS.WARNING) {
            return <Badge className="bg-yellow-500/20 text-yellow-500 border-yellow-500/30">Warning</Badge>;
        }
        return <Badge className="bg-red-500/20 text-red-500 border-red-500/30">Critical</Badge>;
    };

    return (
        <AdminLayout>
            <div className="max-w-7xl mx-auto space-y-6">
                {/* Header */}
                <div className="flex items-center justify-between">
                    <div>
                        <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
                            <UsersRound className="w-8 h-8 text-primary" />
                            Attendance Management
                        </h1>
                        <p className="text-muted-foreground mt-1">
                            Override attendance, track statistics, and manage exceptions
                        </p>
                    </div>
                </div>

                {/* Statistics Cards */}
                <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <Card className="border-border/50 bg-gradient-to-br from-blue-500/10 to-transparent">
                        <CardContent className="p-4">
                            <div className="flex items-center justify-between">
                                <div>
                                    <p className="text-sm text-muted-foreground">Total Students</p>
                                    <p className="text-2xl font-bold text-blue-500">{stats.totalStudents !== null ? stats.totalStudents : "--"}</p>
                                </div>
                                <Users className="w-8 h-8 text-blue-500/50" />
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="border-border/50 bg-gradient-to-br from-green-500/10 to-transparent">
                        <CardContent className="p-4">
                            <div className="flex items-center justify-between">
                                <div>
                                    <p className="text-sm text-muted-foreground">Average Attendance</p>
                                    <p className="text-2xl font-bold text-green-500">
                                        {stats.averageAttendance !== null ? `${stats.averageAttendance}%` : "--"}
                                    </p>
                                </div>
                                <TrendingUp className="w-8 h-8 text-green-500/50" />
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="border-border/50 bg-gradient-to-br from-red-500/10 to-transparent">
                        <CardContent className="p-4">
                            <div className="flex items-center justify-between">
                                <div>
                                    <p className="text-sm text-muted-foreground">Below Threshold</p>
                                    <p className="text-2xl font-bold text-red-500">{stats.belowThreshold !== null ? stats.belowThreshold : "--"}</p>
                                </div>
                                <UserX className="w-8 h-8 text-red-500/50" />
                            </div>
                        </CardContent>
                    </Card>

                    <Card className="border-border/50 bg-gradient-to-br from-purple-500/10 to-transparent">
                        <CardContent className="p-4">
                            <div className="flex items-center justify-between">
                                <div>
                                    <p className="text-sm text-muted-foreground">Perfect Attendance</p>
                                    <p className="text-2xl font-bold text-purple-500">{stats.perfectAttendance !== null ? stats.perfectAttendance : "--"}</p>
                                </div>
                                <Trophy className="w-8 h-8 text-purple-500/50" />
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* Main Content Tabs */}
                <Tabs value={activeTab} onValueChange={setActiveTab} className="space-y-6">
                    <TabsList className="grid grid-cols-6 w-full max-w-4xl">
                        <TabsTrigger value="class" className="gap-2">
                            <Users className="w-4 h-4" />
                            Class Attendance
                        </TabsTrigger>
                        <TabsTrigger value="override" className="gap-2">
                            <Shield className="w-4 h-4" />
                            Override
                        </TabsTrigger>
                        <TabsTrigger value="manage" className="gap-2">
                            <UserCheck className="w-4 h-4" />
                            Manage Records
                        </TabsTrigger>
                        <TabsTrigger value="events" className="gap-2">
                            <Sparkles className="w-4 h-4" />
                            Events/Sports
                        </TabsTrigger>
                        <TabsTrigger value="reports" className="gap-2">
                            <BarChart3 className="w-4 h-4" />
                            Reports
                        </TabsTrigger>
                        <TabsTrigger value="settings" className="gap-2">
                            <FileText className="w-4 h-4" />
                            Settings
                        </TabsTrigger>
                    </TabsList>

                    {/* Class Attendance Tab */}
                    <TabsContent value="class" className="space-y-6">
                        <AdminClassAttendance onStatsUpdate={setStats} />
                    </TabsContent>

                    {/* Override Attendance Tab */}
                    <TabsContent value="override" className="space-y-6">
                        <Card className="border-border/50 shadow-lg">
                            <CardHeader>
                                <CardTitle className="flex items-center gap-2">
                                    <Shield className="w-5 h-5 text-primary" />
                                    Manual Attendance Override
                                </CardTitle>
                                <CardDescription>
                                    Use this for placement drives, CDC activities, or other approved absences.
                                    Select students and provide justification for the override.
                                </CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-6">
                                {/* Filters */}
                                <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
                                    <div>
                                        <Label className="text-xs text-muted-foreground">Year</Label>
                                        <Select value={selectedYear} onValueChange={setSelectedYear}>
                                            <SelectTrigger>
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="22">2022 Batch</SelectItem>
                                                <SelectItem value="23">2023 Batch</SelectItem>
                                                <SelectItem value="24">2024 Batch</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>

                                    <div>
                                        <Label className="text-xs text-muted-foreground">Branch</Label>
                                        <Select value={selectedBranch} onValueChange={setSelectedBranch}>
                                            <SelectTrigger>
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="05">CSE</SelectItem>
                                                <SelectItem value="04">ECE</SelectItem>
                                                <SelectItem value="03">EEE</SelectItem>
                                                <SelectItem value="02">MECH</SelectItem>
                                                <SelectItem value="01">CIVIL</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>

                                    <div>
                                        <Label className="text-xs text-muted-foreground">Section</Label>
                                        <Select value={selectedSection} onValueChange={setSelectedSection}>
                                            <SelectTrigger>
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="B">Section B</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>

                                    <div>
                                        <Label className="text-xs text-muted-foreground">Date</Label>
                                        <Input
                                            type="date"
                                            value={overrideDate}
                                            onChange={(e) => setOverrideDate(e.target.value)}
                                            className="w-full"
                                        />
                                    </div>

                                    <div>
                                        <Label className="text-xs text-muted-foreground">Slot</Label>
                                        <Select value={overrideSlot} onValueChange={setOverrideSlot}>
                                            <SelectTrigger>
                                                <SelectValue placeholder="Select slot" />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {availableSlots.map((slot) => (
                                                    <SelectItem key={slot.id} value={slot.id}>
                                                        Slot {slot.slotNumber} - {slot.subjectName}
                                                    </SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                </div>

                                {/* Search */}
                                <div className="relative">
                                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                                    <Input
                                        placeholder="Search by roll number or name..."
                                        value={searchQuery}
                                        onChange={(e) => setSearchQuery(e.target.value)}
                                        className="pl-10"
                                    />
                                </div>

                                {/* Student Selection Table */}
                                <div className="border rounded-lg overflow-hidden">
                                    <Table>
                                        <TableHeader>
                                            <TableRow className="bg-muted/50">
                                                <TableHead className="w-12">
                                                    <Checkbox
                                                        checked={selectAll}
                                                        onCheckedChange={handleSelectAll}
                                                    />
                                                </TableHead>
                                                <TableHead>Roll Number</TableHead>
                                                <TableHead>Name</TableHead>
                                                <TableHead className="text-center">Current Attendance</TableHead>
                                                <TableHead className="text-center">Status</TableHead>
                                            </TableRow>
                                        </TableHeader>
                                        <TableBody>
                                            {isLoading ? (
                                                <TableRow>
                                                    <TableCell colSpan={5} className="text-center py-8">
                                                        <RefreshCw className="w-6 h-6 animate-spin mx-auto text-muted-foreground" />
                                                    </TableCell>
                                                </TableRow>
                                            ) : filteredStudents.length === 0 ? (
                                                <TableRow>
                                                    <TableCell colSpan={5} className="text-center py-8 text-muted-foreground">
                                                        No students found
                                                    </TableCell>
                                                </TableRow>
                                            ) : (
                                                filteredStudents.map((student) => (
                                                    <TableRow
                                                        key={student.rollNumber}
                                                        className={cn(
                                                            "transition-colors",
                                                            student.selected && "bg-primary/5"
                                                        )}
                                                    >
                                                        <TableCell>
                                                            <Checkbox
                                                                checked={student.selected}
                                                                onCheckedChange={(checked) =>
                                                                    handleSelectStudent(student.rollNumber, checked as boolean)
                                                                }
                                                            />
                                                        </TableCell>
                                                        <TableCell className="font-medium">{student.rollNumber}</TableCell>
                                                        <TableCell>{student.name}</TableCell>
                                                        <TableCell className="text-center">
                                                            <span className={cn(
                                                                "font-semibold",
                                                                getAttendanceStatusColor(student.attendancePercentage || 0)
                                                            )}>
                                                                {student.attendancePercentage || 0}%
                                                            </span>
                                                        </TableCell>
                                                        <TableCell className="text-center">
                                                            {getAttendanceStatusBadge(student.attendancePercentage || 0)}
                                                        </TableCell>
                                                    </TableRow>
                                                ))
                                            )}
                                        </TableBody>
                                    </Table>
                                </div>

                                {/* Override Form */}
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div className="space-y-4">
                                        <div>
                                            <Label>Mark As</Label>
                                            <div className="flex gap-4 mt-2">
                                                <Button
                                                    type="button"
                                                    variant={overrideStatus === "PRESENT" ? "default" : "outline"}
                                                    onClick={() => setOverrideStatus("PRESENT")}
                                                    className={cn(
                                                        "flex-1 gap-2",
                                                        overrideStatus === "PRESENT" && "bg-green-600 hover:bg-green-700"
                                                    )}
                                                >
                                                    <CheckCircle2 className="w-4 h-4" />
                                                    Present
                                                </Button>
                                                <Button
                                                    type="button"
                                                    variant={overrideStatus === "ABSENT" ? "default" : "outline"}
                                                    onClick={() => setOverrideStatus("ABSENT")}
                                                    className={cn(
                                                        "flex-1 gap-2",
                                                        overrideStatus === "ABSENT" && "bg-red-600 hover:bg-red-700"
                                                    )}
                                                >
                                                    <XCircle className="w-4 h-4" />
                                                    Absent
                                                </Button>
                                                <Button
                                                    type="button"
                                                    variant={overrideStatus === "EXCUSED" ? "default" : "outline"}
                                                    onClick={() => setOverrideStatus("EXCUSED")}
                                                    className={cn(
                                                        "flex-1 gap-2",
                                                        overrideStatus === "EXCUSED" && "bg-blue-600 hover:bg-blue-700"
                                                    )}
                                                >
                                                    <AlertTriangle className="w-4 h-4" />
                                                    Excused
                                                </Button>
                                            </div>
                                        </div>

                                        <div>
                                            <Label>Quick Reason</Label>
                                            <div className="flex flex-wrap gap-2 mt-2">
                                                {reasonPresets.map((preset) => (
                                                    <Badge
                                                        key={preset.label}
                                                        variant="outline"
                                                        className="cursor-pointer hover:bg-primary/10"
                                                        onClick={() => handleReasonPreset(preset.value)}
                                                    >
                                                        {preset.label}
                                                    </Badge>
                                                ))}
                                            </div>
                                        </div>
                                    </div>

                                    <div className="space-y-4">
                                        <div>
                                            <Label>Override Reason *</Label>
                                            <Textarea
                                                placeholder="Provide detailed justification for this attendance override..."
                                                value={overrideReason}
                                                onChange={(e) => setOverrideReason(e.target.value)}
                                                className="mt-2 h-32 resize-none"
                                            />
                                        </div>
                                    </div>
                                </div>

                                {/* Selection Summary & Submit */}
                                <div className="flex items-center justify-between pt-4 border-t">
                                    <div className="text-sm text-muted-foreground">
                                        <span className="font-medium text-foreground">{getSelectedStudents().length}</span>
                                        {" "}students selected
                                    </div>
                                    <div className="flex gap-3">
                                        <Button
                                            variant="outline"
                                            onClick={() => {
                                                setStudents(prev => prev.map(s => ({ ...s, selected: false })));
                                                setSelectAll(false);
                                            }}
                                        >
                                            Clear Selection
                                        </Button>
                                        <Button
                                            onClick={handleSubmitOverride}
                                            disabled={getSelectedStudents().length === 0 || isSubmitting}
