interface AttachedFile {
  name: string;
  url: string;
  type: "local" | "drive";
  size?: number;
}

const AdminDashboard = () => {
  const navigate = useNavigate();
  const { userData, logout } = useAuth();
  const { addJob } = usePlacement();
  const { addEvent } = useEvents();
  const { addClub } = useClubs();
  const { sendNotification } = useNotifications();
  const { addExam } = useExams();
  const { toast } = useToast();
  const fileInputRef = useRef<HTMLInputElement>(null);


  const createEmptyExamForm = () => ({
    title: "",
    examType: "Mid-Term" as const,
    date: "",
    startTime: "",
    endTime: "",
    venue: "",
    branches: "",
    sections: "",
    years: "",
  });

  // Modal states
  const [isJobModalOpen, setIsJobModalOpen] = useState(false);
  const [isEventModalOpen, setIsEventModalOpen] = useState(false);
  const [isExamModalOpen, setIsExamModalOpen] = useState(false);
  const [isClubModalOpen, setIsClubModalOpen] = useState(false);
  const [isNotificationModalOpen, setIsNotificationModalOpen] = useState(false);
  const [isJobSubmitting, setIsJobSubmitting] = useState(false);
  const [attachedFiles, setAttachedFiles] = useState<AttachedFile[]>([]);
  const [driveLink, setDriveLink] = useState("");
  const [showDriveLinkInput, setShowDriveLinkInput] = useState(false);

  // Quick Action Modal states
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportsModalOpen, setIsReportsModalOpen] = useState(false);
  const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);
  const [isBackupModalOpen, setIsBackupModalOpen] = useState(false);

  // Quick Action form states
  const [qaActiveTab, setQaActiveTab] = useState("student");
  const [qaUserLoading, setQaUserLoading] = useState(false);
  const [qaStudentForm, setQaStudentForm] = useState({ name: "", email: "", collegeId: "", branch: "", section: "", year: "I", academicBatch: "2026-2030" });
  const [qaFacultyForm, setQaFacultyForm] = useState({ name: "", email: "", collegeId: "", branch: "", section: "Z" });
  const [qaSubAdminForm, setQaSubAdminForm] = useState({ name: "", email: "", collegeId: "", permissions: { manageAttendance: false, manageEvents: false, manageClubs: false, manageNotifications: false, manageResults: false } });

  const [qaReports, setQaReports] = useState<any>(null);
  const [qaReportsLoading, setQaReportsLoading] = useState(false);

  const [qaConfig, setQaConfig] = useState<any>({ academicYear: "2025-2026", defaultSemester: "Odd", attendanceThresholds: { fourWeeks: 75, eightWeeks: 75, twelveWeeks: 75, sixteenWeeks: 75 }, globalNotifications: { emailAlerts: true } });
  const [qaSettingsLoading, setQaSettingsLoading] = useState(false);
  const [qaIsPromoting, setQaIsPromoting] = useState(false);

  const [qaIsBackingUp, setQaIsBackingUp] = useState(false);

  // Form states
  const [jobForm, setJobForm] = useState({
    job_id: "",
    company: "",
    title: "",
    type: "",
    ctc: "",
    stipend: "",
    deadlineDate: "",
    deadlineTime: "",
    deadlineAmPm: "PM",
    eligibility: "",
    description: "",
    bond: "",
    rounds: "",
    location: "",
  });

  const [eventForm, setEventForm] = useState({
    event_id: "",
    title: "",
    category: "",
    date: "",
    endDate: "",
    time: "",
    endTime: "",
    venue: "",
    organizer: "",
    description: "",
    entryFee: "Free",
    maxParticipants: "",
    prizes: "",
    registrationDeadline: "",
    highlights: "",
    contactEmail: "",
    contactPhone: "",
    featured: false,
  });
  const [isEventSubmitting, setIsEventSubmitting] = useState(false);

  const [clubForm, setClubForm] = useState({
    club_id: "",
    name: "",
    category: "",
    description: "",
    foundedYear: "",
    presidentName: "",
    presidentEmail: "",
    presidentPhone: "",
    advisorName: "",
    advisorEmail: "",
    advisorDepartment: "",
    venue: "",
    meetingSchedule: "",
    membershipFee: "Free",
    maxMembers: "",
    eligibility: "All Students",
    achievements: "",
    recruitmentStatus: "Open",
    recruitmentDeadline: "",
    instagram: "",
    linkedin: "",
    website: "",
    featured: false,
  });
  const [isClubSubmitting, setIsClubSubmitting] = useState(false);

  const [examForm, setExamForm] = useState(createEmptyExamForm);

  const [notificationForm, setNotificationForm] = useState({
    title: "",
    message: "",
    urgency: "normal" as "normal" | "important" | "critical",
    targetType: "all" as "all" | "students" | "faculty" | "custom",
    category: "general" as "general" | "academic" | "placement" | "event" | "emergency",
    branches: [] as string[],
    sections: [] as string[],
    years: [] as string[],
  });
  const [isNotificationSubmitting, setIsNotificationSubmitting] = useState(false);

  // Attendance Modal State
  const [isAttendanceModalOpen, setIsAttendanceModalOpen] = useState(false);
  const [isAttendanceSubmitting, setIsAttendanceSubmitting] = useState(false);
  const [isLoadingStudents, setIsLoadingStudents] = useState(false);
  const [attendanceForm, setAttendanceForm] = useState({
    year: "22",
    branch: "05",
    section: "B",  // Default to CSE-B
    slot: "slot_1",
    date: new Date().toISOString().split('T')[0],
    status: "PRESENT" as "PRESENT" | "ABSENT" | "LATE",
    selectedStudents: [] as string[],
  });

  // Available students for attendance (populated from Firebase)
  const [availableStudents, setAvailableStudents] = useState<{ id: string, name: string }[]>([]);

  // Fetch students from Firebase when filters change
  useEffect(() => {
    const loadStudentsFromFirebase = async () => {
      if (!isAttendanceModalOpen) return;

      setIsLoadingStudents(true);
      try {
        const students = await getStudentsForSection(
          attendanceForm.year,
          attendanceForm.branch,
          attendanceForm.section
        );

        setAvailableStudents(students.map(s => ({
          id: s.rollNumber,
          name: s.name,
        })));

        // Clear selected students when section changes
        setAttendanceForm(prev => ({ ...prev, selectedStudents: [] }));

        console.log(`Loaded ${students.length} students for Section ${attendanceForm.section}`);
      } catch (error) {
        console.error("Error loading students:", error);
        setAvailableStudents([]);
      } finally {
        setIsLoadingStudents(false);
      }
    };

    loadStudentsFromFirebase();
  }, [isAttendanceModalOpen, attendanceForm.year, attendanceForm.branch, attendanceForm.section]);

  // Available slots for attendance
  const attendanceSlots = [
    { id: "slot_1", name: "Slot 1 - Linux Programming (9:00 AM - 12:10 PM)", code: "22CS401" },
    { id: "slot_2", name: "Slot 2 - Business Economics (12:10 PM - 1:10 PM)", code: "22HS301" },
    { id: "slot_3", name: "Slot 3 - Professional Elective III (1:55 PM - 2:55 PM)", code: "22HS501" },
    { id: "slot_4", name: "Slot 4 - Professional Elective IV (2:55 PM - 3:55 PM)", code: "22HS601" },
  ];

  // Handle attendance form submission
  const handleAttendanceSubmit = async () => {
    if (attendanceForm.selectedStudents.length === 0) {
      toast({
        title: "No Students Selected",
        description: "Please select at least one student to mark attendance.",
        variant: "destructive",
      });
      return;
    }

    setIsAttendanceSubmitting(true);
    try {
      const selectedSlot = attendanceSlots.find(s => s.id === attendanceForm.slot);

      // Save attendance for each selected student
      for (const studentId of attendanceForm.selectedStudents) {
        const record = {
          studentId,
          slotId: attendanceForm.slot,
          date: attendanceForm.date,
