      });
      setIsNotificationModalOpen(false);
    } catch (err: any) {
      console.error("Error sending notification:", err);
      toast({
        title: "Error",
        description: err.message || "Failed to send notification. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsNotificationSubmitting(false);
    }
  };

  const getActivityIcon = (type: string) => {
    switch (type) {
      case "user":
        return <Users className="w-4 h-4 text-blue-500" />;
      case "course":
        return <BookOpen className="w-4 h-4 text-green-500" />;
      case "system":
        return <Settings className="w-4 h-4 text-gray-500" />;
      case "assignment":
        return <Calendar className="w-4 h-4 text-purple-500" />;
      default:
        return <Bell className="w-4 h-4 text-gray-500" />;
    }
  };

  return (
    <AdminLayout>
      <div className="space-y-6">
        {/* Welcome Section */}
        <div>
          <h2 className="text-2xl font-bold text-foreground">
            Welcome back, Administrator! 👋
          </h2>
          <p className="text-muted-foreground">
            Here's what's happening in your CampVerse system today.
          </p>
        </div>

        {/* Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          {stats.map((stat, index) => (
            <Card key={index} className="hover:shadow-md transition-shadow">
              <CardContent className="p-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm text-muted-foreground">
                      {stat.label}
                    </p>
                    <p className="text-2xl font-bold text-foreground">
                      {stat.value}
                    </p>
                    <p
                      className={`text-xs ${stat.changeType === "positive"
                        ? "text-green-600"
                        : stat.changeType === "negative"
                          ? "text-red-600"
                          : "text-gray-600"
                        }`}
                    >
                      {stat.change}
                    </p>
                  </div>
                  <div className={`${stat.color}`}>{stat.icon}</div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>

        <div className="grid lg:grid-cols-4 gap-6">
          {/* Quick Actions */}
          <Card className="lg:col-span-1">
            <CardHeader>
              <CardTitle className="flex items-center">
                <Settings className="w-5 h-5 mr-2" />
                Quick Actions
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-1 gap-3">
                {quickActions.map((action, index) => (
                  <Button
                    key={index}
                    variant="outline"
                    onClick={action.action}
                    className="h-16 flex flex-col items-center justify-center space-y-1 hover:shadow-md transition-all"
                  >
                    <div
                      className={`w-6 h-6 ${action.color} rounded-md flex items-center justify-center text-white`}
                    >
                      {action.icon}
                    </div>
                    <div className="text-center">
                      <div className="font-medium text-xs">{action.title}</div>
                    </div>
                  </Button>
                ))}
              </div>
            </CardContent>
          </Card>

          {/* Content Hub */}
          <Card className="lg:col-span-2">
            <CardHeader>
              <CardTitle className="flex items-center">
                <Plus className="w-5 h-5 mr-2" />
                Content Hub
              </CardTitle>
              <p className="text-sm text-muted-foreground">
                Manage placements, exams, events, clubs, and notifications
              </p>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-2 gap-4">
                {contentHubActions.map((action, index) => (
                  <Button
                    key={index}
                    variant="outline"
                    onClick={action.action}
                    className="h-20 flex flex-col items-center justify-center space-y-2 hover:shadow-md transition-all"
                  >
                    <div
                      className={`w-8 h-8 ${action.color} rounded-lg flex items-center justify-center text-white`}
                    >
                      {action.icon}
                    </div>
                    <div className="text-center">
                      <div className="font-medium text-sm">{action.title}</div>
                      <div className="text-xs text-muted-foreground">
                        {action.description}
                      </div>
                    </div>
                  </Button>
                ))}
              </div>
            </CardContent>
          </Card>

          {/* Recent Activities */}
          <Card className="lg:col-span-1">
            <CardHeader>
              <CardTitle className="flex items-center">
                <Bell className="w-5 h-5 mr-2" />
                Recent Activities
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-3">
                {recentActivities.slice(0, 4).map((activity, index) => (
                  <div key={index} className="flex items-start space-x-2">
                    <div className="mt-1">{getActivityIcon(activity.type)}</div>
                    <div className="flex-1 min-w-0">
                      <p className="text-xs font-medium text-foreground">
                        {activity.action}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        {activity.user} • {timeAgo(activity.createdAt)}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
              <Button variant="ghost" className="w-full mt-3" size="sm">
                View All
              </Button>
            </CardContent>
          </Card>
        </div>

        {/* System Overview */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center">
              <BarChart3 className="w-5 h-5 mr-2" />
              System Overview
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="text-center p-4 bg-muted/30 rounded-lg">
                <div className="text-2xl font-bold text-blue-600">45GB</div>
                <div className="text-sm text-muted-foreground">
                  Storage Used
                </div>
                <div className="text-xs text-green-600">68% of 66GB</div>
              </div>
              <div className="text-center p-4 bg-muted/30 rounded-lg">
                <div className="text-2xl font-bold text-green-600">24/7</div>
                <div className="text-sm text-muted-foreground">
                  Server Status
                </div>
                <div className="text-xs text-green-600">
                  All systems operational
                </div>
              </div>
              <div className="text-center p-4 bg-muted/30 rounded-lg">
                <div className="text-2xl font-bold text-purple-600">1.2K</div>
                <div className="text-sm text-muted-foreground">
                  Active Sessions
                </div>
                <div className="text-xs text-green-600">
                  +15% from yesterday
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Job Posting Modal */}
        <Dialog open={isJobModalOpen} onOpenChange={setIsJobModalOpen}>
          <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2 text-xl">
                <Building2 className="w-6 h-6 text-primary" />
                Post New Job Opportunity
              </DialogTitle>
            </DialogHeader>
            <div className="space-y-5 py-4">
              {/* Job ID and Company */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">
                    Job ID <span className="text-destructive">*</span>
                  </Label>
                  <div className="flex gap-2">
                    <Input
                      value={jobForm.job_id}
                      onChange={(e) =>
                        setJobForm({ ...jobForm, job_id: e.target.value.toUpperCase() })
                      }
                      placeholder="e.g., GOOGLE2025"
                      className="flex-1"
                    />
                    <Button
                      type="button"
                      variant="outline"
                      size="sm"
                      onClick={() => setJobForm({ ...jobForm, job_id: generateJobId() })}
                    >
                      Auto
                    </Button>
                  </div>
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">
                    Company Name <span className="text-destructive">*</span>
                  </Label>
                  <Input
                    value={jobForm.company}
                    onChange={(e) =>
                      setJobForm({ ...jobForm, company: e.target.value })
                    }
                    placeholder="e.g., Google, Microsoft"
                  />
                </div>
              </div>

              {/* Job Title */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">
                  Job Title <span className="text-destructive">*</span>
                </Label>
                <Input
                  value={jobForm.title}
                  onChange={(e) =>
                    setJobForm({ ...jobForm, title: e.target.value })
                  }
                  placeholder="e.g., Software Engineer, Data Analyst"
                />
              </div>

              {/* Job Type and CTC */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">
                    Job Type <span className="text-destructive">*</span>
                  </Label>
                  <Select
                    value={jobForm.type}
                    onValueChange={(value) =>
                      setJobForm({ ...jobForm, type: value })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Select job type" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Full Time">Full Time</SelectItem>
                      <SelectItem value="Internship">Internship</SelectItem>
                      <SelectItem value="Intern + Full Time">Intern + Full Time</SelectItem>
                      <SelectItem value="Contract">Contract</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">
                    CTC / Package <span className="text-destructive">*</span>
                  </Label>
                  <Input
                    value={jobForm.ctc}
                    onChange={(e) =>
                      setJobForm({ ...jobForm, ctc: e.target.value })
                    }
                    placeholder="e.g., 12 LPA, 8-15 LPA"
                  />
                </div>
              </div>

              {/* Stipend and Location */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Stipend (for internship)</Label>
                  <Input
                    value={jobForm.stipend}
                    onChange={(e) =>
                      setJobForm({ ...jobForm, stipend: e.target.value })
                    }
                    placeholder="e.g., ₹50,000/month or N/A"
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Location</Label>
                  <Input
                    value={jobForm.location}
                    onChange={(e) =>
                      setJobForm({ ...jobForm, location: e.target.value })
                    }
                    placeholder="e.g., Bangalore, Remote, Hybrid"
                  />
                </div>
              </div>

              {/* Deadline Section */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold flex items-center gap-2">
                  <Clock className="w-4 h-4" />
                  Application Deadline <span className="text-destructive">*</span>
                </Label>
                <div className="grid grid-cols-3 gap-3">
                  <div>
                    <Label className="text-xs text-muted-foreground">Date (DD-MM-YYYY)</Label>
                    <Input
                      type="date"
                      value={jobForm.deadlineDate}
                      onChange={(e) =>
                        setJobForm({ ...jobForm, deadlineDate: e.target.value })
                      }
                      min={new Date().toISOString().split("T")[0]}
                    />
                  </div>
                  <div>
                    <Label className="text-xs text-muted-foreground">Time (HH:MM)</Label>
                    <Input
                      type="time"
                      value={jobForm.deadlineTime}
                      onChange={(e) =>
                        setJobForm({ ...jobForm, deadlineTime: e.target.value })
                      }
                    />
                  </div>
                  <div>
                    <Label className="text-xs text-muted-foreground">AM/PM</Label>
                    <Select
                      value={jobForm.deadlineAmPm}
                      onValueChange={(value) =>
                        setJobForm({ ...jobForm, deadlineAmPm: value })
                      }
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="AM">AM</SelectItem>
                        <SelectItem value="PM">PM</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              </div>

              {/* Description */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">Job Description</Label>
                <Textarea
                  value={jobForm.description}
                  onChange={(e) =>
                    setJobForm({ ...jobForm, description: e.target.value })
                  }
                  placeholder="Describe the role, responsibilities, requirements..."
                  rows={3}
                />
              </div>

              {/* Eligibility */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">Eligible Branches</Label>
                <Select
                  value={jobForm.eligibility}
                  onValueChange={(value) =>
                    setJobForm({ ...jobForm, eligibility: value })
                  }
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select eligible branches" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="All Branches">All Branches</SelectItem>
                    <SelectItem value="CSE">Computer Science & Engineering</SelectItem>
                    <SelectItem value="IT">Information Technology</SelectItem>
                    <SelectItem value="ECE">Electronics & Communication</SelectItem>
                    <SelectItem value="EEE">Electrical & Electronics</SelectItem>
                    <SelectItem value="MECH">Mechanical Engineering</SelectItem>
                    <SelectItem value="CIVIL">Civil Engineering</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              {/* Bond and Rounds */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Bond Period</Label>
                  <Input
                    value={jobForm.bond}
                    onChange={(e) =>
                      setJobForm({ ...jobForm, bond: e.target.value })
                    }
                    placeholder="e.g., 2 years, No Bond"
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Selection Rounds</Label>
                  <Input
                    value={jobForm.rounds}
                    onChange={(e) =>
                      setJobForm({ ...jobForm, rounds: e.target.value })
                    }
                    placeholder="e.g., Aptitude, Technical, HR"
                  />
                  <p className="text-xs text-muted-foreground">Separate with commas</p>
                </div>
              </div>

              {/* File Attachments Section */}
              <div className="space-y-3 p-4 border rounded-lg bg-muted/30">
                <Label className="text-sm font-semibold flex items-center gap-2">
                  <FileText className="w-4 h-4" />
                  Attachments (Job Description, Forms, etc.)
                </Label>

                {/* Attached Files List */}
                {attachedFiles.length > 0 && (
                  <div className="space-y-2">
                    {attachedFiles.map((file, index) => (
                      <div
                        key={index}
                        className="flex items-center justify-between p-2 bg-background rounded border"
                      >
                        <div className="flex items-center gap-2">
                          {file.type === "drive" ? (
                            <Link className="w-4 h-4 text-blue-500" />
                          ) : (
                            <FileText className="w-4 h-4 text-muted-foreground" />
                          )}
                          <span className="text-sm truncate max-w-[200px]">{file.name}</span>
                          {file.size && (
                            <span className="text-xs text-muted-foreground">
                              ({(file.size / 1024).toFixed(1)} KB)
                            </span>
                          )}
                        </div>
                        <Button
                          type="button"
                          variant="ghost"
                          size="sm"
                          onClick={() => removeFile(index)}
                        >
                          <X className="w-4 h-4" />
                        </Button>
                      </div>
                    ))}
                  </div>
                )}

                {/* Upload Buttons */}
                <div className="flex flex-wrap gap-2">
                  <input
                    type="file"
                    ref={fileInputRef}
                    onChange={handleFileUpload}
                    multiple
                    accept=".pdf,.doc,.docx,.xls,.xlsx,.ppt,.pptx,.jpg,.jpeg,.png"
                    className="hidden"
                  />
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={() => fileInputRef.current?.click()}
                  >
                    <Upload className="w-4 h-4 mr-2" />
                    Upload from Computer
                  </Button>
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={() => setShowDriveLinkInput(!showDriveLinkInput)}
                  >
                    <Link className="w-4 h-4 mr-2" />
                    Add Google Drive Link
                  </Button>
                </div>

                {/* Google Drive Link Input */}
                {showDriveLinkInput && (
                  <div className="flex gap-2 mt-2">
                    <Input
                      value={driveLink}
                      onChange={(e) => setDriveLink(e.target.value)}
                      placeholder="Paste Google Drive link here..."
                      className="flex-1"
                    />
                    <Button
                      type="button"
                      size="sm"
                      onClick={handleAddDriveLink}
                    >
                      Add
                    </Button>
                    <Button
                      type="button"
                      variant="ghost"
                      size="sm"
                      onClick={() => {
                        setShowDriveLinkInput(false);
                        setDriveLink("");
                      }}
                    >
                      <X className="w-4 h-4" />
                    </Button>
                  </div>
                )}
              </div>

              {/* Form Actions */}
              <div className="flex justify-end gap-3 pt-4 border-t">
                <Button
                  variant="outline"
                  onClick={() => setIsJobModalOpen(false)}
                  disabled={isJobSubmitting}
                >
                  Cancel
                </Button>
                <Button
                  onClick={handleJobSubmit}
                  disabled={isJobSubmitting}
                  className="min-w-[120px]"
                >
                  {isJobSubmitting ? (
                    <>
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                      Posting...
                    </>
                  ) : (
                    <>
                      <Plus className="w-4 h-4 mr-2" />
                      Post Job
                    </>
                  )}
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>

        {/* Event Creation Modal */}
        <Dialog open={isEventModalOpen} onOpenChange={setIsEventModalOpen}>
          <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2 text-xl">
                <CalendarDays className="w-6 h-6 text-primary" />
                Create Campus Event
              </DialogTitle>
            </DialogHeader>
            <div className="space-y-5 py-4">
              {/* Event ID and Title */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">
                    Event ID <span className="text-destructive">*</span>
                  </Label>
                  <div className="flex gap-2">
                    <Input
                      value={eventForm.event_id}
                      onChange={(e) =>
                        setEventForm({ ...eventForm, event_id: e.target.value.toUpperCase() })
                      }
                      placeholder="e.g., HACKATHON2025"
                      className="flex-1"
                    />
                    <Button
                      type="button"
                      variant="outline"
                      size="sm"
                      onClick={() => setEventForm({ ...eventForm, event_id: generateEventId() })}
                    >
                      Auto
                    </Button>
                  </div>
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">
                    Event Title <span className="text-destructive">*</span>
                  </Label>
                  <Input
                    value={eventForm.title}
                    onChange={(e) =>
                      setEventForm({ ...eventForm, title: e.target.value })
                    }
                    placeholder="e.g., CodeStorm Hackathon"
                  />
                </div>
              </div>

              {/* Category and Organizer */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">
                    Category <span className="text-destructive">*</span>
                  </Label>
                  <Select
                    value={eventForm.category}
                    onValueChange={(value) =>
                      setEventForm({ ...eventForm, category: value })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Select category" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Technical">Technical</SelectItem>
                      <SelectItem value="Cultural">Cultural</SelectItem>
                      <SelectItem value="Sports">Sports</SelectItem>
                      <SelectItem value="Workshop">Workshop</SelectItem>
                      <SelectItem value="Seminar">Seminar</SelectItem>
                      <SelectItem value="Competition">Competition</SelectItem>
                      <SelectItem value="Other">Other</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">
                    Organizer <span className="text-destructive">*</span>
                  </Label>
                  <Input
                    value={eventForm.organizer}
                    onChange={(e) =>
                      setEventForm({ ...eventForm, organizer: e.target.value })
                    }
                    placeholder="e.g., IEEE Student Branch"
                  />
                </div>
              </div>

              {/* Venue */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">
                  Venue <span className="text-destructive">*</span>
                </Label>
                <Input
                  value={eventForm.venue}
                  onChange={(e) =>
                    setEventForm({ ...eventForm, venue: e.target.value })
                  }
                  placeholder="e.g., Main Auditorium, Computer Science Block"
                />
              </div>

              {/* Dates and Times */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold flex items-center gap-2">
                    <Calendar className="w-4 h-4" />
                    Start Date & Time <span className="text-destructive">*</span>
                  </Label>
                  <div className="flex gap-2">
                    <Input
                      type="date"
                      value={eventForm.date}
                      onChange={(e) =>
                        setEventForm({ ...eventForm, date: e.target.value })
                      }
                      min={new Date().toISOString().split("T")[0]}
                      className="flex-1"
                    />
                    <Input
                      type="time"
                      value={eventForm.time}
                      onChange={(e) =>
                        setEventForm({ ...eventForm, time: e.target.value })
                      }
                      className="w-32"
                    />
                  </div>
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold flex items-center gap-2">
                    <Clock className="w-4 h-4" />
                    End Date & Time
                  </Label>
                  <div className="flex gap-2">
                    <Input
                      type="date"
                      value={eventForm.endDate}
                      onChange={(e) =>
                        setEventForm({ ...eventForm, endDate: e.target.value })
                      }
                      min={eventForm.date || new Date().toISOString().split("T")[0]}
                      className="flex-1"
                    />
                    <Input
                      type="time"
                      value={eventForm.endTime}
                      onChange={(e) =>
                        setEventForm({ ...eventForm, endTime: e.target.value })
                      }
                      className="w-32"
                    />
                  </div>
                </div>
              </div>

              {/* Description */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">Event Description</Label>
                <Textarea
                  value={eventForm.description}
                  onChange={(e) =>
                    setEventForm({ ...eventForm, description: e.target.value })
                  }
                  placeholder="Share agenda, key speakers, eligibility, and participation instructions..."
                  rows={3}
                />
              </div>

              {/* Entry Fee, Max Participants, Prizes */}
              <div className="grid grid-cols-3 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Entry Fee</Label>
                  <Input
                    value={eventForm.entryFee}
                    onChange={(e) =>
                      setEventForm({ ...eventForm, entryFee: e.target.value })
                    }
                    placeholder="Free, ₹200, etc."
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Max Participants</Label>
                  <Input
                    type="number"
                    value={eventForm.maxParticipants}
                    onChange={(e) =>
                      setEventForm({ ...eventForm, maxParticipants: e.target.value })
                    }
                    placeholder="0 = unlimited"
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold flex items-center gap-1">
                    <Trophy className="w-4 h-4" />
                    Prizes
                  </Label>
                  <Input
                    value={eventForm.prizes}
                    onChange={(e) =>
                      setEventForm({ ...eventForm, prizes: e.target.value })
                    }
                    placeholder="₹50,000 Prize Pool"
                  />
                </div>
              </div>

              {/* Registration Deadline and Highlights */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Registration Deadline</Label>
                  <Input
                    type="date"
                    value={eventForm.registrationDeadline}
                    onChange={(e) =>
                      setEventForm({ ...eventForm, registrationDeadline: e.target.value })
                    }
                    max={eventForm.date}
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Highlights</Label>
                  <Input
                    value={eventForm.highlights}
                    onChange={(e) =>
                      setEventForm({ ...eventForm, highlights: e.target.value })
                    }
                    placeholder="Free Food, Networking, Certificates"
                  />
                  <p className="text-xs text-muted-foreground">Separate with commas</p>
                </div>
              </div>

              {/* Contact Info */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Contact Email</Label>
                  <Input
                    type="email"
                    value={eventForm.contactEmail}
                    onChange={(e) =>
                      setEventForm({ ...eventForm, contactEmail: e.target.value })
                    }
                    placeholder="events@college.ac.in"
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Contact Phone</Label>
                  <Input
                    value={eventForm.contactPhone}
                    onChange={(e) =>
                      setEventForm({ ...eventForm, contactPhone: e.target.value })
                    }
                    placeholder="+91 9876543210"
                  />
                </div>
              </div>

              {/* Featured Toggle */}
              <div className="flex items-center justify-between rounded-lg border border-border bg-muted/20 p-3">
                <div>
                  <p className="text-sm font-medium text-foreground">
                    Featured Event
                  </p>
                  <p className="text-xs text-muted-foreground">
                    Featured events are highlighted on the student dashboard
                  </p>
                </div>
                <Switch
                  checked={eventForm.featured}
                  onCheckedChange={(checked) =>
                    setEventForm({ ...eventForm, featured: checked })
                  }
                />
              </div>

              {/* Form Actions */}
              <div className="flex justify-end gap-3 pt-4 border-t">
                <Button
                  variant="outline"
                  onClick={() => setIsEventModalOpen(false)}
                  disabled={isEventSubmitting}
                >
                  Cancel
                </Button>
                <Button
                  onClick={handleEventSubmit}
                  disabled={isEventSubmitting}
                  className="min-w-[140px]"
                >
                  {isEventSubmitting ? (
                    <>
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                      Creating...
                    </>
                  ) : (
                    <>
                      <Plus className="w-4 h-4 mr-2" />
                      Create Event
                    </>
                  )}
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>


        {/* Exam Scheduling Modal */}
        <Dialog open={isExamModalOpen} onOpenChange={setIsExamModalOpen}>
          <DialogContent className="max-w-xl max-h-[80vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2">
                <Calendar className="w-5 h-5 text-primary" />
                Post Upcoming Exam
              </DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              {/* Exam Title */}
              <div>
                <label className="text-sm font-medium">
                  Exam Title <span className="text-destructive">*</span>
                </label>
                <Input
                  value={examForm.title}
                  onChange={(e) =>
                    setExamForm((prev) => ({ ...prev, title: e.target.value }))
                  }
                  placeholder="e.g., Mid Semester Examination - I"
                />
              </div>

              {/* Exam Type and Date */}
              <div className="grid md:grid-cols-2 gap-4">
                <div>
                  <label className="text-sm font-medium">Exam Type</label>
                  <Select
                    value={examForm.examType}
                    onValueChange={(value) =>
                      setExamForm((prev) => ({ ...prev, examType: value as any }))
                    }
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Choose type" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Mid-Term">Mid-Term</SelectItem>
                      <SelectItem value="End-Term">End-Term</SelectItem>
                      <SelectItem value="Quiz">Quiz</SelectItem>
                      <SelectItem value="Practical">Practical</SelectItem>
                      <SelectItem value="Viva">Viva</SelectItem>
                      <SelectItem value="Assignment">Assignment</SelectItem>
                      <SelectItem value="Other">Other</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <label className="text-sm font-medium">
                    Exam Date <span className="text-destructive">*</span>
                  </label>
                  <Input
                    type="date"
                    value={examForm.date}
                    onChange={(e) =>
                      setExamForm((prev) => ({ ...prev, date: e.target.value }))
                    }
                  />
                </div>
              </div>

              {/* Time and Venue */}
              <div className="grid md:grid-cols-3 gap-4">
                <div>
                  <label className="text-sm font-medium">
                    Start Time <span className="text-destructive">*</span>
                  </label>
                  <Input
                    type="time"
                    value={examForm.startTime}
                    onChange={(e) =>
                      setExamForm((prev) => ({
                        ...prev,
                        startTime: e.target.value,
                      }))
                    }
                  />
                </div>
                <div>
                  <label className="text-sm font-medium">
                    End Time <span className="text-destructive">*</span>
                  </label>
                  <Input
                    type="time"
                    value={examForm.endTime}
                    onChange={(e) =>
                      setExamForm((prev) => ({
                        ...prev,
                        endTime: e.target.value,
                      }))
                    }
                  />
                </div>
                <div>
                  <label className="text-sm font-medium">Venue</label>
                  <Input
                    value={examForm.venue}
                    onChange={(e) =>
                      setExamForm((prev) => ({ ...prev, venue: e.target.value }))
                    }
                    placeholder="e.g., Block A, Room 101"
                  />
                </div>
              </div>

              {/* Target Audience */}
              <div className="space-y-3 rounded-lg border border-border bg-muted/20 p-4">
                <div>
                  <p className="text-sm font-semibold text-foreground">
                    Target Audience (Optional)
                  </p>
                  <p className="text-xs text-muted-foreground">
                    Leave empty to show to all students. Separate multiple entries with commas.
                  </p>
                </div>
                <div className="grid md:grid-cols-3 gap-3">
                  <div>
                    <label className="text-xs font-medium text-muted-foreground">Branches</label>
                    <Input
                      value={examForm.branches}
                      onChange={(e) =>
                        setExamForm((prev) => ({ ...prev, branches: e.target.value }))
                      }
                      placeholder="CSE, ECE, EEE"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-medium text-muted-foreground">Sections</label>
                    <Input
                      value={examForm.sections}
                      onChange={(e) =>
                        setExamForm((prev) => ({ ...prev, sections: e.target.value }))
                      }
                      placeholder="A, B, C"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-medium text-muted-foreground">Years</label>
                    <Input
                      value={examForm.years}
                      onChange={(e) =>
                        setExamForm((prev) => ({ ...prev, years: e.target.value }))
                      }
                      placeholder="1, 2, 3, 4"
                    />
                  </div>
                </div>
              </div>

              {/* Submit Buttons */}
              <div className="flex justify-end gap-3 pt-2">
                <Button
                  variant="outline"
                  onClick={() => {
                    setExamForm(createEmptyExamForm());
                    setIsExamModalOpen(false);
                  }}
                  disabled={isExamSubmitting}
                >
                  Cancel
                </Button>
                <Button onClick={handleExamSubmit} disabled={isExamSubmitting}>
                  {isExamSubmitting ? (
                    <>
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                      Posting...
                    </>
                  ) : (
                    "Post Exam"
                  )}
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>


        {/* Club Addition Modal */}
        <Dialog open={isClubModalOpen} onOpenChange={setIsClubModalOpen}>
          <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2 text-xl">
                <UsersRound className="w-6 h-6 text-primary" />
                Register New Club
              </DialogTitle>
            </DialogHeader>
            <div className="space-y-5 py-4">
              {/* Club ID and Name */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">
                    Club ID <span className="text-destructive">*</span>
                  </Label>
                  <div className="flex gap-2">
                    <Input
                      value={clubForm.club_id}
                      onChange={(e) =>
                        setClubForm({ ...clubForm, club_id: e.target.value.toUpperCase() })
                      }
                      placeholder="e.g., IEEE2025"
                      className="flex-1"
                    />
                    <Button
                      type="button"
                      variant="outline"
                      size="sm"
                      onClick={() => setClubForm({ ...clubForm, club_id: generateClubId() })}
                    >
                      Auto
                    </Button>
                  </div>
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">
                    Club Name <span className="text-destructive">*</span>
                  </Label>
                  <Input
                    value={clubForm.name}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, name: e.target.value })
                    }
                    placeholder="e.g., IEEE Student Branch"
                  />
                </div>
              </div>

              {/* Category and Founded Year */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">
                    Category <span className="text-destructive">*</span>
                  </Label>
                  <Select
                    value={clubForm.category}
                    onValueChange={(value) =>
                      setClubForm({ ...clubForm, category: value })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Select category" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Technical">Technical</SelectItem>
                      <SelectItem value="Cultural">Cultural</SelectItem>
                      <SelectItem value="Sports">Sports</SelectItem>
                      <SelectItem value="Literary">Literary</SelectItem>
                      <SelectItem value="Social">Social</SelectItem>
                      <SelectItem value="Professional">Professional</SelectItem>
                      <SelectItem value="Hobby">Hobby</SelectItem>
                      <SelectItem value="Other">Other</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Founded Year</Label>
                  <Input
                    type="number"
                    value={clubForm.foundedYear}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, foundedYear: e.target.value })
                    }
                    placeholder="e.g., 2020"
                    min={1990}
                    max={new Date().getFullYear()}
                  />
                </div>
              </div>

              {/* Description */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">
                  Description <span className="text-destructive">*</span>
                </Label>
                <Textarea
                  value={clubForm.description}
                  onChange={(e) =>
                    setClubForm({ ...clubForm, description: e.target.value })
                  }
                  placeholder="Club objectives, activities, achievements..."
                  rows={3}
                />
              </div>

              {/* President Info */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">President Details</Label>
                <div className="grid grid-cols-3 gap-3">
                  <Input
                    value={clubForm.presidentName}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, presidentName: e.target.value })
                    }
                    placeholder="President Name"
                  />
                  <Input
                    type="email"
                    value={clubForm.presidentEmail}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, presidentEmail: e.target.value })
                    }
                    placeholder="president@email.com"
                  />
                  <Input
                    value={clubForm.presidentPhone}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, presidentPhone: e.target.value })
                    }
                    placeholder="+91 9876543210"
                  />
                </div>
              </div>

              {/* Faculty Advisor Info */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">Faculty Advisor</Label>
                <div className="grid grid-cols-3 gap-3">
                  <Input
                    value={clubForm.advisorName}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, advisorName: e.target.value })
                    }
                    placeholder="Advisor Name"
                  />
                  <Input
                    type="email"
                    value={clubForm.advisorEmail}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, advisorEmail: e.target.value })
                    }
                    placeholder="advisor@college.ac.in"
                  />
                  <Input
                    value={clubForm.advisorDepartment}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, advisorDepartment: e.target.value })
                    }
                    placeholder="Department"
                  />
                </div>
              </div>

              {/* Venue and Meeting Schedule */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Venue</Label>
                  <Input
                    value={clubForm.venue}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, venue: e.target.value })
                    }
                    placeholder="Room 201, CS Block"
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Meeting Schedule</Label>
                  <Input
                    value={clubForm.meetingSchedule}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, meetingSchedule: e.target.value })
                    }
                    placeholder="Every Saturday, 3 PM"
                  />
                </div>
              </div>

              {/* Membership Fee, Max Members, Eligibility */}
              <div className="grid grid-cols-3 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Membership Fee</Label>
                  <Input
                    value={clubForm.membershipFee}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, membershipFee: e.target.value })
                    }
                    placeholder="Free, ₹500/year"
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Max Members</Label>
                  <Input
                    type="number"
                    value={clubForm.maxMembers}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, maxMembers: e.target.value })
                    }
                    placeholder="0 = unlimited"
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Eligibility</Label>
                  <Input
                    value={clubForm.eligibility}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, eligibility: e.target.value })
                    }
                    placeholder="All Students"
                  />
                </div>
              </div>

              {/* Achievements and Recruitment */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Achievements</Label>
                  <Input
                    value={clubForm.achievements}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, achievements: e.target.value })
                    }
                    placeholder="Winners of XYZ, National Award"
                  />
                  <p className="text-xs text-muted-foreground">Separate with commas</p>
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Recruitment Status</Label>
                  <Select
                    value={clubForm.recruitmentStatus}
                    onValueChange={(value) =>
                      setClubForm({ ...clubForm, recruitmentStatus: value })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Status" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Open">Open</SelectItem>
                      <SelectItem value="Closed">Closed</SelectItem>
                      <SelectItem value="Coming Soon">Coming Soon</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>

              {/* Social Links */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">Social Links</Label>
                <div className="grid grid-cols-3 gap-3">
                  <Input
                    value={clubForm.instagram}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, instagram: e.target.value })
                    }
                    placeholder="Instagram URL"
                  />
                  <Input
                    value={clubForm.linkedin}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, linkedin: e.target.value })
                    }
                    placeholder="LinkedIn URL"
                  />
                  <Input
                    value={clubForm.website}
                    onChange={(e) =>
                      setClubForm({ ...clubForm, website: e.target.value })
                    }
                    placeholder="Website URL"
                  />
                </div>
              </div>

              {/* Featured Toggle */}
              <div className="flex items-center justify-between rounded-lg border border-border bg-muted/20 p-3">
                <div>
                  <p className="text-sm font-medium text-foreground">
                    Featured Club
                  </p>
                  <p className="text-xs text-muted-foreground">
                    Featured clubs are highlighted on the student dashboard
                  </p>
                </div>
                <Switch
                  checked={clubForm.featured}
                  onCheckedChange={(checked) =>
                    setClubForm({ ...clubForm, featured: checked })
                  }
                />
              </div>

              {/* Form Actions */}
              <div className="flex justify-end gap-3 pt-4 border-t">
                <Button
                  variant="outline"
                  onClick={() => setIsClubModalOpen(false)}
                  disabled={isClubSubmitting}
                >
                  Cancel
                </Button>
                <Button
                  onClick={handleClubSubmit}
                  disabled={isClubSubmitting}
                  className="min-w-[140px]"
                >
                  {isClubSubmitting ? (
                    <>
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                      Creating...
                    </>
                  ) : (
                    <>
                      <Plus className="w-4 h-4 mr-2" />
                      Register Club
                    </>
                  )}
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>

        {/* Notification Modal */}
        <Dialog
          open={isNotificationModalOpen}
          onOpenChange={setIsNotificationModalOpen}
        >
          <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2 text-xl">
                <Bell className="w-6 h-6 text-primary" />
                Send Notification Alert
              </DialogTitle>
            </DialogHeader>
            <div className="space-y-5 py-4">
              {/* Title */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">
                  Alert Title <span className="text-destructive">*</span>
                </Label>
                <Input
                  value={notificationForm.title}
                  onChange={(e) =>
                    setNotificationForm({ ...notificationForm, title: e.target.value })
                  }
                  placeholder="e.g., Important: Exam Schedule Update"
                />
              </div>

              {/* Message */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">
                  Message <span className="text-destructive">*</span>
                </Label>
                <Textarea
                  value={notificationForm.message}
                  onChange={(e) =>
                    setNotificationForm({ ...notificationForm, message: e.target.value })
                  }
                  placeholder="Enter your notification message..."
                  rows={4}
                />
              </div>

              {/* Category */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">Category</Label>
                <Select
                  value={notificationForm.category}
                  onValueChange={(value: "general" | "academic" | "placement" | "event" | "emergency") =>
                    setNotificationForm({ ...notificationForm, category: value })
                  }
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="general">General</SelectItem>
                    <SelectItem value="academic">Academic</SelectItem>
                    <SelectItem value="placement">Placement</SelectItem>
                    <SelectItem value="event">Event</SelectItem>
                    <SelectItem value="emergency">Emergency</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              {/* Target Audience */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">Target Audience</Label>
                <Select
                  value={notificationForm.targetType}
                  onValueChange={(value: "all" | "students" | "faculty" | "custom") =>
                    setNotificationForm({ ...notificationForm, targetType: value })
                  }
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Users</SelectItem>
                    <SelectItem value="students">All Students</SelectItem>
                    <SelectItem value="faculty">All Faculty</SelectItem>
                    <SelectItem value="custom">Custom (Specific Branches/Sections)</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              {/* Custom Targeting Options */}
              {notificationForm.targetType === "custom" && (
                <div className="space-y-4 p-4 border border-border rounded-lg bg-muted/20">
                  <p className="text-sm font-medium text-foreground">Custom Targeting Options</p>

                  {/* Branches */}
                  <div className="space-y-2">
                    <Label className="text-sm">Branches (comma-separated)</Label>
                    <Input
                      value={notificationForm.branches.join(", ")}
                      onChange={(e) =>
                        setNotificationForm({
                          ...notificationForm,
                          branches: e.target.value.split(",").map((b) => b.trim()).filter((b) => b),
                        })
                      }
                      placeholder="e.g., CSE, ECE, EEE"
                    />
                    <p className="text-xs text-muted-foreground">Leave empty to include all branches</p>
                  </div>

                  {/* Sections */}
                  <div className="space-y-2">
                    <Label className="text-sm">Sections (comma-separated)</Label>
                    <Input
                      value={notificationForm.sections.join(", ")}
                      onChange={(e) =>
                        setNotificationForm({
                          ...notificationForm,
                          sections: e.target.value.split(",").map((s) => s.trim()).filter((s) => s),
                        })
                      }
                      placeholder="e.g., A, B, C"
                    />
                    <p className="text-xs text-muted-foreground">Leave empty to include all sections</p>
                  </div>

                  {/* Years */}
                  <div className="space-y-2">
                    <Label className="text-sm">Years (comma-separated)</Label>
                    <Input
                      value={notificationForm.years.join(", ")}
                      onChange={(e) =>
                        setNotificationForm({
                          ...notificationForm,
                          years: e.target.value.split(",").map((y) => y.trim()).filter((y) => y),
                        })
                      }
                      placeholder="e.g., 1, 2, 3, 4"
                    />
                    <p className="text-xs text-muted-foreground">Leave empty to include all years</p>
                  </div>
                </div>
              )}



              {/* Form Actions */}
              <div className="flex justify-end gap-3 pt-4 border-t">
                <Button
                  variant="outline"
                  onClick={() => setIsNotificationModalOpen(false)}
                  disabled={isNotificationSubmitting}
                >
                  Cancel
                </Button>
                <Button
                  onClick={handleNotificationSubmit}
                  disabled={isNotificationSubmitting}
                  className="min-w-[140px]"
                >
                  {isNotificationSubmitting ? (
                    <>
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                      Sending...
                    </>
                  ) : (
                    <>
                      <Send className="w-4 h-4 mr-2" />
                      Send Alert
                    </>
                  )}
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>

        {/* Put Attendance Modal */}
        <Dialog open={isAttendanceModalOpen} onOpenChange={setIsAttendanceModalOpen}>
          <DialogContent className="sm:max-w-[700px] max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2 text-xl">
                <Clock className="w-5 h-5 text-cyan-500" />
                Put Attendance
              </DialogTitle>
            </DialogHeader>

            <div className="space-y-6 py-4">
              {/* Selection Filters */}
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-medium">Year</Label>
                  <Select value={attendanceForm.year} onValueChange={(v) => setAttendanceForm({ ...attendanceForm, year: v })}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="22">2022 Batch</SelectItem>
                      <SelectItem value="23">2023 Batch</SelectItem>
                      <SelectItem value="24">2024 Batch</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label className="text-sm font-medium">Branch</Label>
                  <Select value={attendanceForm.branch} onValueChange={(v) => setAttendanceForm({ ...attendanceForm, branch: v })}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="05">CSE</SelectItem>
                      <SelectItem value="04">ECE</SelectItem>
                      <SelectItem value="03">EEE</SelectItem>
                      <SelectItem value="02">MECH</SelectItem>
                      <SelectItem value="01">CIVIL</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label className="text-sm font-medium">Section</Label>
                  <Select value={attendanceForm.section} onValueChange={(v) => setAttendanceForm({ ...attendanceForm, section: v })}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="A">Section A</SelectItem>
                      <SelectItem value="B">Section B</SelectItem>
                      <SelectItem value="C">Section C</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label className="text-sm font-medium">Date</Label>
                  <Input
                    type="date"
                    value={attendanceForm.date}
                    onChange={(e) => setAttendanceForm({ ...attendanceForm, date: e.target.value })}
                  />
                </div>
              </div>

              {/* Slot Selection */}
              <div className="space-y-2">
                <Label className="text-sm font-medium">Select Slot</Label>
                <Select value={attendanceForm.slot} onValueChange={(v) => setAttendanceForm({ ...attendanceForm, slot: v })}>
                  <SelectTrigger>
                    <SelectValue placeholder="Select a slot" />
                  </SelectTrigger>
                  <SelectContent>
                    {attendanceSlots.map((slot) => (
                      <SelectItem key={slot.id} value={slot.id}>
                        {slot.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {/* Status Selection */}
              <div className="space-y-2">
                <Label className="text-sm font-medium">Mark As</Label>
                <div className="flex gap-3">
                  <Button
                    type="button"
                    variant={attendanceForm.status === "PRESENT" ? "default" : "outline"}
                    onClick={() => setAttendanceForm({ ...attendanceForm, status: "PRESENT" })}
                    className={attendanceForm.status === "PRESENT" ? "bg-blue-600 hover:bg-blue-700" : ""}
                  >
                    ✓ Present
                  </Button>
                  <Button
                    type="button"
                    variant={attendanceForm.status === "ABSENT" ? "default" : "outline"}
                    onClick={() => setAttendanceForm({ ...attendanceForm, status: "ABSENT" })}
                    className={attendanceForm.status === "ABSENT" ? "bg-red-600 hover:bg-red-700" : ""}
                  >
                    ✗ Absent
                  </Button>
                  <Button
                    type="button"
                    variant={attendanceForm.status === "LATE" ? "default" : "outline"}
                    onClick={() => setAttendanceForm({ ...attendanceForm, status: "LATE" })}
                    className={attendanceForm.status === "LATE" ? "bg-yellow-600 hover:bg-yellow-700" : ""}
                  >
                    ⏰ Late
                  </Button>
                </div>
              </div>

              {/* Student Selection */}
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <Label className="text-sm font-medium">Select Students</Label>
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={selectAllStudents}
                  >
                    {attendanceForm.selectedStudents.length === availableStudents.length ? "Deselect All" : "Select All"}
                  </Button>
                </div>

                <div className="border rounded-lg overflow-hidden max-h-[250px] overflow-y-auto">
                  {isLoadingStudents ? (
                    <div className="flex items-center justify-center p-6">
                      <Loader2 className="w-6 h-6 animate-spin text-cyan-500" />
                      <span className="ml-2 text-muted-foreground">Loading students...</span>
                    </div>
                  ) : availableStudents.length === 0 ? (
                    <div className="flex items-center justify-center p-6 text-muted-foreground">
                      No students found for Section {attendanceForm.section}
                    </div>
                  ) : (
                    availableStudents.map((student) => (
                      <div
                        key={student.id}
                        className={`flex items-center gap-3 p-3 border-b last:border-b-0 cursor-pointer hover:bg-muted/50 transition-colors ${attendanceForm.selectedStudents.includes(student.id) ? "bg-cyan-500/10" : ""
                          }`}
                        onClick={() => toggleStudentSelection(student.id)}
                      >
                        <input
                          type="checkbox"
                          checked={attendanceForm.selectedStudents.includes(student.id)}
                          onChange={() => { }}
                          className="w-4 h-4 rounded border-gray-300"
                        />
                        <div>
                          <p className="font-medium text-sm">{student.id}</p>
                          <p className="text-xs text-muted-foreground">{student.name}</p>
                        </div>
                      </div>
                    ))
                  )}
                </div>

                <p className="text-xs text-muted-foreground">
                  {attendanceForm.selectedStudents.length} student(s) selected out of {availableStudents.length}
                </p>
              </div>

              {/* Form Actions */}
              <div className="flex justify-between items-center pt-4 border-t">
                <Button
                  variant="outline"
                  onClick={() => window.location.href = "/admin/attendance"}
                  className="gap-2"
                >
                  View All Records
                </Button>
                <div className="flex gap-3">
                  <Button
                    variant="outline"
                    onClick={() => setIsAttendanceModalOpen(false)}
                    disabled={isAttendanceSubmitting}
                  >
                    Cancel
                  </Button>
                  <Button
                    onClick={handleAttendanceSubmit}
                    disabled={isAttendanceSubmitting || attendanceForm.selectedStudents.length === 0}
                    className="min-w-[140px] bg-cyan-600 hover:bg-cyan-700"
                  >
                    {isAttendanceSubmitting ? (
                      <>
                        <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                        Saving...
                      </>
                    ) : (
                      <>
                        <Plus className="w-4 h-4 mr-2" />
                        Mark Attendance
                      </>
                    )}
                  </Button>
                </div>
              </div>
            </div>
          </DialogContent>
        </Dialog>

        {/* ═══ Quick Action Modals ═══════════════════════════════════ */}

        {/* ── Add New User Modal ── */}
        <Dialog open={isUserModalOpen} onOpenChange={setIsUserModalOpen}>
          <DialogContent className="max-w-2xl max-h-[85vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2 text-xl">
                <UserPlus className="w-6 h-6 text-blue-500" />
                User Management
              </DialogTitle>
              <p className="text-sm text-muted-foreground">Add Students, Faculty, and Sub-Admins with role-based access.</p>
            </DialogHeader>
            <Tabs defaultValue="student" onValueChange={setQaActiveTab} className="w-full mt-2">
              <TabsList className="grid w-full grid-cols-3 mb-4">
                <TabsTrigger value="student" className="flex items-center gap-1.5 text-xs"><GraduationCap className="w-3.5 h-3.5" /> Student</TabsTrigger>
                <TabsTrigger value="faculty" className="flex items-center gap-1.5 text-xs"><UsersIcon className="w-3.5 h-3.5" /> Faculty</TabsTrigger>
                <TabsTrigger value="sub-admin" className="flex items-center gap-1.5 text-xs"><ShieldPlus className="w-3.5 h-3.5" /> Sub-Admin</TabsTrigger>
              </TabsList>
              <form onSubmit={handleQaUserSubmit} className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1.5">
                    <Label className="text-sm font-semibold">Full Name <span className="text-destructive">*</span></Label>
                    <Input required value={qaActiveTab === "student" ? qaStudentForm.name : qaActiveTab === "faculty" ? qaFacultyForm.name : qaSubAdminForm.name}
                      onChange={(e) => { const v = e.target.value; if (qaActiveTab === "student") setQaStudentForm(f => ({ ...f, name: v })); if (qaActiveTab === "faculty") setQaFacultyForm(f => ({ ...f, name: v })); if (qaActiveTab === "sub-admin") setQaSubAdminForm(f => ({ ...f, name: v })); }}
                      placeholder="e.g. John Doe" />
                  </div>
                  <div className="space-y-1.5">
                    <Label className="text-sm font-semibold">Email <span className="text-destructive">*</span></Label>
                    <Input type="email" required value={qaActiveTab === "student" ? qaStudentForm.email : qaActiveTab === "faculty" ? qaFacultyForm.email : qaSubAdminForm.email}
                      onChange={(e) => { const v = e.target.value; if (qaActiveTab === "student") setQaStudentForm(f => ({ ...f, email: v })); if (qaActiveTab === "faculty") setQaFacultyForm(f => ({ ...f, email: v })); if (qaActiveTab === "sub-admin") setQaSubAdminForm(f => ({ ...f, email: v })); }}
                      placeholder="e.g. jdoe@cvr.ac.in" />
                  </div>
                  <div className="space-y-1.5">
                    <Label className="text-sm font-semibold">Unique ID <span className="text-destructive">*</span></Label>
                    <div className="flex gap-2">
                      <Input required value={qaActiveTab === "student" ? qaStudentForm.collegeId : qaActiveTab === "faculty" ? qaFacultyForm.collegeId : qaSubAdminForm.collegeId}
                        onChange={(e) => { const v = e.target.value.toUpperCase(); if (qaActiveTab === "student") setQaStudentForm(f => ({ ...f, collegeId: v })); if (qaActiveTab === "faculty") setQaFacultyForm(f => ({ ...f, collegeId: v })); if (qaActiveTab === "sub-admin") setQaSubAdminForm(f => ({ ...f, collegeId: v })); }}
                        placeholder="e.g. 22B81A05C4" />
                      <Button type="button" variant="outline" size="sm" onClick={() => { const v = qaGenerateId(qaActiveTab); if (qaActiveTab === "student") setQaStudentForm(f => ({ ...f, collegeId: v })); if (qaActiveTab === "faculty") setQaFacultyForm(f => ({ ...f, collegeId: v })); if (qaActiveTab === "sub-admin") setQaSubAdminForm(f => ({ ...f, collegeId: v })); }}>Auto</Button>
                    </div>
                  </div>
                  {qaActiveTab !== "sub-admin" && (
                    <div className="space-y-1.5">
                      <Label className="text-sm font-semibold">Branch</Label>
                      <Select value={qaActiveTab === "student" ? qaStudentForm.branch : qaFacultyForm.branch} onValueChange={(v) => { if (qaActiveTab === "student") setQaStudentForm(f => ({ ...f, branch: v })); if (qaActiveTab === "faculty") setQaFacultyForm(f => ({ ...f, branch: v })); }}>
                        <SelectTrigger><SelectValue placeholder="Select Branch" /></SelectTrigger>
                        <SelectContent>
                          <SelectItem value="05">CSE</SelectItem>
                          <SelectItem value="12">IT</SelectItem>
                          <SelectItem value="04">ECE</SelectItem>
                          <SelectItem value="03">EEE</SelectItem>
                          <SelectItem value="02">MECH</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  )}
                  {qaActiveTab === "student" && (
                    <>
                      <div className="space-y-1.5">
                        <Label className="text-sm font-semibold">Academic Batch</Label>
                        <Input value={qaStudentForm.academicBatch} onChange={e => setQaStudentForm(f => ({ ...f, academicBatch: e.target.value }))} placeholder="2026-2030" />
                      </div>
                      <div className="space-y-1.5">
                        <Label className="text-sm font-semibold">Section</Label>
                        <Input value={qaStudentForm.section} onChange={e => setQaStudentForm(f => ({ ...f, section: e.target.value.toUpperCase() }))} placeholder="A, B, C..." maxLength={1} />
                      </div>
                    </>
                  )}
                </div>
                {qaActiveTab === "sub-admin" && (
                  <div className="pt-3 border-t mt-4">
                    <h4 className="text-sm font-semibold mb-3">Granular Permissions</h4>
                    <div className="grid grid-cols-2 gap-3">
                      {(["manageAttendance", "manageEvents", "manageClubs", "manageNotifications", "manageResults"] as const).map(perm => (
                        <div key={perm} className="flex items-center space-x-2">
                          <Checkbox id={`qa-${perm}`} checked={qaSubAdminForm.permissions[perm]}
                            onCheckedChange={(checked) => setQaSubAdminForm(f => ({ ...f, permissions: { ...f.permissions, [perm]: checked } }))} />
                          <label htmlFor={`qa-${perm}`} className="text-sm cursor-pointer">{perm.replace("manage", "Manage ")}</label>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
                <Button type="submit" disabled={qaUserLoading} className="w-full bg-blue-600 hover:bg-blue-700 mt-4">
                  {qaUserLoading ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Processing...</> : `Create ${qaActiveTab === "student" ? "Student" : qaActiveTab === "faculty" ? "Faculty" : "Sub-Admin"}`}
                </Button>
              </form>
            </Tabs>
          </DialogContent>
        </Dialog>

        {/* ── Generate Reports Modal ── */}
        <Dialog open={isReportsModalOpen} onOpenChange={setIsReportsModalOpen}>
          <DialogContent className="max-w-3xl max-h-[85vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2 text-xl">
                <BarChart3 className="w-6 h-6 text-green-500" />
                Analytics Dashboard
              </DialogTitle>
              <p className="text-sm text-muted-foreground">Comprehensive reports on Attendance, Placements, Events, Clubs, and Results.</p>
            </DialogHeader>
            {qaReportsLoading ? (
              <div className="flex items-center justify-center py-12"><Loader2 className="w-8 h-8 animate-spin text-muted-foreground" /></div>
            ) : qaReports ? (
              <div className="grid grid-cols-2 lg:grid-cols-3 gap-4 mt-4">
                <Card>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">Total Students</CardTitle>
                    <GraduationCap className="h-4 w-4 text-blue-600" />
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-bold">{qaReports.users?.studentCount ?? 0}</div>
                    <p className="text-xs text-muted-foreground">Active in system</p>
                  </CardContent>
                </Card>
                <Card>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">Placements</CardTitle>
                    <Building2 className="h-4 w-4 text-green-600" />
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-bold">{qaReports.placements?.totalSelected ?? 0} / {qaReports.placements?.totalPosted ?? 0}</div>
                    <p className="text-xs text-muted-foreground">Selected / Posted</p>
                  </CardContent>
                </Card>
                <Card>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">Graduated</CardTitle>
                    <Trophy className="h-4 w-4 text-orange-600" />
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-bold">{qaReports.users?.graduatedCount ?? 0}</div>
                    <p className="text-xs text-muted-foreground">Alumni archive</p>
                  </CardContent>
                </Card>
                <Card>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">Pass Rate</CardTitle>
                    <BarChart3 className="h-4 w-4 text-purple-600" />
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-bold">{qaReports.results?.passPercentage ?? "N/A"}</div>
                    <p className="text-xs text-muted-foreground">Avg CGPA: {qaReports.results?.avgCGPA ?? "N/A"}</p>
                  </CardContent>
                </Card>
                <Card>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">Active Events</CardTitle>
                    <CalendarDays className="h-4 w-4 text-emerald-600" />
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-bold">{qaReports.events?.activeEvents ?? 0}</div>
                    <p className="text-xs text-muted-foreground">Participation: {qaReports.events?.participationRate ?? "N/A"}</p>
                  </CardContent>
                </Card>
                <Card>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">Active Clubs</CardTitle>
                    <UsersRound className="h-4 w-4 text-rose-600" />
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-bold">{qaReports.clubs?.totalClubs ?? 0}</div>
                    <p className="text-xs text-muted-foreground">{qaReports.clubs?.activeMembers ?? 0} Members</p>
                  </CardContent>
                </Card>
              </div>
            ) : (
              <div className="text-center py-12 text-muted-foreground">No report data available. Check backend connection.</div>
            )}
          </DialogContent>
        </Dialog>

        {/* ── System Settings Modal ── */}
        <Dialog open={isSettingsModalOpen} onOpenChange={setIsSettingsModalOpen}>
          <DialogContent className="max-w-3xl max-h-[85vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2 text-xl">
                <Settings className="w-6 h-6 text-purple-500" />
                System Settings
              </DialogTitle>
              <p className="text-sm text-muted-foreground">Configure Academic Year, Attendance thresholds, and global settings.</p>
            </DialogHeader>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mt-4">
              {/* Global Config */}
              <div className="space-y-4">
                <h3 className="text-sm font-semibold flex items-center gap-2"><Settings className="w-4 h-4" /> Global Configuration</h3>
                <form onSubmit={handleQaSettingsSave} className="space-y-3">
                  <div className="space-y-1.5">
                    <Label className="text-xs font-semibold">Academic Year</Label>
                    <Input value={qaConfig?.academicYear || ""} onChange={e => setQaConfig({ ...qaConfig, academicYear: e.target.value })} />
                  </div>
                  <div className="space-y-1.5">
                    <Label className="text-xs font-semibold">Default Semester</Label>
                    <Select value={qaConfig?.defaultSemester || "Odd"} onValueChange={v => setQaConfig({ ...qaConfig, defaultSemester: v })}>
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        <SelectItem value="Odd">Odd Semester</SelectItem>
                        <SelectItem value="Even">Even Semester</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-1.5">
                    <Label className="text-xs font-semibold">Attendance Thresholds (%)</Label>
                    <div className="grid grid-cols-4 gap-2">
                      <div><span className="text-[10px] text-muted-foreground">4w</span><Input type="number" className="h-8 text-sm" value={qaConfig?.attendanceThresholds?.fourWeeks || 75} onChange={e => setQaConfig({ ...qaConfig, attendanceThresholds: { ...qaConfig.attendanceThresholds, fourWeeks: +e.target.value } })} /></div>
                      <div><span className="text-[10px] text-muted-foreground">8w</span><Input type="number" className="h-8 text-sm" value={qaConfig?.attendanceThresholds?.eightWeeks || 75} onChange={e => setQaConfig({ ...qaConfig, attendanceThresholds: { ...qaConfig.attendanceThresholds, eightWeeks: +e.target.value } })} /></div>
                      <div><span className="text-[10px] text-muted-foreground">12w</span><Input type="number" className="h-8 text-sm" value={qaConfig?.attendanceThresholds?.twelveWeeks || 75} onChange={e => setQaConfig({ ...qaConfig, attendanceThresholds: { ...qaConfig.attendanceThresholds, twelveWeeks: +e.target.value } })} /></div>
                      <div><span className="text-[10px] text-muted-foreground">16w</span><Input type="number" className="h-8 text-sm" value={qaConfig?.attendanceThresholds?.sixteenWeeks || 75} onChange={e => setQaConfig({ ...qaConfig, attendanceThresholds: { ...qaConfig.attendanceThresholds, sixteenWeeks: +e.target.value } })} /></div>
                    </div>
                  </div>
                  <div className="flex items-center gap-2 pt-2">
                    <Checkbox checked={qaConfig?.globalNotifications?.emailAlerts} onCheckedChange={c => setQaConfig({ ...qaConfig, globalNotifications: { ...qaConfig.globalNotifications, emailAlerts: !!c } })} />
                    <Label className="text-sm cursor-pointer">Enable Email Alerts globally</Label>
                  </div>
                  <Button type="submit" disabled={qaSettingsLoading} className="w-full bg-slate-900 mt-2">{qaSettingsLoading ? "Saving..." : "Save Settings"}</Button>
                </form>
              </div>
              {/* Academic Management */}
              <div className="space-y-4">
                <h3 className="text-sm font-semibold flex items-center gap-2 text-orange-600"><AlertTriangle className="w-4 h-4" /> Academic Management</h3>
                <div className="p-4 bg-orange-50/10 border border-orange-200/20 rounded-lg">
                  <p className="text-xs text-muted-foreground mb-1">Execute system-wide processes. These are irreversible.</p>
                  <h4 className="text-sm font-semibold mb-2">Academic Year Promotion</h4>
                  <p className="text-xs text-muted-foreground mb-3">Moves students I→II→III→IV. 4th years become Alumni.</p>
                  <Button onClick={handleQaPromote} disabled={qaIsPromoting} variant="destructive" className="w-full">
                    <RefreshCcw className={`w-4 h-4 mr-2 ${qaIsPromoting ? "animate-spin" : ""}`} />
                    {qaIsPromoting ? "Promoting..." : "Promote All Students"}
                  </Button>
                </div>
              </div>
            </div>
          </DialogContent>
        </Dialog>

        {/* ── Backup Database Modal ── */}
        <Dialog open={isBackupModalOpen} onOpenChange={setIsBackupModalOpen}>
          <DialogContent className="max-w-2xl max-h-[85vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2 text-xl">
                <Database className="w-6 h-6 text-orange-500" />
                Database Backup & Archive
              </DialogTitle>
              <p className="text-sm text-muted-foreground">Securely backup system data and manage historical records.</p>
            </DialogHeader>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-4">
              {/* Manual Backup */}
              <div className="space-y-4">
                <h3 className="text-sm font-semibold flex items-center gap-2"><Database className="w-4 h-4" /> Manual Master Backup</h3>
                <p className="text-xs text-muted-foreground">Creates a snapshot in the MongoDB Archive collection.</p>
                <Button onClick={handleQaBackup} disabled={qaIsBackingUp} className="w-full bg-orange-600 hover:bg-orange-700">
                  {qaIsBackingUp ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Processing...</> : "Create Full Backup"}
                </Button>
                <Button variant="outline" onClick={handleQaExportJSON} className="w-full">
                  <Download className="w-4 h-4 mr-2" /> Export to Local JSON
                </Button>
              </div>
              {/* Restore Points */}
              <div className="space-y-4">
                <h3 className="text-sm font-semibold flex items-center gap-2"><History className="w-4 h-4" /> Restore Points</h3>
                <p className="text-xs text-muted-foreground">Restore is restricted to Super Admins.</p>
                <div className="space-y-2">
                  {[...Array(3)].map((_, i) => (
                    <div key={i} className="flex items-center justify-between p-2.5 border rounded-lg bg-muted/30">
                      <div>
                        <span className="text-sm font-semibold">Backup #{3 - i}</span>
                        <span className="text-xs text-muted-foreground ml-2">{new Date(Date.now() - i * 2592000000).toLocaleDateString()}</span>
                      </div>
                      <Button variant="ghost" size="sm" onClick={() => toast({ title: "Restricted", description: "Super Admin privileges required." })}>Restore</Button>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </DialogContent>
        </Dialog>

      </div>
    </AdminLayout>
  );
};

export default AdminDashboard;

import { useState, useRef } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import AdminLayout from "@/components/AdminLayout";
import { useAuth } from "@/contexts/AuthContext";
import { useEvents, Event } from "@/contexts/EventContext";
import { useToast } from "@/hooks/use-toast";
import { api } from "@/lib/api";
import {
    Plus,
    Calendar,
    Users,
    Edit,
    Trash2,
    Eye,
    RefreshCw,
    Loader2,
    MapPin,
    Clock,
    Star,
    DollarSign,
    Trophy,
    CalendarDays,
    Image,
    Link,
    X,
} from "lucide-react";

const AdminEvents = () => {
    const { userData } = useAuth();
    const { events, loading, error, addEvent, updateEvent, deleteEvent, fetchEvents } = useEvents();
    const { toast } = useToast();
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [isEditModalOpen, setIsEditModalOpen] = useState(false);
    const [isViewModalOpen, setIsViewModalOpen] = useState(false);
    const [selectedEvent, setSelectedEvent] = useState<Event | null>(null);
    const [searchTerm, setSearchTerm] = useState("");
    const [categoryFilter, setCategoryFilter] = useState("all");
    const imageInputRef = useRef<HTMLInputElement>(null);
    const editImageInputRef = useRef<HTMLInputElement>(null);

    // Registrations state for view modal
    const [registrations, setRegistrations] = useState<{
        sno: number;
        _id: string;
        collegeId: string;
        name: string;
        email: string;
        branch: string;
        year: string;
        section: string;
        paymentStatus: string;
    }[]>([]);
    const [loadingRegistrations, setLoadingRegistrations] = useState(false);

    const [editEvent, setEditEvent] = useState({
        event_id: "",
        title: "",
        category: "",
        date: "",
        endDate: "",
        time: "",
        endTime: "",
        venue: "",
        organizer: "",
        description: "",
        entryFee: "Free",
        maxParticipants: "",
        prizes: "",
        registrationDeadline: "",
        highlights: "",
        contactEmail: "",
        contactPhone: "",
        featured: false,
        posterImage: "",
        registrationLink: "",
        coordinatorRollNo: "",
    });

    const [newEvent, setNewEvent] = useState({
        event_id: "",
        title: "",
        category: "",
        date: "",
        endDate: "",
        time: "",
        endTime: "",
        venue: "",
        organizer: "",
        description: "",
        entryFee: "Free",
        maxParticipants: "",
        prizes: "",
        registrationDeadline: "",
        highlights: "",
        contactEmail: "",
        contactPhone: "",
        featured: false,
        posterImage: "",
        registrationLink: "",
        coordinatorRollNo: "",
    });

    // Handle image upload for create
    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = () => {
            setNewEvent({ ...newEvent, posterImage: reader.result as string });
        };
        reader.readAsDataURL(file);
        if (imageInputRef.current) imageInputRef.current.value = "";
    };

    // Handle image upload for edit
    const handleEditImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = () => {
            setEditEvent({ ...editEvent, posterImage: reader.result as string });
        };
        reader.readAsDataURL(file);
        if (editImageInputRef.current) editImageInputRef.current.value = "";
    };

    // Open edit modal with pre-populated data
    const handleOpenEdit = (event: Event) => {
        const dateObj = new Date(event.date);
        const endDateObj = event.endDate ? new Date(event.endDate) : null;
        const regDeadlineObj = event.registrationDeadline ? new Date(event.registrationDeadline) : null;

        setEditEvent({
            event_id: event.event_id,
            title: event.title,
            category: event.category,
            date: dateObj.toISOString().split("T")[0],
            endDate: endDateObj ? endDateObj.toISOString().split("T")[0] : "",
            time: dateObj.toTimeString().slice(0, 5),
            endTime: endDateObj ? endDateObj.toTimeString().slice(0, 5) : "",
            venue: event.venue,
            organizer: event.organizer,
            description: event.description || "",
            entryFee: event.entryFee || "Free",
            maxParticipants: event.maxParticipants ? String(event.maxParticipants) : "",
            prizes: event.prizes || "",
            registrationDeadline: regDeadlineObj ? regDeadlineObj.toISOString().split("T")[0] : "",
            highlights: event.highlights ? event.highlights.join(", ") : "",
            contactEmail: event.contactEmail || "",
            contactPhone: event.contactPhone || "",
            featured: event.featured || false,
            posterImage: event.posterImage || "",
            registrationLink: event.registrationLink || "",
            coordinatorRollNo: (event as any).coordinatorRollNo || "",
        });
        setSelectedEvent(event);
        setIsEditModalOpen(true);
    };

    // Save edited event
    const handleEditEvent = async () => {
        if (!selectedEvent) return;
        if (!editEvent.title || !editEvent.category || !editEvent.date || !editEvent.venue || !editEvent.organizer) {
            toast({
                title: "Missing Fields",
                description: "Please fill in Title, Category, Date, Venue, and Organizer.",
                variant: "destructive",
            });
            return;
        }

        let eventDate = editEvent.date;
        if (editEvent.time) eventDate = `${editEvent.date}T${editEvent.time}:00`;
        let eventEndDate = editEvent.endDate || editEvent.date;
        if (editEvent.endTime) eventEndDate = `${editEvent.endDate || editEvent.date}T${editEvent.endTime}:00`;

        const updates = {
            title: editEvent.title,
            category: editEvent.category,
            date: eventDate,
            endDate: eventEndDate,
            venue: editEvent.venue,
            organizer: editEvent.organizer,
            description: editEvent.description,
            entryFee: editEvent.entryFee || "Free",
            maxParticipants: editEvent.maxParticipants ? parseInt(editEvent.maxParticipants) : 0,
            prizes: editEvent.prizes,
            registrationDeadline: editEvent.registrationDeadline || undefined,
            highlights: editEvent.highlights ? editEvent.highlights.split(",").map((h: string) => h.trim()) : [],
            contactEmail: editEvent.contactEmail,
            contactPhone: editEvent.contactPhone,
            featured: editEvent.featured,
            posterImage: editEvent.posterImage || undefined,
            registrationLink: editEvent.registrationLink || undefined,
            coordinatorRollNo: editEvent.coordinatorRollNo || undefined,
        };

        try {
            setIsSubmitting(true);
            await updateEvent(selectedEvent._id, updates as any);
            toast({ title: "Success!", description: "Event updated successfully." });
            setIsEditModalOpen(false);
            setSelectedEvent(null);
        } catch (err: any) {
            toast({ title: "Error", description: err.message || "Failed to update event.", variant: "destructive" });
        } finally {
            setIsSubmitting(false);
        }
    };

    // Open view modal
    const handleOpenView = async (event: Event) => {
        setSelectedEvent(event);
        setIsViewModalOpen(true);
        setLoadingRegistrations(true);
        try {
            const res = await api.get(`/events/${event._id}/registrations`);
            setRegistrations(res.registrations || []);
        } catch (err) {
            console.error('Error fetching registrations:', err);
            setRegistrations([]);
        } finally {
            setLoadingRegistrations(false);
        }
    };

    const handleAddEvent = async () => {
        // Validate required fields
        if (!newEvent.event_id || !newEvent.title || !newEvent.category || !newEvent.date || !newEvent.venue || !newEvent.organizer) {
            toast({
                title: "Missing Fields",
                description: "Please fill in Event ID, Title, Category, Date, Venue, and Organizer.",
                variant: "destructive",
            });
            return;
        }

        // Combine date and time
        let eventDate = newEvent.date;
        if (newEvent.time) {
            eventDate = `${newEvent.date}T${newEvent.time}:00`;
        }

        let eventEndDate = newEvent.endDate || newEvent.date;
        if (newEvent.endTime) {
            eventEndDate = `${newEvent.endDate || newEvent.date}T${newEvent.endTime}:00`;
        }

        const eventData = {
            event_id: newEvent.event_id,
            title: newEvent.title,
            category: newEvent.category,
            date: eventDate,
            endDate: eventEndDate,
            venue: newEvent.venue,
            organizer: newEvent.organizer,
            description: newEvent.description,
            entryFee: newEvent.entryFee || "Free",
            maxParticipants: newEvent.maxParticipants ? parseInt(newEvent.maxParticipants) : 0,
            prizes: newEvent.prizes,
            registrationDeadline: newEvent.registrationDeadline || undefined,
            highlights: newEvent.highlights ? newEvent.highlights.split(",").map((h) => h.trim()) : [],
            contactEmail: newEvent.contactEmail,
            contactPhone: newEvent.contactPhone,
            featured: newEvent.featured,
            posterImage: newEvent.posterImage || undefined,
            registrationLink: newEvent.registrationLink || undefined,
            coordinatorRollNo: newEvent.coordinatorRollNo || undefined,
            status: "Open",
        };

        try {
            setIsSubmitting(true);
            console.log("Admin adding event to MongoDB:", eventData);
            await addEvent(eventData as any);

            toast({
                title: "Success!",
                description: "Event created successfully. Students can now see it.",
            });

            // Reset form
            setNewEvent({
                event_id: "",
                title: "",
                category: "",
                date: "",
                endDate: "",
                time: "",
                endTime: "",
                venue: "",
                organizer: "",
                description: "",
                entryFee: "Free",
                maxParticipants: "",
                prizes: "",
                registrationDeadline: "",
                highlights: "",
                contactEmail: "",
                contactPhone: "",
                featured: false,
                posterImage: "",
                registrationLink: "",
                coordinatorRollNo: "",
            });
            setIsAddModalOpen(false);
        } catch (err: any) {
            console.error("Error adding event:", err);
            toast({
                title: "Error",
                description: err.message || "Failed to create event. Please try again.",
                variant: "destructive",
            });
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleDeleteEvent = async (eventId: string) => {
        if (!confirm("Are you sure you want to delete this event?")) return;

        try {
            await deleteEvent(eventId);
            toast({
                title: "Success",
                description: "Event deleted successfully.",
            });
        } catch (err: any) {
            console.error("Error deleting event:", err);
            toast({
                title: "Error",
                description: err.message || "Failed to delete event.",
                variant: "destructive",
            });
        }
    };

    const getStatusBadge = (status: string) => {
        switch (status) {
            case "Open":
                return <Badge className="bg-green-500">Open</Badge>;
            case "Closed":
                return <Badge variant="destructive">Closed</Badge>;
            case "Completed":
                return <Badge variant="secondary">Completed</Badge>;
            case "Cancelled":
                return <Badge variant="destructive">Cancelled</Badge>;
            default:
                return <Badge variant="secondary">{status}</Badge>;
        }
    };

    const getCategoryBadge = (category: string) => {
        const colors: { [key: string]: string } = {
            Technical: "bg-blue-500",
            Cultural: "bg-purple-500",
            Sports: "bg-green-500",
            Workshop: "bg-orange-500",
            Seminar: "bg-cyan-500",
            Competition: "bg-red-500",
            Other: "bg-gray-500",
        };
        return <Badge className={colors[category] || "bg-gray-500"}>{category}</Badge>;
    };

    const formatDate = (dateString: string) => {
        return new Date(dateString).toLocaleDateString("en-IN", {
            day: "2-digit",
            month: "short",
            year: "numeric",
        });
    };

    const formatTime = (dateString: string) => {
        return new Date(dateString).toLocaleTimeString("en-IN", {
            hour: "2-digit",
            minute: "2-digit",
            hour12: true,
        });
    };

    // Filter events
    const filteredEvents = events.filter((event) => {
        const matchesSearch =
            event.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
            event.event_id.toLowerCase().includes(searchTerm.toLowerCase()) ||
            event.organizer.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesCategory =
            categoryFilter === "all" || event.category === categoryFilter;
        return matchesSearch && matchesCategory;
    });

    return (
        <AdminLayout>
            <div className="max-w-7xl mx-auto space-y-6">
                {/* Header */}
                <div className="flex items-center justify-between">
                    <div>
                        <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
                            <CalendarDays className="w-8 h-8 text-primary" />
                            Event Management
                        </h1>
                        <p className="text-muted-foreground mt-1">
                            Manage campus events and activities
                        </p>
                    </div>
                    <div className="flex items-center gap-2">
                        <Dialog open={isAddModalOpen} onOpenChange={setIsAddModalOpen}>
                            <DialogTrigger asChild>
                                <Button className="flex items-center gap-2 bg-primary hover:bg-primary/90">
                                    <Plus className="w-4 h-4" />
                                    Create Event
                                </Button>
                            </DialogTrigger>
                            <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
                                <DialogHeader>
                                    <DialogTitle className="text-xl font-bold flex items-center gap-2">
                                        <CalendarDays className="w-6 h-6 text-primary" />
                                        Create New Event
                                    </DialogTitle>
                                </DialogHeader>
                                <div className="space-y-5 py-4">
                                    {/* Event ID and Title */}
                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold">
                                                Event ID <span className="text-destructive">*</span>
                                            </Label>
                                            <Input
                                                value={newEvent.event_id}
                                                onChange={(e) =>
                                                    setNewEvent({ ...newEvent, event_id: e.target.value.toUpperCase() })
                                                }
                                                placeholder="e.g., HACKATHON2025"
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold">
                                                Event Title <span className="text-destructive">*</span>
                                            </Label>
                                            <Input
                                                value={newEvent.title}
                                                onChange={(e) =>
                                                    setNewEvent({ ...newEvent, title: e.target.value })
                                                }
                                                placeholder="e.g., CodeStorm Hackathon"
                                            />
                                        </div>
                                    </div>

                                    {/* Category and Organizer */}
                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold">
                                                Category <span className="text-destructive">*</span>
                                            </Label>
                                            <Select
                                                value={newEvent.category}
                                                onValueChange={(value) =>
                                                    setNewEvent({ ...newEvent, category: value })
                                                }
                                            >
                                                <SelectTrigger>
                                                    <SelectValue placeholder="Select category" />
                                                </SelectTrigger>
                                                <SelectContent>
                                                    <SelectItem value="Technical">Technical</SelectItem>
                                                    <SelectItem value="Cultural">Cultural</SelectItem>
                                                    <SelectItem value="Sports">Sports</SelectItem>
                                                    <SelectItem value="Workshop">Workshop</SelectItem>
                                                    <SelectItem value="Seminar">Seminar</SelectItem>
                                                    <SelectItem value="Competition">Competition</SelectItem>
                                                    <SelectItem value="Other">Other</SelectItem>
                                                </SelectContent>
                                            </Select>
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold">
                                                Organizer <span className="text-destructive">*</span>
                                            </Label>
                                            <Input
                                                value={newEvent.organizer}
                                                onChange={(e) =>
                                                    setNewEvent({ ...newEvent, organizer: e.target.value })
                                                }
                                                placeholder="e.g., IEEE Student Branch"
                                            />
                                        </div>
                                    </div>

                                    {/* Venue */}
                                    <div className="space-y-2">
                                        <Label className="text-sm font-semibold">
                                            Venue <span className="text-destructive">*</span>
                                        </Label>
                                        <Input
                                            value={newEvent.venue}
                                            onChange={(e) =>
                                                setNewEvent({ ...newEvent, venue: e.target.value })
                                            }
                                            placeholder="e.g., Main Auditorium, CS Block"
                                        />
                                    </div>

                                    {/* Student Coordinator */}
                                    <div className="space-y-2">
                                        <Label className="text-sm font-semibold">
                                            Student Coordinator (Roll Number) <span className="text-destructive">*</span>
                                        </Label>
                                        <Input
                                            value={newEvent.coordinatorRollNo}
                                            onChange={(e) =>
                                                setNewEvent({ ...newEvent, coordinatorRollNo: e.target.value.toUpperCase() })
                                            }
                                            placeholder="e.g., 22B81A0565"
                                        />
                                        <p className="text-xs text-muted-foreground">This student can post updates on the event feed</p>
                                    </div>

                                    {/* Dates and Times */}
                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold flex items-center gap-2">
                                                <Calendar className="w-4 h-4" />
                                                Start Date & Time <span className="text-destructive">*</span>
                                            </Label>
                                            <div className="flex gap-2">
                                                <Input
                                                    type="date"
                                                    value={newEvent.date}
                                                    onChange={(e) =>
                                                        setNewEvent({ ...newEvent, date: e.target.value })
                                                    }
                                                    min={new Date().toISOString().split("T")[0]}
                                                    className="flex-1"
                                                />
                                                <Input
                                                    type="time"
                                                    value={newEvent.time}
                                                    onChange={(e) =>
                                                        setNewEvent({ ...newEvent, time: e.target.value })
                                                    }
                                                    className="w-32"
                                                />
                                            </div>
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold flex items-center gap-2">
                                                <Clock className="w-4 h-4" />
                                                End Date & Time
                                            </Label>
                                            <div className="flex gap-2">
                                                <Input
                                                    type="date"
                                                    value={newEvent.endDate}
                                                    onChange={(e) =>
                                                        setNewEvent({ ...newEvent, endDate: e.target.value })
                                                    }
                                                    min={newEvent.date || new Date().toISOString().split("T")[0]}
                                                    className="flex-1"
                                                />
                                                <Input
                                                    type="time"
                                                    value={newEvent.endTime}
                                                    onChange={(e) =>
                                                        setNewEvent({ ...newEvent, endTime: e.target.value })
                                                    }
                                                    className="w-32"
                                                />
                                            </div>
                                        </div>
                                    </div>

                                    {/* Description */}
                                    <div className="space-y-2">
                                        <Label className="text-sm font-semibold">Event Description</Label>
                                        <Textarea
                                            value={newEvent.description}
                                            onChange={(e) =>
                                                setNewEvent({ ...newEvent, description: e.target.value })
                                            }
                                            placeholder="Share agenda, speakers, eligibility..."
                                            rows={3}
                                        />
                                    </div>

                                    {/* Entry Fee, Max Participants, Prizes */}
                                    <div className="grid grid-cols-3 gap-4">
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold">Entry Fee</Label>
                                            <Input
                                                value={newEvent.entryFee}
                                                onChange={(e) =>
                                                    setNewEvent({ ...newEvent, entryFee: e.target.value })
                                                }
                                                placeholder="Free, ₹200"
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold">Max Participants</Label>
                                            <Input
                                                type="number"
                                                value={newEvent.maxParticipants}
                                                onChange={(e) =>
                                                    setNewEvent({ ...newEvent, maxParticipants: e.target.value })
                                                }
                                                placeholder="0 = unlimited"
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold flex items-center gap-1">
                                                <Trophy className="w-4 h-4" />
                                                Prizes
                                            </Label>
                                            <Input
                                                value={newEvent.prizes}
                                                onChange={(e) =>
                                                    setNewEvent({ ...newEvent, prizes: e.target.value })
                                                }
                                                placeholder="₹50,000 Prize Pool"
                                            />
                                        </div>
                                    </div>

                                    {/* Registration Deadline and Highlights */}
                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold">Registration Deadline</Label>
                                            <Input
                                                type="date"
                                                value={newEvent.registrationDeadline}
                                                onChange={(e) =>
                                                    setNewEvent({ ...newEvent, registrationDeadline: e.target.value })
                                                }
                                                max={newEvent.date}
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold">Highlights</Label>
                                            <Input
                                                value={newEvent.highlights}
                                                onChange={(e) =>
                                                    setNewEvent({ ...newEvent, highlights: e.target.value })
                                                }
                                                placeholder="Free Food, Networking, Certificates"
                                            />
                                            <p className="text-xs text-muted-foreground">Separate with commas</p>
                                        </div>
                                    </div>

                                    {/* Registration Link - only shown when deadline is entered */}
                                    {newEvent.registrationDeadline && (
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold flex items-center gap-2">
                                                <Link className="w-4 h-4" />
                                                Registration Link
                                            </Label>
                                            <Input
                                                value={newEvent.registrationLink}
                                                onChange={(e) =>
                                                    setNewEvent({ ...newEvent, registrationLink: e.target.value })
                                                }
                                                placeholder="https://forms.google.com/..."
                                            />
                                            <p className="text-xs text-muted-foreground">External registration form URL (optional)</p>
                                        </div>
                                    )}

                                    {/* Event Poster Image Upload */}
                                    <div className="space-y-2">
                                        <Label className="text-sm font-semibold flex items-center gap-2">
                                            <Image className="w-4 h-4" />
                                            Event Poster Image
                                        </Label>
                                        {newEvent.posterImage ? (
                                            <div className="relative rounded-lg overflow-hidden border border-border">
                                                <img
                                                    src={newEvent.posterImage}
                                                    alt="Event poster preview"
                                                    className="w-full h-48 object-cover"
                                                />
                                                <Button
                                                    type="button"
                                                    variant="destructive"
                                                    size="icon"
                                                    className="absolute top-2 right-2 w-8 h-8"
                                                    onClick={() => setNewEvent({ ...newEvent, posterImage: "" })}
                                                >
                                                    <X className="w-4 h-4" />
                                                </Button>
                                            </div>
                                        ) : (
                                            <div
                                                className="border-2 border-dashed border-muted-foreground/30 rounded-lg p-8 text-center cursor-pointer hover:border-primary/50 transition-colors"
                                                onClick={() => imageInputRef.current?.click()}
                                            >
                                                <Image className="w-10 h-10 mx-auto text-muted-foreground mb-2" />
                                                <p className="text-sm text-muted-foreground">Click to upload event poster</p>
                                                <p className="text-xs text-muted-foreground/60 mt-1">PNG, JPG, WEBP (recommended: 1200×600)</p>
                                            </div>
                                        )}
                                        <input
                                            ref={imageInputRef}
                                            type="file"
                                            accept="image/*"
                                            className="hidden"
                                            onChange={handleImageUpload}
                                        />
                                    </div>

                                    {/* Contact Info */}
                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold">Contact Email</Label>
                                            <Input
                                                type="email"
                                                value={newEvent.contactEmail}
                                                onChange={(e) =>
                                                    setNewEvent({ ...newEvent, contactEmail: e.target.value })
                                                }
                                                placeholder="events@college.ac.in"
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label className="text-sm font-semibold">Contact Phone</Label>
                                            <Input
                                                value={newEvent.contactPhone}
                                                onChange={(e) =>
                                                    setNewEvent({ ...newEvent, contactPhone: e.target.value })
                                                }
                                                placeholder="+91 9876543210"
                                            />
                                        </div>
                                    </div>

                                    {/* Featured Toggle */}
                                    <div className="flex items-center justify-between rounded-lg border border-border bg-muted/20 p-3">
                                        <div>
                                            <p className="text-sm font-medium text-foreground">
                                                Featured Event
                                            </p>
                                            <p className="text-xs text-muted-foreground">
                                                Featured events are highlighted on the student dashboard
                                            </p>
                                        </div>
                                        <Switch
                                            checked={newEvent.featured}
                                            onCheckedChange={(checked) =>
                                                setNewEvent({ ...newEvent, featured: checked })
                                            }
                                        />
                                    </div>

                                    {/* Form Actions */}
                                    <div className="flex justify-end gap-3 pt-4 border-t">
                                        <Button
                                            variant="outline"
                                            onClick={() => setIsAddModalOpen(false)}
                                            disabled={isSubmitting}
                                        >
                                            Cancel
                                        </Button>
                                        <Button
                                            onClick={handleAddEvent}
                                            disabled={isSubmitting}
                                            className="min-w-[140px]"
                                        >
                                            {isSubmitting ? (
                                                <>
                                                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                                    Creating...
                                                </>
                                            ) : (
                                                <>
                                                    <Plus className="w-4 h-4 mr-2" />
                                                    Create Event
                                                </>
                                            )}
                                        </Button>
                                    </div>
                                </div>
                            </DialogContent>
                        </Dialog>
                    </div>
                </div>

                {/* Stats Cards*/}
                <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <Card>
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-lg bg-primary/10 flex items-center justify-center">
                                <CalendarDays className="w-6 h-6 text-primary" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Total Events</p>
                                <p className="text-2xl font-bold">{events.length}</p>
                            </div>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-lg bg-green-500/10 flex items-center justify-center">
                                <Star className="w-6 h-6 text-green-500" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Open Events</p>
                                <p className="text-2xl font-bold">
                                    {events.filter((e) => e.status === "Open").length}
                                </p>
                            </div>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-lg bg-yellow-500/10 flex items-center justify-center">
                                <Star className="w-6 h-6 text-yellow-500 fill-current" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Featured</p>
                                <p className="text-2xl font-bold">
                                    {events.filter((e) => e.featured).length}
                                </p>
                            </div>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-lg bg-blue-500/10 flex items-center justify-center">
                                <Users className="w-6 h-6 text-blue-500" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Total Registrations</p>
                                <p className="text-2xl font-bold">
                                    {events.reduce((sum, e) => sum + (e.registeredParticipants || 0), 0)}
                                </p>
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* Filters */}
                <Card>
                    <CardContent className="p-4">
                        <div className="flex flex-col md:flex-row gap-4">
                            <div className="flex-1">
                                <Input
                                    placeholder="Search events by title, ID, or organizer..."
                                    value={searchTerm}
                                    onChange={(e) => setSearchTerm(e.target.value)}
                                    className="w-full"
                                />
                            </div>
                            <Select value={categoryFilter} onValueChange={setCategoryFilter}>
                                <SelectTrigger className="w-full md:w-[200px]">
                                    <SelectValue placeholder="Category" />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">All Categories</SelectItem>
                                    <SelectItem value="Technical">Technical</SelectItem>
                                    <SelectItem value="Cultural">Cultural</SelectItem>
                                    <SelectItem value="Sports">Sports</SelectItem>
                                    <SelectItem value="Workshop">Workshop</SelectItem>
                                    <SelectItem value="Seminar">Seminar</SelectItem>
                                    <SelectItem value="Competition">Competition</SelectItem>
                                    <SelectItem value="Other">Other</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </CardContent>
                </Card>

                {/* Error Display */}
                {error && (
                    <Card className="border-destructive bg-destructive/10">
                        <CardContent className="p-4 text-destructive">
                            {error}
                        </CardContent>
                    </Card>
                )}

                {/* Loading State */}
                {loading && events.length === 0 && (
                    <Card>
                        <CardContent className="p-12 text-center">
                            <Loader2 className="w-12 h-12 text-primary mx-auto mb-4 animate-spin" />
                            <p className="text-muted-foreground">Loading events...</p>
                        </CardContent>
                    </Card>
                )}

                {/* Events List */}
                {!loading && filteredEvents.length === 0 ? (
                    <Card>
                        <CardContent className="p-12 text-center">
                            <CalendarDays className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                            <h3 className="text-lg font-medium text-foreground mb-2">
                                No events found
                            </h3>
                            <p className="text-muted-foreground mb-4">
                                {events.length === 0
                                    ? "Start by creating your first event."
                                    : "Try adjusting your search or filters."}
                            </p>
                            <Button onClick={() => setIsAddModalOpen(true)}>
                                <Plus className="w-4 h-4 mr-2" />
                                Create First Event
                            </Button>
                        </CardContent>
                    </Card>
                ) : (
                    <div className="grid gap-4">
                        {filteredEvents.map((event) => (
                            <Card key={event._id} className="hover:shadow-lg transition-shadow">
                                <CardContent className="p-6">
                                    <div className="flex items-start justify-between">
                                        <div className="flex items-start gap-4">
                                            {event.posterImage ? (
                                                <div className="w-20 h-20 rounded-lg overflow-hidden shrink-0 border border-border shadow-sm">
                                                    <img
                                                        src={event.posterImage}
                                                        alt={event.title}
                                                        className="w-full h-full object-cover"
                                                    />
                                                </div>
                                            ) : (
                                                <div className="w-16 h-16 bg-primary/10 rounded-lg flex items-center justify-center shrink-0">
                                                    <CalendarDays className="w-8 h-8 text-primary" />
                                                </div>
                                            )}
                                            <div className="space-y-2">
                                                <div className="flex items-center gap-2">
                                                    <h3 className="text-xl font-bold text-foreground">
                                                        {event.title}
                                                    </h3>
                                                    {event.featured && (
                                                        <Star className="w-5 h-5 text-yellow-500 fill-current" />
                                                    )}
                                                </div>
                                                <div className="flex items-center gap-2 flex-wrap">
                                                    <Badge variant="outline">{event.event_id}</Badge>
                                                    {getCategoryBadge(event.category)}
                                                    {getStatusBadge(event.status)}
                                                </div>
                                                <p className="text-muted-foreground text-sm line-clamp-2">
                                                    {event.description}
                                                </p>
                                                <div className="flex flex-wrap items-center gap-4 text-sm text-muted-foreground">
                                                    <span className="flex items-center gap-1">
                                                        <MapPin className="w-4 h-4" />
                                                        {event.venue}
                                                    </span>
                                                    <span className="flex items-center gap-1">
                                                        <Calendar className="w-4 h-4" />
                                                        {formatDate(event.date)}
                                                    </span>
                                                    <span className="flex items-center gap-1">
                                                        <Clock className="w-4 h-4" />
                                                        {formatTime(event.date)}
                                                    </span>
                                                    <span className="flex items-center gap-1">
                                                        <Users className="w-4 h-4" />
                                                        {event.registeredParticipants || 0}
                                                        {event.maxParticipants > 0 && `/${event.maxParticipants}`} registered
                                                    </span>
                                                    <span className="flex items-center gap-1">
                                                        <DollarSign className="w-4 h-4" />
                                                        {event.entryFee}
                                                    </span>
                                                </div>
                                                <p className="text-sm text-muted-foreground">
                                                    <strong>Organizer:</strong> {event.organizer}
                                                </p>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <Button variant="outline" size="icon" title="View Details" onClick={() => handleOpenView(event)}>
                                                <Eye className="w-4 h-4" />
                                            </Button>
                                            <Button variant="outline" size="icon" title="Edit Event" onClick={() => handleOpenEdit(event)}>
                                                <Edit className="w-4 h-4" />
                                            </Button>
                                            <Button
                                                variant="destructive"
                                                size="icon"
                                                title="Delete Event"
                                                onClick={() => handleDeleteEvent(event._id)}
                                            >
                                                <Trash2 className="w-4 h-4" />
                                            </Button>
                                        </div>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                )}
            </div>

            {/* ═══ VIEW EVENT MODAL ═══ */}
            <Dialog open={isViewModalOpen} onOpenChange={setIsViewModalOpen}>
                <DialogContent className="max-w-2xl max-h-[85vh] overflow-y-auto">
                    <DialogHeader>
                        <DialogTitle className="text-xl font-bold flex items-center gap-2">
                            <CalendarDays className="w-5 h-5 text-primary" />
                            {selectedEvent?.title}
                        </DialogTitle>
                        {selectedEvent && (
                            <div className="flex items-center gap-2 mt-1 text-primary font-medium text-sm">
                                {selectedEvent.event_id} · {selectedEvent.category}
                            </div>
                        )}
                    </DialogHeader>

                    {selectedEvent && (
                        <div className="space-y-4 py-2">
                            {/* Poster */}
                            {selectedEvent.posterImage && (
                                <div className="rounded-lg overflow-hidden border border-border">
                                    <img src={selectedEvent.posterImage} alt={selectedEvent.title} className="w-full h-48 object-cover" />
                                </div>
                            )}

                            {/* Summary stat cards */}
                            <div className="grid grid-cols-3 gap-3">
                                <div className="p-3 rounded-lg bg-muted/50 text-center">
                                    <p className="text-xs text-muted-foreground">Status</p>
                                    <div className="mt-1">{getStatusBadge(selectedEvent.status)}</div>
                                </div>
                                <div className="p-3 rounded-lg bg-muted/50 text-center">
                                    <p className="text-xs text-muted-foreground">Entry Fee</p>
                                    <p className="font-semibold text-sm mt-0.5">{selectedEvent.entryFee || "Free"}</p>
                                </div>
                                <div className="p-3 rounded-lg bg-muted/50 text-center">
                                    <p className="text-xs text-muted-foreground">Registered</p>
                                    <p className="font-semibold text-sm mt-0.5">
                                        {selectedEvent.registeredParticipants || 0}
                                        {selectedEvent.maxParticipants > 0 ? ` / ${selectedEvent.maxParticipants}` : ""}
                                    </p>
                                </div>
                            </div>

                            {/* Description */}
                            {selectedEvent.description && (
                                <div className="p-3 rounded-lg bg-muted/30 border">
                                    <p className="text-xs text-muted-foreground font-medium mb-1">Description</p>
                                    <p className="text-sm">{selectedEvent.description}</p>
                                </div>
                            )}

                            {/* Details grid */}
                            <div className="grid grid-cols-2 gap-3">
                                <div className="p-3 rounded-lg bg-muted/30 border">
                                    <p className="text-xs text-muted-foreground font-medium mb-1">Date</p>
                                    <p className="text-sm flex items-center gap-1">
                                        <Calendar className="w-3 h-3" />
                                        {formatDate(selectedEvent.date)}
                                        {selectedEvent.endDate && selectedEvent.endDate !== selectedEvent.date
                                            ? ` — ${formatDate(selectedEvent.endDate)}`
                                            : ""}
                                    </p>
                                </div>
                                <div className="p-3 rounded-lg bg-muted/30 border">
                                    <p className="text-xs text-muted-foreground font-medium mb-1">Time</p>
                                    <p className="text-sm flex items-center gap-1">
                                        <Clock className="w-3 h-3" />
                                        {formatTime(selectedEvent.date)}
                                    </p>
                                </div>
                                <div className="p-3 rounded-lg bg-muted/30 border">
                                    <p className="text-xs text-muted-foreground font-medium mb-1">Venue</p>
                                    <p className="text-sm flex items-center gap-1">
                                        <MapPin className="w-3 h-3" /> {selectedEvent.venue}
                                    </p>
                                </div>
                                <div className="p-3 rounded-lg bg-muted/30 border">
                                    <p className="text-xs text-muted-foreground font-medium mb-1">Organizer</p>
                                    <p className="text-sm">{selectedEvent.organizer}</p>
                                </div>
                                {selectedEvent.prizes && (
                                    <div className="p-3 rounded-lg bg-muted/30 border">
                                        <p className="text-xs text-muted-foreground font-medium mb-1">Prizes</p>
                                        <p className="text-sm flex items-center gap-1">
                                            <Trophy className="w-3 h-3" /> {selectedEvent.prizes}
                                        </p>
                                    </div>
                                )}
                                {selectedEvent.registrationDeadline && (
                                    <div className="p-3 rounded-lg bg-muted/30 border">
                                        <p className="text-xs text-muted-foreground font-medium mb-1">Reg. Deadline</p>
                                        <p className="text-sm font-medium text-destructive">
                                            {formatDate(selectedEvent.registrationDeadline)}
                                        </p>
                                    </div>
                                )}
                            </div>

                            {/* Badges & Featured */}
                            <div className="flex items-center gap-2 flex-wrap">
                                <Badge variant="outline">{selectedEvent.event_id}</Badge>
                                {getCategoryBadge(selectedEvent.category)}
                                {getStatusBadge(selectedEvent.status)}
                                {selectedEvent.featured && (
                                    <Badge className="bg-yellow-500">
                                        <Star className="w-3 h-3 mr-1 fill-current" /> Featured
                                    </Badge>
                                )}
                            </div>

                            {/* Highlights */}
                            {selectedEvent.highlights && selectedEvent.highlights.length > 0 && (
                                <div className="p-3 rounded-lg bg-muted/30 border">
                                    <p className="text-xs text-muted-foreground font-medium mb-1.5">Highlights</p>
                                    <div className="flex flex-wrap gap-1">
                                        {selectedEvent.highlights.map((h, i) => (
                                            <Badge key={i} variant="outline" className="text-xs">{h}</Badge>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* Contact Info */}
                            {(selectedEvent.contactEmail || selectedEvent.contactPhone) && (
                                <div className="grid grid-cols-2 gap-3">
                                    {selectedEvent.contactEmail && (
                                        <div className="p-3 rounded-lg bg-muted/30 border">
                                            <p className="text-xs text-muted-foreground font-medium mb-1">Contact Email</p>
                                            <p className="text-sm">{selectedEvent.contactEmail}</p>
                                        </div>
                                    )}
                                    {selectedEvent.contactPhone && (
                                        <div className="p-3 rounded-lg bg-muted/30 border">
                                            <p className="text-xs text-muted-foreground font-medium mb-1">Contact Phone</p>
                                            <p className="text-sm">{selectedEvent.contactPhone}</p>
                                        </div>
                                    )}
                                </div>
                            )}

                            {/* Registered Students Table */}
                            <div>
                                <h3 className="font-semibold text-sm flex items-center gap-2 mb-3">
                                    <Users className="w-4 h-4 text-primary" />
                                    Registered Students ({registrations.length})
                                </h3>

                                {loadingRegistrations ? (
                                    <div className="py-8 text-center">
                                        <Loader2 className="w-6 h-6 animate-spin mx-auto mb-2 text-primary" />
                                        <p className="text-sm text-muted-foreground">Loading registrations...</p>
                                    </div>
                                ) : registrations.length === 0 ? (
                                    <div className="py-8 text-center border rounded-lg bg-muted/20">
                                        <Users className="w-10 h-10 mx-auto mb-2 text-muted-foreground/40" />
                                        <p className="text-sm text-muted-foreground">No students have registered yet</p>
                                    </div>
                                ) : (
                                    <div className="border rounded-lg overflow-hidden">
                                        <table className="w-full text-sm">
                                            <thead>
                                                <tr className="bg-muted/50 border-b">
                                                    <th className="text-left py-2.5 px-3 font-medium text-muted-foreground">#</th>
                                                    <th className="text-left py-2.5 px-3 font-medium text-muted-foreground">Student</th>
                                                    <th className="text-left py-2.5 px-3 font-medium text-muted-foreground">Roll No</th>
                                                    <th className="text-left py-2.5 px-3 font-medium text-muted-foreground">Branch</th>
                                                    <th className="text-left py-2.5 px-3 font-medium text-muted-foreground">Payment</th>
                                                </tr>
                                            </thead>
                                            <tbody>
                                                {registrations.map((reg) => (
                                                    <tr key={reg._id || reg.sno} className="border-b last:border-0 hover:bg-muted/30 transition-colors">
                                                        <td className="py-2.5 px-3 text-muted-foreground">{reg.sno}</td>
                                                        <td className="py-2.5 px-3">
                                                            <div className="flex items-center gap-2">
                                                                <div className="w-7 h-7 rounded-full bg-primary/10 flex items-center justify-center text-xs font-semibold text-primary">
                                                                    {reg.name?.charAt(0) || "?"}
                                                                </div>
                                                                <div>
                                                                    <span className="font-medium">{reg.name || "Unknown"}</span>
                                                                    {reg.email && (
                                                                        <p className="text-xs text-muted-foreground">{reg.email}</p>
                                                                    )}
                                                                </div>
                                                            </div>
                                                        </td>
                                                        <td className="py-2.5 px-3 font-mono text-xs">{reg.collegeId}</td>
                                                        <td className="py-2.5 px-3">{reg.branch || "—"}</td>
                                                        <td className="py-2.5 px-3">
                                                            <Badge className={reg.paymentStatus === 'Free' ? 'bg-blue-500' : 'bg-green-500'}>
                                                                {reg.paymentStatus === 'Free' ? 'Free' : '✓ Paid'}
                                                            </Badge>
                                                        </td>
                                                    </tr>
                                                ))}
                                            </tbody>
                                        </table>
                                    </div>
                                )}
                            </div>
                        </div>
                    )}
                </DialogContent>
            </Dialog>

            {/* Edit Event Modal */}
            <Dialog open={isEditModalOpen} onOpenChange={setIsEditModalOpen}>
                <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
                    <DialogHeader>
                        <DialogTitle className="text-xl font-bold flex items-center gap-2">
                            <Edit className="w-6 h-6 text-primary" />
                            Edit Event
                        </DialogTitle>
                    </DialogHeader>
                    <div className="space-y-5 py-4">
                        {/* Event ID (read-only) and Title */}
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">Event ID</Label>
                                <Input value={editEvent.event_id} disabled className="bg-muted" />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">Event Title <span className="text-destructive">*</span></Label>
                                <Input value={editEvent.title} onChange={(e) => setEditEvent({ ...editEvent, title: e.target.value })} />
                            </div>
                        </div>

                        {/* Category and Organizer */}
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">Category <span className="text-destructive">*</span></Label>
                                <Select value={editEvent.category} onValueChange={(value) => setEditEvent({ ...editEvent, category: value })}>
                                    <SelectTrigger><SelectValue placeholder="Select category" /></SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="Technical">Technical</SelectItem>
                                        <SelectItem value="Cultural">Cultural</SelectItem>
                                        <SelectItem value="Sports">Sports</SelectItem>
                                        <SelectItem value="Workshop">Workshop</SelectItem>
                                        <SelectItem value="Seminar">Seminar</SelectItem>
                                        <SelectItem value="Competition">Competition</SelectItem>
                                        <SelectItem value="Other">Other</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">Organizer <span className="text-destructive">*</span></Label>
                                <Input value={editEvent.organizer} onChange={(e) => setEditEvent({ ...editEvent, organizer: e.target.value })} />
                            </div>
                        </div>

                        {/* Venue */}
                        <div className="space-y-2">
                            <Label className="text-sm font-semibold">Venue <span className="text-destructive">*</span></Label>
                            <Input value={editEvent.venue} onChange={(e) => setEditEvent({ ...editEvent, venue: e.target.value })} />
                        </div>

                        {/* Student Coordinator */}
                        <div className="space-y-2">
                            <Label className="text-sm font-semibold">Student Coordinator (Roll Number)</Label>
                            <Input
                                value={editEvent.coordinatorRollNo}
                                onChange={(e) => setEditEvent({ ...editEvent, coordinatorRollNo: e.target.value.toUpperCase() })}
                                placeholder="e.g., 22B81A0565"
                            />
                            <p className="text-xs text-muted-foreground">This student can post updates on the event feed</p>
                        </div>

                        {/* Dates and Times */}
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold flex items-center gap-2"><Calendar className="w-4 h-4" /> Start Date & Time <span className="text-destructive">*</span></Label>
                                <div className="flex gap-2">
                                    <Input type="date" value={editEvent.date} onChange={(e) => setEditEvent({ ...editEvent, date: e.target.value })} className="flex-1" />
                                    <Input type="time" value={editEvent.time} onChange={(e) => setEditEvent({ ...editEvent, time: e.target.value })} className="w-32" />
                                </div>
                            </div>
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold flex items-center gap-2"><Clock className="w-4 h-4" /> End Date & Time</Label>
                                <div className="flex gap-2">
                                    <Input type="date" value={editEvent.endDate} onChange={(e) => setEditEvent({ ...editEvent, endDate: e.target.value })} className="flex-1" />
                                    <Input type="time" value={editEvent.endTime} onChange={(e) => setEditEvent({ ...editEvent, endTime: e.target.value })} className="w-32" />
                                </div>
                            </div>
                        </div>

                        {/* Description */}
                        <div className="space-y-2">
                            <Label className="text-sm font-semibold">Description</Label>
                            <Textarea value={editEvent.description} onChange={(e) => setEditEvent({ ...editEvent, description: e.target.value })} rows={3} />
                        </div>

                        {/* Entry Fee, Max Participants, Prizes */}
                        <div className="grid grid-cols-3 gap-4">
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">Entry Fee</Label>
                                <Input value={editEvent.entryFee} onChange={(e) => setEditEvent({ ...editEvent, entryFee: e.target.value })} />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">Max Participants</Label>
                                <Input type="number" value={editEvent.maxParticipants} onChange={(e) => setEditEvent({ ...editEvent, maxParticipants: e.target.value })} placeholder="0 = unlimited" />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold flex items-center gap-1"><Trophy className="w-4 h-4" /> Prizes</Label>
                                <Input value={editEvent.prizes} onChange={(e) => setEditEvent({ ...editEvent, prizes: e.target.value })} />
                            </div>
                        </div>

                        {/* Registration Deadline and Highlights */}
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">Registration Deadline</Label>
                                <Input type="date" value={editEvent.registrationDeadline} onChange={(e) => setEditEvent({ ...editEvent, registrationDeadline: e.target.value })} />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">Highlights</Label>
                                <Input value={editEvent.highlights} onChange={(e) => setEditEvent({ ...editEvent, highlights: e.target.value })} placeholder="Free Food, Networking, Certificates" />
                                <p className="text-xs text-muted-foreground">Separate with commas</p>
                            </div>
                        </div>

                        {/* Registration Link */}
                        {editEvent.registrationDeadline && (
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold flex items-center gap-2"><Link className="w-4 h-4" /> Registration Link</Label>
                                <Input value={editEvent.registrationLink} onChange={(e) => setEditEvent({ ...editEvent, registrationLink: e.target.value })} placeholder="https://forms.google.com/..." />
                            </div>
                        )}

                        {/* Poster Image */}
                        <div className="space-y-2">
                            <Label className="text-sm font-semibold flex items-center gap-2"><Image className="w-4 h-4" /> Event Poster Image</Label>
                            {editEvent.posterImage ? (
                                <div className="relative rounded-lg overflow-hidden border border-border">
                                    <img src={editEvent.posterImage} alt="Event poster" className="w-full h-48 object-cover" />
                                    <Button type="button" variant="destructive" size="icon" className="absolute top-2 right-2 w-8 h-8" onClick={() => setEditEvent({ ...editEvent, posterImage: "" })}>
                                        <X className="w-4 h-4" />
                                    </Button>
                                </div>
                            ) : (
                                <div className="border-2 border-dashed border-muted-foreground/30 rounded-lg p-8 text-center cursor-pointer hover:border-primary/50 transition-colors" onClick={() => editImageInputRef.current?.click()}>
                                    <Image className="w-10 h-10 mx-auto text-muted-foreground mb-2" />
                                    <p className="text-sm text-muted-foreground">Click to upload event poster</p>
                                </div>
                            )}
                            <input ref={editImageInputRef} type="file" accept="image/*" className="hidden" onChange={handleEditImageUpload} />
                        </div>

                        {/* Contact Info */}
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">Contact Email</Label>
                                <Input type="email" value={editEvent.contactEmail} onChange={(e) => setEditEvent({ ...editEvent, contactEmail: e.target.value })} />
                            </div>
                            <div className="space-y-2">
                                <Label className="text-sm font-semibold">Contact Phone</Label>
                                <Input value={editEvent.contactPhone} onChange={(e) => setEditEvent({ ...editEvent, contactPhone: e.target.value })} />
                            </div>
                        </div>

                        {/* Featured Toggle */}
                        <div className="flex items-center justify-between rounded-lg border border-border bg-muted/20 p-3">
                            <div>
                                <p className="text-sm font-medium text-foreground">Featured Event</p>
                                <p className="text-xs text-muted-foreground">Featured events are highlighted on the student dashboard</p>
                            </div>
                            <Switch checked={editEvent.featured} onCheckedChange={(checked) => setEditEvent({ ...editEvent, featured: checked })} />
                        </div>

                        {/* Actions */}
                        <div className="flex justify-end gap-3 pt-4 border-t">
                            <Button variant="outline" onClick={() => setIsEditModalOpen(false)} disabled={isSubmitting}>Cancel</Button>
                            <Button onClick={handleEditEvent} disabled={isSubmitting} className="min-w-[140px]">
                                {isSubmitting ? (<><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Saving...</>) : (<><Edit className="w-4 h-4 mr-2" /> Save Changes</>)}
                            </Button>
                        </div>
                    </div>
                </DialogContent>
            </Dialog>
        </AdminLayout>
    );
};

export default AdminEvents;

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
    AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import AdminLayout from "@/components/AdminLayout";
import { useAuth } from "@/contexts/AuthContext";
import { useExams, Exam } from "@/contexts/ExamContext";
import { useToast } from "@/hooks/use-toast";
import {
    Calendar,
    Clock,
    RefreshCw,
    Loader2,
    Search,
    Plus,
    Trash2,
    MapPin,
    CheckCircle,
    AlertTriangle,
    XCircle,
} from "lucide-react";

const AdminExams = () => {
    const { userData } = useAuth();
    const { exams, loading, error, fetchExams, addExam, deleteExam, updateExamStatus } = useExams();
    const { toast } = useToast();
    const [searchTerm, setSearchTerm] = useState("");
    const [statusFilter, setStatusFilter] = useState("all");
    const [typeFilter, setTypeFilter] = useState("all");
    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [deletingId, setDeletingId] = useState<string | null>(null);

    const [examForm, setExamForm] = useState({
        title: "",
        examType: "Mid-Term" as Exam["examType"],
        date: "",
        startTime: "",
        endTime: "",
        venue: "",
        branches: "",
        sections: "",
        years: "",
        status: "Scheduled" as Exam["status"],
    });

    useEffect(() => {
        fetchExams();
    }, []);

    const resetForm = () => {
        setExamForm({
            title: "",
            examType: "Mid-Term",
            date: "",
            startTime: "",
            endTime: "",
            venue: "",
            branches: "",
            sections: "",
            years: "",
            status: "Scheduled",
        });
    };

    const handleSubmit = async () => {
        if (!examForm.title || !examForm.date || !examForm.startTime || !examForm.endTime) {
            toast({
                title: "Missing Fields",
                description: "Please fill in Title, Date, Start Time and End Time.",
                variant: "destructive",
            });
            return;
        }

        try {
            setIsSubmitting(true);

            // Build target audience
            const branches = examForm.branches.split(",").map((b) => b.trim()).filter((b) => b);
            const sections = examForm.sections.split(",").map((s) => s.trim()).filter((s) => s);
            const years = examForm.years.split(",").map((y) => y.trim()).filter((y) => y);

            const examData: any = {
                exam_id: `EXAM${Date.now()}`,
                title: examForm.title,
                course: examForm.title,
                examType: examForm.examType,
                date: examForm.date,
                startTime: examForm.startTime,
                endTime: examForm.endTime,
                venue: examForm.venue || undefined,
                status: examForm.status,
                postedBy: userData?.collegeId || "admin",
            };

            if (branches.length || sections.length || years.length) {
                examData.targetAudience = {
                    branches: branches.length ? branches : undefined,
                    sections: sections.length ? sections : undefined,
                    years: years.length ? years : undefined,
                };
            }

            await addExam(examData);

            toast({
                title: "Success!",
                description: "Exam scheduled successfully.",
            });

            resetForm();
            setIsAddModalOpen(false);
        } catch (err: any) {
            toast({
                title: "Error",
                description: err.message || "Failed to schedule exam.",
                variant: "destructive",
            });
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleDelete = async (id: string) => {
        try {
            setDeletingId(id);
            await deleteExam(id);
            toast({
                title: "Deleted!",
                description: "Exam has been deleted successfully.",
            });
        } catch (err: any) {
            toast({
                title: "Error",
                description: err.message || "Failed to delete exam.",
                variant: "destructive",
            });
        } finally {
            setDeletingId(null);
        }
    };

    const handleStatusChange = async (id: string, status: Exam["status"]) => {
        try {
            await updateExamStatus(id, status);
            toast({
                title: "Updated!",
                description: `Exam status changed to ${status}.`,
            });
        } catch (err: any) {
            toast({
                title: "Error",
                description: err.message || "Failed to update status.",
                variant: "destructive",
            });
        }
    };

    const formatDate = (dateStr: string) => {
        return new Date(dateStr).toLocaleDateString("en-IN", {
            day: "2-digit",
            month: "short",
            year: "numeric",
        });
    };

    const getStatusBadge = (status: string) => {
        switch (status) {
            case "Scheduled":
                return <Badge className="bg-blue-500">Scheduled</Badge>;
            case "Ongoing":
                return <Badge className="bg-green-500">Ongoing</Badge>;
            case "Completed":
                return <Badge variant="secondary">Completed</Badge>;
            case "Postponed":
                return <Badge className="bg-amber-500">Postponed</Badge>;
            case "Cancelled":
                return <Badge variant="destructive">Cancelled</Badge>;
            default:
                return <Badge variant="secondary">{status}</Badge>;
        }
    };

    const getTypeBadge = (type: string) => {
        const colors: { [key: string]: string } = {
            "Mid-Term": "bg-purple-500",
            "End-Term": "bg-indigo-500",
            "Quiz": "bg-cyan-500",
            "Practical": "bg-green-500",
            "Viva": "bg-pink-500",
            "Assignment": "bg-amber-500",
            "Other": "bg-gray-500",
        };
        return <Badge className={colors[type] || "bg-gray-500"}>{type}</Badge>;
    };

    const filteredExams = exams.filter((exam) => {
        const matchesSearch =
            exam.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
            exam.exam_id.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesStatus = statusFilter === "all" || exam.status === statusFilter;
        const matchesType = typeFilter === "all" || exam.examType === typeFilter;
        return matchesSearch && matchesStatus && matchesType;
    });

    return (
        <AdminLayout>
            <main className="p-6">
                <div className="max-w-7xl mx-auto space-y-6">
                    {/* Header */}
                    <div className="flex items-center justify-between">
                        <div>
                            <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
                                <Calendar className="w-8 h-8 text-primary" />
                                Exam Management
                            </h1>
                            <p className="text-muted-foreground mt-1">
                                Schedule and manage exams for students
                            </p>
                        </div>
                        <div className="flex gap-2">
                            <Button variant="outline" onClick={fetchExams} disabled={loading}>
                                {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <RefreshCw className="w-4 h-4" />}
                                <span className="ml-2">Refresh</span>
                            </Button>
                            <Dialog open={isAddModalOpen} onOpenChange={setIsAddModalOpen}>
                                <DialogTrigger asChild>
                                    <Button>
                                        <Plus className="w-4 h-4 mr-2" />
                                        Schedule Exam
                                    </Button>
                                </DialogTrigger>
                                <DialogContent className="max-w-xl max-h-[80vh] overflow-y-auto">
                                    <DialogHeader>
                                        <DialogTitle className="flex items-center gap-2 text-xl">
                                            <Calendar className="w-6 h-6 text-primary" />
                                            Post Upcoming Exam
                                        </DialogTitle>
                                    </DialogHeader>
                                    <div className="space-y-4 py-4">
                                        {/* Exam Title */}
                                        <div className="space-y-2">
                                            <Label>Exam Title <span className="text-destructive">*</span></Label>
                                            <Input
                                                value={examForm.title}
                                                onChange={(e) => setExamForm({ ...examForm, title: e.target.value })}
                                                placeholder="e.g., Mid Semester Examination - I"
                                            />
                                        </div>

                                        {/* Type and Date */}
                                        <div className="grid grid-cols-2 gap-4">
                                            <div className="space-y-2">
                                                <Label>Exam Type</Label>
                                                <Select
                                                    value={examForm.examType}
                                                    onValueChange={(value) => setExamForm({ ...examForm, examType: value as Exam["examType"] })}
                                                >
                                                    <SelectTrigger>
                                                        <SelectValue />
                                                    </SelectTrigger>
                                                    <SelectContent>
                                                        <SelectItem value="Mid-Term">Mid-Term</SelectItem>
                                                        <SelectItem value="End-Term">End-Term</SelectItem>
                                                        <SelectItem value="Quiz">Quiz</SelectItem>
                                                        <SelectItem value="Practical">Practical</SelectItem>
                                                        <SelectItem value="Viva">Viva</SelectItem>
                                                        <SelectItem value="Assignment">Assignment</SelectItem>
                                                        <SelectItem value="Other">Other</SelectItem>
                                                    </SelectContent>
                                                </Select>
                                            </div>
                                            <div className="space-y-2">
                                                <Label>Date <span className="text-destructive">*</span></Label>
                                                <Input
                                                    type="date"
                                                    value={examForm.date}
                                                    onChange={(e) => setExamForm({ ...examForm, date: e.target.value })}
                                                />
                                            </div>
                                        </div>

                                        {/* Time and Venue */}
                                        <div className="grid grid-cols-3 gap-4">
                                            <div className="space-y-2">
                                                <Label>Start Time <span className="text-destructive">*</span></Label>
                                                <Input
                                                    type="time"
                                                    value={examForm.startTime}
                                                    onChange={(e) => setExamForm({ ...examForm, startTime: e.target.value })}
                                                />
                                            </div>
                                            <div className="space-y-2">
                                                <Label>End Time <span className="text-destructive">*</span></Label>
                                                <Input
                                                    type="time"
                                                    value={examForm.endTime}
                                                    onChange={(e) => setExamForm({ ...examForm, endTime: e.target.value })}
                                                />
                                            </div>
                                            <div className="space-y-2">
                                                <Label>Venue</Label>
                                                <Input
                                                    value={examForm.venue}
                                                    onChange={(e) => setExamForm({ ...examForm, venue: e.target.value })}
                                                    placeholder="Room 101"
                                                />
                                            </div>
                                        </div>

                                        {/* Target Audience */}
                                        <div className="space-y-3 rounded-lg border border-border bg-muted/20 p-4">
                                            <div>
                                                <p className="text-sm font-semibold">Target Audience (Optional)</p>
                                                <p className="text-xs text-muted-foreground">Leave empty for all students</p>
                                            </div>
                                            <div className="grid grid-cols-3 gap-3">
                                                <Input
                                                    value={examForm.branches}
                                                    onChange={(e) => setExamForm({ ...examForm, branches: e.target.value })}
                                                    placeholder="Branches: CSE, ECE"
                                                />
                                                <Input
                                                    value={examForm.sections}
                                                    onChange={(e) => setExamForm({ ...examForm, sections: e.target.value })}
                                                    placeholder="Sections: A, B"
                                                />
                                                <Input
                                                    value={examForm.years}
                                                    onChange={(e) => setExamForm({ ...examForm, years: e.target.value })}
                                                    placeholder="Years: 2, 3"
                                                />
                                            </div>
                                        </div>

                                        {/* Submit */}
                                        <div className="flex justify-end gap-3 pt-4 border-t">
                                            <Button variant="outline" onClick={() => setIsAddModalOpen(false)} disabled={isSubmitting}>
                                                Cancel
                                            </Button>
                                            <Button onClick={handleSubmit} disabled={isSubmitting}>
                                                {isSubmitting ? (
                                                    <>
                                                        <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                                        Posting...
                                                    </>
                                                ) : (
                                                    "Post Exam"
                                                )}
                                            </Button>
                                        </div>
                                    </div>
                                </DialogContent>
                            </Dialog>
                        </div>
                    </div>

                    {/* Stats */}
                    <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
                        <Card>
                            <CardContent className="p-4 flex items-center gap-4">
                                <div className="w-12 h-12 rounded-lg bg-primary/10 flex items-center justify-center">
                                    <Calendar className="w-6 h-6 text-primary" />
                                </div>
                                <div>
                                    <p className="text-sm text-muted-foreground">Total</p>
                                    <p className="text-2xl font-bold">{exams.length}</p>
                                </div>
                            </CardContent>
                        </Card>
                        <Card>
                            <CardContent className="p-4 flex items-center gap-4">
                                <div className="w-12 h-12 rounded-lg bg-blue-500/10 flex items-center justify-center">
                                    <Clock className="w-6 h-6 text-blue-500" />
                                </div>
                                <div>
                                    <p className="text-sm text-muted-foreground">Scheduled</p>
                                    <p className="text-2xl font-bold">{exams.filter((e) => e.status === "Scheduled").length}</p>
                                </div>
                            </CardContent>
                        </Card>
                        <Card>
                            <CardContent className="p-4 flex items-center gap-4">
                                <div className="w-12 h-12 rounded-lg bg-green-500/10 flex items-center justify-center">
                                    <CheckCircle className="w-6 h-6 text-green-500" />
                                </div>
                                <div>
                                    <p className="text-sm text-muted-foreground">Completed</p>
                                    <p className="text-2xl font-bold">{exams.filter((e) => e.status === "Completed").length}</p>
                                </div>
                            </CardContent>
                        </Card>
                        <Card>
                            <CardContent className="p-4 flex items-center gap-4">
                                <div className="w-12 h-12 rounded-lg bg-amber-500/10 flex items-center justify-center">
                                    <AlertTriangle className="w-6 h-6 text-amber-500" />
                                </div>
                                <div>
                                    <p className="text-sm text-muted-foreground">Postponed</p>
                                    <p className="text-2xl font-bold">{exams.filter((e) => e.status === "Postponed").length}</p>
                                </div>
                            </CardContent>
                        </Card>
                        <Card>
                            <CardContent className="p-4 flex items-center gap-4">
                                <div className="w-12 h-12 rounded-lg bg-red-500/10 flex items-center justify-center">
                                    <XCircle className="w-6 h-6 text-red-500" />
                                </div>
                                <div>
                                    <p className="text-sm text-muted-foreground">Cancelled</p>
                                    <p className="text-2xl font-bold">{exams.filter((e) => e.status === "Cancelled").length}</p>
                                </div>
                            </CardContent>
                        </Card>
                    </div>

                    {/* Filters */}
                    <Card>
                        <CardContent className="p-4">
                            <div className="flex flex-col md:flex-row gap-4">
                                <div className="flex-1">
                                    <div className="relative">
                                        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground w-4 h-4" />
                                        <Input
                                            placeholder="Search exams..."
                                            value={searchTerm}
                                            onChange={(e) => setSearchTerm(e.target.value)}
                                            className="pl-10"
                                        />
                                    </div>
                                </div>
                                <Select value={statusFilter} onValueChange={setStatusFilter}>
                                    <SelectTrigger className="w-full md:w-[150px]">
                                        <SelectValue placeholder="Status" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="all">All Status</SelectItem>
                                        <SelectItem value="Scheduled">Scheduled</SelectItem>
                                        <SelectItem value="Ongoing">Ongoing</SelectItem>
                                        <SelectItem value="Completed">Completed</SelectItem>
                                        <SelectItem value="Postponed">Postponed</SelectItem>
                                        <SelectItem value="Cancelled">Cancelled</SelectItem>
                                    </SelectContent>
                                </Select>
                                <Select value={typeFilter} onValueChange={setTypeFilter}>
                                    <SelectTrigger className="w-full md:w-[150px]">
                                        <SelectValue placeholder="Type" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="all">All Types</SelectItem>
                                        <SelectItem value="Mid-Term">Mid-Term</SelectItem>
                                        <SelectItem value="End-Term">End-Term</SelectItem>
                                        <SelectItem value="Quiz">Quiz</SelectItem>
                                        <SelectItem value="Practical">Practical</SelectItem>
                                        <SelectItem value="Viva">Viva</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>
                        </CardContent>
                    </Card>

                    {/* Error */}
                    {error && (
                        <Card className="border-destructive bg-destructive/10">
                            <CardContent className="p-4 text-destructive">{error}</CardContent>
                        </Card>
                    )}

                    {/* Loading */}
                    {loading && exams.length === 0 && (
                        <Card>
                            <CardContent className="p-12 text-center">
                                <Loader2 className="w-12 h-12 text-primary mx-auto mb-4 animate-spin" />
                                <p className="text-muted-foreground">Loading exams...</p>
                            </CardContent>
                        </Card>
                    )}

                    {/* Exams List */}
                    {!loading && filteredExams.length === 0 ? (
                        <Card>
                            <CardContent className="p-12 text-center">
                                <Calendar className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                                <h3 className="text-lg font-medium text-foreground mb-2">No exams found</h3>
                                <p className="text-muted-foreground">
                                    {exams.length === 0
                                        ? "No exams scheduled yet. Click 'Schedule Exam' to add one."
                                        : "Try adjusting your search or filters."}
                                </p>
                            </CardContent>
                        </Card>
                    ) : (
                        <div className="space-y-4">
                            {filteredExams.map((exam) => (
                                <Card key={exam._id} className="hover:shadow-lg transition-shadow">
                                    <CardContent className="p-6">
                                        <div className="flex items-start justify-between gap-4">
                                            <div className="flex-1 space-y-2">
                                                <div className="flex items-start gap-3 flex-wrap">
                                                    <h3 className="text-lg font-bold text-foreground">{exam.title}</h3>
                                                    {getStatusBadge(exam.status)}
                                                    {getTypeBadge(exam.examType)}
                                                </div>

                                                <div className="flex flex-wrap items-center gap-4 text-sm text-muted-foreground">
                                                    <span className="flex items-center gap-1">
                                                        <Calendar className="w-4 h-4" />
                                                        {formatDate(exam.date)}
                                                    </span>
                                                    <span className="flex items-center gap-1">
                                                        <Clock className="w-4 h-4" />
                                                        {exam.startTime} - {exam.endTime}
                                                    </span>
                                                    {exam.venue && (
                                                        <span className="flex items-center gap-1">
                                                            <MapPin className="w-4 h-4" />
                                                            {exam.venue}
                                                        </span>
                                                    )}
                                                </div>
                                            </div>

                                            <div className="flex items-center gap-2">
                                                <Select
                                                    value={exam.status}
                                                    onValueChange={(value) => handleStatusChange(exam._id, value as Exam["status"])}
                                                >
                                                    <SelectTrigger className="w-[120px]">
                                                        <SelectValue />
                                                    </SelectTrigger>
                                                    <SelectContent>
                                                        <SelectItem value="Scheduled">Scheduled</SelectItem>
                                                        <SelectItem value="Ongoing">Ongoing</SelectItem>
                                                        <SelectItem value="Completed">Completed</SelectItem>
                                                        <SelectItem value="Postponed">Postponed</SelectItem>
                                                        <SelectItem value="Cancelled">Cancelled</SelectItem>
                                                    </SelectContent>
                                                </Select>

                                                <AlertDialog>
                                                    <AlertDialogTrigger asChild>
                                                        <Button
                                                            variant="ghost"
                                                            size="sm"
                                                            className="text-destructive hover:text-destructive hover:bg-destructive/10"
                                                            disabled={deletingId === exam._id}
                                                        >
                                                            {deletingId === exam._id ? (
                                                                <Loader2 className="w-4 h-4 animate-spin" />
                                                            ) : (
                                                                <Trash2 className="w-4 h-4" />
                                                            )}
                                                        </Button>
                                                    </AlertDialogTrigger>
                                                    <AlertDialogContent>
                                                        <AlertDialogHeader>
                                                            <AlertDialogTitle>Delete Exam?</AlertDialogTitle>
                                                            <AlertDialogDescription>
                                                                Are you sure you want to delete "{exam.title}"? This action cannot be undone.
                                                            </AlertDialogDescription>
                                                        </AlertDialogHeader>
                                                        <AlertDialogFooter>
                                                            <AlertDialogCancel>Cancel</AlertDialogCancel>
                                                            <AlertDialogAction
                                                                onClick={() => handleDelete(exam._id)}
                                                                className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                                                            >
                                                                Delete
                                                            </AlertDialogAction>
                                                        </AlertDialogFooter>
                                                    </AlertDialogContent>
                                                </AlertDialog>
                                            </div>
                                        </div>
                                    </CardContent>
                                </Card>
                            ))}
                        </div>
                    )}
                </div>
            </main>
        </AdminLayout>
    );
};

export default AdminExams;

