}

const AdminPlacement = () => {
  const { userData } = useAuth();
  const { jobs, loading, error, addJob, updateJob, deleteJob, refreshJobs } = usePlacement();
  const { toast } = useToast();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [attachedFiles, setAttachedFiles] = useState<AttachedFile[]>([]);
  const [driveLink, setDriveLink] = useState("");
  const [showDriveLinkInput, setShowDriveLinkInput] = useState(false);

  // Resume generator state
  const [isGeneratingResume, setIsGeneratingResume] = useState<string | null>(null);

  // View modal state
  const [isViewModalOpen, setIsViewModalOpen] = useState(false);
  const [viewJob, setViewJob] = useState<any>(null);
  const [applicants, setApplicants] = useState<Applicant[]>([]);
  const [loadingApplicants, setLoadingApplicants] = useState(false);

  // Edit modal state
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editJob, setEditJob] = useState<any>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [editAttachedFiles, setEditAttachedFiles] = useState<AttachedFile[]>([]);
  const [editDriveLink, setEditDriveLink] = useState("");
  const [showEditDriveLinkInput, setShowEditDriveLinkInput] = useState(false);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  // Student Selection state
  const [studentList, setStudentList] = useState<any[]>([]);
  const [loadingStudents, setLoadingStudents] = useState(false);
  const [selectedRollNumbers, setSelectedRollNumbers] = useState<string[]>([]);

  // Delete confirmation state
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState<any>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  const [newJob, setNewJob] = useState({
    job_id: "",
    title: "",
    company: "",
    type: "",
    ctc: "",
    stipend: "",
    deadlineDate: "",
    deadlineTime: "",
    deadlineAmPm: "AM",
    eligibleBranches: [] as string[],
    filters: {
        branch: "",
        degree: "",
        year: "",
        semester: "",
        section: "",
    },
    selectedStudents: [] as string[],
    description: "",
    bond: "",
    rounds: "",
    location: "",
  });

  const availableBranches = [
    "CSE", "ECE", "EEE", "ME", "CE"
  ];

  const yearMapping: Record<string, string> = {
    "IV Year": "22",
    "III Year": "23",
    "II Year": "24",
    "I Year": "25"
  };

  const fetchStudents = useCallback(async (filters: any) => {
    if (!filters.branch || !filters.year) {
        setStudentList([]);
        return;
    }
    
    setLoadingStudents(true);
    try {
        const yearCode = filters.year; 
        const response = await api.get(`/students/section/${yearCode}/${filters.branch}/${filters.section || 'All'}`);
        if (response && response.students) {
            setStudentList(response.students);
        } else {
            setStudentList([]);
        }
    } catch (err) {
        console.error("Error fetching students:", err);
        setStudentList([]);
    } finally {
        setLoadingStudents(false);
    }
  }, []);

  useEffect(() => {
    if (isAddModalOpen || isEditModalOpen) {
        const job = isEditModalOpen ? editJob : newJob;
        if (job && job.filters && job.filters.branch && job.filters.year) {
            fetchStudents(job.filters);
        }
    }
  }, [newJob.filters.branch, newJob.filters.year, newJob.filters.section, isAddModalOpen]);

  useEffect(() => {
    if (isEditModalOpen && editJob?.filters) {
        fetchStudents(editJob.filters);
        if (editJob.selectedStudents) {
            setSelectedRollNumbers(editJob.selectedStudents);
        }
    }
  }, [editJob?.filters?.branch, editJob?.filters?.year, editJob?.filters?.section, isEditModalOpen]);

  // Generate unique Job ID
  const generateJobId = () => {
    const company = newJob.company.replace(/\s+/g, "").toUpperCase().slice(0, 6);
    const year = new Date().getFullYear();
    return `${company || "JOB"}${year}`;
  };

  // Format deadline for display
  const formatDeadlineForSubmit = () => {
    if (!newJob.deadlineDate || !newJob.deadlineTime) return "";
    return `${newJob.deadlineDate}T${newJob.deadlineTime}:00`;
  };

  // Handle file upload from local computer (max 5MB per file)
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files) return;

    const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB
    const newFiles: AttachedFile[] = [];
    const skippedFiles: string[] = [];

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      if (file.size > MAX_FILE_SIZE) {
        skippedFiles.push(file.name);
        continue;
      }
      newFiles.push({
        name: file.name,
        url: "", // URL will be set after uploading to server
        type: "local",
        size: file.size,
        file: file, // keep the File object for upload
      });
    }

    if (skippedFiles.length > 0) {
      toast({
        title: "File Too Large",
        description: `${skippedFiles.join(", ")} exceeded the 5MB limit and was not added.`,
        variant: "destructive",
      });
    }

    if (newFiles.length > 0) {
      setAttachedFiles([...attachedFiles, ...newFiles]);
      toast({
        title: "Files Added",
        description: `${newFiles.length} file(s) attached successfully.`,
      });
    }
  };

  // Handle Google Drive link
  const handleAddDriveLink = () => {
    if (!driveLink.trim()) return;

    // Extract file name from Google Drive link or use default
    let fileName = "Google Drive File";
    if (driveLink.includes("/d/")) {
      fileName = "Drive Document";
    }

    setAttachedFiles([
      ...attachedFiles,
      {
        name: fileName,
        url: driveLink,
        type: "drive",
      },
    ]);
    setDriveLink("");
    setShowDriveLinkInput(false);
    toast({
      title: "Drive Link Added",
      description: "Google Drive link attached successfully.",
    });
  };

  // Remove attached file
  const removeFile = (index: number) => {
    const newFiles = [...attachedFiles];
    newFiles.splice(index, 1);
    setAttachedFiles(newFiles);
  };

  const handleAddJob = async () => {
    // Validate required fields
    if (!newJob.job_id || !newJob.title || !newJob.company || !newJob.type || !newJob.ctc) {
      toast({
        title: "Missing Fields",
        description: "Please fill in all required fields (Job ID, Title, Company, Type, CTC).",
        variant: "destructive",
      });
      return;
    }

    if (!newJob.deadlineDate || !newJob.deadlineTime) {
      toast({
        title: "Missing Deadline",
        description: "Please set the application deadline.",
        variant: "destructive",
      });
      return;
    }

    const deadline = formatDeadlineForSubmit();

    try {
      setIsSubmitting(true);
      console.log("Admin adding job to MongoDB...");

      // Upload local files to server first
      const localFiles = attachedFiles.filter((f) => f.type === "local" && f.file);
      let uploadedAttachments: { filename: string; url: string }[] = [];

      if (localFiles.length > 0) {
        const jobDataToSubmit = {
        ...newJob,
        deadline: deadline,
        selectedStudents: selectedRollNumbers
      };

      const formData = new FormData();
      formData.append("jobData", JSON.stringify(jobDataToSubmit));
        localFiles.forEach((f) => {
          if (f.file) formData.append("files", f.file);
        });

        // Use fetch directly for multipart uploads (api.post always JSON-stringifies)
        const token = localStorage.getItem("campverse_auth_token");
        const uploadResponse = await fetch(
          `${import.meta.env.VITE_API_BASE_URL || "http://localhost:5000/api"}/placements/upload`,
          {
            method: "POST",
            headers: { Authorization: `Bearer ${token}` },
            body: formData,
          }
        );
        if (!uploadResponse.ok) throw new Error("File upload failed");
        const uploadData = await uploadResponse.json();
        uploadedAttachments = uploadData.files || [];
      }

      // Add drive links as-is
      const driveAttachments = attachedFiles
        .filter((f) => f.type === "drive")
        .map((f) => ({ filename: f.name, url: f.url }));

      const allAttachments = [...uploadedAttachments, ...driveAttachments];

      // Create job data object with only the fields the API expects
      const jobData = {
        job_id: newJob.job_id,
        title: newJob.title,
        company: newJob.company,
        type: newJob.type,
        ctc: newJob.ctc,
        stipend: newJob.stipend || "N/A",
        deadline,
        description: newJob.description,
        bond: newJob.bond,
        location: newJob.location,
        eligibleBranches: newJob.eligibleBranches,
        filters: newJob.filters,
        selectedStudents: selectedRollNumbers,
        rounds: newJob.rounds
          ? newJob.rounds.split(",").map((r) => r.trim())
          : [],
        attachments: allAttachments,
      };

      await addJob(jobData);

      toast({
        title: "Success!",
        description: "Job posted successfully. Students can now see it.",
      });

      // Reset form
      setNewJob({
        job_id: "",
        title: "",
        company: "",
        type: "",
        ctc: "",
        stipend: "",
        deadlineDate: "",
        deadlineTime: "",
        deadlineAmPm: "AM",
        eligibleBranches: [],
        filters: {
            branch: "",
            degree: "",
            year: "",
            semester: "",
            section: "",
        },
        selectedStudents: [],
        description: "",
        bond: "",
        rounds: "",
        location: "",
      });
      setAttachedFiles([]);
      setIsAddModalOpen(false);
    } catch (err: any) {
      console.error("Error adding job:", err);
      toast({
        title: "Error",
        description: err.message || "Failed to post job. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  // ── View modal handler ──
  const handleViewJob = async (job: any) => {
    setViewJob(job);
    setIsViewModalOpen(true);
    setLoadingApplicants(true);
    try {
      const res = await api.get(`/placements/${job._id}/applications?limit=100`);
      setApplicants(res.applications || []);
    } catch (err) {
      console.error("Error fetching applicants:", err);
      setApplicants([]);
    } finally {
      setLoadingApplicants(false);
    }
  };

  // ── Edit modal handler ──
  const handleOpenEdit = (job: any) => {
    const datePart = job.deadline ? job.deadline.split("T")[0] : "";
    const timePart = job.deadline ? job.deadline.split("T")[1]?.slice(0, 5) || "" : "";

    setEditJob({
      ...job,
      deadlineDate: datePart,
      deadlineTime: timePart,
      filters: job.filters || { branch: "", degree: "", year: "", semester: "", section: "" },
      selectedStudents: job.selectedStudents || [],
      eligibleBranches: job.eligibleBranches && job.eligibleBranches.length > 0 ? job.eligibleBranches : (job.eligibility || [])
    });
    // Load existing attachments into edit state
    const existingAttachments: AttachedFile[] = (job.attachments || []).map((a: any) => ({
      name: a.filename || a.name || "Attachment",
      url: a.url || "",
      type: (a.url && (a.url.startsWith("http") || a.url.startsWith("https"))) ? "drive" as const : "local" as const,
    }));
    setEditAttachedFiles(existingAttachments);
    setEditDriveLink("");
    setShowEditDriveLinkInput(false);
    setIsEditModalOpen(true);
  };

  // Handle file upload for edit modal
  const handleEditFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files) return;
    const MAX_FILE_SIZE = 5 * 1024 * 1024;
    const newFiles: AttachedFile[] = [];
    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      if (file.size > MAX_FILE_SIZE) continue;
      newFiles.push({ name: file.name, url: "", type: "local", size: file.size, file });
    }
    if (newFiles.length > 0) {
      setEditAttachedFiles([...editAttachedFiles, ...newFiles]);
      toast({ title: "Files Added", description: `${newFiles.length} file(s) attached.` });
    }
  };

  const handleAddEditDriveLink = () => {
    if (!editDriveLink.trim()) return;
    setEditAttachedFiles([
      ...editAttachedFiles,
      { name: "Google Drive File", url: editDriveLink, type: "drive" },
    ]);
    setEditDriveLink("");
    setShowEditDriveLinkInput(false);
  };

  const removeEditFile = (index: number) => {
    const updated = [...editAttachedFiles];
    updated.splice(index, 1);
    setEditAttachedFiles(updated);
  };

  const handleSaveEdit = async () => {
    if (!editJob) return;
    setIsEditing(true);
    try {
      const deadline = editJob.deadlineDate && editJob.deadlineTime
        ? `${editJob.deadlineDate}T${editJob.deadlineTime}:00`
        : editJob.deadline;

      // Upload new local files to server
      const newLocalFiles = editAttachedFiles.filter((f) => f.type === "local" && f.file);
      let uploadedAttachments: { filename: string; url: string }[] = [];

      if (newLocalFiles.length > 0) {
        const formData = new FormData();
        newLocalFiles.forEach((f) => {
          if (f.file) formData.append("files", f.file);
        });
        const token = localStorage.getItem("campverse_auth_token");
        const uploadResponse = await fetch(
          `${import.meta.env.VITE_API_BASE_URL || "http://localhost:5000/api"}/placements/upload`,
          {
            method: "POST",
            headers: { Authorization: `Bearer ${token}` },
            body: formData,
          }
        );
        if (!uploadResponse.ok) throw new Error("File upload failed");
        const uploadData = await uploadResponse.json();
        uploadedAttachments = uploadData.files || [];
      }

      // Keep existing files (already on server) + drive links
      const existingAttachments = editAttachedFiles
        .filter((f) => !f.file) // not a new upload
        .map((f) => ({ filename: f.name, url: f.url }));

      const allAttachments = [...existingAttachments, ...uploadedAttachments];

      await updateJob(editJob.job_id, {
        title: editJob.title,
        company: editJob.company,
        type: editJob.type,
        ctc: editJob.ctc,
        stipend: editJob.stipend,
        deadline,
        description: editJob.description,
        bond: editJob.bond,
        location: editJob.location,
        eligibleBranches: editJob.eligibleBranches,
        filters: editJob.filters,
        selectedStudents: selectedRollNumbers,
        rounds: editJob.rounds ? editJob.rounds.split(",").map((r: string) => r.trim()) : [],
        attachments: allAttachments,
      });
      toast({ title: "Success", description: "Job updated successfully." });
      setIsEditModalOpen(false);
    } catch (err: any) {
      toast({ title: "Error", description: err.message || "Failed to update job.", variant: "destructive" });
    } finally {
      setIsEditing(false);
    }
  };

  // ── Delete handler ──
  const handleDeleteClick = (job: any) => {
    setDeleteTarget(job);
    setIsDeleteDialogOpen(true);
  };

  const handleConfirmDelete = async () => {
    if (!deleteTarget) return;
    setIsDeleting(true);
    try {
      await deleteJob(deleteTarget.job_id);
      toast({ title: "Deleted", description: `"${deleteTarget.title}" and all its applications have been deleted.` });
      setIsDeleteDialogOpen(false);
      setDeleteTarget(null);
    } catch (err: any) {
      toast({ title: "Error", description: err.message || "Failed to delete job.", variant: "destructive" });
    } finally {
      setIsDeleting(false);
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "Open":
        return <Badge className="bg-green-500">Open</Badge>;
      case "Closed":
        return <Badge variant="destructive">Closed</Badge>;
      default:
        return <Badge variant="secondary">{status}</Badge>;
    }
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString("en-IN", {
      day: "2-digit",
      month: "short",
      year: "numeric",
    });
  };

  const getApplicationStatusColor = (status: string) => {
    switch (status) {
      case "Applied": return "bg-green-500/10 text-green-500 border-green-500/20";
      case "Shortlisted": return "bg-yellow-500/10 text-yellow-500 border-yellow-500/20";
      case "Selected": return "bg-green-500/10 text-green-500 border-green-500/20";
      case "Rejected": return "bg-red-500/10 text-red-500 border-red-500/20";
      default: return "bg-gray-500/10 text-gray-500 border-gray-500/20";
    }
  };

  // If deadline has passed, treat the job as "Closed" regardless of stored status
  const getEffectiveStatus = (job: any) => {
    if (job.deadline && new Date(job.deadline) < new Date()) {
      return "Closed";
    }
    return job.status;
  };

  // Map full branch names to short codes
  const branchShortName = (branch: string | undefined): string => {
    if (!branch) return "—";
    const map: Record<string, string> = {
      "Computer Science and Engineering": "CSE",
      "Computer Science & Engineering": "CSE",
      "Computer Science": "CSE",
      "Information Technology": "IT",
      "Electronics and Communication Engineering": "ECE",
      "Electronics & Communication Engineering": "ECE",
      "Electrical and Electronics Engineering": "EEE",
      "Electrical & Electronics Engineering": "EEE",
      "Mechanical Engineering": "ME", // Changed per request
      "Civil Engineering": "CE",      // Changed per request
      "Chemical Engineering": "CHEM",
      "Aerospace Engineering": "AERO",
      "Biotechnology": "BIOTECH",
      "Data Science": "DS",
    };
    return map[branch] || branch;
  };

  const handleViewResume = async (studentData: any) => {
    if (!studentData.email || !studentData.collegeId) {
      toast({ title: "Incomplete Profile", description: "This student has not completed their profile.", variant: "destructive" });
      return;
    }
    
    setIsGeneratingResume(studentData._id);
    
    try {
      const jsPDFModule = await import('jspdf');
      const jsPDFCtor: any = (jsPDFModule as any).jsPDF || (jsPDFModule as any).default;
      const pdf = new jsPDFCtor('p', 'mm', 'a4');
      const pageWidth = pdf.internal.pageSize.getWidth();
      const pageHeight = pdf.internal.pageSize.getHeight();
      const margin = 15;
      const contentWidth = pageWidth - margin * 2;
      let y = 0;

      // Colors
      const primaryColor = [37, 99, 235]; // blue-600
      const darkColor = [17, 24, 39]; // gray-900
      const mutedColor = [107, 114, 128]; // gray-500
      const accentBg = [239, 246, 255]; // blue-50
      const white = [255, 255, 255];

      // Helper: check page overflow
      const checkPage = (needed: number) => {
        if (y + needed > pageHeight - margin) {
          pdf.addPage();
          y = margin;
        }
      };

      // Helper: draw section header
      const drawSectionHeader = (title: string) => {
        checkPage(14);
        pdf.setFillColor(...primaryColor);
        pdf.rect(margin, y, contentWidth, 9, 'F');
        pdf.setFont('helvetica', 'bold');
        pdf.setFontSize(11);
        pdf.setTextColor(...white);
        pdf.text(title, margin + 4, y + 6.5);
        y += 13;
      };

      // ========== HEADER ==========
      pdf.setFillColor(...primaryColor);
      pdf.rect(0, 0, pageWidth, 42, 'F');

      // Name
      pdf.setFont('helvetica', 'bold');
      pdf.setFontSize(22);
      pdf.setTextColor(...white);
      pdf.text((studentData.name || "").toUpperCase(), margin, 16);

      // Roll Number & Branch
      pdf.setFont('helvetica', 'normal');
      pdf.setFontSize(11);
      pdf.setTextColor(220, 230, 255);
      const headerBranch = branchShortName(studentData.branch);
      pdf.text(`${studentData.collegeId}  |  ${headerBranch}  |  Semester ${studentData.semester || "N/A"}`, margin, 24);

      // Contact info row
      pdf.setFontSize(9);
      const contactParts: string[] = [];
      if (studentData.email) contactParts.push(studentData.email);
      if (studentData.phone) contactParts.push(studentData.phone);
      if (contactParts.length > 0) {
        pdf.text(contactParts.join('  •  '), margin, 31);
      }

      // Social links row
      const socialParts: string[] = [];
      if (studentData.linkedin) socialParts.push(`LinkedIn: ${studentData.linkedin.replace(/^https?:\/\/(www\.)?/, '')}`);
      if (studentData.github) socialParts.push(`GitHub: ${studentData.github.replace(/^https?:\/\/(www\.)?/, '')}`);
      if (studentData.portfolio) socialParts.push(`Portfolio: ${studentData.portfolio.replace(/^https?:\/\/(www\.)?/, '')}`);
      if (socialParts.length > 0) {
        pdf.setFontSize(8);
        pdf.text(socialParts.join('  |  '), margin, 37);
      }

      y = 50;

      // ========== ABOUT ==========
      if (studentData.bio) {
        drawSectionHeader('ABOUT');
        pdf.setFont('helvetica', 'normal');
        pdf.setFontSize(10);
        pdf.setTextColor(...darkColor);
        const bioLines = pdf.splitTextToSize(studentData.bio, contentWidth - 4);
        checkPage(bioLines.length * 5 + 4);
        pdf.text(bioLines, margin + 2, y);
        y += bioLines.length * 4.5 + 6;
      }

      // ========== PROJECTS ==========
      if (studentData.projects && studentData.projects.length > 0) {
        drawSectionHeader('PROJECTS');
        studentData.projects.forEach((project: any) => {
          checkPage(22);
          pdf.setFont('helvetica', 'bold');
          pdf.setFontSize(11);
          pdf.setTextColor(...darkColor);
          pdf.text(project.title, margin + 2, y);
          y += 5;
          if (project.techStack) {
            pdf.setFont('helvetica', 'italic');
            pdf.setFontSize(9);
            pdf.setTextColor(...primaryColor);
            pdf.text(`Tech: ${project.techStack}`, margin + 2, y);
            y += 4.5;
          }
          if (project.description) {
            pdf.setFont('helvetica', 'normal');
            pdf.setFontSize(9);
            pdf.setTextColor(...mutedColor);
            // Replace bullets seamlessly with standard hyphens across multiline text
            const descStr = project.description;
            const descLines = pdf.splitTextToSize(descStr, contentWidth - 4);
            checkPage(descLines.length * 4);
            pdf.text(descLines, margin + 2, y);
            y += descLines.length * 4 + 1;
          }
          if (project.link) {
            pdf.setFont('helvetica', 'normal');
            pdf.setFontSize(8);
            pdf.setTextColor(...primaryColor);
            pdf.textWithLink(project.link, margin + 2, y, { url: project.link });
            y += 4;
          }
          y += 3;
        });
      }

      // ========== SKILLS ==========
      if (studentData.skills && studentData.skills.length > 0) {
        drawSectionHeader('SKILLS');
        checkPage(12);
        let skillX = margin + 2;
        studentData.skills.forEach((skill: string) => {
          const textWidth = pdf.getTextWidth(skill) + 6;
          if (skillX + textWidth > pageWidth - margin) {
            skillX = margin + 2;
            y += 7;
          }
          checkPage(8);
          pdf.setFillColor(...accentBg);
          pdf.roundedRect(skillX, y - 4, textWidth, 6, 1.5, 1.5, 'F');
          pdf.setFont('helvetica', 'normal');
          pdf.setFontSize(9);
          pdf.setTextColor(...primaryColor);
          pdf.text(skill, skillX + 3, y);
          skillX += textWidth + 3;
        });
        y += 8;
      }

      // ========== CERTIFICATIONS ==========
      if (studentData.certifications && studentData.certifications.length > 0) {
        drawSectionHeader('CERTIFICATIONS');
        studentData.certifications.forEach((cert: any) => {
          checkPage(16);
          pdf.setFont('helvetica', 'bold');
          pdf.setFontSize(10);
          pdf.setTextColor(...darkColor);
          pdf.text(cert.name, margin + 2, y);

          const metaParts: string[] = [];
          if (cert.issuer) metaParts.push(cert.issuer);
          if (cert.date) metaParts.push(cert.date);

          pdf.setFont('helvetica', 'normal');
          pdf.setFontSize(9);
          pdf.setTextColor(...mutedColor);
          if (metaParts.length > 0) {
            pdf.text(metaParts.join(' | '), margin + 2, y + 4.5);
          }
          
          if (cert.credentialLink) {
            pdf.setTextColor(...primaryColor);
            try {
              pdf.textWithLink('View Credential', margin + 2 + pdf.getTextWidth(metaParts.join(' | ')) + 2, y + 4.5, { url: cert.credentialLink });
            } catch (e) {
              // ignore invalid url schema failures
            }
          }
          y += 8;
        });
      }
      
      // ========== ACHIEVEMENTS ==========
      if (studentData.achievements && studentData.achievements.length > 0) {
        drawSectionHeader('ACHIEVEMENTS');
        studentData.achievements.forEach((ach: string) => {
          checkPage(10);
          pdf.setFont('helvetica', 'normal');
          pdf.setFontSize(9);
          pdf.setTextColor(...darkColor);
          const lines = pdf.splitTextToSize(`• ${ach}`, contentWidth - 4);
          pdf.text(lines, margin + 2, y);
          y += lines.length * 4.5 + 1;
        });
      }

      const blobUrl = pdf.output('bloburl');
      window.open(blobUrl, '_blank');
      
    } catch (err) {
      console.error("Resume generation error:", err);
      toast({ title: "Error", description: "Failed to generate resume.", variant: "destructive" });
    } finally {
      setIsGeneratingResume(null);
    }
  };

  const handleExportExcel = () => {
    if (!applicants.length || !viewJob) return;
    const data = applicants.map((app, idx) => ({
      "S.No": idx + 1,
      "Student Name": app.studentId?.name || "Unknown",
      "Roll No": app.studentId?.collegeId || "—",
      "Branch": branchShortName(app.studentId?.branch),
      "Status": app.status,
      "Timestamp": app.appliedDate ? new Date(app.appliedDate).toLocaleString("en-IN") : "—",
      "Resume Link": app.studentId?.resumeUrl || "Not Uploaded"
    }));
    
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Applications");
    XLSX.writeFile(wb, `${viewJob.company}_${viewJob.job_id}_Applications.xlsx`);
  };

  return (
    <AdminLayout>
      <div className="max-w-7xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
              <Building2 className="w-8 h-8 text-primary" />
              Placement Management
            </h1>
            <p className="text-muted-foreground mt-1">
              Manage job opportunities and placement drives
            </p>
          </div>
          <div className="flex items-center gap-2">
            <Dialog open={isAddModalOpen} onOpenChange={setIsAddModalOpen}>
              <DialogTrigger asChild>
                <Button className="flex items-center gap-2 bg-primary hover:bg-primary/90">
                  <Plus className="w-4 h-4" />
                  Post New Job
                </Button>
              </DialogTrigger>
              <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                  <DialogTitle className="text-xl font-bold">Post New Job Opportunity</DialogTitle>
                </DialogHeader>
                <div className="space-y-6 py-4">
                  {/* Job ID and Company */}
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="job_id" className="text-sm font-semibold">
                        Job ID <span className="text-destructive">*</span>
                      </Label>
                      <div className="flex gap-2">
                        <Input
                          id="job_id"
                          value={newJob.job_id}
                          onChange={(e) =>
                            setNewJob({ ...newJob, job_id: e.target.value.toUpperCase() })
                          }
                          placeholder="e.g., GOOGLE2025"
                          className="flex-1"
                        />
                        <Button
                          type="button"
                          variant="outline"
                          size="sm"
                          onClick={() => setNewJob({ ...newJob, job_id: generateJobId() })}
                        >
                          Auto
                        </Button>
                      </div>
                      <p className="text-xs text-muted-foreground">Format: COMPANY+YEAR</p>
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="company" className="text-sm font-semibold">
                        Company Name <span className="text-destructive">*</span>
                      </Label>
                      <Input
                        id="company"
                        value={newJob.company}
                        onChange={(e) =>
                          setNewJob({ ...newJob, company: e.target.value })
                        }
                        placeholder="e.g., Google, Microsoft"
                      />
                    </div>
                  </div>

                  {/* Job Title */}
                  <div className="space-y-2">
                    <Label htmlFor="title" className="text-sm font-semibold">
                      Job Title <span className="text-destructive">*</span>
                    </Label>
                    <Input
                      id="title"
                      value={newJob.title}
                      onChange={(e) =>
                        setNewJob({ ...newJob, title: e.target.value })
                      }
                      placeholder="e.g., Software Engineer, Data Analyst"
                    />
                  </div>

                  {/* Job Type and CTC */}
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label className="text-sm font-semibold">
                        Job Type <span className="text-destructive">*</span>
                      </Label>
                      <Select
                        value={newJob.type}
                        onValueChange={(value) =>
                          setNewJob({ ...newJob, type: value })
                        }
                      >
                        <SelectTrigger>
                          <SelectValue placeholder="Select job type" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="Full Time">Full Time</SelectItem>
                          <SelectItem value="Internship">Internship</SelectItem>
                          <SelectItem value="Intern + Full Time">Intern + Full Time</SelectItem>
                          <SelectItem value="Contract">Contract</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="ctc" className="text-sm font-semibold">
                        CTC / Package <span className="text-destructive">*</span>
                      </Label>
                      <Input
                        id="ctc"
                        value={newJob.ctc}
                        onChange={(e) =>
                          setNewJob({ ...newJob, ctc: e.target.value })
                        }
                        placeholder="e.g., 12 LPA, 8-15 LPA"
                      />
                    </div>
                  </div>

                  {/* Stipend and Location */}
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="stipend" className="text-sm font-semibold">Stipend (for internship)</Label>
                      <Input
                        id="stipend"
                        value={newJob.stipend}
                        onChange={(e) =>
                          setNewJob({ ...newJob, stipend: e.target.value })
                        }
                        placeholder="e.g., ₹50,000/month or N/A"
                      />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="location" className="text-sm font-semibold">Location</Label>
                      <Input
                        id="location"
                        value={newJob.location}
                        onChange={(e) =>
                          setNewJob({ ...newJob, location: e.target.value })
                        }
                        placeholder="e.g., Bangalore, Remote, Hybrid"
                      />
                    </div>
                  </div>

                  {/* Deadline Section */}
                  <div className="space-y-2">
                    <Label className="text-sm font-semibold flex items-center gap-2">
                      <Clock className="w-4 h-4" />
                      Application Deadline <span className="text-destructive">*</span>
                    </Label>
                    <div className="grid grid-cols-2 gap-3">
                      <div>
                        <Label className="text-xs text-muted-foreground">Date (DD-MM-YYYY)</Label>
                        <Input
                          type="date"
                          value={newJob.deadlineDate}
                          onChange={(e) =>
                            setNewJob({ ...newJob, deadlineDate: e.target.value })
                          }
                          min={new Date().toISOString().split("T")[0]}
                        />
                      </div>
                      <div>
                        <Label className="text-xs text-muted-foreground">Time (HH:MM)</Label>
                        <Input
                          type="time"
                          value={newJob.deadlineTime}
                          onChange={(e) =>
                            setNewJob({ ...newJob, deadlineTime: e.target.value })
                          }
                        />
                      </div>
                    </div>
                  </div>

                  {/* Visibility & Student Selection Section */}
                  <div className="pt-4 mt-6 border-t border-muted">
                    <h3 className="text-lg font-bold mb-4">Job Visibility & Student Selection</h3>
                    
                    <div className="space-y-4">
                      {/* Branch Selection Dropdown */}
                      <div className="space-y-2">
                        <Label className="text-sm font-semibold">Target Branch</Label>
                        <Select 
                          value={newJob.filters.branch} 
                          onValueChange={(val) => setNewJob({ ...newJob, filters: { ...newJob.filters, branch: val } })}
                        >
                            <SelectTrigger>
                                <SelectValue placeholder="Select Branch" />
                            </SelectTrigger>
                            <SelectContent>
                                {availableBranches.map(b => (
                                    <SelectItem key={b} value={b}>{b}</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                      </div>

                      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        <div className="space-y-2">
                          <Label className="text-xs">Degree</Label>
                          <Select
                            value={newJob.filters.degree}
                            onValueChange={(val) => setNewJob({ ...newJob, filters: { ...newJob.filters, degree: val === "clear" ? "" : val } })}
                          >
                            <SelectTrigger><SelectValue placeholder="Any" /></SelectTrigger>
                            <SelectContent>
                              <SelectItem value="clear">Any Degree</SelectItem>
                              <SelectItem value="Major">Major</SelectItem>
                              <SelectItem value="Minor">Minor</SelectItem>
                            </SelectContent>
                          </Select>
                        </div>
                        
                        <div className="space-y-2">
                          <Label className="text-xs">Year</Label>
                          <Select
                            value={newJob.filters.year}
                            onValueChange={(val) => setNewJob({ ...newJob, filters: { ...newJob.filters, year: val === "clear" ? "" : val } })}
                          >
                            <SelectTrigger><SelectValue placeholder="Any" /></SelectTrigger>
                            <SelectContent>
                              <SelectItem value="clear">Any Year</SelectItem>
                              <SelectItem value="22">IV Year (22 Batch)</SelectItem>
                              <SelectItem value="23">III Year (23 Batch)</SelectItem>
                              <SelectItem value="24">II Year (24 Batch)</SelectItem>
                              <SelectItem value="25">I Year (25 Batch)</SelectItem>
                            </SelectContent>
                          </Select>
                        </div>

                        <div className="space-y-2">
                          <Label className="text-xs">Semester</Label>
                          <Select
                            value={newJob.filters.semester}
                            onValueChange={(val) => setNewJob({ ...newJob, filters: { ...newJob.filters, semester: val === "clear" ? "" : val } })}
                          >
                            <SelectTrigger><SelectValue placeholder="Any" /></SelectTrigger>
                            <SelectContent>
                              <SelectItem value="clear">Any Semester</SelectItem>
                              <SelectItem value="Semester I">Semester I</SelectItem>
                              <SelectItem value="Semester II">Semester II</SelectItem>
                            </SelectContent>
                          </Select>
                        </div>

                        <div className="space-y-2">
                          <Label className="text-xs">Section</Label>
                          <Select
                            value={newJob.filters.section}
                            onValueChange={(val) => setNewJob({ ...newJob, filters: { ...newJob.filters, section: val === "clear" ? "" : val } })}
                          >
                            <SelectTrigger><SelectValue placeholder="Any" /></SelectTrigger>
                            <SelectContent>
                              <SelectItem value="clear">Any Section</SelectItem>
                              {["A", "B", "C"].map(sec => (
                                <SelectItem key={sec} value={sec}>Section {sec}</SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </div>
                      </div>

                      {/* Student Selection List */}
                      <div className="mt-6 space-y-3">
                        <div className="flex items-center justify-between">
                            <Label className="text-sm font-semibold">Select Students ({studentList.length} found)</Label>
                            <div className="flex items-center gap-4 text-xs">
                                <div className="flex items-center gap-1">
                                    <Checkbox 
                                        id="select-all" 
                                        checked={studentList.length > 0 && selectedRollNumbers.length === studentList.length}
                                        onCheckedChange={(checked) => {
                                            if (checked) {
                                                setSelectedRollNumbers(studentList.map(s => s.rollNumber));
                                            } else {
                                                setSelectedRollNumbers([]);
                                            }
                                        }}
                                    />
                                    <label htmlFor="select-all">Select All</label>
                                </div>
                                <span className="text-primary font-medium">{selectedRollNumbers.length} selected</span>
                            </div>
                        </div>

                        <ScrollArea className="h-[200px] border rounded-md p-2 bg-muted/20">
                            {loadingStudents ? (
                                <div className="flex items-center justify-center h-full">
                                    <Loader2 className="w-5 h-5 animate-spin text-primary" />
                                </div>
                            ) : studentList.length === 0 ? (
                                <div className="flex items-center justify-center h-full text-xs text-muted-foreground italic">
                                    No students found for these filters
                                </div>
                            ) : (
                                <div className="grid grid-cols-2 gap-2">
                                    {studentList.map((student) => {
                                        const isIVYearCSEB = newJob.filters.year === "22" && newJob.filters.branch === "CSE" && newJob.filters.section === "B";
                                        return (
                                            <div key={student.rollNumber} className="flex items-center gap-3 p-1.5 hover:bg-muted/50 rounded-md transition-colors">
                                                <Checkbox 
                                                    id={`std-${student.rollNumber}`} 
                                                    checked={selectedRollNumbers.includes(student.rollNumber)}
                                                    onCheckedChange={(checked) => {
                                                        if (checked) {
                                                            setSelectedRollNumbers([...selectedRollNumbers, student.rollNumber]);
                                                        } else {
                                                            setSelectedRollNumbers(selectedRollNumbers.filter(r => r !== student.rollNumber));
                                                        }
                                                    }}
                                                />
                                                <label htmlFor={`std-${student.rollNumber}`} className="text-xs cursor-pointer truncate">
                                                    <span className="font-bold mr-2">{student.rollNumber}</span>
                                                    {isIVYearCSEB && <span>{student.name}</span>}
                                                </label>
                                            </div>
                                        );
                                    })}
                                </div>
                            )}
                        </ScrollArea>
                      </div>
                    </div>
                  </div>

                  <div className="pt-4 mt-6 border-t border-muted space-y-4">
                    <h3 className="text-lg font-bold mb-4">Job Details & Requirements</h3>
                    {/* Description */}
                    <div className="space-y-2">
                      <Label htmlFor="description" className="text-sm font-semibold">Job Description</Label>
                      <Textarea
                        id="description"
                        value={newJob.description}
                        onChange={(e) =>
                          setNewJob({ ...newJob, description: e.target.value })
                        }
                        placeholder="Describe the role, responsibilities, requirements..."
                        rows={4}
                      />
                    </div>
                  </div>

                  {/* Bond and Rounds */}
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="bond" className="text-sm font-semibold">Bond Period</Label>
                      <Input
                        id="bond"
                        value={newJob.bond}
                        onChange={(e) =>
                          setNewJob({ ...newJob, bond: e.target.value })
                        }
                        placeholder="e.g., 2 years, No Bond"
                      />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="rounds" className="text-sm font-semibold">Selection Rounds</Label>
                      <Input
                        id="rounds"
                        value={newJob.rounds}
                        onChange={(e) =>
                          setNewJob({ ...newJob, rounds: e.target.value })
                        }
                        placeholder="e.g., Aptitude, Technical, HR"
                      />
                      <p className="text-xs text-muted-foreground">Separate with commas</p>
                    </div>
                  </div>

                  {/* File Attachments Section */}
                  <div className="space-y-3 p-4 border rounded-lg bg-muted/30">
                    <Label className="text-sm font-semibold flex items-center gap-2">
                      <FileText className="w-4 h-4" />
                      Attachments (Job Description, Forms, etc.)
                    </Label>

                    {/* Attached Files List */}
                    {attachedFiles.length > 0 && (
                      <div className="space-y-2">
                        {attachedFiles.map((file, index) => (
                          <div
                            key={index}
                            className="flex items-center justify-between p-2 bg-background rounded border"
                          >
                            <div className="flex items-center gap-2">
                              {file.type === "drive" ? (
                                <Link className="w-4 h-4 text-blue-500" />
                              ) : (
                                <FileText className="w-4 h-4 text-muted-foreground" />
                              )}
                              <span className="text-sm truncate max-w-[200px]">{file.name}</span>
                              {file.size && (
                                <span className="text-xs text-muted-foreground">
                                  ({(file.size / 1024).toFixed(1)} KB)
                                </span>
                              )}
                            </div>
                            <Button
                              type="button"
                              variant="ghost"
                              size="sm"
                              onClick={() => removeFile(index)}
                            >
                              <X className="w-4 h-4" />
                            </Button>
                          </div>
                        ))}
                      </div>
                    )}

                    {/* Upload Buttons */}
                    <div className="flex flex-wrap gap-2">
                      <input
                        type="file"
                        ref={fileInputRef}
                        onChange={handleFileUpload}
                        multiple
                        accept=".pdf,.doc,.docx,.xls,.xlsx,.ppt,.pptx,.jpg,.jpeg,.png"
                        className="hidden"
                      />
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        onClick={() => fileInputRef.current?.click()}
                      >
                        <Upload className="w-4 h-4 mr-2" />
                        Upload from Computer
                      </Button>
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        onClick={() => setShowDriveLinkInput(!showDriveLinkInput)}
                      >
                        <Link className="w-4 h-4 mr-2" />
                        Add Google Drive Link
                      </Button>
                    </div>

                    {/* Google Drive Link Input */}
                    {showDriveLinkInput && (
                      <div className="flex gap-2 mt-2">
                        <Input
                          value={driveLink}
                          onChange={(e) => setDriveLink(e.target.value)}
                          placeholder="Paste Google Drive link here..."
                          className="flex-1"
                        />
                        <Button
                          type="button"
                          size="sm"
                          onClick={handleAddDriveLink}
                        >
                          Add
                        </Button>
                        <Button
                          type="button"
                          variant="ghost"
                          size="sm"
                          onClick={() => {
                            setShowDriveLinkInput(false);
                            setDriveLink("");
                          }}
                        >
                          <X className="w-4 h-4" />
                        </Button>
                      </div>
                    )}
                  </div>

                  {/* Form Actions */}
                  <div className="flex justify-end gap-3 pt-4 border-t">
                    <Button
                      variant="outline"
                      onClick={() => setIsAddModalOpen(false)}
                      disabled={isSubmitting}
                    >
                      Cancel
                    </Button>
                    <Button
                      onClick={handleAddJob}
                      disabled={isSubmitting}
                      className="min-w-[120px]"
                    >
                      {isSubmitting ? (
                        <>
                          <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                          Posting...
                        </>
                      ) : (
                        <>
                          <Plus className="w-4 h-4 mr-2" />
                          Post Job
                        </>
                      )}
                    </Button>
                  </div>
                </div>
              </DialogContent>
            </Dialog>
          </div>
        </div>

        {/* Error Alert */}
        {error && (
          <div className="bg-destructive/10 border border-destructive text-destructive px-4 py-3 rounded-lg">
            <p className="font-medium">Error</p>
            <p className="text-sm">{error}</p>
          </div>
        )}

        {/* Stats Cards */}
        <div className="grid md:grid-cols-3 gap-6">
          <Card>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Total Jobs</p>
                  <p className="text-2xl font-bold">{jobs.length}</p>
                </div>
                <Building2 className="w-8 h-8 text-primary" />
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">Active Jobs</p>
                  <p className="text-2xl font-bold">
                    {jobs.filter((job) => job.status === "Open").length}
                  </p>
                </div>
                <Calendar className="w-8 h-8 text-green-500" />
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardContent className="p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-muted-foreground">
                    Total Applications
                  </p>
                  <p className="text-2xl font-bold">
                    {jobs.reduce((sum, job) => sum + (job.appliedCount || 0), 0)}
                  </p>
                </div>
                <Users className="w-8 h-8 text-blue-500" />
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Jobs Table */}
        <Card>
          <CardHeader>
            <CardTitle>Posted Job Opportunities</CardTitle>
          </CardHeader>
          <CardContent>
            {loading ? (
              <div className="py-12 text-center">
                <Loader2 className="w-8 h-8 animate-spin mx-auto mb-4 text-primary" />
                <p className="text-muted-foreground">Loading jobs...</p>
              </div>
            ) : jobs.length === 0 ? (
              <div className="py-12 text-center">
                <Building2 className="w-12 h-12 mx-auto mb-4 text-muted-foreground" />
                <h3 className="text-lg font-medium mb-2">No jobs posted yet</h3>
                <p className="text-muted-foreground mb-4">
                  Click "Post New Job" to add your first job opportunity.
                </p>
              </div>
            ) : (
              <div className="space-y-4">
                {jobs.map((job) => (
                  <Card key={job.job_id || job._id} className="p-4">
                    <div className="flex items-start justify-between">
                      <div className="space-y-2">
                        <div className="flex items-center gap-3">
                          <div className="w-10 h-10 bg-primary/10 rounded-lg flex items-center justify-center">
                            <Building2 className="w-5 h-5 text-primary" />
                          </div>
                          <div>
                            <h3 className="font-semibold text-lg">
                              {job.title}
                            </h3>
                            <p className="text-primary font-medium">
                              {job.company}
                            </p>
                          </div>
                        </div>
                        <div className="flex flex-wrap gap-2">
                          <Badge variant="outline">{job.type}</Badge>
                          {getStatusBadge(getEffectiveStatus(job))}
                          <Badge variant="secondary">ID: {job.job_id}</Badge>
                        </div>
                      </div>

                      <div className="flex items-center gap-2">
                        <Button variant="outline" size="sm" onClick={() => handleViewJob(job)}>
                          <Eye className="w-4 h-4 mr-1" />
                          View
                        </Button>
                        <Button variant="outline" size="sm" onClick={() => handleOpenEdit(job)}>
                          <Edit className="w-4 h-4 mr-1" />
                          Edit
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => handleDeleteClick(job)}
                          className="text-red-500 hover:text-red-700"
                        >
                          <Trash2 className="w-4 h-4 mr-1" />
                          Delete
                        </Button>
                      </div>
                    </div>

                    <div className="grid md:grid-cols-4 gap-4 mt-4 pt-4 border-t">
                      <div>
                        <p className="text-sm text-muted-foreground">CTC</p>
                        <p className="font-medium">{job.ctc}</p>
                      </div>
                      <div>
                        <p className="text-sm text-muted-foreground">
                          Deadline
                        </p>
                        <p className="font-medium">
                          {formatDate(job.deadline)}
                        </p>
                      </div>
                      <div>
                        <p className="text-sm text-muted-foreground">
                          Applications
                        </p>
                        <div className="flex gap-2 text-sm">
                          <span className="text-blue-600">
                            {job.appliedCount || 0} Applied
                          </span>
                          <span className="text-green-600">
                            {job.selectedCount || 0} Selected
                          </span>
                        </div>
                      </div>
                      <div>
                        <p className="text-sm text-muted-foreground">
                          Eligibility
                        </p>
                        <div className="flex flex-wrap gap-1">
                          {job.eligibility?.slice(0, 2).map((branch) => (
                            <Badge
                              key={branch}
                              variant="outline"
                              className="text-xs"
                            >
                              {branch}
                            </Badge>
                          ))}
                          {job.eligibility?.length > 2 && (
                            <span className="text-xs text-muted-foreground">
                              +{job.eligibility.length - 2} more
                            </span>
                          )}
                        </div>
                      </div>
                    </div>
                  </Card>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      {/* ═══ VIEW MODAL ═══ */}
      <Dialog open={isViewModalOpen} onOpenChange={setIsViewModalOpen}>
        <DialogContent className="max-w-5xl w-[95vw] max-h-[85vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="text-xl font-bold flex items-center gap-2">
              <Building2 className="w-5 h-5 text-primary" />
              {viewJob?.title}
            </DialogTitle>
            <DialogDescription className="text-primary font-medium">
              {viewJob?.company} · {viewJob?.type}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4 py-2">
            {/* Job summary row */}
            <div className="grid grid-cols-3 gap-3">
              <div className="p-3 rounded-lg bg-muted/50 text-center">
                <p className="text-xs text-muted-foreground">CTC</p>
                <p className="font-semibold text-sm">{viewJob?.ctc}</p>
              </div>
              <div className="p-3 rounded-lg bg-muted/50 text-center">
                <p className="text-xs text-muted-foreground">Deadline</p>
                <p className="font-semibold text-sm">{viewJob?.deadline ? formatDate(viewJob.deadline) : "—"}</p>
              </div>
              <div className="p-3 rounded-lg bg-muted/50 text-center">
                <p className="text-xs text-muted-foreground">Status</p>
                <p className="font-semibold text-sm">{viewJob ? getEffectiveStatus(viewJob) : ""}</p>
              </div>
            </div>

            {/* Registered Students */}
            <div>
              <div className="flex items-center justify-between mb-3">
                <h3 className="font-semibold text-sm flex items-center gap-2">
                  <Users className="w-4 h-4 text-primary" />
                  Registered Students ({applicants.length})
                </h3>
                {applicants.length > 0 && (
                  <Button onClick={handleExportExcel} size="sm" className="h-8 text-xs bg-primary text-primary-foreground shadow-sm">
                    <Download className="w-3.5 h-3.5 mr-1.5" />
                    Download Extracted (Excel)
                  </Button>
                )}
              </div>

              {loadingApplicants ? (
                <div className="py-8 text-center">
                  <Loader2 className="w-6 h-6 animate-spin mx-auto mb-2 text-primary" />
                  <p className="text-sm text-muted-foreground">Loading applicants...</p>
                </div>
              ) : applicants.length === 0 ? (
                <div className="py-8 text-center border rounded-lg bg-muted/20">
                  <Users className="w-10 h-10 mx-auto mb-2 text-muted-foreground/40" />
                  <p className="text-sm text-muted-foreground">No students have registered yet</p>
                </div>
              ) : (
                <div className="border rounded-lg overflow-x-auto">
                  <table className="w-full text-sm">
                    <thead>
                      <tr className="bg-muted/50 border-b">
                        <th className="text-left py-2.5 px-3 font-medium text-muted-foreground whitespace-nowrap">S.No</th>
                        <th className="text-left py-2.5 px-3 font-medium text-muted-foreground">Student Name</th>
                        <th className="text-left py-2.5 px-3 font-medium text-muted-foreground whitespace-nowrap">Roll No</th>
                        <th className="text-left py-2.5 px-3 font-medium text-muted-foreground">Branch</th>
                        <th className="text-left py-2.5 px-3 font-medium text-muted-foreground">Resume</th>
                        <th className="text-left py-2.5 px-3 font-medium text-muted-foreground">Status</th>
                        <th className="text-left py-2.5 px-3 font-medium text-muted-foreground whitespace-nowrap">Timestamp</th>
                      </tr>
                    </thead>
                    <tbody>
                      {applicants.map((app, idx) => (
                        <tr key={app._id} className="border-b last:border-0 hover:bg-muted/30 transition-colors">
                          <td className="py-2.5 px-3 text-muted-foreground">{idx + 1}</td>
                          <td className="py-2.5 px-3">
                            <div className="flex items-center gap-2">
                              <div className="w-7 h-7 rounded-full bg-primary/10 flex items-center justify-center text-xs font-semibold text-primary">
                                {app.studentId?.name?.charAt(0) || "?"}
                              </div>
                              <span className="font-medium">{app.studentId?.name || "Unknown"}</span>
                            </div>
                          </td>
                          <td className="py-2.5 px-3 font-mono text-xs whitespace-nowrap">{app.studentId?.collegeId || "—"}</td>
                          <td className="py-2.5 px-3">{branchShortName(app.studentId?.branch)}</td>
                          <td className="py-2.5 px-3">
                            {(!app.studentId?.email || !app.studentId?.name) ? (
                              <span className="text-muted-foreground text-xs italic">Incomplete Profile</span>
                            ) : (
                              <Button
                                variant="outline"
                                size="sm"
                                disabled={isGeneratingResume === app.studentId._id}
                                className="h-7 text-xs border-primary text-primary hover:bg-primary/10"
                                onClick={() => handleViewResume(app.studentId)}
                                title="Auto-generated from student profile"
                              >
                                {isGeneratingResume === app.studentId._id ? (
                                  <><Loader2 className="w-3 h-3 mr-1 animate-spin" /> Generating</>
                                ) : (
                                  "View Resume"
                                )}
                              </Button>
                            )}
                          </td>
                          <td className="py-2.5 px-3 whitespace-nowrap">
                            <Badge variant="outline" className={`text-xs ${getApplicationStatusColor(app.status)}`}>
                              {app.status}
                            </Badge>
                          </td>
                          <td className="py-2.5 px-3 text-muted-foreground text-xs whitespace-nowrap">
                            {app.appliedDate ? new Date(app.appliedDate).toLocaleDateString("en-IN", { day: "2-digit", month: "short" }) + ", " + new Date(app.appliedDate).toLocaleTimeString("en-IN", { hour: "2-digit", minute: "2-digit" }) : "—"}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        </DialogContent>
      </Dialog>

      {/* ═══ EDIT MODAL ═══ */}
      <Dialog open={isEditModalOpen} onOpenChange={setIsEditModalOpen}>
        <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="text-xl font-bold">Edit Job Opportunity</DialogTitle>
            <DialogDescription>Update the details for this job posting.</DialogDescription>
          </DialogHeader>

          {editJob && (
            <div className="space-y-5 py-2">
              {/* Title & Company */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Job Title</Label>
                  <Input
                    value={editJob.title}
                    onChange={(e) => setEditJob({ ...editJob, title: e.target.value })}
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Company Name</Label>
                  <Input
                    value={editJob.company}
                    onChange={(e) => setEditJob({ ...editJob, company: e.target.value })}
                  />
                </div>
              </div>

              {/* Type & CTC */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Job Type</Label>
                  <Select value={editJob.type} onValueChange={(v) => setEditJob({ ...editJob, type: v })}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Full Time">Full Time</SelectItem>
                      <SelectItem value="Internship">Internship</SelectItem>
                      <SelectItem value="Intern + Full Time">Intern + Full Time</SelectItem>
                      <SelectItem value="Contract">Contract</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">CTC / Package</Label>
                  <Input
                    value={editJob.ctc}
                    onChange={(e) => setEditJob({ ...editJob, ctc: e.target.value })}
                  />
                </div>
              </div>

              {/* Visibility & Selection */}
              <div className="pt-4 mt-2 border-t border-muted">
                <h3 className="text-sm font-bold mb-4 uppercase tracking-wider text-muted-foreground">Job Visibility & Student Selection</h3>
                
                <div className="space-y-4">
                  <div className="space-y-2">
                    <Label className="text-sm font-semibold">Target Branch</Label>
                    <Select 
                      value={editJob.filters.branch} 
                      onValueChange={(val) => setEditJob({ ...editJob, filters: { ...editJob.filters, branch: val } })}
                    >
                        <SelectTrigger>
                            <SelectValue placeholder="Select Branch" />
                        </SelectTrigger>
                        <SelectContent>
                            {availableBranches.map(b => (
                                <SelectItem key={b} value={b}>{b}</SelectItem>
                            ))}
                        </SelectContent>
                    </Select>
                  </div>

                  <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                    <div className="space-y-2">
                      <Label className="text-xs">Degree</Label>
                      <Select
                        value={editJob.filters.degree}
                        onValueChange={(val) => setEditJob({ ...editJob, filters: { ...editJob.filters, degree: val === "clear" ? "" : val } })}
                      >
                        <SelectTrigger><SelectValue placeholder="Any" /></SelectTrigger>
                        <SelectContent>
                          <SelectItem value="clear">Any Degree</SelectItem>
                          <SelectItem value="Major">Major</SelectItem>
                          <SelectItem value="Minor">Minor</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                    
                    <div className="space-y-2">
                      <Label className="text-xs">Year</Label>
                      <Select
                        value={editJob.filters.year}
                        onValueChange={(val) => setEditJob({ ...editJob, filters: { ...editJob.filters, year: val === "clear" ? "" : val } })}
                      >
                        <SelectTrigger><SelectValue placeholder="Any" /></SelectTrigger>
                        <SelectContent>
                          <SelectItem value="clear">Any Year</SelectItem>
                          <SelectItem value="22">IV Year (22 Batch)</SelectItem>
                          <SelectItem value="23">III Year (23 Batch)</SelectItem>
                          <SelectItem value="24">II Year (24 Batch)</SelectItem>
                          <SelectItem value="25">I Year (25 Batch)</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>

                    <div className="space-y-2">
                      <Label className="text-xs">Semester</Label>
                      <Select
                        value={editJob.filters.semester}
                        onValueChange={(val) => setEditJob({ ...editJob, filters: { ...editJob.filters, semester: val === "clear" ? "" : val } })}
                      >
                        <SelectTrigger><SelectValue placeholder="Any" /></SelectTrigger>
                        <SelectContent>
                          <SelectItem value="clear">Any Semester</SelectItem>
                          <SelectItem value="Semester I">Semester I</SelectItem>
                          <SelectItem value="Semester II">Semester II</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>

                    <div className="space-y-2">
                      <Label className="text-xs">Section</Label>
                      <Select
                        value={editJob.filters.section}
                        onValueChange={(val) => setEditJob({ ...editJob, filters: { ...editJob.filters, section: val === "clear" ? "" : val } })}
                      >
                        <SelectTrigger><SelectValue placeholder="Any" /></SelectTrigger>
                        <SelectContent>
                          <SelectItem value="clear">Any Section</SelectItem>
                          {["A", "B", "C"].map(sec => (
                            <SelectItem key={sec} value={sec}>Section {sec}</SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                  </div>

                  <div className="mt-4 space-y-3">
                    <div className="flex items-center justify-between">
                        <Label className="text-sm font-semibold">Select Students ({studentList.length} found)</Label>
                        <div className="flex items-center gap-4 text-xs">
                             <div className="flex items-center gap-1">
                                <Checkbox 
                                    id="edit-select-all" 
                                    checked={studentList.length > 0 && selectedRollNumbers.length === studentList.length}
                                    onCheckedChange={(checked) => {
                                        if (checked) {
                                            setSelectedRollNumbers(studentList.map(s => s.rollNumber));
                                        } else {
                                            setSelectedRollNumbers([]);
                                        }
                                    }}
                                />
                                <label htmlFor="edit-select-all">Select All</label>
                            </div>
                            <span className="text-primary font-medium">{selectedRollNumbers.length} selected</span>
                        </div>
                    </div>

                    <ScrollArea className="h-[180px] border rounded-md p-2 bg-muted/20">
                        {loadingStudents ? (
                            <div className="flex items-center justify-center h-full">
                                <Loader2 className="w-5 h-5 animate-spin text-primary" />
                            </div>
                        ) : studentList.length === 0 ? (
                            <div className="flex items-center justify-center h-full text-xs text-muted-foreground italic">
                                No students found for these filters
                            </div>
                        ) : (
                            <div className="grid grid-cols-2 gap-2">
                                {studentList.map((student) => {
                                    const isIVYearCSEB = editJob.filters.year === "22" && editJob.filters.branch === "CSE" && editJob.filters.section === "B";
                                    return (
                                        <div key={student.rollNumber} className="flex items-center gap-3 p-1.5 hover:bg-muted/50 rounded-md transition-colors">
                                            <Checkbox 
                                                id={`edit-std-${student.rollNumber}`} 
                                                checked={selectedRollNumbers.includes(student.rollNumber)}
                                                onCheckedChange={(checked) => {
                                                    if (checked) {
                                                        setSelectedRollNumbers([...selectedRollNumbers, student.rollNumber]);
                                                    } else {
                                                        setSelectedRollNumbers(selectedRollNumbers.filter(r => r !== student.rollNumber));
                                                    }
                                                }}
                                            />
                                            <label htmlFor={`edit-std-${student.rollNumber}`} className="text-xs cursor-pointer truncate">
                                                <span className="font-bold mr-2">{student.rollNumber}</span>
                                                {isIVYearCSEB && <span>{student.name}</span>}
                                            </label>
                                        </div>
                                    );
                                })}
                            </div>
                        )}
                    </ScrollArea>
                  </div>
                </div>
              </div>

              {/* Deadline & Location */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Stipend</Label>
                  <Input
                    value={editJob.stipend || ""}
                    onChange={(e) => setEditJob({ ...editJob, stipend: e.target.value })}
                    placeholder="N/A"
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Location</Label>
                  <Input
                    value={editJob.location || ""}
                    onChange={(e) => setEditJob({ ...editJob, location: e.target.value })}
                  />
                </div>
              </div>

              {/* Deadline */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold flex items-center gap-2">
                  <Clock className="w-4 h-4" /> Deadline
                </Label>
                <div className="grid grid-cols-2 gap-3">
                  <Input
                    type="date"
                    value={editJob.deadlineDate}
                    onChange={(e) => setEditJob({ ...editJob, deadlineDate: e.target.value })}
                  />
                  <Input
                    type="time"
                    value={editJob.deadlineTime}
                    onChange={(e) => setEditJob({ ...editJob, deadlineTime: e.target.value })}
                  />
                </div>
              </div>

              {/* Description */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">Description</Label>
                <Textarea
                  value={editJob.description || ""}
                  onChange={(e) => setEditJob({ ...editJob, description: e.target.value })}
                  rows={3}
                />
              </div>

              {/* Bond & Rounds */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Bond Period</Label>
                  <Input
                    value={editJob.bond || ""}
                    onChange={(e) => setEditJob({ ...editJob, bond: e.target.value })}
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-sm font-semibold">Selection Rounds</Label>
                  <Input
                    value={editJob.rounds || ""}
                    onChange={(e) => setEditJob({ ...editJob, rounds: e.target.value })}
                    placeholder="e.g., Aptitude, Technical, HR"
                  />
                </div>
              </div>

              {/* Eligibility */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold">Eligible Branches</Label>
                <Select
                  value={editJob.eligibility?.[0] || ""}
                  onValueChange={(v) => setEditJob({ ...editJob, eligibility: v === "All Branches" ? ["All Branches"] : [v] })}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="All Branches">All Branches</SelectItem>
                    <SelectItem value="CSE">CSE</SelectItem>
                    <SelectItem value="IT">IT</SelectItem>
                    <SelectItem value="ECE">ECE</SelectItem>
                    <SelectItem value="EEE">EEE</SelectItem>
                    <SelectItem value="MECH">MECH</SelectItem>
                    <SelectItem value="CIVIL">CIVIL</SelectItem>
                    <SelectItem value="DS">DS</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              {/* File Attachments */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold flex items-center gap-2">
                  <FileText className="w-4 h-4" /> Attachments
                </Label>

                {/* Existing files */}
                {editAttachedFiles.length > 0 && (
                  <div className="space-y-2">
                    {editAttachedFiles.map((file, index) => (
                      <div key={index} className="flex items-center justify-between bg-muted/30 rounded-md px-3 py-2">
                        <div className="flex items-center gap-2">
                          <FileText className="w-4 h-4 text-muted-foreground" />
                          <span className="text-sm truncate max-w-[250px]">{file.name}</span>
                          {file.size && (
                            <span className="text-xs text-muted-foreground">({(file.size / 1024).toFixed(1)} KB)</span>
                          )}
                        </div>
                        <Button variant="ghost" size="sm" onClick={() => removeEditFile(index)} className="h-6 w-6 p-0">
                          <X className="w-3 h-3" />
                        </Button>
                      </div>
                    ))}
                  </div>
                )}

                {/* Upload buttons */}
                <div className="flex gap-2">
                  <input
                    type="file"
                    ref={editFileInputRef}
                    className="hidden"
                    multiple
                    accept=".pdf,.doc,.docx,.jpg,.jpeg,.png"
                    onChange={handleEditFileUpload}
                  />
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={() => editFileInputRef.current?.click()}
                  >
                    <FileText className="w-4 h-4 mr-2" />
                    Upload File
                  </Button>
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={() => setShowEditDriveLinkInput(!showEditDriveLinkInput)}
                  >
                    <ExternalLink className="w-4 h-4 mr-2" />
                    Drive Link
                  </Button>
                </div>

                {/* Drive link input */}
                {showEditDriveLinkInput && (
                  <div className="flex gap-2">
                    <Input
                      placeholder="Paste Google Drive link..."
                      value={editDriveLink}
                      onChange={(e) => setEditDriveLink(e.target.value)}
                    />
                    <Button size="sm" onClick={handleAddEditDriveLink}>Add</Button>
                  </div>
                )}
              </div>

              {/* Actions */}
              <div className="flex justify-end gap-3 pt-3 border-t">
                <Button variant="outline" onClick={() => setIsEditModalOpen(false)} disabled={isEditing}>
                  Cancel
                </Button>
                <Button onClick={handleSaveEdit} disabled={isEditing} className="min-w-[100px]">
                  {isEditing ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Saving...</> : "Save Changes"}
                </Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>

      {/* ═══ DELETE CONFIRMATION ═══ */}
      <AlertDialog open={isDeleteDialogOpen} onOpenChange={setIsDeleteDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle className="flex items-center gap-2">
              <AlertTriangle className="w-5 h-5 text-red-500" />
              Delete Job Permanently?
            </AlertDialogTitle>
            <AlertDialogDescription className="space-y-2">
              <p>
                You are about to delete <strong>"{deleteTarget?.title}"</strong> at <strong>{deleteTarget?.company}</strong>.
              </p>
              {(deleteTarget?.appliedCount || 0) > 0 && (
                <p className="text-red-500 font-medium">
                  ⚠️ {deleteTarget.appliedCount} student(s) have applied to this job. Their applications will also be deleted.
                </p>
              )}
              <p>This action cannot be undone.</p>
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={isDeleting}>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleConfirmDelete}
              disabled={isDeleting}
              className="bg-red-600 hover:bg-red-700 text-white"
            >
              {isDeleting ? <><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Deleting...</> : "Delete Job"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </AdminLayout>
  );
};

export default AdminPlacement;

import { useState, useEffect } from "react";
import AdminLayout from "@/components/AdminLayout";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { useToast } from "@/hooks/use-toast";
import { getStoredToken } from "@/lib/api";
import { BarChart3, GraduationCap, Building2, CalendarDays, UsersRound, Trophy } from "lucide-react";

export default function Reports() {
    const { toast } = useToast();
    const [reports, setReports] = useState<any>(null);

    const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || "http://127.0.0.1:5000/api";

    useEffect(() => {
        const fetchReports = async () => {
            try {
                const response = await fetch(`${API_BASE_URL}/admin/reports`, {
                    headers: {
                        Authorization: `Bearer ${getStoredToken()}`,
                    }
                });
                if (response.ok) {
                    const data = await response.json();
                    setReports(data);
                }
            } catch (err) {
                toast({ title: "Warning", description: "Could not load latest reports" });
            }
        };
        fetchReports();
    }, [toast, API_BASE_URL]);

    if (!reports) return <AdminLayout><div className="p-8">Loading Reports...</div></AdminLayout>;

    return (
        <AdminLayout>
            <div className="space-y-6">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Analytics Dashboard</h1>
                    <p className="text-muted-foreground mt-2">
                        Comprehensive reports on Attendance, Placements, Events, Clubs, and Results.
                    </p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    <Card>
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium">Total Students</CardTitle>
                            <GraduationCap className="h-4 w-4 text-blue-600" />
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">{reports.users.studentCount}</div>
                            <p className="text-xs text-muted-foreground">Active in the system</p>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium">Placements / Job Posts</CardTitle>
                            <Building2 className="h-4 w-4 text-green-600" />
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">{reports.placements.totalSelected} / {reports.placements.totalPosted}</div>
                            <p className="text-xs text-muted-foreground">Students Placed this year</p>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium">Graduated Alumni</CardTitle>
                            <Trophy className="h-4 w-4 text-orange-600" />
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">{reports.users.graduatedCount}</div>
                            <p className="text-xs text-muted-foreground">Moved to Archive Collection</p>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium">Results Pass Rate</CardTitle>
                            <BarChart3 className="h-4 w-4 text-purple-600" />
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">{reports.results.passPercentage}</div>
                            <p className="text-xs text-muted-foreground">Average CGPA: {reports.results.avgCGPA}</p>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium">Active Events</CardTitle>
                            <CalendarDays className="h-4 w-4 text-emerald-600" />
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">{reports.events.activeEvents}</div>
                            <p className="text-xs text-muted-foreground">Participation: {reports.events.participationRate}</p>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium">Active Clubs</CardTitle>
                            <UsersRound className="h-4 w-4 text-rose-600" />
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">{reports.clubs.totalClubs}</div>
                            <p className="text-xs text-muted-foreground">{reports.clubs.activeMembers} Members across campus</p>
                        </CardContent>
                    </Card>
                </div>
            </div>
        </AdminLayout>
    );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Label } from "@/components/ui/label";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import AdminLayout from "@/components/AdminLayout";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import {
    CheckCircle2,
    FileSpreadsheet,
    Loader2,
    Users,
    Calculator,
    Send,
    Eye,
    Edit,
    BarChart3,
} from "lucide-react";
import {
    getSubmittedGradeSheets,
    getGradeSheet,
    addExternalMarks,
    publishResults,
    GradeSheet,
    StudentGrade,
    calculateGrade,
    calculateInternalMarks,
} from "@/services/gradeService";

const AdminResults = () => {
    const { userData } = useAuth();
    const [gradeSheets, setGradeSheets] = useState<GradeSheet[]>([]);
    const [loading, setLoading] = useState(true);
    const [selectedSheet, setSelectedSheet] = useState<GradeSheet | null>(null);
    const [editingGrades, setEditingGrades] = useState<StudentGrade[]>([]);
    const [saving, setSaving] = useState(false);
    const [publishing, setPublishing] = useState(false);
    const [isEditing, setIsEditing] = useState(false);

    // Filters
    const [filterDegree, setFilterDegree] = useState("Major");
    const [filterYear, setFilterYear] = useState("IV Year");
    const [filterBranch, setFilterBranch] = useState("CSE");
    const [filterSection, setFilterSection] = useState("B");
    const [filterSemester, setFilterSemester] = useState("Semester I");

    // Fetch submitted grade sheets
    const fetchGradeSheets = async () => {
        try {
            setLoading(true);
            const data = await getSubmittedGradeSheets();
            setGradeSheets(data);
        } catch (error) {
            console.error("Error fetching grade sheets:", error);
            toast.error("Failed to load grade sheets");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchGradeSheets();
    }, []);

    // Load a grade sheet for editing
    const handleOpenSheet = async (sheet: GradeSheet) => {
        try {
            const fullSheet = await getGradeSheet(sheet._id);
            setSelectedSheet(fullSheet);
            setEditingGrades([...fullSheet.studentGrades]);
            setIsEditing(false);
        } catch (error) {
            console.error("Error loading grade sheet:", error);
            toast.error("Failed to load grade sheet");
        }
    };

    // Update external marks
    const handleExternalChange = (studentId: string, value: string) => {
        const numValue = value === "" ? null : parseFloat(value);
        setEditingGrades((prev) =>
            prev.map((g) =>
                g.studentId === studentId ? { ...g, external: numValue } : g
            )
        );
    };

    // Save external marks
    const handleSaveExternal = async () => {
        if (!selectedSheet) return;

        try {
            setSaving(true);
            const updates = editingGrades
                .filter((g) => g.external !== null)
                .map((g) => ({ studentId: g.studentId, external: g.external as number }));

            await addExternalMarks(selectedSheet._id, updates);
            toast.success("External marks saved!");

            // Refresh the sheet
            const updatedSheet = await getGradeSheet(selectedSheet._id);
            setSelectedSheet(updatedSheet);
            setEditingGrades([...updatedSheet.studentGrades]);
            setIsEditing(false);
            fetchGradeSheets();
        } catch (error) {
            console.error("Error saving external marks:", error);
            toast.error("Failed to save external marks");
        } finally {
            setSaving(false);
        }
    };

    // Publish results
    const handlePublish = async () => {
        if (!selectedSheet) return;

        // Check if all students have external marks
        const missingExternal = editingGrades.filter(
            (g) => g.external === null && g.internalMarks !== null
        );
        if (missingExternal.length > 0) {
            toast.error(`${missingExternal.length} students are missing external marks`);
            return;
        }

        try {
            setPublishing(true);
            await publishResults(selectedSheet._id, userData?.collegeId || "ADMIN");
            toast.success("Results published successfully!");
            setSelectedSheet(null);
            fetchGradeSheets();
        } catch (error) {
            console.error("Error publishing results:", error);
            toast.error("Failed to publish results");
        } finally {
            setPublishing(false);
        }
    };

    const handleBulkPublish = async () => {
        if (!userData?.collegeId) return;

        const pendingSheets = filteredGradeSheets.filter(
            (s) => s.status === "Submitted" || s.status === "Modified"
        );
        if (pendingSheets.length === 0) {
            toast.info("No pending results to publish for this section.");
            return;
        }

        if (!confirm(`Are you sure you want to logically publish all ${pendingSheets.length} pending subjects for this section? This locks them from further automated modification.`)) {
            return;
        }

        try {
            setPublishing(true);
            for (const sheet of pendingSheets) {
                await publishResults(sheet._id, userData.collegeId);
            }
            toast.success("All section results published successfully!");
            fetchGradeSheets();
        } catch (error) {
            console.error("Error bulk publishing:", error);
            toast.error("Failed to publish some results");
        } finally {
            setPublishing(false);
        }
    };

    // Calculate total and grade dynamically 
    const calculateTotal = (g: StudentGrade, external: number | null, isLab = false) => {
        let parsedInternal = null;
        if (isLab) {
            const internal = (g.labSecA || 0) + (g.labSecB || 0) + (g.labSecC || 0) + (g.labSecD || 0);
            parsedInternal = g.labSecA !== null || g.labSecB !== null || g.labSecC !== null || g.labSecD !== null ? internal : null;
        } else {
            parsedInternal = calculateInternalMarks(g.mid1Total, g.mid2Total, g.project);
        }
        if (parsedInternal === null || external === null) return null;
        return parsedInternal + external;
    };

    const getStatusBadge = (status: string) => {
        switch (status) {
            case "Published":
                return <Badge className="bg-green-500 text-white">Published</Badge>;
            case "Submitted":
                return <Badge className="bg-blue-500 text-white">Pending Review</Badge>;
            case "Modified":
                return <Badge className="bg-yellow-500 text-white">Modified</Badge>;
            default:
                return <Badge className="bg-gray-500 text-white">Draft</Badge>;
        }
    };

    const normalize = (val: string | undefined) => val?.replace(/-/g, " ").trim().toLowerCase();
    
    const filteredGradeSheets = gradeSheets.filter(
        (sheet) =>
            (sheet.degree === filterDegree || (!sheet.degree && filterDegree === "Major")) &&
            sheet.year === filterYear &&
            sheet.branch === filterBranch &&
            sheet.section === filterSection &&
            normalize(sheet.semester) === normalize(filterSemester)
    );

    const getGradeBadge = (grade: string | null) => {
        if (!grade) return null;
        const colors: Record<string, string> = {
            "O": "bg-green-600",
            "S": "bg-green-600",
            "A+": "bg-green-500",
            "A": "bg-blue-500",
            "B+": "bg-blue-400",
            "B": "bg-yellow-500",
            "P": "bg-orange-500",
            "F": "bg-red-500",
        };
        return (
            <Badge className={`${colors[grade] || "bg-gray-500"} text-white`}>
                {grade}
            </Badge>
        );
    };

    return (
        <AdminLayout>
            <div className="max-w-7xl mx-auto space-y-6">
                {/* Header */}
                <div className="flex items-center justify-between">
                    <div>
                        <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
                            <BarChart3 className="w-8 h-8 text-primary" />
                            Result Management
                        </h1>
                        <p className="text-muted-foreground mt-1">
                            Add external marks and publish final results
                        </p>
                    </div>
                </div>

                {loading ? (
                    <div className="flex items-center justify-center py-12">
                        <Loader2 className="w-8 h-8 animate-spin text-primary" />
                    </div>
                ) : selectedSheet ? (
                    /* External Marks Entry View */
                    <Card>
                        <CardHeader className="flex flex-row items-center justify-between">
                            <div>
                                <CardTitle className="flex items-center gap-2">
                                    <FileSpreadsheet className="w-5 h-5" />
                                    {selectedSheet.subjectName} ({selectedSheet.subjectCode})
                                </CardTitle>
                                <p className="text-sm text-muted-foreground mt-1">
                                    Section {selectedSheet.section} | Semester {selectedSheet.semester} |
                                    Faculty: {selectedSheet.facultyName}
                                </p>
                            </div>
                            <div className="flex gap-2">
                                <Button
                                    variant="outline"
                                    onClick={() => setIsEditing(!isEditing)}
                                    disabled={saving}
                                >
                                    <Edit className="w-4 h-4 mr-2" />
                                    {isEditing ? "Cancel Edit" : "Edit"}
                                </Button>
                                <Button variant="outline" onClick={() => {
                                    if (isEditing) {
                                        setIsEditing(false);
                                        setEditingGrades([...selectedSheet.studentGrades]);
                                    } else {
                                        setSelectedSheet(null);
                                    }
                                }}>
                                    Back
                                </Button>
                                {isEditing && (
                                    <Button onClick={handleSaveExternal} disabled={saving}>
                                        {saving && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                                        Save Changes
                                    </Button>
                                )}
                                {!isEditing && (selectedSheet.status === "Submitted" || selectedSheet.status === "Modified" || selectedSheet.status === "Published") && (
                                    <Button
                                        onClick={handlePublish}
                                        disabled={publishing}
                                        className="bg-green-600 hover:bg-green-700"
                                    >
                                        {publishing ? (
                                            <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                        ) : (
                                            <CheckCircle2 className="w-4 h-4 mr-2" />
                                        )}
                                        {selectedSheet.status === "Published" ? "Re-publish Results" : "Publish Results"}
                                    </Button>
                                )}
                            </div>
                        </CardHeader>
                        <CardContent>
                            <div className="overflow-x-auto">
                                <Table>
                                    <TableHeader>
                                        <TableRow>
                                            <TableHead className="w-[50px]">#</TableHead>
                                            <TableHead className="w-[120px]">Roll No</TableHead>
                                            {selectedSheet.courseType === "Lab" ? (
                                                <>
                                                    <TableHead className="w-[80px] text-center bg-blue-500/10">Sec A (10)</TableHead>
                                                    <TableHead className="w-[80px] text-center bg-blue-500/10">Sec B (10)</TableHead>
                                                    <TableHead className="w-[80px] text-center bg-blue-500/10">Sec C (10)</TableHead>
                                                    <TableHead className="w-[80px] text-center bg-blue-500/10">Sec D (10)</TableHead>
                                                </>
                                            ) : (
                                                <>
                                                    <TableHead className="text-center bg-blue-500/10">Mid-1 Total (35)</TableHead>
                                                    <TableHead className="text-center bg-blue-500/10">Mid-2 Total (35)</TableHead>
                                                    <TableHead className="text-center bg-purple-500/10">Project (5)</TableHead>
                                                </>
                                            )}
                                            <TableHead className="text-center bg-orange-500/10 font-bold">Internal (40)</TableHead>
                                            <TableHead className="text-center bg-red-500/10 font-bold">External (60)</TableHead>
                                            <TableHead className="text-center bg-cyan-500/10 font-bold">Total (100)</TableHead>
                                            <TableHead className="text-center">Grade</TableHead>
                                        </TableRow>
                                    </TableHeader>
                                    <TableBody>
                                        {editingGrades.map((g, idx) => {
                                            const isLab = selectedSheet.courseType === "Lab";
                                            const external = editingGrades.find(
                                                (e) => e.studentId === g.studentId
                                            )?.external ?? g.external;
                                            const total = calculateTotal(g, external, isLab);
                                            const gradeInfo = total ? calculateGrade(total) : null;

                                            let internalVal = null;
                                            if (isLab) {
                                                const rawInternal = (g.labSecA || 0) + (g.labSecB || 0) + (g.labSecC || 0) + (g.labSecD || 0);
                                                internalVal = (g.labSecA !== null || g.labSecB !== null || g.labSecC !== null || g.labSecD !== null) ? rawInternal : null;
                                            } else {
                                                internalVal = calculateInternalMarks(g.mid1Total, g.mid2Total, g.project);
                                            }

                                            return (
                                                <TableRow key={g.studentId}>
                                                    <TableCell className="text-muted-foreground">{idx + 1}</TableCell>
                                                    <TableCell className="font-mono text-sm">{g.studentId}</TableCell>
                                                    
                                                    {isLab ? (
                                                        <>
                                                            <TableCell className="text-center bg-blue-500/5">{g.labSecA ?? "-"}</TableCell>
                                                            <TableCell className="text-center bg-blue-500/5">{g.labSecB ?? "-"}</TableCell>
                                                            <TableCell className="text-center bg-blue-500/5">{g.labSecC ?? "-"}</TableCell>
                                                            <TableCell className="text-center bg-blue-500/5">{g.labSecD ?? "-"}</TableCell>
                                                        </>
                                                    ) : (
                                                        <>
                                                            <TableCell className="text-center bg-blue-500/5">{g.mid1Total?.toFixed(2) ?? "-"}</TableCell>
                                                            <TableCell className="text-center bg-blue-500/5">{g.mid2Total?.toFixed(2) ?? "-"}</TableCell>
                                                            <TableCell className="text-center bg-purple-500/5">{g.project ?? "-"}</TableCell>
                                                        </>
                                                    )}
                                                    
                                                    <TableCell className="text-center font-bold bg-orange-500/10">
                                                        {internalVal?.toFixed(2) ?? "-"}
                                                    </TableCell>
                                                    <TableCell className="bg-red-500/5">
                                                        <Input
                                                            type="number"
                                                            min={0}
                                                            max={60}
                                                            className="w-16 h-8 text-center"
                                                            value={external ?? ""}
                                                            onChange={(e) =>
                                                                handleExternalChange(g.studentId, e.target.value)
                                                            }
                                                            disabled={!isEditing}
                                                        />
                                                    </TableCell>
                                                    <TableCell className="text-center font-bold text-lg bg-cyan-500/10">
                                                        {total?.toFixed(2) ?? "-"}
                                                    </TableCell>
                                                    <TableCell className="text-center">
                                                        {gradeInfo ? getGradeBadge(gradeInfo.grade) : "-"}
                                                    </TableCell>
                                                </TableRow>
                                            );
                                        })}
                                    </TableBody>
                                </Table>
                            </div>
                        </CardContent>
                    </Card>
                ) : (
                    /* Grade Sheets List */
                    <div className="space-y-6">
                        {/* Filters */}
                        <Card>
                            <CardContent className="p-4">
                                <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
                                    <div className="space-y-2">
                                        <Label>Degree</Label>
                                        <Select value={filterDegree} onValueChange={setFilterDegree}>
                                            <SelectTrigger><SelectValue /></SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="Major">Major</SelectItem>
                                                <SelectItem value="Minor">Minor</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Year</Label>
                                        <Select value={filterYear} onValueChange={setFilterYear}>
                                            <SelectTrigger><SelectValue /></SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="I Year">I Year</SelectItem>
                                                <SelectItem value="II Year">II Year</SelectItem>
                                                <SelectItem value="III Year">III Year</SelectItem>
                                                <SelectItem value="IV Year">IV Year</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Branch</Label>
                                        <Select value={filterBranch} onValueChange={setFilterBranch}>
                                            <SelectTrigger><SelectValue /></SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="CSE">CSE</SelectItem>
                                                <SelectItem value="ECE">ECE</SelectItem>
                                                <SelectItem value="EEE">EEE</SelectItem>
                                                <SelectItem value="MECH">MECH</SelectItem>
                                                <SelectItem value="AI">AI</SelectItem>
                                                <SelectItem value="IT">IT</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Section</Label>
                                        <Select value={filterSection} onValueChange={setFilterSection}>
                                            <SelectTrigger><SelectValue /></SelectTrigger>
                                            <SelectContent>
                                                {["A", "B", "C", "D", "E", "F", "G"].map((s) => (
                                                    <SelectItem key={s} value={s}>Section {s}</SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Semester</Label>
                                        <Select value={filterSemester} onValueChange={setFilterSemester}>
                                            <SelectTrigger><SelectValue /></SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="Semester I">Semester I</SelectItem>
                                                <SelectItem value="Semester II">Semester II</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                </div>

                                <div className="mt-6 flex justify-end border-t pt-4">
                                    <Button
                                        onClick={handleBulkPublish}
                                        disabled={
                                            publishing ||
                                            filteredGradeSheets.length === 0 ||
                                            filteredGradeSheets.every(s => s.status === "Published")
                                        }
                                        className="bg-green-600 hover:bg-green-700"
                                    >
                                        {publishing ? (
                                            <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                        ) : (
                                            <CheckCircle2 className="w-4 h-4 mr-2" />
                                        )}
                                        Publish Section Results
                                    </Button>
                                </div>
                            </CardContent>
                        </Card>

                        {filteredGradeSheets.length === 0 ? (
                            <Card>
                                <CardContent className="py-12 text-center">
                                    <FileSpreadsheet className="w-12 h-12 mx-auto text-muted-foreground mb-4" />
                                    <h3 className="text-lg font-medium mb-2">No Submitted Grade Sheets</h3>
                                    <p className="text-muted-foreground">
                                        Grade sheets submitted by faculty will appear here
                                    </p>
                                </CardContent>
                            </Card>
                        ) : (
                            <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
                                {filteredGradeSheets.map((sheet) => (
                                    <Card
                                        key={sheet._id}
                                        className="cursor-pointer hover:shadow-md transition-shadow"
                                        onClick={() => handleOpenSheet(sheet)}
                                    >
                                        <CardContent className="p-6">
                                            <div className="flex justify-between items-start mb-4">
                                                <div>
                                                    <h3 className="font-semibold text-lg">{sheet.subjectName}</h3>
                                                    <p className="text-sm text-muted-foreground">{sheet.subjectCode}</p>
                                                </div>
                                                {getStatusBadge(sheet.status)}
                                            </div>
                                            <div className="space-y-2 text-sm text-muted-foreground">
                                                <div className="flex items-center gap-2">
                                                    <Users className="w-4 h-4" />
                                                    <span>
                                                        Section {sheet.section} | {sheet.studentCount} students
                                                    </span>
                                                </div>
                                                <div className="flex items-center gap-2">
                                                    <Calculator className="w-4 h-4" />
                                                    <span>
                                                        Sem {sheet.semester} | {sheet.academicYear}
                                                    </span>
                                                </div>
                                                <div className="text-xs">
                                                    Faculty: {sheet.facultyName}
                                                </div>
                                            </div>
                                            <Button
                                                className="w-full mt-4"
                                                variant={sheet.status === "Published" ? "outline" : "default"}
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    handleOpenSheet(sheet);
                                                }}
                                            >
                                                {sheet.status === "Published" ? (
                                                    <>
                                                        <Eye className="w-4 h-4 mr-2" />
                                                        View Results
                                                    </>
                                                ) : (
                                                    <>
                                                        <Send className="w-4 h-4 mr-2" />
                                                        Add External & Publish
                                                    </>
                                                )}
                                            </Button>
                                        </CardContent>
                                    </Card>
                                ))}
                            </div>
                        )}
                    </div>
                )}
            </div>
        </AdminLayout>
    );
};

export default AdminResults;

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { SearchableSelect } from "@/components/ui/searchable-select";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
    AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import AdminLayout from "@/components/AdminLayout";
import { useAuth } from "@/contexts/AuthContext";
import { useToast } from "@/hooks/use-toast";
import {
    Calendar,
    Clock,
    Loader2,
    Plus,
    Trash2,
    Edit,
    Save,
    BookOpen,
    GraduationCap,
    Users,
} from "lucide-react";
import { api } from "@/lib/api";

// ─── Interfaces ───────────────────────────────
interface ScheduleSlot {
    _id?: string;
    slotNumber: number;
    subjectCode: string;
    subjectName: string;
    startTime: string;
    endTime: string;
    facultyName?: string;
    facultyId?: string;
    room?: string;
    classType?: string;
    className?: string; // only if it's faculty schedule
    section?: string; // only if it's faculty schedule
}

interface DaySchedule {
    day: string;
    slots: ScheduleSlot[];
}

interface ScheduleDoc {
    _id: string;
    scheduleType: "student" | "faculty";
    // Student fields
    year?: string;
    branch?: string;
    section?: string;
    semester?: string;
    degree?: string;
    // Faculty fields
    department?: string;
    rollNumber?: string;
    // Common
    schedule: DaySchedule[];
    createdAt: string;
    updatedAt: string;
    createdBy: string;
}

// ─── Constants ────────────────────────────────
const DAYS = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];

const DEFAULT_SLOTS: Omit<ScheduleSlot, '_id'>[] = [];

const DEPARTMENTS = ["CSE", "ECE", "EEE", "Civil", "Mech", "IT", "AIDS", "AIML"];

const AdminScheduler = () => {
    const { userData } = useAuth();
    const { toast } = useToast();

    // ─── Core State ──────────────────────────
    const [loading, setLoading] = useState(false);
    const [schedules, setSchedules] = useState<ScheduleDoc[]>([]);

    // Toggle: "student" or "faculty"
    const [activeTab, setActiveTab] = useState<"student" | "faculty">("student");

    // ─── Filter State ────────────────────────
    // Student filters
    const [filterDegree, setFilterDegree] = useState("");
    const [filterYear, setFilterYear] = useState("");
    const [filterBranch, setFilterBranch] = useState("");
    const [filterSemester, setFilterSemester] = useState("");
    // Faculty filters
    const [filterDepartment, setFilterDepartment] = useState("");
    const [filterRollNumber, setFilterRollNumber] = useState("");

    // ─── Create Schedule Modal ───────────────
    const [isCreateTypeModalOpen, setIsCreateTypeModalOpen] = useState(false);
    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [createType, setCreateType] = useState<"student" | "faculty">("student");

    // Student form
    const [studentForm, setStudentForm] = useState({
        year: "22",
        branch: "05",
        section: "B",
        semester: "VI",
        degree: "Major",
    });

    // Faculty form
    const [facultyForm, setFacultyForm] = useState({
        department: "CSE",
        rollNumber: "",
    });

    // ─── Edit Modal ──────────────────────────
    const [isEditModalOpen, setIsEditModalOpen] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [deletingId, setDeletingId] = useState<string | null>(null);
    const [selectedScheduleId, setSelectedScheduleId] = useState<string | null>(null);
    const [currentDaySchedule, setCurrentDaySchedule] = useState<DaySchedule[]>([]);
    const [selectedDay, setSelectedDay] = useState<string>("Monday");

    // ─── Load schedules from MongoDB ─────────
    useEffect(() => {
        loadSchedules();
    }, [activeTab, filterDegree, filterYear, filterBranch, filterSemester, filterDepartment, filterRollNumber]);

    const loadSchedules = async () => {
        setLoading(true);
        try {
            const params = new URLSearchParams();
            params.set("scheduleType", activeTab);

            if (activeTab === "student") {
                if (filterDegree && filterDegree !== "all") params.set("degree", filterDegree);
                if (filterYear && filterYear !== "all") params.set("year", filterYear);
                if (filterBranch && filterBranch !== "all") params.set("branch", filterBranch);
                if (filterSemester && filterSemester !== "all") params.set("semester", filterSemester);
            } else {
                if (filterDepartment && filterDepartment !== "all") params.set("department", filterDepartment);
                if (filterRollNumber) params.set("rollNumber", filterRollNumber);
            }

            const data = await api.get(`/schedules?${params.toString()}`);
            setSchedules(data);
        } catch (error: any) {
            console.error("Error loading schedules:", error);
            // If API fails, try localStorage fallback for student schedules
            if (activeTab === "student") {
                try {
                    const saved = localStorage.getItem("campverse_schedules");
                    if (saved) {
                        const localSchedules = JSON.parse(saved);
                        // Convert to ScheduleDoc format
                        const converted: ScheduleDoc[] = localSchedules.map((s: any) => ({
                            _id: s.id || s._id,
                            scheduleType: "student" as const,
                            year: s.year,
                            branch: s.branch,
                            section: s.section,
                            semester: s.semester,
                            degree: s.degree || "Major",
                            schedule: s.schedule,
                            createdAt: s.createdAt,
                            updatedAt: s.updatedAt,
                            createdBy: s.createdBy,
                        }));
                        setSchedules(converted);
                    }
                } catch (e) {
                    console.error("Error loading from localStorage:", e);
                }
            }
        } finally {
            setLoading(false);
        }
    };

    // ─── Create Schedule Flow ────────────────
    const handleOpenCreateModal = () => {
        setIsCreateTypeModalOpen(true);
    };

    const handleSelectCreateType = (type: "student" | "faculty") => {
        setCreateType(type);
        setIsCreateTypeModalOpen(false);
        setIsAddModalOpen(true);
    };

    const handleCreateSchedule = async () => {
        setIsSubmitting(true);
        try {
            const defaultDaySchedule: DaySchedule[] = DAYS.map(day => ({
                day,
                slots: DEFAULT_SLOTS.map((slot, idx) => ({
                    ...slot,
                    slotNumber: idx + 1,
                })),
            }));

            let body: any = {
                scheduleType: createType,
                schedule: defaultDaySchedule,
                createdBy: userData?.collegeId || "admin",
            };

            if (createType === "student") {
                body = {
                    ...body,
                    year: studentForm.year,
                    branch: studentForm.branch,
                    section: studentForm.section,
                    semester: studentForm.semester,
                    degree: studentForm.degree,
                };
            } else {
                if (!facultyForm.rollNumber.trim()) {
                    toast({
                        title: "Roll Number Required",
                        description: "Please enter a faculty roll/ID number.",
                        variant: "destructive",
                    });
                    setIsSubmitting(false);
                    return;
                }
                body = {
                    ...body,
                    department: facultyForm.department,
                    rollNumber: facultyForm.rollNumber.trim(),
                };
            }

            const saved = await api.post("/schedules", body);

            toast({
                title: "Success!",
                description: "Schedule created successfully. Now edit it to add subjects.",
            });

            setIsAddModalOpen(false);

            // Also save to localStorage for backward compatibility (student only)
            if (createType === "student") {
                syncStudentScheduleToLocalStorage([...schedules, saved]);
            }

            // Open edit modal
            setSelectedScheduleId(saved._id);
            setCurrentDaySchedule(saved.schedule);
            setIsEditModalOpen(true);

            // Refresh list
            loadSchedules();
        } catch (error: any) {
            const msg = error.message || "Failed to create schedule.";
            toast({
                title: "Error",
                description: msg.includes("409") ? "A schedule with these parameters already exists." : msg,
                variant: "destructive",
            });
        } finally {
            setIsSubmitting(false);
        }
    };

    // ─── Edit Schedule ───────────────────────
    const handleEditSchedule = (schedule: ScheduleDoc) => {
        setSelectedScheduleId(schedule._id);
        
        // Ensure all days (including newly added Sunday) are present in the local editing state
        const scheduleCopy = JSON.parse(JSON.stringify(schedule.schedule));
        const hydratedSchedule = DAYS.map(dayName => {
            const existingDay = scheduleCopy.find((d: any) => d.day === dayName);
            return existingDay || { day: dayName, slots: [] };
        });

        setCurrentDaySchedule(hydratedSchedule);
        setSelectedDay("Monday");
        setIsEditModalOpen(true);
    };

    const handleSlotChange = (day: string, slotIndex: number, field: keyof ScheduleSlot, value: string) => {
        setCurrentDaySchedule(prev => prev.map(d => {
            if (d.day === day) {
                const updatedSlots = [...d.slots];
                updatedSlots[slotIndex] = {
                    ...updatedSlots[slotIndex],
                    [field]: value,
                };
                return { ...d, slots: updatedSlots };
            }
            return d;
        }));
    };

    const handleAddSlot = () => {
        setCurrentDaySchedule(prev => prev.map(d => {
            if (d.day === selectedDay) {
                const newSlotNumber = d.slots.length + 1;
                const lastSlot = d.slots[d.slots.length - 1];
                const newSlot: ScheduleSlot = {
                    slotNumber: newSlotNumber,
                    subjectCode: "",
                    subjectName: "",
                    startTime: lastSlot ? lastSlot.endTime : "09:00",
                    endTime: lastSlot ? addHourToTime(lastSlot.endTime) : "10:00",
                    facultyName: "",
                    facultyId: "",
                    room: "",
                    classType: "Class",
                };
                return { ...d, slots: [...d.slots, newSlot] };
            }
            return d;
        }));

        toast({
            title: "Slot Added",
            description: `Added slot ${(currentDayData?.slots.length || 0) + 1} to ${selectedDay}`,
        });
    };

    const handleDeleteSlot = (slotIndex: number) => {
        setCurrentDaySchedule(prev => prev.map(d => {
            if (d.day === selectedDay) {
                const updatedSlots = d.slots.filter((_, idx) => idx !== slotIndex);
                return {
                    ...d,
                    slots: updatedSlots.map((slot, idx) => ({
                        ...slot,
                        slotNumber: idx + 1,
                    })),
                };
            }
            return d;
        }));

        toast({
            title: "Slot Deleted",
            description: `Removed slot from ${selectedDay}`,
        });
    };

    const addHourToTime = (time: string): string => {
        const [hours, minutes] = time.split(':').map(Number);
        const newHours = (hours + 1) % 24;
        return `${newHours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}`;
    };

    const handleSaveSchedule = async () => {
        if (!selectedScheduleId) return;

        setIsSubmitting(true);
        try {
            const cleanedDaySchedule = currentDaySchedule.map(day => {
                const filledSlots = day.slots.filter(slot => 
                    (slot.subjectName?.trim() || slot.subjectCode?.trim() || slot.facultyName?.trim() || slot.facultyId?.trim() || slot.room?.trim())
                );

                // Validation: if subjectCode or subjectName exists, facultyId must exist
                for (const slot of filledSlots) {
                    if ((slot.subjectCode?.trim() || slot.subjectName?.trim()) && !slot.facultyId?.trim()) {
                        throw new Error(`Faculty ID is required for slot ${slot.slotNumber} on ${day.day}`);
                    }
                }

                return {
                    ...day,
                    slots: filledSlots.map((slot, idx) => ({ ...slot, slotNumber: idx + 1 }))
                };
            });

            const updated = await api.put(`/schedules/${selectedScheduleId}`, {
                schedule: cleanedDaySchedule,
            });

            toast({
                title: "Schedule Updated!",
                description: "The timetable has been updated. Changes will reflect on dashboards.",
            });

            // Also update localStorage for student schedules (backward compat)
            const targetSchedule = schedules.find(s => s._id === selectedScheduleId);
            if (targetSchedule?.scheduleType === "student") {
                const updatedSchedules = schedules.map(s => {
                    if (s._id === selectedScheduleId) {
                        return { ...s, schedule: cleanedDaySchedule, updatedAt: new Date().toISOString() };
                    }
                    return s;
                });
                syncStudentScheduleToLocalStorage(updatedSchedules);
            }

            setIsEditModalOpen(false);
            loadSchedules();
        } catch (error: any) {
            toast({
                title: "Error",
                description: error.message || "Failed to save schedule.",
                variant: "destructive",
            });
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleDeleteSchedule = async (id: string) => {
        setDeletingId(id);
        try {
            await api.delete(`/schedules/${id}`);

            toast({
                title: "Deleted!",
                description: "Schedule has been deleted successfully.",
            });

            // Remove from localStorage too
            const remaining = schedules.filter(s => s._id !== id);
            syncStudentScheduleToLocalStorage(remaining.filter(s => s.scheduleType === "student"));

            loadSchedules();
        } catch (error: any) {
            toast({
                title: "Error",
                description: error.message || "Failed to delete schedule.",
                variant: "destructive",
            });
        } finally {
            setDeletingId(null);
        }
    };

    // ─── Helpers ─────────────────────────────
    const syncStudentScheduleToLocalStorage = (studentSchedules: ScheduleDoc[]) => {
        try {
            // Save in old format for student dashboard backward compat
            const scheduleConfig: Record<string, DaySchedule[]> = {};
            studentSchedules.forEach(s => {
                if (s.scheduleType === "student" && s.year && s.branch && s.section) {
                    const key = `${s.year}_${s.branch}_${s.section}`;
                    scheduleConfig[key] = s.schedule;
                }
            });
            localStorage.setItem("campverse_schedule_config", JSON.stringify(scheduleConfig));
        } catch (e) {
            console.error("Error syncing to localStorage:", e);
        }
    };

    const formatTime = (time: string) => {
        const [hours, minutes] = time.split(':');
        const hour = parseInt(hours);
        const ampm = hour >= 12 ? 'PM' : 'AM';
        const displayHour = hour > 12 ? hour - 12 : hour === 0 ? 12 : hour;
        return `${displayHour}:${minutes} ${ampm}`;
    };

    const getBranchName = (code: string) => {
        const branches: Record<string, string> = {
            "05": "CSE",
            "04": "ECE",
            "02": "EEE",
            "01": "Civil",
            "03": "Mech",
        };
        return branches[code] || code;
    };

    const getYearLabel = (code: string) => {
        const years: Record<string, string> = {
            "22": "I Year", "23": "II Year", "24": "III Year", "25": "IV Year",
        };
        return years[code] || `20${code} Batch`;
    };

    const currentDayData = currentDaySchedule.find(d => d.day === selectedDay);

    // ─── Stats ───────────────────────────────
    const studentSchedules = schedules.filter(s => s.scheduleType === "student");
    const facultySchedules = schedules.filter(s => s.scheduleType === "faculty");
    const displayedSchedules = activeTab === "student" ? studentSchedules : facultySchedules;

    // Determine the type of schedule being edited
    const editingScheduleType = schedules.find(s => s._id === selectedScheduleId)?.scheduleType || createType;

    return (
        <AdminLayout>
            <div className="max-w-7xl mx-auto space-y-6">
                {/* Header */}
                <div className="flex items-center justify-between">
                    <div>
                        <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
                            <Calendar className="w-8 h-8 text-primary" />
                            Schedule Management
                        </h1>
                        <p className="text-muted-foreground mt-1">
                            Manage class timetables for all sections
                        </p>
                    </div>
                    <div className="flex gap-2">
                        <Button onClick={handleOpenCreateModal}>
                            <Plus className="w-4 h-4 mr-2" />
                            Create Schedule
                        </Button>
                    </div>
                </div>

                {/* Stats */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <Card>
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-lg bg-primary/10 flex items-center justify-center">
                                <Calendar className="w-6 h-6 text-primary" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Total Schedules</p>
                                <p className="text-2xl font-bold">{schedules.length}</p>
                            </div>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-lg bg-blue-500/10 flex items-center justify-center">
                                <GraduationCap className="w-6 h-6 text-blue-500" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">
                                    {activeTab === "student" ? "Sections Covered" : "Faculty Covered"}
                                </p>
                                <p className="text-2xl font-bold">
                                    {activeTab === "student"
                                        ? new Set(studentSchedules.map(s => s.section)).size
                                        : facultySchedules.length}
                                </p>
                            </div>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-lg bg-green-500/10 flex items-center justify-center">
                                <BookOpen className="w-6 h-6 text-green-500" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Daily Slots</p>
                                <p className="text-2xl font-bold">
                                    {displayedSchedules[0]?.schedule?.[0]?.slots?.length || 4}
                                </p>
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {/* ─── Toggle Switch: Student | Faculty ─── */}
                <div className="flex justify-start">
                    <div className="inline-flex rounded-full p-1 bg-muted/60 border border-border">
                        <button
                            onClick={() => setActiveTab("student")}
                            className={`px-8 py-2.5 rounded-full text-sm font-semibold transition-all duration-200 ${activeTab === "student"
                                ? "bg-blue-500 text-white shadow-lg shadow-blue-500/25"
                                : "text-muted-foreground hover:text-foreground"
                                }`}
                        >
                            Student
                        </button>
                        <button
                            onClick={() => setActiveTab("faculty")}
                            className={`px-8 py-2.5 rounded-full text-sm font-semibold transition-all duration-200 ${activeTab === "faculty"
                                ? "bg-blue-500 text-white shadow-lg shadow-blue-500/25"
                                : "text-muted-foreground hover:text-foreground"
                                }`}
                        >
                            Faculty
                        </button>
                    </div>
                </div>

                {/* ─── Filter Dropdowns ─── */}
                <Card>
                    <CardContent className="p-4">
                        {activeTab === "student" ? (
                            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                                <div className="space-y-1">
                                    <Label className="text-xs text-muted-foreground">Degree</Label>
                                    <Select value={filterDegree} onValueChange={setFilterDegree}>
                                        <SelectTrigger>
                                            <SelectValue placeholder="All Degrees" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="all">All Degrees</SelectItem>
                                            <SelectItem value="Major">Major</SelectItem>
                                            <SelectItem value="Minor">Minor</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="space-y-1">
                                    <Label className="text-xs text-muted-foreground">Year</Label>
                                    <Select value={filterYear} onValueChange={setFilterYear}>
                                        <SelectTrigger>
                                            <SelectValue placeholder="All Years" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="all">All Years</SelectItem>
                                            <SelectItem value="22">I Year</SelectItem>
                                            <SelectItem value="23">II Year</SelectItem>
                                            <SelectItem value="24">III Year</SelectItem>
                                            <SelectItem value="25">IV Year</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="space-y-1">
                                    <Label className="text-xs text-muted-foreground">Semester</Label>
                                    <Select value={filterSemester} onValueChange={setFilterSemester}>
                                        <SelectTrigger>
                                            <SelectValue placeholder="All Semesters" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="all">All Semesters</SelectItem>
                                            <SelectItem value="I">Semester I</SelectItem>
                                            <SelectItem value="II">Semester II</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="space-y-1">
                                    <Label className="text-xs text-muted-foreground">Branch</Label>
                                    <Select value={filterBranch} onValueChange={setFilterBranch}>
                                        <SelectTrigger>
                                            <SelectValue placeholder="All Branches" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="all">All Branches</SelectItem>
                                            <SelectItem value="05">CSE</SelectItem>
                                            <SelectItem value="04">ECE</SelectItem>
                                            <SelectItem value="02">EEE</SelectItem>
                                            <SelectItem value="01">Civil</SelectItem>
                                            <SelectItem value="03">Mech</SelectItem>
                                            <SelectItem value="06">IT</SelectItem>
                                            <SelectItem value="07">AIDS</SelectItem>
                                            <SelectItem value="08">AIML</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                            </div>
                        ) : (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div className="space-y-1">
                                    <Label className="text-xs text-muted-foreground">Department</Label>
                                    <Select value={filterDepartment} onValueChange={setFilterDepartment}>
                                        <SelectTrigger>
                                            <SelectValue placeholder="All Departments" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="all">All Departments</SelectItem>
                                            {DEPARTMENTS.map(dept => (
                                                <SelectItem key={dept} value={dept}>{dept}</SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="space-y-1">
                                    <Label className="text-xs text-muted-foreground">Roll Number (Optional)</Label>
                                    <Input
                                        placeholder="Enter faculty roll number..."
                                        value={filterRollNumber}
                                        onChange={(e) => setFilterRollNumber(e.target.value)}
                                    />
                                </div>
                            </div>
                        )}
                    </CardContent>
                </Card>

                {/* Loading */}
                {loading && schedules.length === 0 && (
                    <Card>
                        <CardContent className="p-12 text-center">
                            <Loader2 className="w-12 h-12 text-primary mx-auto mb-4 animate-spin" />
                            <p className="text-muted-foreground">Loading schedules...</p>
                        </CardContent>
                    </Card>
                )}

                {/* Schedules List */}
                {!loading && displayedSchedules.length === 0 ? (
                    <Card>
                        <CardContent className="p-12 text-center">
                            <Calendar className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                            <h3 className="text-lg font-medium text-foreground mb-2">No schedules found</h3>
                            <p className="text-muted-foreground">
                                No {activeTab} schedules created yet. Click "Create Schedule" to add one.
                            </p>
                        </CardContent>
                    </Card>
                ) : (
                    <div className="space-y-4">
                        {displayedSchedules.map((schedule) => (
                            <Card key={schedule._id} className="hover:shadow-lg transition-shadow">
                                <CardContent className="p-6">
                                    <div className="flex items-start justify-between gap-4">
                                        <div className="flex-1 space-y-2">
                                            <div className="flex items-start gap-3 flex-wrap">
                                                {schedule.scheduleType === "student" ? (
                                                    <>
                                                        <h3 className="text-lg font-bold text-foreground">
                                                            {getBranchName(schedule.branch || "")} - Section {schedule.section}
                                                        </h3>
                                                        <Badge className="bg-blue-500">20{schedule.year} Batch</Badge>
                                                        <Badge variant="secondary">Semester {schedule.semester}</Badge>
                                                        {schedule.degree && (
                                                            <Badge variant="outline">{schedule.degree}</Badge>
                                                        )}
                                                    </>
                                                ) : (
                                                    <>
                                                        <h3 className="text-lg font-bold text-foreground flex items-center gap-2">
                                                            <Users className="w-5 h-5 text-purple-500" />
                                                            {schedule.department} - {schedule.rollNumber}
                                                        </h3>
                                                        <Badge className="bg-purple-500">Faculty</Badge>
                                                    </>
                                                )}
                                            </div>

                                            <div className="flex flex-wrap items-center gap-4 text-sm text-muted-foreground">
                                                <span className="text-xs">
                                                    Updated: {new Date(schedule.updatedAt).toLocaleDateString()}
                                                </span>
                                            </div>
                                        </div>

                                        <div className="flex items-center gap-2">
                                            <Button
                                                variant="outline"
                                                size="sm"
                                                onClick={() => handleEditSchedule(schedule)}
                                            >
                                                <Edit className="w-4 h-4 mr-2" />
                                                Edit
                                            </Button>

                                            <AlertDialog>
                                                <AlertDialogTrigger asChild>
                                                    <Button
                                                        variant="ghost"
                                                        size="sm"
                                                        className="text-destructive hover:text-destructive hover:bg-destructive/10"
                                                        disabled={deletingId === schedule._id}
                                                    >
                                                        {deletingId === schedule._id ? (
                                                            <Loader2 className="w-4 h-4 animate-spin" />
                                                        ) : (
                                                            <Trash2 className="w-4 h-4" />
                                                        )}
                                                    </Button>
                                                </AlertDialogTrigger>
                                                <AlertDialogContent>
                                                    <AlertDialogHeader>
                                                        <AlertDialogTitle>Delete Schedule?</AlertDialogTitle>
                                                        <AlertDialogDescription>
                                                            Are you sure you want to delete this schedule? This action cannot be undone.
                                                        </AlertDialogDescription>
                                                    </AlertDialogHeader>
                                                    <AlertDialogFooter>
                                                        <AlertDialogCancel>Cancel</AlertDialogCancel>
                                                        <AlertDialogAction
                                                            onClick={() => handleDeleteSchedule(schedule._id)}
                                                            className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                                                        >
                                                            Delete
                                                        </AlertDialogAction>
                                                    </AlertDialogFooter>
                                                </AlertDialogContent>
                                            </AlertDialog>
                                        </div>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                )}

                {/* ─── Create Type Selection Modal ─── */}
                <Dialog open={isCreateTypeModalOpen} onOpenChange={setIsCreateTypeModalOpen}>
                    <DialogContent className="max-w-sm">
                        <DialogHeader>
                            <DialogTitle className="flex items-center gap-2 text-xl">
                                <Calendar className="w-6 h-6 text-primary" />
                                Create Schedule For
                            </DialogTitle>
                        </DialogHeader>
                        <div className="flex gap-4 py-6">
                            <Button
                                className="flex-1 h-24 flex-col gap-2"
                                variant="outline"
                                onClick={() => handleSelectCreateType("student")}
                            >
                                <GraduationCap className="w-8 h-8 text-blue-500" />
                                <span className="text-sm font-semibold">Student</span>
                            </Button>
                            <Button
                                className="flex-1 h-24 flex-col gap-2"
                                variant="outline"
                                onClick={() => handleSelectCreateType("faculty")}
                            >
                                <Users className="w-8 h-8 text-purple-500" />
                                <span className="text-sm font-semibold">Faculty</span>
                            </Button>
                        </div>
                    </DialogContent>
                </Dialog>

                {/* ─── Create Schedule Form Modal ─── */}
                <Dialog open={isAddModalOpen} onOpenChange={setIsAddModalOpen}>
                    <DialogContent className="max-w-md">
                        <DialogHeader>
                            <DialogTitle className="flex items-center gap-2 text-xl">
                                {createType === "student" ? (
                                    <GraduationCap className="w-6 h-6 text-blue-500" />
                                ) : (
                                    <Users className="w-6 h-6 text-purple-500" />
                                )}
                                Create {createType === "student" ? "Student" : "Faculty"} Schedule
                            </DialogTitle>
                        </DialogHeader>
                        <div className="space-y-4 py-4">
                            {createType === "student" ? (
                                <>
                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label>Degree</Label>
                                            <Select
                                                value={studentForm.degree}
                                                onValueChange={(value) => setStudentForm({ ...studentForm, degree: value })}
                                            >
                                                <SelectTrigger>
                                                    <SelectValue />
                                                </SelectTrigger>
                                                <SelectContent>
                                                    <SelectItem value="Major">Major</SelectItem>
                                                    <SelectItem value="Minor">Minor</SelectItem>
                                                </SelectContent>
                                            </Select>
                                        </div>
                                        <div className="space-y-2">
                                            <Label>Year</Label>
                                            <Select
                                                value={studentForm.year}
                                                onValueChange={(value) => setStudentForm({ ...studentForm, year: value })}
                                            >
                                                <SelectTrigger>
                                                    <SelectValue />
                                                </SelectTrigger>
                                                <SelectContent>
                                                    <SelectItem value="22">I Year</SelectItem>
                                                    <SelectItem value="23">II Year</SelectItem>
                                                    <SelectItem value="24">III Year</SelectItem>
                                                    <SelectItem value="25">IV Year</SelectItem>
                                                </SelectContent>
                                            </Select>
                                        </div>
                                    </div>
                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label>Branch</Label>
                                            <Select
                                                value={studentForm.branch}
                                                onValueChange={(value) => setStudentForm({ ...studentForm, branch: value })}
                                            >
                                                <SelectTrigger>
                                                    <SelectValue />
                                                </SelectTrigger>
                                                <SelectContent>
                                                    <SelectItem value="05">CSE</SelectItem>
                                                    <SelectItem value="04">ECE</SelectItem>
                                                    <SelectItem value="02">EEE</SelectItem>
                                                    <SelectItem value="01">Civil</SelectItem>
                                                    <SelectItem value="03">Mech</SelectItem>
                                                </SelectContent>
                                            </Select>
                                        </div>
                                        <div className="space-y-2">
                                            <Label>Section</Label>
                                            <Select
                                                value={studentForm.section}
                                                onValueChange={(value) => setStudentForm({ ...studentForm, section: value })}
                                            >
                                                <SelectTrigger>
                                                    <SelectValue />
                                                </SelectTrigger>
                                                <SelectContent>
                                                    <SelectItem value="A">Section A</SelectItem>
                                                    <SelectItem value="B">Section B</SelectItem>
                                                    <SelectItem value="C">Section C</SelectItem>
                                                    <SelectItem value="D">Section D</SelectItem>
                                                </SelectContent>
                                            </Select>
                                        </div>
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Semester</Label>
                                        <Select
                                            value={studentForm.semester}
                                            onValueChange={(value) => setStudentForm({ ...studentForm, semester: value })}
                                        >
                                            <SelectTrigger>
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="I">Semester I</SelectItem>
                                                <SelectItem value="II">Semester II</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>
                                </>
                            ) : (
                                <>
                                    <div className="space-y-2">
                                        <Label>Department</Label>
                                        <Select
                                            value={facultyForm.department}
                                            onValueChange={(value) => setFacultyForm({ ...facultyForm, department: value })}
                                        >
                                            <SelectTrigger>
                                                <SelectValue />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {DEPARTMENTS.map(dept => (
                                                    <SelectItem key={dept} value={dept}>{dept}</SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Roll Number / Faculty ID</Label>
                                        <Input
                                            placeholder="Enter faculty roll number..."
                                            value={facultyForm.rollNumber}
                                            onChange={(e) => setFacultyForm({ ...facultyForm, rollNumber: e.target.value })}
                                        />
                                    </div>
                                </>
                            )}
                            <div className="flex justify-end gap-3 pt-4 border-t">
                                <Button variant="outline" onClick={() => setIsAddModalOpen(false)}>
                                    Cancel
                                </Button>
                                <Button onClick={handleCreateSchedule} disabled={isSubmitting}>
                                    {isSubmitting ? (
                                        <>
                                            <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                            Creating...
                                        </>
                                    ) : (
                                        "Create & Edit"
                                    )}
                                </Button>
                            </div>
                        </div>
                    </DialogContent>
                </Dialog>

                {/* ─── Edit Schedule Modal ─── */}
                <Dialog open={isEditModalOpen} onOpenChange={setIsEditModalOpen}>
                    <DialogContent className="max-w-[1400px] w-full max-h-[90vh] overflow-y-auto">
                        <DialogHeader>
                            <DialogTitle className="flex items-center gap-2 text-xl">
                                <Calendar className="w-6 h-6 text-primary" />
                                Edit Schedule
                            </DialogTitle>
                        </DialogHeader>
                        <div className="space-y-4 py-4">
                            {/* Day Selector */}
                            <div className="flex gap-2 flex-wrap">
                                {DAYS.map(day => (
                                    <Button
                                        key={day}
                                        variant={selectedDay === day ? "default" : "outline"}
                                        size="sm"
                                        onClick={() => setSelectedDay(day)}
                                    >
                                        {day}
                                    </Button>
                                ))}
                            </div>

                            {/* Slots Table */}
                            {currentDayData && (
                                <Table>
                                    <TableHeader>
                                        <TableRow>
                                            <TableHead className="w-14">Slot</TableHead>
                                            <TableHead className="min-w-[140px]">Subject Code</TableHead>
                                            <TableHead className="min-w-[280px]">Subject Name</TableHead>
                                            <TableHead className="min-w-[140px]">Start Time</TableHead>
                                            <TableHead className="min-w-[140px]">End Time</TableHead>
                                            {editingScheduleType === "faculty" ? (
                                                <>
                                                    <TableHead className="min-w-[140px]">Class</TableHead>
                                                    <TableHead className="min-w-[120px]">Section</TableHead>
                                                </>
                                            ) : (
                                                <>
                                                    <TableHead className="min-w-[180px]">Faculty Name</TableHead>
                                                    <TableHead className="min-w-[140px]">Faculty ID *</TableHead>
                                                </>
                                            )}
                                            <TableHead className="min-w-[120px]">Room</TableHead>
                                            <TableHead className="min-w-[120px]">Class Type</TableHead>
                                            <TableHead className="w-14">Action</TableHead>
                                        </TableRow>
                                    </TableHeader>
                                    <TableBody>
                                        {currentDayData.slots.map((slot, idx) => (
                                            <TableRow key={idx}>
                                                <TableCell className="font-medium">{slot.slotNumber}</TableCell>
                                                <TableCell>
                                                    <Input
                                                        value={slot.subjectCode}
                                                        onChange={(e) => handleSlotChange(selectedDay, idx, "subjectCode", e.target.value)}
                                                        placeholder=""
                                                        className="h-9 min-w-[120px]"
                                                    />
                                                </TableCell>
                                                <TableCell>
                                                    <Input
                                                        value={slot.subjectName}
                                                        onChange={(e) => handleSlotChange(selectedDay, idx, "subjectName", e.target.value)}
                                                        placeholder=""
                                                        className="h-9 min-w-[250px]"
                                                    />
                                                </TableCell>
                                                <TableCell>
                                                    <Input
                                                        type="time"
                                                        value={slot.startTime}
                                                        onChange={(e) => handleSlotChange(selectedDay, idx, "startTime", e.target.value)}
                                                        className="h-9 w-32"
                                                    />
                                                </TableCell>
                                                <TableCell>
                                                    <Input
                                                        type="time"
                                                        value={slot.endTime}
                                                        onChange={(e) => handleSlotChange(selectedDay, idx, "endTime", e.target.value)}
                                                        className="h-9 w-32"
                                                    />
                                                </TableCell>
                                                {editingScheduleType === "faculty" ? (
                                                    <>
                                                        <TableCell>
                                                            <Input
                                                                value={slot.className || ""}
                                                                onChange={(e) => handleSlotChange(selectedDay, idx, "className", e.target.value)}
                                                                placeholder=""
                                                                className="h-9 min-w-[120px]"
                                                            />
                                                        </TableCell>
                                                        <TableCell>
                                                            <Input
                                                                value={slot.section || ""}
                                                                onChange={(e) => handleSlotChange(selectedDay, idx, "section", e.target.value)}
                                                                placeholder=""
                                                                className="h-9 min-w-[80px]"
                                                            />
                                                        </TableCell>
                                                    </>
                                                ) : (
                                                    <>
                                                        <TableCell>
                                                            <Input
                                                                value={slot.facultyName || ""}
                                                                onChange={(e) => handleSlotChange(selectedDay, idx, "facultyName", e.target.value)}
                                                                placeholder="Faculty name"
                                                                className="h-9 min-w-[160px]"
                                                            />
                                                        </TableCell>
                                                        <TableCell>
                                                            <Input
                                                                value={slot.facultyId || ""}
                                                                onChange={(e) => handleSlotChange(selectedDay, idx, "facultyId", e.target.value)}
                                                                placeholder="Faculty ID"
                                                                className="h-9 min-w-[120px] bg-primary/5 border-primary/20"
                                                                required
                                                            />
                                                        </TableCell>
                                                    </>
                                                )}
                                                <TableCell>
                                                    <Input
                                                        value={slot.room || ""}
                                                        onChange={(e) => handleSlotChange(selectedDay, idx, "room", e.target.value)}
                                                        placeholder=""
                                                        className="h-9 min-w-[100px]"
                                                    />
                                                </TableCell>
                                                <TableCell>
                                                    <Select
                                                        value={slot.classType || "Class"}
                                                        onValueChange={(val) => handleSlotChange(selectedDay, idx, "classType", val)}
                                                    >
                                                        <SelectTrigger className="h-9 min-w-[100px] rounded-xl bg-background/50 backdrop-blur-md border-border/60 hover:bg-accent/30 transition-all duration-300">
                                                            <SelectValue />
                                                        </SelectTrigger>
                                                        <SelectContent className="rounded-xl border-border/40 shadow-xl bg-popover/80 backdrop-blur-xl">
                                                            <SelectItem value="Class">Class</SelectItem>
                                                            <SelectItem value="Lab">Lab</SelectItem>
                                                            <SelectItem value="Tutorial">Tutorial</SelectItem>
                                                            <SelectItem value="Sports">Sports</SelectItem>
                                                            <SelectItem value="Library">Library</SelectItem>
                                                            <SelectItem value="Mentoring">Mentoring</SelectItem>
                                                            <SelectItem value="Review">Review</SelectItem>
                                                        </SelectContent>
                                                    </Select>
                                                </TableCell>
                                                <TableCell>
                                                    <Button
                                                        variant="ghost"
                                                        size="sm"
                                                        className="h-8 w-8 p-0 text-destructive hover:text-destructive hover:bg-destructive/10"
                                                        onClick={() => handleDeleteSlot(idx)}
                                                        disabled={currentDayData!.slots.length <= 1}
                                                    >
                                                        <Trash2 className="w-4 h-4" />
                                                    </Button>
                                                </TableCell>
                                            </TableRow>
                                        ))}
                                    </TableBody>
                                </Table>
                            )}

                            {/* Add Slot Button */}
                            <div className="flex justify-center">
                                <Button
                                    variant="outline"
                                    onClick={handleAddSlot}
                                    className="border-dashed"
                                >
                                    <Plus className="w-4 h-4 mr-2" />
                                    Add New Slot
                                </Button>
                            </div>

                            <div className="flex justify-end gap-3 pt-4 border-t">
                                <Button variant="outline" onClick={() => setIsEditModalOpen(false)} disabled={isSubmitting}>
                                    Cancel
                                </Button>
                                <Button onClick={handleSaveSchedule} disabled={isSubmitting}>
                                    {isSubmitting ? (
                                        <>
                                            <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                            Saving...
                                        </>
                                    ) : (
                                        <>
                                            <Save className="w-4 h-4 mr-2" />
                                            Save Schedule
                                        </>
                                    )}
                                </Button>
                            </div>
                        </div>
                    </DialogContent>
                </Dialog>
            </div>
        </AdminLayout>
    );
};

export default AdminScheduler;

import React, { useState } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Badge } from '@/components/ui/badge';
import { 
  Database, 
  Users, 
  Upload, 
  Settings, 
  BarChart3, 
  Download,
  Search,
  Filter
} from 'lucide-react';
import DatasetImport from '@/components/DatasetImport';
import CustomStudentDashboard from '@/components/CustomStudentDashboard';
import FirebaseUserSetup from '@/components/FirebaseUserSetup';
import ExcelUploadGuide from '@/components/ExcelUploadGuide';
import { useStudentsList } from '@/hooks/useFirestore';
import { Input } from '@/components/ui/input';
import { 
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';

const StudentDataManagement = () => {
  const [selectedStudentId, setSelectedStudentId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterBranch, setFilterBranch] = useState('all');
  const [filterYear, setFilterYear] = useState('all');
  
  const { students, loading, reloadStudents } = useStudentsList();

  // Filter students based on search and filters
  const filteredStudents = students.filter(student => {
    const matchesSearch = student.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         student.collegeId.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesBranch = filterBranch === 'all' || student.branch === filterBranch;
    const matchesYear = filterYear === 'all' || student.year === filterYear;
    
    return matchesSearch && matchesBranch && matchesYear;
  });

  // Get unique branches and years for filters
  const branches = [...new Set(students.map(s => s.branch))].filter(Boolean);
  const years = [...new Set(students.map(s => s.year))].filter(Boolean);

  const handleImportComplete = () => {
    reloadStudents();
  };

  const exportStudentData = () => {
    const csvContent = [
      'name,collegeId,email,year,section,branch,rollNumber,phone,dateOfBirth,address,cgpa,semester',
      ...students.map(student => [
        student.name,
        student.collegeId,
        student.email,
        student.year,
        student.section,
        student.branch,
        student.rollNumber,
        student.profile?.phone || '',
        student.profile?.dateOfBirth || '',
        student.profile?.address || '',
        student.profile?.academic?.cgpa || '',
        student.profile?.academic?.semester || ''
      ].join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'student_data_export.csv';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    window.URL.revokeObjectURL(url);
  };

  return (
    <div className="space-y-6 p-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-foreground">Student Data Management</h1>
          <p className="text-muted-foreground mt-1">
            Import datasets, manage student profiles, and customize dashboards
          </p>
        </div>
        <div className="flex gap-2">
          <Button 
            variant="outline" 
            onClick={exportStudentData}
            className="flex items-center gap-2"
            disabled={students.length === 0}
          >
            <Download className="w-4 h-4" />
            Export Data
          </Button>
          <Button onClick={reloadStudents} className="flex items-center gap-2">
            <Database className="w-4 h-4" />
            Refresh Data
          </Button>
        </div>
      </div>

      {/* Statistics Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-muted-foreground">Total Students</p>
                <p className="text-2xl font-bold">{students.length}</p>
              </div>
              <Users className="w-8 h-8 text-blue-500" />
            </div>
          </CardContent>
        </Card>
        
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-muted-foreground">Branches</p>
                <p className="text-2xl font-bold">{branches.length}</p>
              </div>
              <BarChart3 className="w-8 h-8 text-green-500" />
            </div>
          </CardContent>
        </Card>
        
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-muted-foreground">Academic Years</p>
                <p className="text-2xl font-bold">{years.length}</p>
              </div>
              <Settings className="w-8 h-8 text-orange-500" />
            </div>
          </CardContent>
        </Card>
        
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-muted-foreground">Avg CGPA</p>
                <p className="text-2xl font-bold">
                  {students.length > 0 
                    ? (students.reduce((sum, s) => sum + (s.profile?.academic?.cgpa || 0), 0) / students.length).toFixed(1)
                    : '0.0'
                  }
                </p>
              </div>
              <Database className="w-8 h-8 text-purple-500" />
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Main Content Tabs */}
      <Tabs defaultValue="firebase" className="space-y-6">
        <TabsList className="grid w-full grid-cols-4">
          <TabsTrigger value="firebase" className="flex items-center gap-2">
            <Settings className="w-4 h-4" />
            Firebase Setup
          </TabsTrigger>
          <TabsTrigger value="dataset" className="flex items-center gap-2">
            <Upload className="w-4 h-4" />
            Dataset Import
          </TabsTrigger>
          <TabsTrigger value="students" className="flex items-center gap-2">
            <Users className="w-4 h-4" />
            Student Management
          </TabsTrigger>
          <TabsTrigger value="dashboard" className="flex items-center gap-2">
            <BarChart3 className="w-4 h-4" />
            Dashboard Preview
          </TabsTrigger>
        </TabsList>

        {/* Firebase Setup Tab */}
        <TabsContent value="firebase" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Settings className="w-5 h-5" />
                Firebase Authentication Setup
              </CardTitle>
              <CardDescription>
                Configure Firebase Authentication and create initial users for your CampVerse system
              </CardDescription>
            </CardHeader>
            <CardContent>
              <FirebaseUserSetup />
            </CardContent>
          </Card>
        </TabsContent>

        {/* Dataset Import Tab */}
        <TabsContent value="dataset" className="space-y-6">
          <ExcelUploadGuide />
          <DatasetImport onImportComplete={handleImportComplete} />
        </TabsContent>

        {/* Student Management Tab */}
        <TabsContent value="students" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Users className="w-5 h-5" />
                Student Directory ({filteredStudents.length})
              </CardTitle>
              <CardDescription>
                Search and filter students to view their custom dashboards
              </CardDescription>
            </CardHeader>
            <CardContent>
              {/* Search and Filters */}
              <div className="flex flex-col sm:flex-row gap-4 mb-6">
                <div className="flex-1">
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground w-4 h-4" />
                    <Input
                      placeholder="Search by name or college ID..."
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                      className="pl-10"
                    />
                  </div>
                </div>
                <Select value={filterBranch} onValueChange={setFilterBranch}>
                  <SelectTrigger className="w-full sm:w-[180px]">
                    <SelectValue placeholder="Filter by branch" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Branches</SelectItem>
                    {branches.map(branch => (
                      <SelectItem key={branch} value={branch}>Branch {branch}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <Select value={filterYear} onValueChange={setFilterYear}>
                  <SelectTrigger className="w-full sm:w-[180px]">
                    <SelectValue placeholder="Filter by year" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Years</SelectItem>
                    {years.map(year => (
                      <SelectItem key={year} value={year}>Year {year}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {/* Students List */}
              {loading ? (
                <div className="text-center py-8">
                  <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-4"></div>
                  <p className="text-muted-foreground">Loading students...</p>
                </div>
              ) : filteredStudents.length === 0 ? (
                <div className="text-center py-8">
                  <Users className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                  <p className="text-muted-foreground">No students found</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {filteredStudents.map((student) => (
                    <Card 
                      key={student.uid} 
                      className={`cursor-pointer transition-colors hover:bg-muted/50 ${
                        selectedStudentId === student.uid ? 'ring-2 ring-primary' : ''
                      }`}
                      onClick={() => setSelectedStudentId(student.uid)}
                    >
                      <CardContent className="pt-4">
                        <div className="space-y-2">
                          <h4 className="font-semibold">{student.name}</h4>
                          <p className="text-sm font-mono text-muted-foreground">{student.collegeId}</p>
                          <div className="flex flex-wrap gap-1">
                            <Badge variant="outline" className="text-xs">
                              {student.role}
                            </Badge>
                            <Badge variant="secondary" className="text-xs">
                              Year {student.year}
                            </Badge>
                            <Badge variant="secondary" className="text-xs">
                              Branch {student.branch}
                            </Badge>
                          </div>
                          {student.profile?.academic?.cgpa && (
                            <div className="text-sm text-muted-foreground">
                              CGPA: {student.profile.academic.cgpa.toFixed(2)}
                            </div>
                          )}
                        </div>
                      </CardContent>
                    </Card>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        {/* Dashboard Preview Tab */}
        <TabsContent value="dashboard" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <BarChart3 className="w-5 h-5" />
                Custom Student Dashboard
              </CardTitle>
              <CardDescription>
                {selectedStudentId 
                  ? `Viewing dashboard for ${students.find(s => s.uid === selectedStudentId)?.name}`
                  : 'Select a student from the Student Management tab to preview their dashboard'
                }
              </CardDescription>
            </CardHeader>
            <CardContent>
              {selectedStudentId ? (
                <CustomStudentDashboard studentId={selectedStudentId} />
              ) : (
                <div className="text-center py-12">
                  <BarChart3 className="w-16 h-16 text-muted-foreground mx-auto mb-4" />
                  <h3 className="text-lg font-semibold mb-2">No Student Selected</h3>
                  <p className="text-muted-foreground mb-4">
                    Go to the Student Management tab and click on a student to preview their custom dashboard
                  </p>
                  <Button 
                    variant="outline" 
                    onClick={() => {
                      // Auto-select first student if available
                      if (students.length > 0) {
                        setSelectedStudentId(students[0].uid);
                      }
                    }}
                    disabled={students.length === 0}
                  >
                    {students.length > 0 ? 'Select First Student' : 'Import Students First'}
                  </Button>
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
};

export default StudentDataManagement;

import { useState, useEffect } from "react";
import AdminLayout from "@/components/AdminLayout";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Checkbox } from "@/components/ui/checkbox";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import { getStoredToken } from "@/lib/api";
import { AlertTriangle, Download, Settings, RefreshCcw } from "lucide-react";

export default function SystemSettings() {
    const { toast } = useToast();
    const [config, setConfig] = useState<any>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [isPromoting, setIsPromoting] = useState(false);

    const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || "http://127.0.0.1:5000/api";

    useEffect(() => {
        fetchConfig();
    }, []);

    const fetchConfig = async () => {
        try {
            const response = await fetch(`${API_BASE_URL}/admin/settings`, {
                headers: { Authorization: `Bearer ${getStoredToken()}` }
            });
            if (response.ok) {
                setConfig(await response.json());
            }
        } catch (err) {
            console.error(err);
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        try {
            const response = await fetch(`${API_BASE_URL}/admin/settings`, {
                method: "PUT",
                headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${getStoredToken()}`
                },
                body: JSON.stringify(config)
            });
            if (response.ok) {
                toast({ title: "Settings Saved", description: "Global configuration updated successfully." });
            }
        } catch (err) {
            toast({ title: "Error", description: "Failed to save settings.", variant: "destructive" });
        } finally {
            setIsLoading(false);
        }
    };

    const handlePromoteStudents = async () => {
        if (!window.confirm("WARNING: This will promote all students to the next academic year and archive 4th years. Continue?")) {
            return;
        }

        setIsPromoting(true);
        try {
            const response = await fetch(`${API_BASE_URL}/admin/promote`, {
                method: "POST",
                headers: { Authorization: `Bearer ${getStoredToken()}` }
            });

            const data = await response.json();

            if (response.ok) {
                toast({ title: "Promotion Successful", description: data.message });
            } else {
                throw new Error(data.message);
            }
        } catch (err: any) {
            toast({ title: "Failed to promote students", description: err.message, variant: "destructive" });
        } finally {
            setIsPromoting(false);
        }
    };

    if (!config) return <AdminLayout><div className="p-8">Loading Settings...</div></AdminLayout>;

    return (
        <AdminLayout>
            <div className="space-y-6">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">System Settings</h1>
                    <p className="text-muted-foreground mt-2">
                        Configure Academic Year, Attendance thresholds, CGPA formula and global settings.
                    </p>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center"><Settings className="w-5 h-5 mr-2" /> Global Configuration</CardTitle>
                        </CardHeader>
                        <CardContent>
                            <form onSubmit={handleSave} className="space-y-4">
                                <div className="space-y-2">
                                    <Label>Academic Year</Label>
                                    <Input
                                        value={config.academicYear || ""}
                                        onChange={e => setConfig({ ...config, academicYear: e.target.value })}
                                    />
                                </div>

                                <div className="space-y-2">
                                    <Label>Default Semester</Label>
                                    <Select
                                        value={config.defaultSemester || "Odd"}
                                        onValueChange={v => setConfig({ ...config, defaultSemester: v })}
                                    >
                                        <SelectTrigger><SelectValue /></SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="Odd">Odd Semester</SelectItem>
                                            <SelectItem value="Even">Even Semester</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>

                                <div className="space-y-2">
                                    <Label>Attendance Thresholds (%)</Label>
                                    <div className="grid grid-cols-4 gap-2">
                                        <div><span className="text-xs">4w</span><Input type="number" value={config.attendanceThresholds?.fourWeeks || 75} onChange={e => setConfig({ ...config, attendanceThresholds: { ...config.attendanceThresholds, fourWeeks: +e.target.value } })} /></div>
                                        <div><span className="text-xs">8w</span><Input type="number" value={config.attendanceThresholds?.eightWeeks || 75} onChange={e => setConfig({ ...config, attendanceThresholds: { ...config.attendanceThresholds, eightWeeks: +e.target.value } })} /></div>
                                        <div><span className="text-xs">12w</span><Input type="number" value={config.attendanceThresholds?.twelveWeeks || 75} onChange={e => setConfig({ ...config, attendanceThresholds: { ...config.attendanceThresholds, twelveWeeks: +e.target.value } })} /></div>
                                        <div><span className="text-xs">16w</span><Input type="number" value={config.attendanceThresholds?.sixteenWeeks || 75} onChange={e => setConfig({ ...config, attendanceThresholds: { ...config.attendanceThresholds, sixteenWeeks: +e.target.value } })} /></div>
                                    </div>
                                </div>

                                <div className="space-y-2 border-t pt-4">
                                    <Label className="flex items-center gap-2">
                                        <Checkbox
                                            checked={config.globalNotifications?.emailAlerts}
                                            onCheckedChange={c => setConfig({ ...config, globalNotifications: { ...config.globalNotifications, emailAlerts: !!c } })}
                                        />
                                        Enable Email Alerts globally
                                    </Label>
                                </div>

                                <Button type="submit" disabled={isLoading} className="w-full bg-slate-900">{isLoading ? "Saving..." : "Save Settings"}</Button>
                            </form>
                        </CardContent>
                    </Card>

                    <Card className="border-orange-200 bg-orange-50/30">
                        <CardHeader>
                            <CardTitle className="flex items-center text-orange-700">
                                <AlertTriangle className="w-5 h-5 mr-2" /> Academic Management
                            </CardTitle>
                            <CardDescription>
                                Execute system-wide academic processes. These actions are irreversible.
                            </CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-6">
                            <div className="p-4 bg-white rounded-lg border shadow-sm">
                                <h3 className="font-semibold text-sm mb-2">Academic Year Promotion</h3>
                                <p className="text-sm text-gray-500 mb-4">
                                    Moves all students up one year (I &rarr; II &rarr; III &rarr; IV). 4th Year students will be marked as Graduated and moved to the Alumni archive.
                                </p>
                                <Button
                                    onClick={handlePromoteStudents}
                                    disabled={isPromoting}
                                    variant="destructive"
                                    className="w-full"
                                >
                                    <RefreshCcw className={`w-4 h-4 mr-2 ${isPromoting ? 'animate-spin' : ''}`} />
                                    {isPromoting ? "Promoting Students..." : "Promote All Students to Next Year"}
                                </Button>
                            </div>
                        </CardContent>
                    </Card>
                </div>
            </div>
        </AdminLayout>
    );
}

import { useState } from "react";
import AdminLayout from "@/components/AdminLayout";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useToast } from "@/hooks/use-toast";
import { getStoredToken } from "@/lib/api";
import { useAuth } from "@/contexts/AuthContext";
import { Checkbox } from "@/components/ui/checkbox";
import { UserPlus, ShieldPlus, GraduationCap, Users } from "lucide-react";

export default function UserManagement() {
    const { userData } = useAuth();
    const { toast } = useToast();
    const [loading, setLoading] = useState(false);
    const [activeTab, setActiveTab] = useState("student");

    // Form states
    const [studentForm, setStudentForm] = useState({
        name: "", email: "", collegeId: "", branch: "", section: "", year: "I", academicBatch: "2026-2030"
    });

    const [facultyForm, setFacultyForm] = useState({
        name: "", email: "", collegeId: "", branch: "", section: "Z"
    });

    const [subAdminForm, setSubAdminForm] = useState({
        name: "", email: "", collegeId: "",
        permissions: {
            manageAttendance: false, manageEvents: false, manageClubs: false, manageNotifications: false, manageResults: false
        }
    });

    const generateCollegeId = (role: string) => {
        // Basic generator for visual
        const prefix = role === "student" ? "22B81A" : "FCL-";
        const rand = Math.floor(1000 + Math.random() * 9000);
        return `${prefix}${rand}`;
    };

    const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || "http://127.0.0.1:5000/api";

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        let payload: any = {};
        if (activeTab === "student") {
            payload = { ...studentForm, role: "student" };
        } else if (activeTab === "faculty") {
            payload = { ...facultyForm, role: "faculty" };
        } else {
            payload = { ...subAdminForm, role: "sub-admin" };
        }

        try {
            const response = await fetch(`${API_BASE_URL}/admin/users`, {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${getStoredToken()}`,
                },
                body: JSON.stringify(payload),
            });

            if (!response.ok) {
                const err = await response.json();
                throw new Error(err.message || "Failed to create user");
            }

            toast({
                title: "User Created Successfully",
                description: `${payload.role} account created for ${payload.name}`,
            });

            // Reset logic
            if (activeTab === "student") setStudentForm({ ...studentForm, name: "", email: "", collegeId: "" });
            if (activeTab === "faculty") setFacultyForm({ ...facultyForm, name: "", email: "", collegeId: "" });
            if (activeTab === "sub-admin") setSubAdminForm({ ...subAdminForm, name: "", email: "", collegeId: "" });

        } catch (err: any) {
            toast({
                title: "Error",
                description: err.message,
                variant: "destructive",
            });
        } finally {
            setLoading(false);
        }
    };

    return (
        <AdminLayout>
            <div className="space-y-6">
                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-3xl font-bold tracking-tight">User Management</h1>
                        <p className="text-muted-foreground mt-2">
                            Add new Students, Faculty, and Sub-Admins. Assign Roles & Permissions.
                        </p>
                    </div>
                </div>

                <Tabs defaultValue="student" onValueChange={setActiveTab} className="w-full">
                    <TabsList className="grid w-full grid-cols-3 max-w-2xl mb-8">
                        <TabsTrigger value="student" className="flex items-center gap-2">
                            <GraduationCap className="w-4 h-4" /> Student
                        </TabsTrigger>
                        <TabsTrigger value="faculty" className="flex items-center gap-2">
                            <Users className="w-4 h-4" /> Faculty
                        </TabsTrigger>
                        <TabsTrigger value="sub-admin" className="flex items-center gap-2">
                            <ShieldPlus className="w-4 h-4" /> Sub-Admin
                        </TabsTrigger>
                    </TabsList>

                    <Card className="max-w-3xl">
                        <CardHeader>
                            <CardTitle className="flex items-center">
                                <UserPlus className="w-5 h-5 mr-2" /> Add {activeTab === "student" ? "Student" : activeTab === "faculty" ? "Faculty" : "Sub-Admin"}
                            </CardTitle>
                            <CardDescription>
                                Fill in the details carefully. Passwords are set by default to their ID.
                            </CardDescription>
                        </CardHeader>
                        <CardContent>
                            <form onSubmit={handleSubmit} className="space-y-4">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <label className="text-sm font-medium">Full Name</label>
                                        <Input
                                            required
                                            value={activeTab === "student" ? studentForm.name : activeTab === "faculty" ? facultyForm.name : subAdminForm.name}
                                            onChange={(e) => {
                                                const val = e.target.value;
                                                if (activeTab === "student") setStudentForm(f => ({ ...f, name: val }));
                                                if (activeTab === "faculty") setFacultyForm(f => ({ ...f, name: val }));
                                                if (activeTab === "sub-admin") setSubAdminForm(f => ({ ...f, name: val }));
                                            }}
                                            placeholder="e.g. John Doe"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-sm font-medium">Email Address</label>
                                        <Input
                                            type="email"
                                            required
                                            value={activeTab === "student" ? studentForm.email : activeTab === "faculty" ? facultyForm.email : subAdminForm.email}
                                            onChange={(e) => {
                                                const val = e.target.value;
                                                if (activeTab === "student") setStudentForm(f => ({ ...f, email: val }));
                                                if (activeTab === "faculty") setFacultyForm(f => ({ ...f, email: val }));
                                                if (activeTab === "sub-admin") setSubAdminForm(f => ({ ...f, email: val }));
                                            }}
                                            placeholder="e.g. jdoe@cvr.ac.in"
                                        />
                                    </div>

                                    <div className="space-y-2">
                                        <label className="text-sm font-medium">Unique ID</label>
                                        <div className="flex gap-2">
                                            <Input
                                                required
                                                value={activeTab === "student" ? studentForm.collegeId : activeTab === "faculty" ? facultyForm.collegeId : subAdminForm.collegeId}
                                                onChange={(e) => {
                                                    const val = e.target.value.toUpperCase();
                                                    if (activeTab === "student") setStudentForm(f => ({ ...f, collegeId: val }));
                                                    if (activeTab === "faculty") setFacultyForm(f => ({ ...f, collegeId: val }));
                                                    if (activeTab === "sub-admin") setSubAdminForm(f => ({ ...f, collegeId: val }));
                                                }}
                                                placeholder="e.g. 22B81A05C4"
                                            />
                                            <Button
                                                type="button"
                                                variant="outline"
                                                onClick={() => {
                                                    const val = generateCollegeId(activeTab);
                                                    if (activeTab === "student") setStudentForm(f => ({ ...f, collegeId: val }));
                                                    if (activeTab === "faculty") setFacultyForm(f => ({ ...f, collegeId: val }));
                                                    if (activeTab === "sub-admin") setSubAdminForm(f => ({ ...f, collegeId: val }));
                                                }}
                                            >
                                                Auto
                                            </Button>
                                        </div>
                                    </div>

                                    {activeTab !== "sub-admin" && (
                                        <div className="space-y-2">
                                            <label className="text-sm font-medium">Branch</label>
                                            <Select
                                                value={activeTab === "student" ? studentForm.branch : facultyForm.branch}
                                                onValueChange={(val) => {
                                                    if (activeTab === "student") setStudentForm(f => ({ ...f, branch: val }));
                                                    if (activeTab === "faculty") setFacultyForm(f => ({ ...f, branch: val }));
                                                }}
                                            >
                                                <SelectTrigger>
                                                    <SelectValue placeholder="Select Branch" />
                                                </SelectTrigger>
                                                <SelectContent>
                                                    <SelectItem value="05">CSE</SelectItem>
                                                    <SelectItem value="12">IT</SelectItem>
                                                    <SelectItem value="04">ECE</SelectItem>
                                                </SelectContent>
                                            </Select>
                                        </div>
                                    )}

                                    {activeTab === "student" && (
                                        <div className="space-y-2">
                                            <label className="text-sm font-medium">Academic Batch</label>
                                            <Input
                                                value={studentForm.academicBatch}
                                                onChange={e => setStudentForm(f => ({ ...f, academicBatch: e.target.value }))}
                                                placeholder="2026-2030"
                                            />
                                        </div>
                                    )}
                                    {activeTab === "student" && (
                                        <div className="space-y-2">
                                            <label className="text-sm font-medium">Section</label>
                                            <Input
                                                value={studentForm.section}
                                                onChange={e => setStudentForm(f => ({ ...f, section: e.target.value.toUpperCase() }))}
                                                placeholder="A, B, C..."
                                                maxLength={1}
                                            />
                                        </div>
                                    )}

                                </div>

                                {/* Sub Admin Permissions section */}
                                {activeTab === "sub-admin" && (
                                    <div className="pt-4 border-t mt-6">
                                        <h3 className="text-lg font-semibold mb-4">Granular Permissions</h3>
                                        <div className="grid grid-cols-2 gap-4">
                                            {["manageAttendance", "manageEvents", "manageClubs", "manageNotifications", "manageResults"].map(perm => (
                                                <div key={perm} className="flex items-center space-x-2">
                                                    <Checkbox
                                                        id={perm}
                                                        checked={subAdminForm.permissions[perm as keyof typeof subAdminForm.permissions]}
                                                        onCheckedChange={(checked) =>
                                                            setSubAdminForm(f => ({
                                                                ...f,
                                                                permissions: { ...f.permissions, [perm]: checked }
                                                            }))
                                                        }
                                                    />
                                                    <label htmlFor={perm} className="text-sm font-medium leading-none cursor-pointer">
                                                        {perm.replace("manage", "Manage ")}
                                                    </label>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                <Button type="submit" disabled={loading} className="w-full mt-6 bg-blue-600 hover:bg-blue-700">
                                    {loading ? "Processing..." : `Create ${activeTab === "student" ? "Student" : activeTab === "faculty" ? "Faculty" : "Sub-Admin"}`}
                                </Button>
                            </form>
                        </CardContent>
                    </Card>
                </Tabs>
            </div>
        </AdminLayout>
    );
}

