    const [isAlertModalOpen, setIsAlertModalOpen] = useState(false);
    const [isNotificationSubmitting, setIsNotificationSubmitting] = useState(false);
    const [notificationForm, setNotificationForm] = useState({
        title: "",
        message: "",
        urgency: "normal" as "normal" | "important" | "critical",
        targetType: "all" as "all" | "students" | "faculty" | "custom",
        category: "general" as "general" | "academic" | "placement" | "event" | "emergency",
        branches: [] as string[],
        sections: [] as string[],
        years: [] as string[],
    });

    const [facultyCourses, setFacultyCourses] = useState<FacultyCourseAssignment[]>([]);

    useEffect(() => {
        fetchNotifications();
        if (userData?.collegeId) {
            fetchAssignments();
        }
    }, [userData]);

    const fetchAssignments = async () => {
        try {
            const apiBaseUrl = import.meta.env.VITE_API_URL || "http://localhost:5000";
            const res = await fetch(`${apiBaseUrl}/api/faculty-assignments?facultyId=${userData?.collegeId}`);
            if (res.ok) {
                const data = await res.json();
                setFacultyCourses(data);
            }
        } catch (error) {
            console.error("Failed to fetch faculty assignments:", error);
        }
    };

    const handleNotificationSubmit = async () => {
        if (!notificationForm.title.trim() || !notificationForm.message.trim()) {
            toast({
                title: "Missing Fields",
                description: "Please fill in Title and Message.",
                variant: "destructive",
            });
            return;
        }

        try {
            setIsNotificationSubmitting(true);
            const targetAudience: any = { type: notificationForm.targetType };
            
            if (notificationForm.targetType === 'custom') {
                if (notificationForm.branches.length > 0) targetAudience.branches = notificationForm.branches;
                if (notificationForm.sections.length > 0) targetAudience.sections = notificationForm.sections;
                if (notificationForm.years.length > 0) targetAudience.years = notificationForm.years;
            }

            await sendNotification({
                title: notificationForm.title,
                message: notificationForm.message,
                urgency: notificationForm.urgency,
                targetAudience,
                category: notificationForm.category,
            });

            toast({ title: "Alert Sent Successfully!" });
            
            setNotificationForm({
                title: "",
                message: "",
                urgency: "normal",
                targetType: "all",
                category: "general",
                branches: [],
                sections: [],
                years: [],
            });
            setIsAlertModalOpen(false);
            fetchNotifications();
        } catch (error: any) {
            toast({
                title: "Error",
                description: error.message || "Failed to send alert.",
                variant: "destructive"
            });
        } finally {
             setIsNotificationSubmitting(false);
        }
    };

    const formatDate = (timestamp: number) => {
        return new Date(timestamp).toLocaleString("en-IN", {
            day: "2-digit",
            month: "short",
            year: "numeric",
            hour: "2-digit",
            minute: "2-digit",
        });
    };

    const getCategoryBadge = (category?: string) => {
        const colors: { [key: string]: string } = {
            general: "bg-gray-500",
            academic: "bg-blue-500",
            placement: "bg-green-500",
            event: "bg-purple-500",
            emergency: "bg-red-500",
        };
        return (
            <Badge className={colors[category || "general"] || "bg-gray-500"}>
                {(category || "general").charAt(0).toUpperCase() + (category || "general").slice(1)}
            </Badge>
        );
    };

    // Filter to only show notifications created by this faculty
    const facultyNotifications = allNotifications.filter(n => n.postedBy?.collegeId === userData?.collegeId);

    const filteredNotifications = facultyNotifications.filter((notification) => {
        const matchesSearch =
            notification.title?.toLowerCase().includes(searchTerm.toLowerCase()) ||
            notification.message.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesCategory =
            categoryFilter === "all" || notification.category === categoryFilter;
        return matchesSearch && matchesCategory;
    });

    const handleDelete = async (notificationId: string) => {
        try {
            setDeletingId(notificationId);
            await deleteNotification(notificationId);
            toast({
                title: "Deleted!",
                description: "Alert has been deleted successfully.",
            });
        } catch (err) {
            toast({
                title: "Error",
                description: "Failed to delete alert.",
                variant: "destructive",
            });
        } finally {
            setDeletingId(null);
        }
    };

    return (
        <FacultyLayout>
            <div className="max-w-7xl mx-auto space-y-6">
                <div className="flex items-center justify-between">
                    <div>
                        <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
                            <Bell className="w-8 h-8 text-primary" />
                            Faculty Alerts
                        </h1>
                        <p className="text-muted-foreground mt-1">
                            Send contextual notifications to your course batches
                        </p>
                    </div>
                    <div className="flex gap-3">

                        <Dialog open={isAlertModalOpen} onOpenChange={setIsAlertModalOpen}>
                            <DialogTrigger asChild>
                                <Button className="flex gap-2">
                                    <Send className="w-4 h-4" /> Send Alert
                                </Button>
                            </DialogTrigger>
                            <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                                <DialogHeader>
                                    <DialogTitle className="flex gap-2 items-center text-xl">
                                        <Bell className="w-5 h-5 text-primary" /> Send Alert
                                    </DialogTitle>
                                </DialogHeader>
                                
                                <div className="space-y-4 py-4">
                                    <div className="space-y-2">
                                        <Label>Title <span className="text-destructive">*</span></Label>
                                        <Input
                                            value={notificationForm.title}
                                            onChange={(e) => setNotificationForm({ ...notificationForm, title: e.target.value })}
                                            placeholder="e.g. Test Cancelled" 
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Message <span className="text-destructive">*</span></Label>
                                        <Textarea
                                            value={notificationForm.message}
                                            onChange={(e) => setNotificationForm({ ...notificationForm, message: e.target.value })}
                                            placeholder="Enter your notification message..."
                                            rows={4}
                                        />
                                    </div>
                                    
                                    <div className="space-y-2">
                                        <Label>Urgency</Label>
                                        <Select
                                            value={notificationForm.urgency}
                                            onValueChange={(value: "normal" | "important" | "critical") => setNotificationForm({ ...notificationForm, urgency: value })}
                                        >
                                            <SelectTrigger><SelectValue /></SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="normal">Normal</SelectItem>
                                                <SelectItem value="important">Important</SelectItem>
                                                <SelectItem value="critical">Critical</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>

                                    <div className="space-y-2">
                                        <Label>Category</Label>
                                        <Select
                                            value={notificationForm.category}
                                            onValueChange={(value: "general" | "academic" | "placement" | "event" | "emergency") => setNotificationForm({ ...notificationForm, category: value })}
                                        >
                                            <SelectTrigger><SelectValue /></SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="general">General</SelectItem>
                                                <SelectItem value="academic">Academic</SelectItem>
                                                <SelectItem value="placement">Placement</SelectItem>
                                                <SelectItem value="event">Event</SelectItem>
                                                <SelectItem value="emergency">Emergency</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>

                                    {/* Target Audience */}
                                    <div className="space-y-2">
                                        <Label className="text-sm font-semibold">Target Audience</Label>
                                        <Select
                                            value={notificationForm.targetType}
                                            onValueChange={(value: "all" | "students" | "faculty" | "custom") =>
                                                setNotificationForm({ ...notificationForm, targetType: value })
                                            }
                                        >
                                            <SelectTrigger><SelectValue /></SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="all">All Users</SelectItem>
                                                <SelectItem value="students">All Students</SelectItem>
                                                <SelectItem value="faculty">All Faculty</SelectItem>
                                                <SelectItem value="custom">Custom (Specific Branches/Sections)</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </div>

                                    {/* Custom Targeting Options */}
                                    {notificationForm.targetType === "custom" && (
                                        <div className="space-y-4 p-4 border border-border rounded-lg bg-muted/20">
                                            <p className="text-sm font-medium text-foreground">Custom Targeting Options</p>

                                            <div className="space-y-2">
                                                <Label className="text-sm">Branches (comma-separated)</Label>
                                                <Input
                                                    value={notificationForm.branches.join(", ")}
                                                    onChange={(e) =>
                                                        setNotificationForm({
                                                            ...notificationForm,
                                                            branches: e.target.value.split(",").map((b) => b.trim()).filter((b) => b),
                                                        })
                                                    }
                                                    placeholder="e.g., CSE, ECE"
                                                />
                                            </div>

                                            <div className="space-y-2">
                                                <Label className="text-sm">Sections (comma-separated)</Label>
                                                <Input
                                                    value={notificationForm.sections.join(", ")}
                                                    onChange={(e) =>
                                                        setNotificationForm({
                                                            ...notificationForm,
                                                            sections: e.target.value.split(",").map((s) => s.trim()).filter((s) => s),
                                                        })
                                                    }
                                                    placeholder="e.g., A, B"
                                                />
                                            </div>

                                            <div className="space-y-2">
                                                <Label className="text-sm">Years (comma-separated)</Label>
                                                <Input
                                                    value={notificationForm.years.join(", ")}
                                                    onChange={(e) =>
                                                        setNotificationForm({
                                                            ...notificationForm,
                                                            years: e.target.value.split(",").map((y) => y.trim()).filter((y) => y),
                                                        })
                                                    }
                                                    placeholder="e.g., 1, 2, 3, 4"
                                                />
                                            </div>
                                        </div>
                                    )}

                                    <div className="flex justify-end gap-3 mt-4 pt-4 border-t">
                                        <Button variant="outline" onClick={() => setIsAlertModalOpen(false)}>Cancel</Button>
                                        <Button
                                            onClick={handleNotificationSubmit}
                                            disabled={isNotificationSubmitting}
                                            className="min-w-[140px] bg-blue-600 hover:bg-blue-700 rounded-xl"
                                        >
                                            {isNotificationSubmitting ? (
                                                <>
                                                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                                    Sending...
                                                </>
                                            ) : (
                                                <>
                                                    <Send className="w-4 h-4 mr-2" />
                                                    Send Alert
                                                </>
                                            )}
                                        </Button>
                                    </div>
                                </div>
                            </DialogContent>
                        </Dialog>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <Card>
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-lg bg-primary/10 flex items-center justify-center">
                                <Bell className="w-6 h-6 text-primary" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">My Alerts Sent</p>
                                <p className="text-2xl font-bold">{facultyNotifications.length}</p>
                            </div>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-lg bg-blue-500/10 flex items-center justify-center">
                                <BookOpen className="w-6 h-6 text-blue-500" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Assigned Courses</p>
                                <p className="text-2xl font-bold">{facultyCourses.length}</p>
                            </div>
                        </CardContent>
                    </Card>
                </div>

                <Card>
                    <CardContent className="p-4">
                        <div className="flex flex-col md:flex-row gap-4">
                            <div className="flex-1">
                                <div className="relative">
                                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground w-4 h-4" />
                                    <Input placeholder="Search alerts..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="pl-10" />
                                </div>
                            </div>
                            <Select value={categoryFilter} onValueChange={setCategoryFilter}>
                                <SelectTrigger className="w-full md:w-[180px]"><SelectValue placeholder="Category" /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">All Categories</SelectItem>
                                    <SelectItem value="general">General</SelectItem>
                                    <SelectItem value="academic">Academic</SelectItem>
                                    <SelectItem value="emergency">Emergency</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </CardContent>
                </Card>

                {!loading && filteredNotifications.length === 0 ? (
                    <Card>
                        <CardContent className="py-12 text-center">
                            <Bell className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                            <h3 className="text-lg font-medium">No alerts found</h3>
                            <p className="text-muted-foreground">Send contextual alerts using the "Send Alert" button.</p>
                        </CardContent>
                    </Card>
                ) : (
                    <div className="space-y-4">
                        {filteredNotifications.map((notification) => (
                            <Card key={notification.id} className="hover:shadow-lg transition-shadow border-l-4 border-l-blue-500">
                                <CardContent className="p-6">
                                    <div className="flex items-start justify-between gap-4">
                                        <div className="flex-1 space-y-3">
                                            <div className="flex items-start gap-3 flex-wrap">
                                                <h3 className="text-lg font-bold text-foreground">{notification.title}</h3>
                                                {getCategoryBadge(notification.category)}
                                                <Badge variant="outline">Course: {notification.targetAudience.courseCode}</Badge>
                                                <Badge variant="outline">Section: {notification.targetAudience.sections?.[0]}</Badge>
                                            </div>
                                            <p className="text-muted-foreground">{notification.message}</p>
                                            <div className="flex flex-wrap items-center gap-4 text-sm text-muted-foreground">
                                                <span className="flex items-center gap-1"><Clock className="w-4 h-4" />{formatDate(notification.createdAt)}</span>
                                                <span className="flex items-center gap-1"><Users className="w-4 h-4" />Targeted Batch</span>
                                            </div>
                                        </div>
                                        <AlertDialog>
                                            <AlertDialogTrigger asChild>
                                                <Button variant="ghost" size="sm" className="text-destructive" disabled={deletingId === notification.id}>
                                                    {deletingId === notification.id ? <Loader2 className="w-4 h-4 animate-spin" /> : <Trash2 className="w-4 h-4" />}
                                                </Button>
                                            </AlertDialogTrigger>
                                            <AlertDialogContent>
                                                <AlertDialogHeader>
                                                    <AlertDialogTitle>Delete Alert?</AlertDialogTitle>
                                                    <AlertDialogDescription>This will delete the alert permanently.</AlertDialogDescription>
                                                </AlertDialogHeader>
                                                <AlertDialogFooter>
                                                    <AlertDialogCancel>Cancel</AlertDialogCancel>
                                                    <AlertDialogAction onClick={() => handleDelete(notification.id)} className="bg-destructive text-destructive-foreground">Delete</AlertDialogAction>
                                                </AlertDialogFooter>
                                            </AlertDialogContent>
                                        </AlertDialog>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                )}
            </div>
        </FacultyLayout>
    );
};

export default FacultyAlerts;

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import FacultyLayout from "@/components/FacultyLayout";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import {
  Search,
  Plus,
  Eye,
  Edit,
  Trash2,
  Download,
  FileText,
  Calendar,
  Users,
  Loader2,
  X,
  ClipboardList,
} from "lucide-react";
import {
  getFacultyAssignments,
  getAllAssignments,
  createAssignment,
  updateAssignment,
  deleteAssignment,
  getSubmissions,
  downloadSubmission,
  gradeSubmission,
  openPdfInNewTab,
  formatDate,
  formatFileSize,
  isOverdue,
} from "@/services/assignmentService";

type Assignment = {
  _id: string;
  title: string;
  description: string;
  course: string;
  courseCode: string;
  dueDate: string;
  createdBy: string;
  createdByName: string;
  section: string;
  status: "Active" | "Completed" | "Draft";
  submissionCount: number;
  createdAt: string;
};

type Submission = {
  _id: string;
  studentId: string;
  studentName: string;
  fileName: string;
  fileSize: number;
  submittedAt: string;
  grade: number | null;
  feedback: string;
};

const FacultyAssignments = () => {
  const { userData } = useAuth();
  const [assignments, setAssignments] = useState<Assignment[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [isCreateDialogOpen, setIsCreateDialogOpen] = useState(false);
  const [isSubmissionsDialogOpen, setIsSubmissionsDialogOpen] = useState(false);
  const [selectedAssignment, setSelectedAssignment] = useState<Assignment | null>(null);
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [submissionsLoading, setSubmissionsLoading] = useState(false);
  const [creating, setCreating] = useState(false);

  // Edit dialog state
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [editingAssignment, setEditingAssignment] = useState<Assignment | null>(null);
  const [editFormData, setEditFormData] = useState({
    title: "",
    description: "",
    course: "",
    courseCode: "",
    dueDate: "",
    status: "Active" as "Active" | "Completed" | "Draft",
  });
  const [updating, setUpdating] = useState(false);

  // Form state for create assignment
  const [formData, setFormData] = useState({
    title: "",
    description: "",
    course: "",
    courseCode: "",
    dueDate: "",
    maxMarks: 100,
    degree: "Major",
    year: "IV Year",
    semester: "Semester-I",
    branch: "CSE",
    section: "",
  });

  // Fetch assignments - only fetch this faculty's assignments
  const fetchAssignments = async () => {
    try {
      setLoading(true);
      const facultyId = userData?.collegeId || "";
      if (!facultyId) {
        toast.error("Faculty ID not found");
        return;
      }
      // Only get assignments created by this faculty
      const data = await getFacultyAssignments(facultyId);
      setAssignments(data);
    } catch (error) {
      console.error("Error fetching assignments:", error);
      toast.error("Failed to load assignments");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAssignments();
  }, [userData?.collegeId]);

  // Create assignment handler
  const handleCreateAssignment = async () => {
    if (!formData.title || !formData.course || !formData.dueDate || !formData.section) {
      toast.error("Please fill in all required fields (including Section)");
      return;
    }

    try {
      setCreating(true);
      await createAssignment({
        ...formData,
        createdBy: userData?.collegeId || "FACULTY001",
        createdByName: userData?.name || "Faculty",
      });

      toast.success("Assignment created successfully!");
      setIsCreateDialogOpen(false);
      setFormData({
        title: "",
        description: "",
        course: "",
        courseCode: "",
        dueDate: "",
        maxMarks: 100,
        degree: "Major",
        year: "IV Year",
        semester: "Semester-I",
        branch: "CSE",
        section: "",
      });
      fetchAssignments();
    } catch (error) {
      console.error("Error creating assignment:", error);
      toast.error("Failed to create assignment");
    } finally {
      setCreating(false);
    }
  };

  // Delete assignment handler
  const handleDeleteAssignment = async (id: string) => {
    if (!confirm("Are you sure you want to delete this assignment?")) return;

    try {
      await deleteAssignment(id);
      toast.success("Assignment deleted");
      fetchAssignments();
    } catch (error) {
      console.error("Error deleting assignment:", error);
      toast.error("Failed to delete assignment");
    }
  };

  // Edit assignment handler
  const handleEditAssignment = (assignment: Assignment) => {
    setEditingAssignment(assignment);
    setEditFormData({
      title: assignment.title,
      description: assignment.description || "",
      course: assignment.course,
      courseCode: assignment.courseCode || "",
      dueDate: assignment.dueDate ? new Date(assignment.dueDate).toISOString().split('T')[0] : "",
      status: assignment.status,
    });
    setIsEditDialogOpen(true);
  };

  const handleUpdateAssignment = async () => {
    if (!editingAssignment) return;
    if (!editFormData.title || !editFormData.course || !editFormData.dueDate) {
      toast.error("Please fill in all required fields");
      return;
    }

    try {
      setUpdating(true);
      await updateAssignment(editingAssignment._id, editFormData);
      toast.success("Assignment updated successfully!");
      setIsEditDialogOpen(false);
      setEditingAssignment(null);
      fetchAssignments();
    } catch (error) {
      console.error("Error updating assignment:", error);
      toast.error("Failed to update assignment");
    } finally {
      setUpdating(false);
    }
  };

  // View submissions handler
  const handleViewSubmissions = async (assignment: Assignment) => {
    setSelectedAssignment(assignment);
    setIsSubmissionsDialogOpen(true);
    setSubmissionsLoading(true);

    try {
      const data = await getSubmissions(assignment._id);
      setSubmissions(data.submissions);
    } catch (error) {
      console.error("Error fetching submissions:", error);
      toast.error("Failed to load submissions");
    } finally {
      setSubmissionsLoading(false);
    }
  };

  // Download/View submission PDF
  const handleViewPdf = async (submissionId: string, fileName: string) => {
    if (!selectedAssignment) return;

    try {
      const data = await downloadSubmission(selectedAssignment._id, submissionId);
      openPdfInNewTab(data.fileData, fileName);
    } catch (error) {
      console.error("Error viewing PDF:", error);
      toast.error("Failed to open PDF");
    }
  };

  // Filter assignments
  const filteredAssignments = assignments.filter(
    (a) =>
      a.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      a.course.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const getStatusBadge = (assignment: Assignment) => {
    const baseClasses = "text-white border-none shrink-0 cursor-default uppercase tracking-wider text-[10px] shadow-sm px-2 py-0.5";
    if (assignment.status === "Completed") {
      return <Badge className={`bg-green-500 hover:bg-green-600 ${baseClasses}`}>Completed</Badge>;
    }
    if (isOverdue(assignment.dueDate)) {
      return <Badge className={`bg-red-500 hover:bg-red-600 ${baseClasses}`}>Overdue</Badge>;
    }
    return <Badge className={`bg-blue-500 hover:bg-blue-600 ${baseClasses}`}>Active</Badge>;
  };

  return (
    <FacultyLayout>
      <div className="max-w-7xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
              <ClipboardList className="w-8 h-8 text-primary" />
              Assignment Management
            </h1>
            <p className="text-muted-foreground mt-1">
              Streamline assignment distribution and evaluate student performance.
            </p>
          </div>
        </div>

        <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
          <div className="relative w-full md:w-72">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground w-4 h-4" />
            <Input
              placeholder="Search assignments..."
              className="pl-10"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>

          <Dialog open={isCreateDialogOpen} onOpenChange={setIsCreateDialogOpen}>
            <DialogTrigger asChild>
              <Button className="w-full md:w-auto">
                <Plus className="w-4 h-4 mr-2" />
                Create Assignment
              </Button>
            </DialogTrigger>
            <DialogContent className="sm:max-w-[500px]">
              <DialogHeader>
                <DialogTitle>Create New Assignment</DialogTitle>
                <DialogDescription>
                  Fill in the details to create a new assignment for students.
                </DialogDescription>
              </DialogHeader>

              <div className="grid gap-4 py-4">
                <div className="grid gap-2">
                  <Label htmlFor="title">Assignment Title *</Label>
                  <Input
                    id="title"
                    placeholder="e.g., Data Analysis Project"
                    value={formData.title}
                    onChange={(e) =>
                      setFormData({ ...formData, title: e.target.value })
                    }
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="grid gap-2">
                    <Label htmlFor="course">Course Name *</Label>
                    <Input
                      id="course"
                      placeholder="e.g., Python for EDA"
                      value={formData.course}
                      onChange={(e) =>
                        setFormData({ ...formData, course: e.target.value })
                      }
                    />
                  </div>
                  <div className="grid gap-2">
                    <Label htmlFor="courseCode">Course Code</Label>
                    <Input
                      id="courseCode"
                      placeholder="e.g., 22CS401"
                      value={formData.courseCode}
                      onChange={(e) =>
                        setFormData({ ...formData, courseCode: e.target.value })
                      }
                    />
                  </div>
                </div>

                <div className="grid gap-2">
                  <Label htmlFor="description">Description</Label>
                  <Textarea
                    id="description"
                    placeholder="Describe the assignment requirements..."
                    rows={3}
                    value={formData.description}
                    onChange={(e) =>
                      setFormData({ ...formData, description: e.target.value })
                    }
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="grid gap-2">
                    <Label htmlFor="dueDate">Due Date *</Label>
                    <Input
                      id="dueDate"
                      type="date"
                      value={formData.dueDate}
                      onChange={(e) =>
                        setFormData({ ...formData, dueDate: e.target.value })
                      }
                    />
                  </div>
                  <div className="grid gap-2">
                    <Label htmlFor="maxMarks">Max Marks</Label>
                    <Input
                      id="maxMarks"
                      type="number"
                      min={0}
                      max={100}
                      value={formData.maxMarks}
                      onChange={(e) =>
                        setFormData({
                          ...formData,
                          maxMarks: parseInt(e.target.value) || 100,
                        })
                      }
                    />
                  </div>
                </div>

                {/* Student Category Selection */}
                {/* Row 1: Degree + Year */}
                <div className="grid grid-cols-2 gap-4">
                  <div className="grid gap-2">
                    <Label htmlFor="degree">Degree *</Label>
                    <Select
                      value={formData.degree}
                      onValueChange={(value) =>
                        setFormData({ ...formData, degree: value })
                      }
                    >
                      <SelectTrigger id="degree">
                        <SelectValue placeholder="Select Degree" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="Major">Major</SelectItem>
                        <SelectItem value="Minor">Minor</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="grid gap-2">
                    <Label htmlFor="year">Year *</Label>
                    <Select
                      value={formData.year}
                      onValueChange={(value) =>
                        setFormData({ ...formData, year: value })
                      }
                    >
                      <SelectTrigger id="year">
                        <SelectValue placeholder="Select Year" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="I Year">I Year</SelectItem>
                        <SelectItem value="II Year">II Year</SelectItem>
                        <SelectItem value="III Year">III Year</SelectItem>
                        <SelectItem value="IV Year">IV Year</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                {/* Row 2: Semester + Branch */}
                <div className="grid grid-cols-2 gap-4">
                  <div className="grid gap-2">
                    <Label htmlFor="semester">Semester *</Label>
                    <Select
                      value={formData.semester}
                      onValueChange={(value) =>
                        setFormData({ ...formData, semester: value })
                      }
                    >
                      <SelectTrigger id="semester">
                        <SelectValue placeholder="Select Semester" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="Semester-I">Semester-I</SelectItem>
                        <SelectItem value="Semester-II">Semester-II</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="grid gap-2">
                    <Label htmlFor="branch">Branch *</Label>
                    <Select
                      value={formData.branch}
                      onValueChange={(value) =>
                        setFormData({ ...formData, branch: value })
                      }
                    >
                      <SelectTrigger id="branch">
                        <SelectValue placeholder="Select Branch" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="CSE">CSE</SelectItem>
                        <SelectItem value="ECE">ECE</SelectItem>
                        <SelectItem value="EEE">EEE</SelectItem>
                        <SelectItem value="MECH">MECH</SelectItem>
                        <SelectItem value="CIVIL">CIVIL</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                {/* Row 3: Section (full width text input) */}
                <div className="grid gap-2">
                  <Label htmlFor="section">Section *</Label>
                  <Input
                    id="section"
                    placeholder="e.g., B"
                    value={formData.section}
                    onChange={(e) =>
                      setFormData({ ...formData, section: e.target.value.trim() })
                    }
                  />
                </div>
              </div>

              <DialogFooter>
                <Button
                  variant="outline"
                  onClick={() => setIsCreateDialogOpen(false)}
                >
                  Cancel
                </Button>
                <Button onClick={handleCreateAssignment} disabled={creating}>
                  {creating && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                  Create Assignment
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        </div>

        {/* Edit Assignment Dialog */}
        <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
          <DialogContent className="max-w-xl">
            <DialogHeader>
              <DialogTitle className="flex items-center gap-2">
                <Edit className="w-5 h-5 text-primary" />
                Edit Assignment
              </DialogTitle>
              <DialogDescription>
                Update the assignment details below.
              </DialogDescription>
            </DialogHeader>

            <div className="space-y-4 py-2">
              <div className="space-y-2">
                <Label>Title *</Label>
                <Input
                  placeholder="Assignment Title"
                  value={editFormData.title}
                  onChange={(e) =>
                    setEditFormData({ ...editFormData, title: e.target.value })
                  }
                />
              </div>

              <div className="space-y-2">
                <Label>Description</Label>
                <Textarea
                  placeholder="Assignment description..."
                  rows={3}
                  value={editFormData.description}
                  onChange={(e) =>
                    setEditFormData({ ...editFormData, description: e.target.value })
                  }
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Course *</Label>
                  <Input
                    placeholder="Course Name"
                    value={editFormData.course}
                    onChange={(e) =>
                      setEditFormData({ ...editFormData, course: e.target.value })
                    }
                  />
                </div>
                <div className="space-y-2">
                  <Label>Course Code</Label>
                  <Input
                    placeholder="e.g. CS401"
                    value={editFormData.courseCode}
                    onChange={(e) =>
                      setEditFormData({ ...editFormData, courseCode: e.target.value })
                    }
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Due Date *</Label>
                  <Input
                    type="date"
                    value={editFormData.dueDate}
                    onChange={(e) =>
                      setEditFormData({ ...editFormData, dueDate: e.target.value })
                    }
                  />
                </div>
                <div className="space-y-2">
                  <Label>Status</Label>
                  <Select
                    value={editFormData.status}
                    onValueChange={(val: any) =>
                      setEditFormData({ ...editFormData, status: val })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Active">Active</SelectItem>
                      <SelectItem value="Completed">Completed</SelectItem>
                      <SelectItem value="Draft">Draft</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
            </div>

            <DialogFooter>
              <Button
                variant="outline"
                onClick={() => setIsEditDialogOpen(false)}
              >
                Cancel
              </Button>
              <Button onClick={handleUpdateAssignment} disabled={updating}>
                {updating && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                Save Changes
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>

        {loading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="w-8 h-8 animate-spin text-primary" />
          </div>
        ) : filteredAssignments.length === 0 ? (
          <Card>
            <CardContent className="py-12 text-center">
              <FileText className="w-12 h-12 mx-auto text-muted-foreground mb-4" />
              <h3 className="text-lg font-medium text-foreground mb-2">
                No Assignments Found
              </h3>
              <p className="text-muted-foreground">
                {searchQuery
                  ? "No assignments match your search."
                  : "Click 'Create Assignment' to add your first assignment."}
              </p>
            </CardContent>
          </Card>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredAssignments.map((assignment) => (
              <Card
                key={assignment._id}
                className="overflow-hidden border-border/50 bg-card/50 hover:bg-card transition-all duration-300 flex flex-col group relative"
              >
                {/* Top colored section with assignment title */}
                <div className={`m-3 h-[100px] rounded-xl flex flex-col items-center justify-center bg-blue-500 px-4 text-center`}>
                   <h3 className="font-bold text-white text-lg tracking-wide line-clamp-2" title={assignment.title}>{assignment.title}</h3>
                </div>
                
                <CardContent className="px-5 pb-5 pt-2 flex flex-col flex-1">
                  <div className="flex justify-between items-start gap-2 mb-4">
                    <div className="flex-1">
                      <p className="text-sm text-muted-foreground flex items-center">
                         <Calendar className="w-3.5 h-3.5 mr-1.5 text-primary" />
                         Due: {formatDate(assignment.dueDate)}
                      </p>
                    </div>
                    {getStatusBadge(assignment)}
                  </div>
                  
                  <div className="grid grid-cols-1 gap-4 my-2 mb-6">
                    <div className="text-center bg-muted/20 py-3 rounded-lg border border-border/50">
                      <p className="text-2xl font-bold text-foreground">{assignment.submissionCount}</p>
                      <p className="text-xs text-muted-foreground uppercase tracking-wider mt-1">Submissions</p>
                    </div>
                  </div>
                  
                  {/* Action Icons */}
                  <div className="grid grid-cols-3 gap-2 mt-auto pt-4 border-t border-border/50">
                     <Button 
                        variant="ghost" 
                        className="w-full h-10 bg-transparent hover:bg-primary/20 text-white hover:text-primary-foreground transition-all duration-300"
                        title="View Submissions"
                        onClick={() => handleViewSubmissions(assignment)}
                     >
                       <Eye className="w-5 h-5" />
                     </Button>
                     <Button 
                        variant="ghost" 
                        className="w-full h-10 bg-transparent hover:bg-blue-500/20 text-white hover:text-blue-100 transition-all duration-300"
                        title="Edit Assignment"
                        onClick={() => handleEditAssignment(assignment)}
                     >
                       <Edit className="w-5 h-5" />
                     </Button>
                     <Button 
                        variant="ghost" 
                        className="w-full h-10 bg-transparent hover:bg-red-500/20 text-white hover:text-red-100 transition-all duration-300"
                        title="Delete Assignment"
                        onClick={() => handleDeleteAssignment(assignment._id)}
                     >
                       <Trash2 className="w-5 h-5" />
                     </Button>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}

        {/* Submissions Dialog */}
        <Dialog open={isSubmissionsDialogOpen} onOpenChange={setIsSubmissionsDialogOpen}>
          <DialogContent className="sm:max-w-[700px] max-h-[80vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>
                Submissions - {selectedAssignment?.title}
              </DialogTitle>
              <DialogDescription>
                View and download student submissions for this assignment.
              </DialogDescription>
            </DialogHeader>

            {submissionsLoading ? (
              <div className="flex items-center justify-center py-8">
                <Loader2 className="w-6 h-6 animate-spin text-primary" />
              </div>
            ) : submissions.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                No submissions yet.
              </div>
            ) : (
              <div className="space-y-4">
                {submissions.map((sub) => (
                  <div
                    key={sub._id}
                    className="flex items-center justify-between p-4 border rounded-lg bg-muted/20"
                  >
                    <div className="flex-1">
                      <div className="font-medium text-foreground">
                        {sub.studentName}
                      </div>
                      <div className="text-sm text-muted-foreground">
                        {sub.studentId}
                      </div>
                      <div className="text-xs text-muted-foreground mt-1">
                        Submitted: {formatDate(sub.submittedAt)}
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <div className="text-sm text-muted-foreground mr-4">
                        {formatFileSize(sub.fileSize)}
                      </div>
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => handleViewPdf(sub._id, sub.fileName)}
                      >
                        <Eye className="w-4 h-4 mr-1" />
                        View PDF
                      </Button>
                      {sub.grade !== null && (
                        <Badge className="bg-green-500 text-white">
                          Grade: {sub.grade}
                        </Badge>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </DialogContent>
        </Dialog>
      </div>
    </FacultyLayout>
  );
};

export default FacultyAssignments;

import { useState, useEffect, useRef } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogFooter,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import FacultyLayout from "@/components/FacultyLayout";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import {
  Search,
  Eye,
  Users,
  BookOpen,
  Plus,
  Trash2,
  Upload,
  FileText,
  X,
  Loader2,
  Calendar,
  Clock,
  Edit2,
  CheckSquare,
} from "lucide-react";

const API_BASE = import.meta.env.VITE_API_URL || "http://localhost:5000/api";

const COURSE_COLORS = [
  "bg-blue-500",
  "bg-green-500",
  "bg-orange-500",
  "bg-purple-500",
  "bg-pink-500",
  "bg-cyan-500",
  "bg-red-500",
  "bg-indigo-500",
  "bg-teal-500",
  "bg-amber-500",
];

const ALL_SECTIONS = ["A", "B", "C", "D", "E", "F", "G"];

interface CourseResource {
  _id?: string;
  name: string;
  type: string;
  fileData?: string;
  fileName?: string;
  fileSize?: number;
  uploadedAt?: string;
}

interface SyllabusTopic {
  topic: string;
  duration: string;
}

interface Course {
  _id: string;
  courseCode: string;
  courseName: string;
  department: string;
  degree?: string;
  classType?: string;
  year: string;
  semester: string;
  credits: number;
  maxStudents: number;
  description: string;
  objectives: string[];
  syllabus: SyllabusTopic[];
  resources: CourseResource[];
  facultyId: string;
  facultyName: string;
  status: string;
  color: string;
  createdAt: string;
  sections?: string[];
  assignedStudents?: string[];
}

interface StudentInfo {
  rollNumber: string;
  name: string;
  section: string;
}

const FacultyCourses = () => {
  const { userData } = useAuth();
  const [courses, setCourses] = useState<Course[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [addDialogOpen, setAddDialogOpen] = useState(false);
  const [viewDialogOpen, setViewDialogOpen] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState<Course | null>(null);
  const [submitting, setSubmitting] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [editCourseId, setEditCourseId] = useState<string | null>(null);

  // Form state
  const [courseCode, setCourseCode] = useState("");
  const [courseName, setCourseName] = useState("");
  const [department, setDepartment] = useState("CSE");
  const [degree, setDegree] = useState("Major");
  const [classType, setClassType] = useState("Theory");
  const [year, setYear] = useState("IV Year");
  const [semester, setSemester] = useState("Semester I");
  const [credits, setCredits] = useState("3");
  const [description, setDescription] = useState("");
  const [objectives, setObjectives] = useState("");
  const [syllabus, setSyllabus] = useState<SyllabusTopic[]>([
    { topic: "", duration: "" },
  ]);
  const [pendingFiles, setPendingFiles] = useState<
    { name: string; type: string; fileData: string; fileName: string; fileSize: number }[]
  >([]);
  const [courseColor, setCourseColor] = useState("bg-blue-500");
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sections & Students state
  const [selectedSections, setSelectedSections] = useState<string[]>([]);
  const [sectionStudents, setSectionStudents] = useState<StudentInfo[]>([]);
  const [selectedStudents, setSelectedStudents] = useState<string[]>([]);
  const [studentSearchQuery, setStudentSearchQuery] = useState("");
  const [loadingStudents, setLoadingStudents] = useState(false);

  // Fetch courses
  const fetchCourses = async () => {
    try {
      setLoading(true);
      const facultyId = userData?.collegeId || "";
      const res = await fetch(`${API_BASE}/courses?facultyId=${facultyId}`);
      if (res.ok) {
        const data = await res.json();
        setCourses(data);
      }
    } catch (error) {
      console.error("Error fetching courses:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (userData?.collegeId) {
      fetchCourses();
    }
  }, [userData?.collegeId]);

  // Fetch students when sections change
  useEffect(() => {
    if (selectedSections.length === 0) {
      setSectionStudents([]);
      return;
    }

    const fetchStudents = async () => {
      setLoadingStudents(true);
      try {
        const allStudents: StudentInfo[] = [];
        const yearCode = userData?.year || "22";
        const branchCode = userData?.branch || "05";

        for (const section of selectedSections) {
          try {
            const res = await fetch(
              `${API_BASE}/students/section/${yearCode}/${branchCode}/${section}`
            );
            if (res.ok) {
              const data = await res.json();
              if (data.students) {
                data.students.forEach((s: any) => {
                  if (!allStudents.some((existing) => existing.rollNumber === s.rollNumber)) {
                    allStudents.push({
                      rollNumber: s.rollNumber,
                      name: s.name || s.rollNumber,
                      section: s.section || section,
                    });
                  }
                });
              }
            }
          } catch (err) {
            console.warn(`Failed to fetch students for section ${section}:`, err);
          }
        }

        setSectionStudents(allStudents.sort((a, b) => a.rollNumber.localeCompare(b.rollNumber)));
      } catch (error) {
        console.error("Error fetching students:", error);
      } finally {
        setLoadingStudents(false);
      }
    };

    fetchStudents();
  }, [selectedSections, userData?.year, userData?.branch]);

  // Toggle section selection
  const toggleSection = (section: string) => {
    setSelectedSections((prev) =>
      prev.includes(section) ? prev.filter((s) => s !== section) : [...prev, section]
    );
  };

  // Toggle student selection
  const toggleStudent = (rollNumber: string) => {
    setSelectedStudents((prev) =>
      prev.includes(rollNumber)
        ? prev.filter((r) => r !== rollNumber)
        : [...prev, rollNumber]
    );
  };

  // Select/Deselect all filtered students
  const toggleAllFilteredStudents = () => {
    const filtered = filteredStudents.map((s) => s.rollNumber);
    const allSelected = filtered.every((r) => selectedStudents.includes(r));
    if (allSelected) {
      setSelectedStudents((prev) => prev.filter((r) => !filtered.includes(r)));
    } else {
      setSelectedStudents((prev) => [...new Set([...prev, ...filtered])]);
    }
  };

  // Filter students for search (restricted to Section B only dynamically)
  const isOnlySectionB = selectedSections.length > 0 && selectedSections.every(s => s === "B");
  const filteredStudents = isOnlySectionB
    ? sectionStudents.filter(
        (s) =>
          s.rollNumber.toLowerCase().includes(studentSearchQuery.toLowerCase()) ||
          s.name.toLowerCase().includes(studentSearchQuery.toLowerCase())
      )
    : [];

  // Reset form
  const resetForm = () => {
    setIsEditing(false);
    setEditCourseId(null);
    setCourseCode("");
    setCourseName("");
    setDepartment("CSE");
    setDegree("Major");
    setClassType("Theory");
    setYear("IV Year");
    setSemester("Semester I");
    setCredits("3");
    setDescription("");
    setObjectives("");
    setSyllabus([{ topic: "", duration: "" }]);
    setPendingFiles([]);
    setCourseColor(COURSE_COLORS[Math.floor(Math.random() * COURSE_COLORS.length)]);
    setSelectedSections([]);
    setSelectedStudents([]);
    setSectionStudents([]);
    setStudentSearchQuery("");
  };

  // Handle file upload
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file) => {
      const reader = new FileReader();
      reader.onload = () => {
        const base64 = reader.result as string;
        const ext = file.name.split(".").pop()?.toUpperCase() || "PDF";
        setPendingFiles((prev) => [
          ...prev,
          {
            name: file.name.replace(/\.[^/.]+$/, ""),
            type: ext,
            fileData: base64,
            fileName: file.name,
            fileSize: file.size,
          },
        ]);
      };
      reader.readAsDataURL(file);
    });
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  // Remove a pending file
  const removePendingFile = (index: number) => {
    setPendingFiles((prev) => prev.filter((_, i) => i !== index));
  };

  // Add syllabus topic
  const addSyllabusTopic = () => {
    setSyllabus((prev) => [...prev, { topic: "", duration: "" }]);
  };

  // Remove syllabus topic
  const removeSyllabusTopic = (index: number) => {
    setSyllabus((prev) => prev.filter((_, i) => i !== index));
  };

  // Update syllabus topic
  const updateSyllabusTopic = (index: number, field: "topic" | "duration", value: string) => {
    setSyllabus((prev) =>
      prev.map((item, i) => (i === index ? { ...item, [field]: value } : item))
    );
  };

  // Submit new course
  const handleSubmit = async () => {
    if (!courseCode.trim() || !courseName.trim()) {
      toast.error("Course Code and Course Name are required");
      return;
    }

    try {
      setSubmitting(true);
      const payload: any = {
        courseCode: courseCode.trim(),
        courseName: courseName.trim(),
        department: department,
        degree: degree,
        classType: classType,
        year: year,
        semester: semester,
        credits: Number(credits) || 3,
        maxStudents: selectedStudents.length || 0,
        description: description.trim(),
        objectives: objectives
          .split("\n")
          .map((o) => o.trim())
          .filter((o) => o.length > 0),
        syllabus: syllabus.filter((s) => s.topic.trim().length > 0),
        facultyId: userData?.collegeId || "",
        facultyName: userData?.name || "Faculty",
        color: courseColor,
        sections: selectedSections,
        assignedStudents: selectedStudents,
      };

      let url = `${API_BASE}/courses`;
      let method = "POST";

      if (isEditing && editCourseId) {
        url = `${API_BASE}/courses/${editCourseId}`;
        method = "PUT";
      } else {
        payload.resources = pendingFiles;
      }

      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (res.ok) {
        if (isEditing && editCourseId && pendingFiles.length > 0) {
          for (const file of pendingFiles) {
            await fetch(`${API_BASE}/courses/${editCourseId}/resources`, {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify(file),
            });
          }
        }

        toast.success(isEditing ? "Course updated successfully!" : "Course added successfully!");
        setAddDialogOpen(false);
        resetForm();
        fetchCourses();
      } else {
        const err = await res.json();
        toast.error(err.error || (isEditing ? "Failed to update course" : "Failed to add course"));
      }
    } catch (error) {
      console.error("Error adding course:", error);
      toast.error(isEditing ? "Failed to update course" : "Failed to add course");
    } finally {
      setSubmitting(false);
    }
  };

  const handleEdit = (course: Course) => {
    setIsEditing(true);
    setEditCourseId(course._id);
    setCourseCode(course.courseCode);
    setCourseName(course.courseName);
    setDepartment(course.department || "CSE");
    setDegree(course.degree || "Major");
    setClassType(course.classType || "Theory");
    setYear(course.year || "IV Year");
    setSemester(course.semester || "Semester I");
    setCredits(String(course.credits));
    setDescription(course.description || "");
    setObjectives((course.objectives || []).join("\n"));
    setSyllabus(course.syllabus?.length > 0 ? course.syllabus : [{ topic: "", duration: "" }]);
    setCourseColor(course.color || COURSE_COLORS[0]);
    setPendingFiles([]);
    setSelectedSections(course.sections || []);
    setSelectedStudents(course.assignedStudents || []);
    setAddDialogOpen(true);
  };

  // Delete course
  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this course?")) return;
    try {
      const res = await fetch(`${API_BASE}/courses/${id}`, { method: "DELETE" });
      if (res.ok) {
        toast.success("Course deleted");
        fetchCourses();
        setViewDialogOpen(false);
      } else {
        toast.error("Failed to delete course");
      }
    } catch (error) {
      toast.error("Failed to delete course");
    }
  };

  // Download a resource
  const handleDownload = async (courseId: string, resource: CourseResource) => {
    try {
      if (!resource._id) {
        if (resource.fileData) {
          const link = document.createElement("a");
          link.href = resource.fileData;
          link.download = resource.fileName || resource.name;
          link.click();
        }
        return;
      }

      const res = await fetch(`${API_BASE}/courses/${courseId}/resources/${resource._id}/download`);
      if (res.ok) {
        const data = await res.json();
        const link = document.createElement("a");
        link.href = data.fileData;
        link.download = data.fileName || data.name || resource.name;
        link.click();
      } else {
        toast.error("Failed to download resource");
      }
    } catch (error) {
      console.error("Error downloading resource:", error);
      toast.error("Error downloading resource");
    }
  };

  // Calculate stats
  const totalStudents = courses.reduce((sum, c) => sum + (c.assignedStudents?.length || c.maxStudents || 0), 0);
  const totalCredits = courses.reduce((sum, c) => sum + c.credits, 0);

  // Filter courses
  const filteredCourses = courses.filter(
    (c) =>
      c.courseCode.toLowerCase().includes(searchQuery.toLowerCase()) ||
      c.courseName.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <FacultyLayout>
      <div className="max-w-7xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
              <BookOpen className="w-8 h-8 text-primary" />
              My Courses
            </h1>
            <p className="text-muted-foreground mt-1">
              Organize your teaching workflow and course responsibilities.
            </p>
          </div>
        </div>

        <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
          <div className="relative w-full md:w-80">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground w-4 h-4" />
            <Input
              placeholder="Search courses..."
              className="pl-10"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
          </div>

          {/* ─── ADD COURSE DIALOG ───────────────────────────────────── */}
          <Dialog open={addDialogOpen} onOpenChange={(open) => {
            setAddDialogOpen(open);
            if (open) resetForm();
          }}>
            <DialogTrigger asChild>
              <Button className="w-full md:w-auto">
                <Plus className="w-4 h-4 mr-2" />
                Add Course
              </Button>
            </DialogTrigger>
            <DialogContent className="max-w-2xl max-h-[85vh] overflow-y-auto">
              <DialogHeader>
                <DialogTitle className="flex items-center gap-2">
                  <BookOpen className="w-5 h-5 text-primary" />
                  {isEditing ? "Edit Course" : "Add New Course"}
                </DialogTitle>
              </DialogHeader>

              <div className="space-y-5 py-2">
                {/* Row 1: Code + Name */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="courseCode">Course Code *</Label>
                    <Input
                      id="courseCode"
                      placeholder="e.g. CS301"
                      value={courseCode}
                      onChange={(e) => setCourseCode(e.target.value)}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="courseName">Course Name *</Label>
                    <Input
                      id="courseName"
                      placeholder="e.g. Data Structures"
                      value={courseName}
                      onChange={(e) => setCourseName(e.target.value)}
                    />
                  </div>
                </div>

                {/* Row 1.5: Department, Degree, Year, Semester */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="department">Department *</Label>
                    <Select value={department} onValueChange={setDepartment}>
                      <SelectTrigger id="department">
                        <SelectValue placeholder="Select Department" />
                      </SelectTrigger>
                      <SelectContent>
                        {["CSE", "CSE (AI & ML)", "CSE (Data Science)", "ECE", "EEE", "Mechanical", "Civil", "IT"].map((dept) => (
                          <SelectItem key={dept} value={dept}>{dept}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="degree">Degree *</Label>
                    <Select value={degree} onValueChange={setDegree}>
                      <SelectTrigger id="degree">
                        <SelectValue placeholder="Select Degree" />
                      </SelectTrigger>
                      <SelectContent>
                        {["Major", "Minor"].map((deg) => (
                          <SelectItem key={deg} value={deg}>{deg}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="year">Year *</Label>
                    <Select value={year} onValueChange={setYear}>
                      <SelectTrigger id="year">
                        <SelectValue placeholder="Select Year" />
                      </SelectTrigger>
                      <SelectContent>
                        {["I Year", "II Year", "III Year", "IV Year"].map((y) => (
                          <SelectItem key={y} value={y}>{y}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="semester">Semester *</Label>
                    <Select value={semester} onValueChange={setSemester}>
                      <SelectTrigger id="semester">
                        <SelectValue placeholder="Select Semester" />
                      </SelectTrigger>
                      <SelectContent>
                        {["Semester I", "Semester II"].map((sem) => (
                          <SelectItem key={sem} value={sem}>{sem}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                {/* Row 2: Class Type, Credits, Color */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="classType">Class Type *</Label>
                    <Select value={classType} onValueChange={setClassType}>
                      <SelectTrigger id="classType">
                        <SelectValue placeholder="Select Type" />
                      </SelectTrigger>
                      <SelectContent>
                        {["Theory", "Lab"].map((t) => (
                          <SelectItem key={t} value={t}>{t}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="credits">Credits</Label>
                    <Input
                      id="credits"
                      type="number"
                      min="1"
                      max="10"
                      placeholder="e.g. 3"
                      value={credits}
                      onChange={(e) => setCredits(e.target.value)}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label>Card Color</Label>
                    <div className="flex gap-1.5 flex-wrap mt-1">
                      {[...new Set(COURSE_COLORS)].map((color) => (
                        <button
                          key={color}
                          className={`w-7 h-7 rounded-full ${color} border-2 transition-all ${courseColor === color
                            ? "border-white scale-110 ring-2 ring-primary"
                            : "border-transparent opacity-60 hover:opacity-100"
                            }`}
                          onClick={() => setCourseColor(color)}
                          type="button"
                        />
                      ))}
                    </div>
                  </div>
                </div>

                {/* ─── SECTIONS DROPDOWN ──────────────────────────────── */}
                <div className="space-y-3">
                  <Label className="flex items-center gap-2">
                    <Users className="w-4 h-4 text-muted-foreground" />
                    Assign Sections
                    <span className="text-xs text-muted-foreground font-normal ml-1">(select one or more)</span>
                  </Label>
                  <Select
                    key={selectedSections.join(",")}
                    onValueChange={(value) => {
                      if (!selectedSections.includes(value)) {
                        setSelectedSections((prev) => [...prev, value]);
                      }
                    }}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder={selectedSections.length > 0 ? `${selectedSections.length} section(s) selected` : "Select sections..."} />
                    </SelectTrigger>
                    <SelectContent>
                      {ALL_SECTIONS.map((section) => {
                        const isSelected = selectedSections.includes(section);
                        return (
                          <SelectItem
                            key={section}
                            value={section}
                            disabled={isSelected}
                            className={isSelected ? "opacity-50" : ""}
                          >
                            <span className="flex items-center gap-2">
                              {isSelected && (
                                <svg className="w-3.5 h-3.5 text-primary" viewBox="0 0 12 12" fill="none">
                                  <path d="M2 6L5 9L10 3" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                                </svg>
                              )}
                              Section {section}
                            </span>
                          </SelectItem>
                        );
                      })}
                    </SelectContent>
                  </Select>
                  {selectedSections.length > 0 && (
                    <div className="flex flex-wrap gap-1.5 mt-1">
                      {selectedSections.sort().map((s) => (
                        <Badge
                          key={s}
                          variant="secondary"
                          className="bg-primary/10 text-primary border-primary/20 text-xs gap-1 px-3 py-1"
                        >
                          Section {s}
                          <button
                            type="button"
                            onClick={() => toggleSection(s)}
                            className="hover:text-red-500 transition-colors ml-1"
                          >
                            <X className="w-3 h-3" />
                          </button>
                        </Badge>
                      ))}
                    </div>
                  )}
                </div>

                {/* ─── STUDENTS ASSIGNMENT ───────────────────────────── */}
                {selectedSections.length > 0 && (
                  <div className="space-y-3">
                    <Label className="flex items-center gap-2">
                      <CheckSquare className="w-4 h-4 text-muted-foreground" />
                      Assign Students
                      <span className="text-xs text-muted-foreground font-normal ml-1">
                        ({selectedStudents.length} selected)
                      </span>
                    </Label>

                    {/* Search + Select All */}
                    <div className="flex gap-2 items-center">
                      <div className="relative flex-1">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground w-3.5 h-3.5" />
                        <Input
                          placeholder="Search by name or roll number..."
                          className="pl-9 h-9 text-sm"
                          value={studentSearchQuery}
                          onChange={(e) => setStudentSearchQuery(e.target.value)}
                        />
                      </div>
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        onClick={toggleAllFilteredStudents}
                        className="shrink-0 text-xs h-9"
                      >
                        {filteredStudents.length > 0 &&
                         filteredStudents.every((s) => selectedStudents.includes(s.rollNumber))
                          ? "Deselect All"
                          : "Select All"}
                      </Button>
                    </div>

                    {/* Students list */}
                    <div className="border border-border/50 rounded-lg max-h-48 overflow-y-auto bg-muted/10">
                      {loadingStudents ? (
                        <div className="flex items-center justify-center py-8">
                          <Loader2 className="w-5 h-5 animate-spin text-muted-foreground" />
                          <span className="ml-2 text-sm text-muted-foreground">Loading students...</span>
                        </div>
                      ) : filteredStudents.length === 0 ? (
                        <div className="py-6 text-center text-sm text-muted-foreground">
                          {sectionStudents.length === 0
                            ? "No students found in selected sections"
                            : "No students match your search"}
                        </div>
                      ) : (
                        <div className="divide-y divide-border/30">
                          {filteredStudents.map((student) => {
                            const isChecked = selectedStudents.includes(student.rollNumber);
                            return (
                              <button
                                key={student.rollNumber}
                                type="button"
                                onClick={() => toggleStudent(student.rollNumber)}
                                className={`
                                  w-full flex items-center gap-3 px-3 py-2.5 text-left transition-all text-sm
                                  ${isChecked
                                    ? "bg-primary/5 hover:bg-primary/10"
                                    : "hover:bg-muted/30"
                                  }
                                `}
                              >
                                <div
                                  className={`
                                    w-4.5 h-4.5 rounded-[4px] border-2 flex items-center justify-center shrink-0 transition-all
                                    ${isChecked
                                      ? "bg-primary border-primary"
                                      : "border-border"
                                    }
                                  `}
                                >
                                  {isChecked && (
                                    <svg className="w-3 h-3 text-primary-foreground" viewBox="0 0 12 12" fill="none">
                                      <path d="M2 6L5 9L10 3" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                                    </svg>
                                  )}
                                </div>
                                <div className="flex-1 min-w-0">
                                  <span className="font-medium text-foreground truncate block">
                                    {student.name !== student.rollNumber ? student.name : student.rollNumber}
                                  </span>
                                </div>
                                <span className="text-xs text-muted-foreground font-mono shrink-0">
                                  {student.rollNumber}
                                </span>
                                <Badge variant="outline" className="text-[10px] h-5 shrink-0">
                                  Sec {student.section}
                                </Badge>
                              </button>
                            );
                          })}
                        </div>
                      )}
                    </div>
                  </div>
                )}

                {/* Description */}
                <div className="space-y-2">
                  <Label htmlFor="description">Course Description</Label>
                  <Textarea
                    id="description"
                    placeholder="Describe what this course covers..."
                    rows={3}
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                  />
                </div>

                {/* Objectives */}
                <div className="space-y-2">
                  <Label htmlFor="objectives">
                    Course Objectives{" "}
                    <span className="text-xs text-muted-foreground">(one per line)</span>
                  </Label>
                  <Textarea
                    id="objectives"
                    placeholder={"Understand core concepts\nApply practical skills\nBuild projects"}
                    rows={3}
                    value={objectives}
                    onChange={(e) => setObjectives(e.target.value)}
                  />
                </div>

                {/* Syllabus */}
                <div className="space-y-2">
                  <Label>
                    Syllabus Topics{" "}
                    <span className="text-xs text-muted-foreground">(optional)</span>
                  </Label>
                  <div className="space-y-2">
                    {syllabus.map((item, i) => (
                      <div key={i} className="flex gap-2 items-center">
                        <Input
                          placeholder="Topic name"
                          value={item.topic}
                          onChange={(e) => updateSyllabusTopic(i, "topic", e.target.value)}
                          className="flex-1"
                        />
                        <Input
                          placeholder="Duration"
                          value={item.duration}
                          onChange={(e) => updateSyllabusTopic(i, "duration", e.target.value)}
                          className="w-28"
                        />
                        {syllabus.length > 1 && (
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => removeSyllabusTopic(i)}
                            className="shrink-0"
                          >
                            <X className="w-4 h-4" />
                          </Button>
                        )}
                      </div>
                    ))}
                    <Button variant="outline" size="sm" onClick={addSyllabusTopic}>
                      <Plus className="w-3 h-3 mr-1" /> Add Topic
                    </Button>
                  </div>
                </div>

                {/* File Upload */}
                <div className="space-y-2">
                  <Label>
                    Course Resources{" "}
                    <span className="text-xs text-muted-foreground">(PDFs, Documents)</span>
                  </Label>
                  <div
                    className="border-2 border-dashed border-muted-foreground/30 rounded-lg p-6 text-center cursor-pointer hover:border-primary/50 transition-colors"
                    onClick={() => fileInputRef.current?.click()}
                  >
                    <Upload className="w-8 h-8 mx-auto text-muted-foreground mb-2" />
                    <p className="text-sm text-muted-foreground">
                      Click to upload PDFs or documents
                    </p>
                    <p className="text-xs text-muted-foreground/60 mt-1">
                      PDF, DOC, DOCX, PPT, PPTX supported
                    </p>
                  </div>
                  <input
                    ref={fileInputRef}
                    type="file"
                    accept=".pdf,.doc,.docx,.ppt,.pptx"
                    multiple
                    className="hidden"
                    onChange={handleFileUpload}
                  />

                  {/* Pending files list */}
                  {pendingFiles.length > 0 && (
                    <div className="space-y-2 mt-2">
                      {pendingFiles.map((file, i) => (
                        <div
                          key={i}
                          className="flex items-center justify-between p-2 bg-muted/30 rounded-lg"
                        >
                          <div className="flex items-center gap-2">
                            <FileText className="w-4 h-4 text-primary" />
                            <span className="text-sm">{file.fileName}</span>
                            <Badge variant="secondary" className="text-xs">
                              {file.type}
                            </Badge>
                            <span className="text-xs text-muted-foreground">
                              {(file.fileSize / 1024).toFixed(0)} KB
                            </span>
                          </div>
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => removePendingFile(i)}
                          >
                            <X className="w-4 h-4" />
                          </Button>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>

              <DialogFooter>
                <Button variant="outline" onClick={() => setAddDialogOpen(false)}>
                  Cancel
                </Button>
                <Button onClick={handleSubmit} disabled={submitting}>
                  {submitting ? (
                    <>
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                      {isEditing ? "Updating..." : "Adding..."}
                    </>
                  ) : (
                    <>
                      {isEditing ? <Edit2 className="w-4 h-4 mr-2" /> : <Plus className="w-4 h-4 mr-2" />}
                      {isEditing ? "Update Course" : "Add Course"}
                    </>
                  )}
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        </div>

        <div className="space-y-6">
          {/* Stats Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <Card>
              <CardContent className="p-6">
                <div className="flex items-center space-x-4">
                  <div className="p-2 bg-primary/10 rounded-lg">
                    <BookOpen className="w-6 h-6 text-primary" />
                  </div>
                  <div>
                    <p className="text-2xl font-bold text-foreground">
                      {courses.length}
                    </p>
                    <p className="text-sm text-muted-foreground">Total Courses</p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardContent className="p-6">
                <div className="flex items-center space-x-4">
                  <div className="p-2 bg-green-500/10 rounded-lg">
                    <Users className="w-6 h-6 text-green-600" />
                  </div>
                  <div>
                    <p className="text-2xl font-bold text-foreground">
                      {totalStudents}
                    </p>
                    <p className="text-sm text-muted-foreground">Total Students</p>
                  </div>
                </div>
              </CardContent>
            </Card>

          </div>

          {/* Courses Grid */}
          <div>
              {loading ? (
                <div className="flex items-center justify-center py-12">
                  <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
                </div>
              ) : filteredCourses.length === 0 ? (
                <div className="text-center py-12">
                  <BookOpen className="w-12 h-12 mx-auto text-muted-foreground/40 mb-4" />
                  <p className="text-lg font-medium text-muted-foreground">
                    {searchQuery ? "No courses match your search" : "No courses yet"}
                  </p>
                  <p className="text-sm text-muted-foreground/60 mt-1">
                    {searchQuery
                      ? "Try a different search term"
                      : 'Click "Add Course" to create your first course'}
                  </p>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {filteredCourses.map((course) => (
                    <Card
                      key={course._id}
                      className="overflow-hidden border-border/50 bg-card/50 hover:bg-card hover:shadow-xl hover:shadow-primary/5 transition-all duration-300 flex flex-col group relative"
                    >
                      {/* Top colored section with course code */}
                      <div className={`m-3 h-[100px] rounded-xl flex items-center justify-center ${course.color || "bg-blue-500"} shadow-inner`}>
                         <h3 className="font-bold text-white text-2xl tracking-wider uppercase">{course.courseCode}</h3>
                      </div>

                      <CardContent className="px-5 pb-5 pt-2 flex flex-col flex-1">
                        <div className="flex justify-between items-start gap-2 mb-4">
                          <div>
                            <h3 className="font-semibold text-lg text-foreground line-clamp-1" title={course.courseName}>{course.courseName}</h3>
                            <p className="text-sm text-muted-foreground flex items-center mt-1">
                               <svg className="w-3.5 h-3.5 mr-1.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                               </svg>
                               {course.facultyName || "Faculty"}
                            </p>
                          </div>
                          <Badge className="bg-green-500 hover:bg-green-600 text-white border-none shrink-0 cursor-default uppercase tracking-wider text-[10px] shadow-sm px-2 py-0.5" title="Active Course">
                            Active
                          </Badge>
                        </div>

                        <div className="grid grid-cols-2 gap-4 my-2 mb-6">
                          <div className="text-center">
                            <p className="text-2xl font-bold text-foreground">{course.credits}</p>
                            <p className="text-xs text-muted-foreground uppercase tracking-wider">Credits</p>
                          </div>
                          <div className="text-center">
                            <p className="text-2xl font-bold text-foreground">{course.assignedStudents?.length || course.maxStudents || 0}</p>
                            <p className="text-xs text-muted-foreground uppercase tracking-wider">Students</p>
                          </div>
                        </div>

                        {/* Action Icons */}
                        <div className="grid grid-cols-3 gap-2 mt-auto pt-4 border-t border-border/50">
                           <Button 
                              variant="ghost" 
                              className="w-full h-10 bg-transparent hover:bg-primary/20 text-white hover:text-primary-foreground transition-all duration-300" 
                              title="View Details"
                              onClick={() => { setSelectedCourse(course); setViewDialogOpen(true); }}
                           >
                             <Eye className="w-5 h-5" />
                           </Button>
                           <Button 
                              variant="ghost" 
                              className="w-full h-10 bg-transparent hover:bg-blue-500/20 text-white hover:text-blue-100 transition-all duration-300"
                              title="Edit Course"
                              onClick={() => handleEdit(course)}
                           >
                             <Edit2 className="w-5 h-5" />
                           </Button>
                           <Button 
                              variant="ghost" 
                              className="w-full h-10 bg-transparent hover:bg-red-500/20 text-white hover:text-red-100 transition-all duration-300"
                              title="Delete Course"
                              onClick={() => handleDelete(course._id)}
                           >
                             <Trash2 className="w-5 h-5" />
                           </Button>
                        </div>
                      </CardContent>
                    </Card>
                  ))}
                </div>
              )}
          </div>
        </div>

        {/* ─── VIEW COURSE DETAILS DIALOG ─────────────────────────── */}
        <Dialog open={viewDialogOpen} onOpenChange={setViewDialogOpen}>
          <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
            {selectedCourse && (
              <>
                <DialogHeader>
                  <DialogTitle>
                    {selectedCourse.courseCode} - {selectedCourse.courseName}
                  </DialogTitle>
                </DialogHeader>

                <div className="space-y-6">
                  {/* Description */}
                  {selectedCourse.description && (
                    <div>
                      <h4 className="font-semibold text-foreground mb-2">
                        Course Description
                      </h4>
                      <p className="text-muted-foreground">{selectedCourse.description}</p>
                    </div>
                  )}

                  {/* Sections & Students */}
                  {(selectedCourse.sections?.length || 0) > 0 && (
                    <div>
                      <h4 className="font-semibold text-foreground mb-2">Assigned Sections</h4>
                      <div className="flex gap-2 flex-wrap">
                        {selectedCourse.sections?.map((s) => (
                          <Badge key={s} className="bg-primary/10 text-primary border-primary/20">
                            Section {s}
                          </Badge>
                        ))}
                      </div>
                    </div>
                  )}



                  {/* Objectives */}
                  {selectedCourse.objectives.length > 0 && (
                    <div>
                      <h4 className="font-semibold text-foreground mb-2">
                        Course Objectives
                      </h4>
                      <ul className="space-y-1">
                        {selectedCourse.objectives.map((obj, i) => (
                          <li key={i} className="text-muted-foreground flex items-start">
                            <span className="mr-2">•</span>
                            {obj}
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}

                  {/* Syllabus */}
                  {selectedCourse.syllabus.length > 0 && (
                    <div>
                      <h4 className="font-semibold text-foreground mb-2">Course Syllabus</h4>
                      <div className="space-y-2">
                        {selectedCourse.syllabus.map((item, i) => (
                          <div
                            key={i}
                            className="flex justify-between items-center p-2 bg-muted/30 rounded"
                          >
                            <span className="text-foreground">{item.topic}</span>
                            {item.duration && (
                              <span className="text-sm text-muted-foreground">
                                {item.duration}
                              </span>
                            )}
                          </div>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Resources */}
                  {selectedCourse.resources.length > 0 && (
                    <div>
                      <h4 className="font-semibold text-foreground mb-2">
                        Course Resources
                      </h4>
                      <div className="grid grid-cols-2 gap-3">
                        {selectedCourse.resources.map((resource, i) => (
                          <div
                            key={i}
                            className="flex items-center space-x-2 p-3 bg-primary/10 rounded-lg cursor-pointer hover:bg-primary/20 transition-colors"
                            onClick={() => handleDownload(selectedCourse._id, resource)}
                          >
                            <FileText className="w-5 h-5 text-primary" />
                            <div>
                              <div className="font-medium text-primary text-sm">
                                {resource.name}
                              </div>
                              <div className="text-xs text-muted-foreground">
                                {resource.type}
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Meta info */}
                  <div className="flex items-center gap-4 text-sm text-muted-foreground pt-2 border-t">
                    <span className="flex items-center gap-1">
                      <Calendar className="w-3 h-3" />
                      Created{" "}
                      {new Date(selectedCourse.createdAt).toLocaleDateString("en-IN", {
                        day: "2-digit",
                        month: "short",
                        year: "numeric",
                      })}
                    </span>
                    <span className="flex items-center gap-1">
                      <Users className="w-3 h-3" />
                      {selectedCourse.assignedStudents?.length || selectedCourse.maxStudents} students
                    </span>
                    <span className="flex items-center gap-1">
                      <Clock className="w-3 h-3" />
                      {selectedCourse.credits} credits
                    </span>
                  </div>
                </div>
              </>
            )}
          </DialogContent>
        </Dialog>
      </div>
    </FacultyLayout>
  );
};

export default FacultyCourses;

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import FacultyLayout from "@/components/FacultyLayout";
import { BookOpen, Users, FileText, Calendar, Clock, Loader2, MapPin, Megaphone } from "lucide-react";
import { useAuth } from "@/contexts/AuthContext";
import { useState, useEffect } from "react";
import { api } from "@/lib/api";
import { cn } from "@/lib/utils";

const FacultyDashboard = () => {
  const { userData } = useAuth();
  const [displayName, setDisplayName] = useState(userData?.name || userData?.collegeId || "Faculty");
  const [courses, setCourses] = useState<any[]>([]);
  const [loadingCourses, setLoadingCourses] = useState(true);
  const [viewDialogOpen, setViewDialogOpen] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState<any | null>(null);

  // Faculty schedule state
  const [todaySchedule, setTodaySchedule] = useState<any[]>([]);
  const [loadingSchedule, setLoadingSchedule] = useState(true);

  // Announcements
  const [announcements, setAnnouncements] = useState<any[]>([]);
  const [expandedAnnouncements, setExpandedAnnouncements] = useState<Record<string, boolean>>({});
  
  // Upcoming Events
  const [upcomingEvents, setUpcomingEvents] = useState<any[]>([]);

  const toggleAnnouncement = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setExpandedAnnouncements(prev => ({ ...prev, [id]: !prev[id] }));
  };

  // Fetch announcements
  useEffect(() => {
    const fetchAnnouncements = async () => {
      try {
        const apiBaseUrl = import.meta.env.VITE_API_BASE_URL || "http://localhost:5000/api";
        const res = await fetch(`${apiBaseUrl}/announcements/active?audience=Faculty`);
        if (res.ok) {
          const data = await res.json();
          setAnnouncements(data);
        }
      } catch (error) {
        console.error("Failed to fetch announcements:", error);
      }
    };
    fetchAnnouncements();
  }, []);

  useEffect(() => {
    if (!userData?.uid) return;

    const fetchProfileName = async () => {
      try {
        const profile = await api.get(`/users/${userData.uid}`);
        if (profile && profile.name) {
          setDisplayName(profile.name);
        }
      } catch (error: any) {
        if (!error.message?.includes('404')) {
          console.error("Error fetching profile for dashboard:", error);
        }
      }
    };

    const fetchDashboardCourses = async () => {
      try {
        setLoadingCourses(true);
        const facultyId = userData?.collegeId || "";
        const res = await fetch(`${import.meta.env.VITE_API_URL || "http://localhost:5000/api"}/courses?facultyId=${facultyId}`);
        if (res.ok) {
          const data = await res.json();
          setCourses(data);
        }
      } catch (error) {
        console.error("Error fetching courses:", error);
      } finally {
        setLoadingCourses(false);
      }
    };

    fetchProfileName();
    fetchDashboardCourses();
  }, [userData?.uid, userData?.collegeId]);

  // Fetch faculty schedule from MongoDB
  useEffect(() => {
    if (!userData?.collegeId) {
      setLoadingSchedule(false);
      return;
    }

    const fetchFacultySchedule = async () => {
      setLoadingSchedule(true);
      try {
        const rollNumber = userData.collegeId;
        const apiBaseUrl = import.meta.env.VITE_API_BASE_URL || "http://localhost:5000/api";

        // Fetch all schedules containing slots for this faculty
        const res = await fetch(
          `${apiBaseUrl}/schedules?facultyId=${encodeURIComponent(rollNumber)}`
        );

        if (res.ok) {
          const schedules = await res.json();

          if (schedules.length > 0) {
            // Get today's day name
            const days = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
            let today = days[new Date().getDay()];
            
            // Map to collect all assigned slots for today across all schedules
            const allTodaySlots: any[] = [];
            
            schedules.forEach((scheduleDoc: any) => {
              const todayData = scheduleDoc.schedule?.find((d: any) => d.day === today);
              if (todayData?.slots) {
                // IMPORTANT: Filter slots strictly by facultyId
                const assignedSlots = todayData.slots.filter((slot: any) => 
                  slot.facultyId === rollNumber &&
                  (slot.subjectCode?.trim() || slot.subjectName?.trim())
                );
                allTodaySlots.push(...assignedSlots);
              }
            });

            if (allTodaySlots.length > 0) {
              const SLOT_COLORS = ["bg-red-500", "bg-blue-500", "bg-orange-500", "bg-purple-500", "bg-green-500", "bg-teal-500"];

              // Sort slots by start time
              allTodaySlots.sort((a, b) => a.startTime.localeCompare(b.startTime));

              const mapped = allTodaySlots.map((slot: any, idx: number) => {
                const formatTime = (t: string) => {
                  const [h, m] = t.split(":");
                  const hour = parseInt(h);
                  const ampm = hour >= 12 ? "PM" : "AM";
                  const dh = hour > 12 ? hour - 12 : hour === 0 ? 12 : hour;
                  return `${dh}:${m} ${ampm}`;
                };

                return {
                  time: `${formatTime(slot.startTime)} - ${formatTime(slot.endTime)}`,
                  course: slot.subjectCode || `S${idx + 1}`,
                  courseName: slot.subjectName || "—",
                  room: slot.room || "—",
                  classType: slot.classType || "Class",
                  section: slot.section || "",
                  students: 0,
                  type: slot.classType || "Class",
                  color: SLOT_COLORS[idx % SLOT_COLORS.length],
                };
              });

              setTodaySchedule(mapped);
              setLoadingSchedule(false);
              return;
            }
          }
        }
      } catch (error) {
        console.error("Error fetching faculty schedule:", error);
      }

      // No valid schedule data — show empty state
      setTodaySchedule([]);
      setLoadingSchedule(false);
    };

    fetchFacultySchedule();
  }, [userData?.collegeId]);

  // Fetch Academic Calendar (Upcoming Events)
  useEffect(() => {
    const fetchAcademicCalendar = async () => {
      try {
        const apiBaseUrl = import.meta.env.VITE_API_BASE_URL || "http://localhost:5000/api";
        const res = await fetch(`${apiBaseUrl}/academic-calendar`);
        if (res.ok) {
          const events = await res.json();
          // Filter relevant events for faculty
          const filtered = events.filter((e: any) => {
            const txt = `${e.title} ${e.type} ${e.description || ""}`.toLowerCase();
            
            // Target Faculty teaching 4th Year, Semester 2 (representing semester 8 conventionally or explicitly via string)
            const is42 = String(e.semester) === "8" || txt.includes("4-2") || txt.includes("semester 8") || txt.includes("iv-ii");
            
            // Events must relate to Exams or Project Vivas/Reviews
            const isRelevantAction = txt.includes("exam") || txt.includes("viva") || txt.includes("review");
            
            return is42 && isRelevantAction;
          });

          // Sort by start date (ascending -> closest upcoming)
          filtered.sort((a: any, b: any) => new Date(a.startDate).getTime() - new Date(b.startDate).getTime());
          
          const uniqueEvents: any[] = [];
          const seen = new Set();
          
          let count = 0;
          for (const ev of filtered) {
             const key = ev.title.trim().toLowerCase();
             
             // Check to ensure we only render future or current events
             const eDate = new Date(ev.endDate);
             // allow viewing events completed very recently (yesterday) to not prematurely cut
             if (eDate < new Date(Date.now() - 86400000)) continue;

             if (!seen.has(key)) {
                seen.add(key);
                
                const sDate = new Date(ev.startDate);
                let typeLabel = "Event";
                let color = "text-primary";
                
                if (key.includes("exam") || key.includes("mid") || key.includes("end")) {
                  typeLabel = "Exams";
                  color = "text-red-500";
                } else if (key.includes("viva") || key.includes("review") || key.includes("project")) {
                  typeLabel = "Project Viva";
                  color = "text-purple-500";
                }

                uniqueEvents.push({
                  date: sDate.getDate().toString().padStart(2, '0'),
                  month: sDate.toLocaleString("default", { month: "short" }).toUpperCase(),
                  title: ev.title,
                  time: `Duration: ${sDate.toLocaleDateString("en-IN", { month: "short", day: "numeric" })} - ${eDate.toLocaleDateString("en-IN", { month: "short", day: "numeric" })}, ${eDate.getFullYear()}`,
                  type: typeLabel,
                  color: color,
                });
                
                count++;
                if (count >= 5) break; 
             }
          }
          setUpcomingEvents(uniqueEvents);
        }
      } catch (err) {
        console.error("Failed to fetch academic calendar", err);
      }
    };
    
    fetchAcademicCalendar();
  }, []);

  const getTypeColor = (type: string) => {
    switch (type) {
      case "Class":
      case "Lecture":
        return "bg-blue-100 text-blue-800";
      case "Lab":
        return "bg-green-100 text-green-800";
      case "Tutorial":
        return "bg-yellow-100 text-yellow-800";
      case "Meeting":
        return "bg-purple-100 text-purple-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  return (
    <FacultyLayout>
      {/* Welcome Section */}
      <div>
        <h1 className="text-2xl font-bold text-foreground flex items-center gap-2">
          Hello, <span className="text-primary">{displayName}</span> 👋
        </h1>
        <p className="text-muted-foreground mt-1">
          Manage your teaching schedule and track student progress.
        </p>
      </div>

      {/* Today's Schedule */}
      <Card className="my-6">
        <CardHeader>
          <CardTitle>Today's Schedule</CardTitle>
        </CardHeader>
        <CardContent>
          {loadingSchedule ? (
            <div className="flex justify-center py-8">
              <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
            </div>
          ) : todaySchedule.length === 0 ? (
            <div className="text-center py-8 text-sm text-muted-foreground">
              <Calendar className="w-10 h-10 mx-auto mb-3 text-muted-foreground/50" />
              No schedule found for today.
            </div>
          ) : (
            <div className="space-y-4">
              {todaySchedule.map((class_, index) => (
                <div
                  key={index}
                  className="flex flex-col sm:flex-row sm:items-center justify-between p-4 bg-muted/20 rounded-xl hover:bg-muted/30 transition-colors gap-4"
                >
                  <div className="flex items-center space-x-4 sm:space-x-5 flex-1 min-w-0">
                    {/* Highlighted Course Code Box */}
                    <div
                      className={`shrink-0 h-14 w-auto min-w-[4rem] px-3 ${class_.color || "bg-primary"} rounded-xl flex items-center justify-center text-white font-bold text-sm tracking-wide`}
                    >
                      {class_.course}
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="font-semibold text-foreground text-base truncate">
                        {class_.courseName}
                      </div>
                      <div className="flex flex-wrap items-center gap-x-5 gap-y-1.5 text-sm text-muted-foreground mt-1.5">
                        <div className="flex items-center space-x-1.5">
                          <MapPin className="w-4 h-4" />
                          <span>Room: {class_.room}</span>
                        </div>
                        <div className="flex items-center space-x-1.5">
                          <BookOpen className="w-4 h-4" />
                          <span>Class Type: {class_.classType || class_.type || "Class"}</span>
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* Right Side Info */}
                  <div className="flex items-center space-x-4 shrink-0 self-start sm:self-auto pl-[5.5rem] sm:pl-0 mt-1 sm:mt-0">
                    <div className="text-sm font-medium text-muted-foreground whitespace-nowrap">
                      {class_.time}
                    </div>
                    <Badge variant="outline" className={`${getTypeColor(class_.type)} border-transparent font-medium px-4 py-1 rounded-full`}>
                      {class_.type}
                    </Badge>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      <div className="grid lg:grid-cols-2 gap-6 mt-6">
        {/* LEFT COLUMN */}
        <div className="flex flex-col gap-6">
          {/* Active Courses */}
          <Card className="flex flex-col h-[340px]">
            <CardHeader>
              <div className="flex items-center justify-between">
                <CardTitle className="flex items-center gap-2">
                  <BookOpen className="w-5 h-5 text-primary" />
                  Active Courses
                </CardTitle>
              </div>
            </CardHeader>
            <CardContent className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar">
          {loadingCourses ? (
            <div className="flex justify-center py-4">
              <Loader2 className="w-6 h-6 animate-spin text-muted-foreground" />
            </div>
          ) : courses.length === 0 ? (
            <div className="text-center py-4 text-sm text-muted-foreground">
              No active courses. Add courses from the Courses tab.
            </div>
          ) : (
            courses.map((course) => (
              <div
                key={course._id}
                className="flex items-center space-x-4 p-4 bg-muted/30 rounded-lg pr-5"
              >
                <div
                  className={`shrink-0 h-12 w-auto min-w-[3rem] px-3 ${course.color || "bg-blue-500"} rounded-lg flex items-center justify-center text-white font-bold text-sm`}
                >
                  {course.courseCode}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="font-medium text-foreground truncate">
                    {course.courseName}
                  </div>
                  <div className="text-sm text-muted-foreground flex items-center gap-1.5 mt-0.5">
                    <Users className="w-3.5 h-3.5" />
                    {course.maxStudents} Students
                  </div>
                </div>
                <Button
                  variant="outline"
                  size="sm"
                  className="shrink-0"
                  onClick={() => {
                    setSelectedCourse(course);
                    setViewDialogOpen(true);
                  }}
                >
                  View Details
                </Button>
              </div>
            ))
          )}
        </CardContent>
      </Card>

          {/* Upcoming Events */}
          <Card className="flex flex-col h-[340px]">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Calendar className="w-5 h-5 text-primary" />
                Upcoming Events
              </CardTitle>
            </CardHeader>
            <CardContent className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar">
          {upcomingEvents.map((event, index) => (
            <div
              key={index}
              className="flex items-start space-x-4 p-4 bg-muted/30 rounded-lg shadow-sm"
            >
              <div className="text-center">
                <div className="text-2xl font-bold text-foreground">
                  {event.date}
                </div>
                <div className="text-xs text-muted-foreground uppercase tracking-wide font-medium">
                  {event.month}
                </div>
              </div>
              <div className="flex-1">
                <div className="font-semibold text-foreground">
                  {event.title}
                </div>
                <div className="text-sm text-muted-foreground mt-1.5 flex items-center">
                  <Clock className="w-3.5 h-3.5 mr-1.5 opacity-70" />
                  {event.time}
                </div>
                <Badge variant="secondary" className="mt-2.5 font-medium border-border/50">
                  {event.type}
                </Badge>
              </div>
            </div>
          ))}
        </CardContent>
      </Card>
    </div>

    {/* RIGHT COLUMN */}
    {/* Announcements Section */}
    <Card className="flex flex-col h-[704px]">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Megaphone className="w-5 h-5 text-primary" />
          System Announcements
        </CardTitle>
      </CardHeader>
      
      <CardContent className="flex-1 overflow-y-auto pr-2 custom-scrollbar">
        {announcements.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-12 text-center h-full">
            <Megaphone className="w-10 h-10 text-muted-foreground/30 mb-3" />
            <p className="text-sm text-muted-foreground font-medium">No system notifications at this time</p>
          </div>
        ) : (
          <div className="space-y-4">
            {announcements.map((ann) => {
              const isExpanded = expandedAnnouncements[ann._id];
              return (
                <Card 
                  key={ann._id} 
                  className="border-border/40 bg-muted/10 transition-all duration-300 relative overflow-hidden"
                >
                  <CardContent className="p-4 sm:p-5">
                    <div className="flex flex-col gap-2">
                      <div className="flex justify-between items-start gap-3">
                        <h4 className="font-bold text-base sm:text-lg text-foreground leading-tight">
                          {ann.title}
                         </h4>
                              {ann.priority === "Important" && (
                                <Badge className="bg-red-500/10 text-red-500 border-red-500/20 shrink-0 text-[10px] px-2 py-0.5 uppercase tracking-wider font-bold">
                                  Priority
                                </Badge>
                              )}
                            </div>
                            
                            <div className="relative">
                              <p className={cn(
                                "text-sm text-muted-foreground leading-relaxed transition-all duration-500 ease-in-out",
                                isExpanded ? "opacity-100" : "line-clamp-3 opacity-90"
                              )}>
                                {ann.message}
                              </p>
                              
                              {ann.message && ann.message.length > 150 && (
                                <button
                                  onClick={(e) => toggleAnnouncement(ann._id, e)}
                                  className="text-primary text-xs font-semibold hover:underline mt-2 flex items-center gap-1 transition-all"
                                >
                                  {isExpanded ? 'Show less' : 'Show more'}
                                </button>
                              )}
                            </div>

                            <div className="flex flex-wrap items-center gap-x-4 gap-y-2 mt-4 pt-3 border-t border-border/30 text-[10px] sm:text-xs text-muted-foreground/70">
                              <div className="flex items-center gap-1.5">
                                <div className="w-5 h-5 rounded-full bg-primary/20 flex items-center justify-center text-[10px] font-bold text-primary">
                                  {(ann.createdBy || 'A')[0].toUpperCase()}
                                </div>
                                <span className="font-semibold text-muted-foreground">Admin: {ann.createdBy}</span>
                              </div>
                              <div className="flex items-center gap-1.5">
                                <Clock className="w-3.5 h-3.5" />
                                <span>{new Date(ann.createdAt).toLocaleDateString("en-IN", { month: "short", day: "numeric", year: "numeric" })}</span>
                              </div>
                            </div>
                          </div>
                        </CardContent>
                      </Card>
                    );
                  })}
                </div>
              )}
            </CardContent>
          </Card>
      </div>

      {/* ─── VIEW COURSE DETAILS DIALOG ─────────────────────────── */}
      <Dialog open={viewDialogOpen} onOpenChange={setViewDialogOpen}>
        <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto w-[95vw]">
          {selectedCourse && (
            <>
              <DialogHeader>
                <DialogTitle className="text-xl">
                  {selectedCourse.courseCode} - {selectedCourse.courseName}
                </DialogTitle>
              </DialogHeader>

              <div className="space-y-6 mt-2">
                {/* Description */}
                {selectedCourse.description && (
                  <div>
                    <h4 className="font-semibold text-foreground mb-2">
                      Course Description
                    </h4>
                    <p className="text-muted-foreground text-sm leading-relaxed">{selectedCourse.description}</p>
                  </div>
                )}

                {/* Objectives */}
                {selectedCourse.objectives?.length > 0 && (
                  <div>
                    <h4 className="font-semibold text-foreground mb-2">
                      Course Objectives
                    </h4>
                    <ul className="space-y-1.5 list-disc pl-5">
                      {selectedCourse.objectives.map((obj: string, i: number) => (
                        <li key={i} className="text-muted-foreground text-sm">
                          {obj}
                        </li>
                      ))}
                    </ul>
                  </div>
                )}

                {/* Syllabus */}
                {selectedCourse.syllabus?.length > 0 && (
                  <div>
                    <h4 className="font-semibold text-foreground mb-2">Course Syllabus</h4>
                    <div className="space-y-2">
                      {selectedCourse.syllabus.map((item: any, i: number) => (
                        <div
                          key={i}
                          className="flex justify-between items-center p-2.5 bg-muted/30 rounded border border-border/50"
                        >
                          <span className="text-foreground text-sm font-medium">{item.topic}</span>
                          {item.duration && (
                            <span className="text-xs px-2 py-0.5 rounded-full bg-primary/10 text-primary whitespace-nowrap">
                              {item.duration}
                            </span>
                          )}
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {/* Resources */}
                {selectedCourse.resources?.length > 0 && (
                  <div>
                    <h4 className="font-semibold text-foreground mb-2">
                      Course Resources
                    </h4>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                      {selectedCourse.resources.map((resource: any, i: number) => (
                        <div
                          key={i}
                          className="flex items-center space-x-3 p-3 bg-primary/5 border border-primary/20 rounded-lg cursor-pointer hover:bg-primary/10 transition-colors"
                          onClick={() => {
                            if (resource.fileData) {
                              const link = document.createElement("a");
                              link.href = resource.fileData;
                              link.download = resource.fileName || resource.name;
                              link.click();
                            }
                          }}
                        >
                          <div className="bg-primary/10 p-2 rounded shrink-0">
                            <FileText className="w-5 h-5 text-primary" />
                          </div>
                          <div className="min-w-0">
                            <div className="font-medium text-primary text-sm truncate">
                              {resource.name}
                            </div>
                            <div className="text-xs text-muted-foreground">
                              {resource.type}
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {/* Meta info */}
                <div className="flex flex-wrap items-center gap-x-6 gap-y-2 text-xs text-muted-foreground pt-4 border-t">
                  <span className="flex items-center gap-1.5">
                    <Calendar className="w-3.5 h-3.5" />
                    Created{" "}
                    {new Date(selectedCourse.createdAt).toLocaleDateString("en-IN", {
                      day: "2-digit",
                      month: "short",
                      year: "numeric",
                    })}
                  </span>
                  <span className="flex items-center gap-1.5">
                    <Users className="w-3.5 h-3.5" />
                    {selectedCourse.maxStudents} students max
                  </span>
                  <span className="flex items-center gap-1.5">
                    <Clock className="w-3.5 h-3.5" />
                    {selectedCourse.credits} credits
                  </span>
                </div>
              </div>
            </>
          )}
        </DialogContent>
      </Dialog>
    </FacultyLayout>
  );
};

export default FacultyDashboard;

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import FacultyLayout from "@/components/FacultyLayout";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import {
  Search,
  Plus,
  Save,
  Send,
  Trash2,
  FileSpreadsheet,
  Loader2,
  Calculator,
  Users,
  Award,
} from "lucide-react";
import {
  getFacultyGradeSheets,
  getGradeSheet,
  createGradeSheet,
  updateGrades,
  submitGradeSheet,
  deleteGradeSheet,
  generateStudentsForSection,
  GradeSheet,
  StudentGrade,
} from "@/services/gradeService";

const FacultyGrades = () => {
  const { userData } = useAuth();
  const [gradeSheets, setGradeSheets] = useState<GradeSheet[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedSheet, setSelectedSheet] = useState<GradeSheet | null>(null);
  const [editingGrades, setEditingGrades] = useState<StudentGrade[]>([]);
  const [saving, setSaving] = useState(false);
  const [isCreateDialogOpen, setIsCreateDialogOpen] = useState(false);
  const [creating, setCreating] = useState(false);

  // Form state for create
  const [formData, setFormData] = useState({
    subjectCode: "",
    subjectName: "",
    credits: 3,
    courseType: "Class",
    degree: "Major",
    year: "IV Year",
    branch: "CSE",
    section: "B",
    semester: "Semester I",
  });

  // Fetch grade sheets
  const fetchGradeSheets = async () => {
    try {
      setLoading(true);
      const facultyId = userData?.collegeId || "";
      if (!facultyId) return;
      const data = await getFacultyGradeSheets(facultyId);
      setGradeSheets(data);
    } catch (error) {
      console.error("Error fetching grade sheets:", error);
      toast.error("Failed to load grade sheets");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (userData?.collegeId) {
      fetchGradeSheets();
    }
  }, [userData?.collegeId]);

  // Create new grade sheet
  const handleCreateSheet = async () => {
    if (!formData.subjectCode || !formData.subjectName) {
      toast.error("Please fill in subject code and name");
      return;
    }

    try {
      setCreating(true);
      const students = generateStudentsForSection(
        formData.year,
        formData.branch,
        formData.section,
        64
      );

      await createGradeSheet({
        ...formData,
        facultyId: userData?.collegeId || "",
        facultyName: userData?.name || "Faculty",
        students,
      });

      toast.success("Grade sheet created!");
      setIsCreateDialogOpen(false);
      setFormData({
        subjectCode: "",
        subjectName: "",
        credits: 3,
        courseType: "Class",
        degree: "Major",
        year: "IV Year",
        branch: "CSE",
        section: "B",
        semester: "Semester I",
      });
      fetchGradeSheets();
    } catch (error: any) {
      console.error("Error creating grade sheet:", error);
      toast.error(error.message || "Failed to create grade sheet");
    } finally {
      setCreating(false);
    }
  };

  // Load a grade sheet for editing
  const handleOpenSheet = async (sheet: GradeSheet) => {
    try {
      const fullSheet = await getGradeSheet(sheet._id);
      setSelectedSheet(fullSheet);
      setEditingGrades([...fullSheet.studentGrades]);
    } catch (error) {
      console.error("Error loading grade sheet:", error);
      toast.error("Failed to load grade sheet");
    }
  };

  // Update a grade value
  const handleGradeChange = (
    studentId: string,
    field: keyof StudentGrade,
    value: string
  ) => {
    const numValue = value === "" ? null : parseFloat(value);
    setEditingGrades((prev) =>
      prev.map((g) =>
        g.studentId === studentId ? { ...g, [field]: numValue } : g
      )
    );
  };

  // Save grades
  const handleSaveGrades = async () => {
    if (!selectedSheet) return;

    try {
      setSaving(true);
      await updateGrades(selectedSheet._id, editingGrades);
      toast.success("Grades saved successfully!");
      fetchGradeSheets();
    } catch (error) {
      console.error("Error saving grades:", error);
      toast.error("Failed to save grades");
    } finally {
      setSaving(false);
    }
  };

  // Submit to admin
  const handleSubmitToAdmin = async () => {
    if (!selectedSheet) return;

    try {
      await submitGradeSheet(selectedSheet._id);
      toast.success("Grade sheet submitted to admin!");
      setSelectedSheet(null);
      fetchGradeSheets();
    } catch (error) {
      console.error("Error submitting:", error);
      toast.error("Failed to submit");
    }
  };

  // Delete grade sheet
  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this grade sheet?")) return;

    try {
      await deleteGradeSheet(id);
      toast.success("Grade sheet deleted");
      fetchGradeSheets();
    } catch (error) {
      console.error("Error deleting:", error);
      toast.error("Failed to delete");
    }
  };

  // Calculate derived values for display
  const calculateDerived = (g: StudentGrade, isLab = false) => {
    if (isLab) {
      const internal = (g.labSecA || 0) + (g.labSecB || 0) + (g.labSecC || 0) + (g.labSecD || 0);
      return { internal: g.labSecA !== null || g.labSecB !== null || g.labSecC !== null || g.labSecD !== null ? internal : null };
    }
    const mid1Conv = g.mid1 !== null ? Math.round(g.mid1 * 0.75 * 100) / 100 : null;
    const mid2Conv = g.mid2 !== null ? Math.round(g.mid2 * 0.75 * 100) / 100 : null;
    const mid1Total = mid1Conv !== null && g.assignment1 !== null ? mid1Conv + g.assignment1 : null;
    const mid2Total = mid2Conv !== null && g.assignment2 !== null ? mid2Conv + g.assignment2 : null;
    const avg = mid1Total !== null && mid2Total !== null ? (mid1Total + mid2Total) / 2 : null;
    const internal = avg !== null && g.project !== null ? Math.round((avg + g.project) * 100) / 100 : null;
    return { mid1Conv, mid2Conv, mid1Total, mid2Total, internal };
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "Published":
        return <Badge className="bg-green-500 text-white">Published</Badge>;
      case "Submitted":
        return <Badge className="bg-blue-500 text-white">Submitted</Badge>;
      case "Modified":
        return <Badge className="bg-yellow-500 text-white">Modified</Badge>;
      default:
        return <Badge className="bg-gray-500 text-white">Draft</Badge>;
    }
  };

  return (
    <FacultyLayout>
      <div className="max-w-7xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
              <Award className="w-8 h-8 text-primary" />
              Grade Management
            </h1>
            <p className="text-muted-foreground mt-1">
              Maintain accurate and structured academic records.
            </p>
          </div>
        </div>

        <div className="flex flex-col gap-4 lg:flex-row lg:items-center lg:justify-end">
          <Dialog open={isCreateDialogOpen} onOpenChange={setIsCreateDialogOpen}>
            <DialogTrigger asChild>
              <Button>
                <Plus className="w-4 h-4 mr-2" />
                Create Grade Sheet
              </Button>
            </DialogTrigger>
            <DialogContent className="sm:max-w-[500px]">
              <DialogHeader>
                <DialogTitle>Create Grade Sheet</DialogTitle>
                <DialogDescription>
                  Create a new grade sheet for a subject
                </DialogDescription>
              </DialogHeader>
              <div className="grid gap-4 py-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="grid gap-2">
                    <Label>Subject Code *</Label>
                    <Input
                      placeholder="e.g., 22CS701"
                      value={formData.subjectCode}
                      onChange={(e) =>
                        setFormData({ ...formData, subjectCode: e.target.value })
                      }
                    />
                  </div>
                  <div className="grid gap-2">
                    <Label>Credits</Label>
                    <Input
                      type="number"
                      min={1}
                      max={5}
                      value={formData.credits}
                      onChange={(e) =>
                        setFormData({ ...formData, credits: parseInt(e.target.value) || 3 })
                      }
                    />
                  </div>
                </div>
                <div className="grid gap-2">
                  <Label>Subject Name *</Label>
                  <Input
                    placeholder="e.g., Machine Learning"
                    value={formData.subjectName}
                    onChange={(e) =>
                      setFormData({ ...formData, subjectName: e.target.value })
                    }
                  />
                </div>

                {/* Degree and Course Type Add-ins */}
                <div className="grid grid-cols-2 gap-4">
                  <div className="grid gap-2">
                    <Label>Degree</Label>
                    <Select
                      value={formData.degree}
                      onValueChange={(v) => setFormData({ ...formData, degree: v })}
                    >
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        <SelectItem value="Major">Major</SelectItem>
                        <SelectItem value="Minor">Minor</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="grid gap-2">
                    <Label>Course Type</Label>
                    <Select
                      value={formData.courseType}
                      onValueChange={(v) => setFormData({ ...formData, courseType: v })}
                    >
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        <SelectItem value="Class">Class</SelectItem>
                        <SelectItem value="Lab">Lab</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="grid grid-cols-3 gap-4">
                  <div className="grid gap-2">
                    <Label>Year</Label>
                    <Select
                      value={formData.year}
                      onValueChange={(v) => setFormData({ ...formData, year: v })}
                    >
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        <SelectItem value="I Year">I Year</SelectItem>
                        <SelectItem value="II Year">II Year</SelectItem>
                        <SelectItem value="III Year">III Year</SelectItem>
                        <SelectItem value="IV Year">IV Year</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="grid gap-2">
                    <Label>Branch</Label>
                    <Select
                      value={formData.branch}
                      onValueChange={(v) => setFormData({ ...formData, branch: v })}
                    >
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        <SelectItem value="CSE">CSE</SelectItem>
                        <SelectItem value="ECE">ECE</SelectItem>
                        <SelectItem value="EEE">EEE</SelectItem>
                        <SelectItem value="MECH">MECH</SelectItem>
                        <SelectItem value="AI">AI</SelectItem>
                        <SelectItem value="IT">IT</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="grid gap-2">
                    <Label>Section</Label>
                    <Select
                      value={formData.section}
                      onValueChange={(v) => setFormData({ ...formData, section: v })}
                    >
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        {["A", "B", "C", "D", "E", "F", "G"].map((s) => (
                          <SelectItem key={s} value={s}>Section {s}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>
                <div className="grid grid-cols-1 gap-4">
                  <div className="grid gap-2">
                    <Label>Semester</Label>
                    <Select
                      value={formData.semester}
                      onValueChange={(v) => setFormData({ ...formData, semester: v })}
                    >
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        <SelectItem value="Semester I">Semester I</SelectItem>
                        <SelectItem value="Semester II">Semester II</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              </div>
              <DialogFooter>
                <Button variant="outline" onClick={() => setIsCreateDialogOpen(false)}>
                  Cancel
                </Button>
                <Button onClick={handleCreateSheet} disabled={creating}>
                  {creating && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                  Create Sheet
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        </div>

        {loading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="w-8 h-8 animate-spin text-primary" />
          </div>
        ) : selectedSheet ? (
          /* Grade Entry View */
          <Card>
            <CardHeader className="flex flex-row items-center justify-between">
              <div>
                <CardTitle className="flex items-center gap-2">
                  <FileSpreadsheet className="w-5 h-5" />
                  {selectedSheet.subjectName} ({selectedSheet.subjectCode})
                </CardTitle>
                <p className="text-sm text-muted-foreground mt-1">
                  Section {selectedSheet.section} | Semester {selectedSheet.semester} | {selectedSheet.academicYear}
                </p>
              </div>
              <div className="flex gap-2">
                <Button variant="outline" onClick={() => setSelectedSheet(null)}>
                  Back
                </Button>
                <Button onClick={handleSaveGrades} disabled={saving}>
                  {saving ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}
                  Save
                </Button>
                {(selectedSheet.status === "Draft" || selectedSheet.status === "Modified") && (
                  <Button onClick={handleSubmitToAdmin} className="bg-green-600 hover:bg-green-700">
                    <Send className="w-4 h-4 mr-2" />
                    Submit to Admin
                  </Button>
                )}
              </div>
            </CardHeader>
            <CardContent>
              <div className="overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead className="w-[50px]">#</TableHead>
                      <TableHead className="w-[120px]">Roll No</TableHead>
                      {selectedSheet.courseType === "Lab" ? (
                        <>
                          <TableHead className="w-[80px] text-center bg-blue-500/10">Section A (10)</TableHead>
                          <TableHead className="w-[80px] text-center bg-blue-500/10">Section B (10)</TableHead>
                          <TableHead className="w-[80px] text-center bg-blue-500/10">Section C (10)</TableHead>
                          <TableHead className="w-[80px] text-center bg-blue-500/10">Section D (10)</TableHead>
                        </>
                      ) : (
                        <>
                          <TableHead className="w-[80px] text-center bg-blue-500/10">Mid-1 (40)</TableHead>
                          <TableHead className="w-[60px] text-center bg-blue-500/10">×0.75</TableHead>
                          <TableHead className="w-[80px] text-center bg-green-500/10">Assign-1 (5)</TableHead>
                          <TableHead className="w-[60px] text-center bg-yellow-500/10">Mid-1 Total</TableHead>
                          <TableHead className="w-[80px] text-center bg-blue-500/10">Mid-2 (40)</TableHead>
                          <TableHead className="w-[60px] text-center bg-blue-500/10">×0.75</TableHead>
                          <TableHead className="w-[80px] text-center bg-green-500/10">Assign-2 (5)</TableHead>
                          <TableHead className="w-[60px] text-center bg-yellow-500/10">Mid-2 Total</TableHead>
                          <TableHead className="w-[80px] text-center bg-purple-500/10">Project (5)</TableHead>
                        </>
                      )}
                      <TableHead className="w-[80px] text-center bg-orange-500/10 font-bold">Internal (40)</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {editingGrades.map((g, idx) => {
                      const isLab = selectedSheet.courseType === "Lab";
                      const calc = calculateDerived(g, isLab);
                      return (
                        <TableRow key={g.studentId}>
                          <TableCell className="text-muted-foreground">{idx + 1}</TableCell>
                          <TableCell className="font-mono text-sm">{g.studentId}</TableCell>
                          
                          {isLab ? (
                            <>
                              <TableCell className="bg-blue-500/5">
                                <Input
                                  type="number" min={0} max={10} className="w-16 h-8 text-center"
                                  value={g.labSecA ?? ""} onChange={(e) => handleGradeChange(g.studentId, "labSecA", e.target.value)}
                                />
                              </TableCell>
                              <TableCell className="bg-blue-500/5">
                                <Input
                                  type="number" min={0} max={10} className="w-16 h-8 text-center"
                                  value={g.labSecB ?? ""} onChange={(e) => handleGradeChange(g.studentId, "labSecB", e.target.value)}
                                />
                              </TableCell>
                              <TableCell className="bg-blue-500/5">
                                <Input
                                  type="number" min={0} max={10} className="w-16 h-8 text-center"
                                  value={g.labSecC ?? ""} onChange={(e) => handleGradeChange(g.studentId, "labSecC", e.target.value)}
                                />
                              </TableCell>
                              <TableCell className="bg-blue-500/5">
                                <Input
                                  type="number" min={0} max={10} className="w-16 h-8 text-center"
                                  value={g.labSecD ?? ""} onChange={(e) => handleGradeChange(g.studentId, "labSecD", e.target.value)}
                                />
                              </TableCell>
                            </>
                          ) : (
                            <>
                              <TableCell className="bg-blue-500/5">
                                <Input type="number" min={0} max={40} className="w-16 h-8 text-center" value={g.mid1 ?? ""} onChange={(e) => handleGradeChange(g.studentId, "mid1", e.target.value)} />
                              </TableCell>
                              <TableCell className="text-center text-sm bg-blue-500/5">{calc.mid1Conv?.toFixed(2) ?? "-"}</TableCell>
                              <TableCell className="bg-green-500/5">
                                <Input type="number" min={0} max={5} className="w-14 h-8 text-center" value={g.assignment1 ?? ""} onChange={(e) => handleGradeChange(g.studentId, "assignment1", e.target.value)} />
                              </TableCell>
                              <TableCell className="text-center font-medium bg-yellow-500/5">{calc.mid1Total?.toFixed(2) ?? "-"}</TableCell>
                              <TableCell className="bg-blue-500/5">
                                <Input type="number" min={0} max={40} className="w-16 h-8 text-center" value={g.mid2 ?? ""} onChange={(e) => handleGradeChange(g.studentId, "mid2", e.target.value)} />
                              </TableCell>
                              <TableCell className="text-center text-sm bg-blue-500/5">{calc.mid2Conv?.toFixed(2) ?? "-"}</TableCell>
                              <TableCell className="bg-green-500/5">
                                <Input type="number" min={0} max={5} className="w-14 h-8 text-center" value={g.assignment2 ?? ""} onChange={(e) => handleGradeChange(g.studentId, "assignment2", e.target.value)} />
                              </TableCell>
                              <TableCell className="text-center font-medium bg-yellow-500/5">{calc.mid2Total?.toFixed(2) ?? "-"}</TableCell>
                              <TableCell className="bg-purple-500/5">
                                <Input type="number" min={0} max={5} className="w-14 h-8 text-center" value={g.project ?? ""} onChange={(e) => handleGradeChange(g.studentId, "project", e.target.value)} />
                              </TableCell>
                            </>
                          )}
                          
                          <TableCell className="text-center font-bold text-lg bg-orange-500/10">
                            {calc.internal?.toFixed(2) ?? "-"}
                          </TableCell>
                        </TableRow>
                      );
                    })}
                  </TableBody>
                </Table>
              </div>
            </CardContent>
          </Card>
        ) : (
          /* Grade Sheets List */
          <div className="space-y-4">
            {gradeSheets.length === 0 ? (
              <Card>
                <CardContent className="py-12 text-center">
                  <FileSpreadsheet className="w-12 h-12 mx-auto text-muted-foreground mb-4" />
                  <h3 className="text-lg font-medium mb-2">No Grade Sheets</h3>
                  <p className="text-muted-foreground">
                    Click "Create Grade Sheet" to start entering grades
                  </p>
                </CardContent>
              </Card>
            ) : (
              <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                {gradeSheets.map((sheet) => (
                  <Card
                    key={sheet._id}
                    className="cursor-pointer hover:shadow-md transition-shadow"
                    onClick={() => handleOpenSheet(sheet)}
                  >
                    <CardContent className="p-6">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <h3 className="font-semibold text-lg">{sheet.subjectName}</h3>
                          <p className="text-sm text-muted-foreground">{sheet.subjectCode}</p>
                        </div>
                        {getStatusBadge(sheet.status)}
                      </div>
                      <div className="space-y-2 text-sm text-muted-foreground">
                        <div className="flex items-center gap-2">
                          <Users className="w-4 h-4" />
                          <span>Section {sheet.section} | {sheet.studentCount} students</span>
                        </div>
                        <div className="flex items-center gap-2">
                          <Calculator className="w-4 h-4" />
                          <span>Sem {sheet.semester} | {sheet.academicYear}</span>
                        </div>
                      </div>
                      <div className="flex gap-2 mt-4">
                        <Button
                          variant="outline"
                          size="sm"
                          className="flex-1"
                          onClick={(e) => {
                            e.stopPropagation();
                            handleOpenSheet(sheet);
                          }}
                        >
                          Edit Grades
                        </Button>
                        <Button
                          variant="ghost"
                          size="sm"
                          className="text-red-500"
                          onClick={(e) => {
                            e.stopPropagation();
                            handleDelete(sheet._id);
                          }}
                        >
                          <Trash2 className="w-4 h-4" />
                        </Button>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    </FacultyLayout>
  );
};

