              <div className="text-center md:text-left flex-1">
                <h2 className="text-2xl font-bold text-primary">
                  {formData.firstName} {formData.lastName}
                </h2>
                <p className="text-lg text-foreground font-medium flex items-center justify-center md:justify-start gap-2">
                  <Briefcase className="w-4 h-4" />
                  {formData.designation || "Faculty Member"}
                </p>
                <div className="flex flex-wrap gap-2 mt-3 justify-center md:justify-start">
                  <Badge variant="outline" className="text-sm">
                    Faculty ID: {facultyId}
                  </Badge>
                  <Badge variant="secondary" className="text-sm border-primary/20 bg-primary/5 text-primary">
                    {department}
                  </Badge>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Profile Information */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <User className="w-5 h-5 text-primary" />
              Profile Information
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="firstName">First Name</Label>
                <Input
                  id="firstName"
                  value={formData.firstName}
                  onChange={(e) => handleInputChange("firstName", e.target.value)}
                  disabled={!isEditing}
                  className={!isEditing ? "bg-muted/50 text-foreground" : ""}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="lastName">Last Name</Label>
                <Input
                  id="lastName"
                  value={formData.lastName}
                  onChange={(e) => handleInputChange("lastName", e.target.value)}
                  disabled={!isEditing}
                  className={!isEditing ? "bg-muted/50 text-foreground" : ""}
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Department</Label>
                <Input
                  value={department}
                  disabled
                  readOnly
                  title="Locked by admin"
                  className="bg-muted text-muted-foreground"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="designation">Designation</Label>
                <Input
                  id="designation"
                  value={formData.designation}
                  onChange={(e) => handleInputChange("designation", e.target.value)}
                  disabled={!isEditing}
                  className={!isEditing ? "bg-muted/50 text-foreground" : ""}
                  placeholder="e.g., Assistant Professor"
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="bio">Bio</Label>
              <Textarea
                id="bio"
                value={formData.bio}
                onChange={(e) => handleInputChange("bio", e.target.value)}
                disabled={!isEditing}
                className={`resize-none ${!isEditing ? "bg-muted/50 text-foreground" : ""}`}
                placeholder="Enter your professional bio..."
                rows={4}
              />
            </div>
          </CardContent>
        </Card>

        {/* Contact Information Section */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Phone className="w-5 h-5 text-green-500" />
