                        )}
                        title="Present"
                      >
                        Present
                      </button>
                      <button
                        onClick={() => handleAttendanceStatus(student.studentId, "ABSENT")}
                        className={cn(
                          "px-4 py-1.5 text-sm font-medium rounded-md transition-all duration-200 border",
                          student.status === "ABSENT"
                            ? "bg-red-500 text-white border-red-500 shadow-sm"
                            : "bg-transparent text-muted-foreground border-border hover:border-red-500/50 hover:bg-red-500/10 hover:text-red-500"
                        )}
                        title="Absent"
                      >
                        Absent
                      </button>
                    </div>
                    <div className="text-muted-foreground text-sm flex items-center gap-2">
                      {student.lastUpdated}
                      {student.isModified && (
                        <Badge variant="outline" className="text-xs text-blue-500 border-blue-500">
                          Modified
                        </Badge>
                      )}
                    </div>
                  </div>
                ))
              )}
            </div>

            {/* Slot Lock Warning Notice */}
            {selectedSlot && (
              <div className="mt-6 p-4 bg-muted/30 rounded-lg border border-border/50">
                <div className="flex items-center gap-3 text-sm text-muted-foreground">
                  <LockKeyhole className="w-4 h-4" />
                  <span>
                    Attendance marking will be locked 15 minutes after the slot ends
                    ({selectedSlot.endTime}). Contact admin for late entries.
                  </span>
                </div>
              </div>
            )}
            </>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Slot Lock Warning Dialog */}
      <Dialog open={showLockWarning} onOpenChange={setShowLockWarning}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2 text-yellow-500">
              <AlertTriangle className="w-5 h-5" />
              Slot Time Expired
            </DialogTitle>
            <DialogDescription>
              The attendance marking window for this slot has closed.
              You can no longer mark attendance for this period.
            </DialogDescription>
          </DialogHeader>
          <div className="py-4">
            <p className="text-sm text-muted-foreground">
              If you need to make changes to this attendance record, please contact
              your administrator who can override the slot lock.
            </p>
          </div>
          <DialogFooter>
            <Button onClick={() => setShowLockWarning(false)}>
              Understood
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Save Confirmation Dialog */}
      <Dialog open={showSaveConfirm} onOpenChange={setShowSaveConfirm}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Confirm Attendance Submission</DialogTitle>
            <DialogDescription>
              You are about to submit attendance for {students.filter(s => s.status !== (s.initialStatus || "NOT_MARKED")).length} students.
            </DialogDescription>
          </DialogHeader>
          <div className="py-4 space-y-3">
            <div className="grid grid-cols-2 gap-4 text-sm">
              <div className="flex items-center gap-2">
                <CheckCircle2 className="w-4 h-4 text-green-500" />
                <span>{students.filter(s => s.status === "PRESENT" && s.status !== (s.initialStatus || "NOT_MARKED")).length} Present</span>
              </div>
              <div className="flex items-center gap-2">
                <XCircle className="w-4 h-4 text-red-500" />
                <span>{students.filter(s => s.status === "ABSENT" && s.status !== (s.initialStatus || "NOT_MARKED")).length} Absent</span>
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowSaveConfirm(false)}>
              Cancel
            </Button>
            <Button onClick={saveAttendance} disabled={isSaving}>
              {isSaving ? (
                <>
                  <RefreshCw className="w-4 h-4 mr-2 animate-spin" />
                  Saving...
                </>
              ) : (
                "Confirm & Save"
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </FacultyLayout>
  );
};

export default FacultyStudents;

import { useState, useEffect, useRef, type ChangeEvent } from "react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import StudentLayout from "@/components/StudentLayout";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import {
  Calendar,
  Eye,
  Upload,
  CheckCircle2,
  Clock,
  AlertCircle,
  FileText,
  Loader2,
  Download,
  X,
} from "lucide-react";
import {
  getStudentAssignments,
  submitAssignment,
  getStudentSubmission,
  fileToBase64,
  openPdfInNewTab,
  formatDate,
  formatFileSize,
  isOverdue,
} from "@/services/assignmentService";

type Assignment = {
  _id: string;
  title: string;
  description: string;
  course: string;
  courseCode: string;
  dueDate: string;
  maxMarks: number;
  status: "Active" | "Completed" | "Draft";
  hasSubmitted: boolean;
  submittedAt: string | null;
  grade: number | null;
  feedback: string;
  year?: string;
  degree?: string;
  semester?: string;
};

const StudentAssignments = () => {
  const { userData } = useAuth();
  const [assignments, setAssignments] = useState<Assignment[]>([]);
  const [loading, setLoading] = useState(true);
  const [uploading, setUploading] = useState<string | null>(null);
  const [viewingSubmission, setViewingSubmission] = useState<string | null>(null);
  const fileInputRefs = useRef<{ [key: string]: HTMLInputElement | null }>({});

  // View modal state
  const [viewModalOpen, setViewModalOpen] = useState(false);
  const [viewAssignment, setViewAssignment] = useState<Assignment | null>(null);

  // ── Compute student's current academic year from collegeId ──
  const getStudentCurrentYear = (): string => {
    const collegeId = userData?.collegeId || "";
    const yearCode = collegeId.substring(0, 2);
    if (!yearCode || !/^\d{2}$/.test(yearCode)) return "IV Year";
    const admissionYear = parseInt("20" + yearCode);
    const now = new Date();
    const curYear = now.getFullYear();
    const curMonth = now.getMonth(); // 0-indexed
    // Academic year starts in July
    const academicStartYear = curMonth >= 6 ? curYear : curYear - 1;
    const yearNum = academicStartYear - admissionYear + 1;
    const yearLabels = ["I Year", "II Year", "III Year", "IV Year"];
    return yearLabels[Math.min(Math.max(yearNum - 1, 0), 3)];
  };

  // ── Filter State (matching Results page) ──
  const [degree, setDegree] = useState("Major");
  const [year, setYear] = useState(() => getStudentCurrentYear());
  const [semester, setSemester] = useState(() => {
    return userData?.collegeId?.startsWith('22') ? "Semester-II" : "Semester-I";
  });

  // Dynamically configure dropdown defaults mapping exactly to the backend student Current Semester logic
  useEffect(() => {
    if (!userData?.uid) return;
    const fetchProfileSemester = async () => {
      try {
        const apiBaseUrl = import.meta.env.VITE_API_URL || import.meta.env.VITE_API_BASE_URL || "http://localhost:5000/api";
        const res = await fetch(`${apiBaseUrl}/users/${userData.uid}`);
        if (res.ok) {
          const profile = await res.json();
          let currentSem = profile.academicInformation?.currentSemester || profile.semester;
          
          if (userData?.collegeId?.startsWith('22')) {
            currentSem = "VIII";
          }
          
          if (currentSem) {
            const romanMap: Record<string, { year: string; semLabel: string }> = {
              "I": { year: "I Year", semLabel: "Semester-I" },
              "II": { year: "I Year", semLabel: "Semester-II" },
              "III": { year: "II Year", semLabel: "Semester-I" },
              "IV": { year: "II Year", semLabel: "Semester-II" },
              "V": { year: "III Year", semLabel: "Semester-I" },
              "VI": { year: "III Year", semLabel: "Semester-II" },
              "VII": { year: "IV Year", semLabel: "Semester-I" },
              "VIII": { year: "IV Year", semLabel: "Semester-II" }
            };
            const mapping = romanMap[String(currentSem).toUpperCase()];
            if (mapping) {
              setDegree("Major");
              setYear(mapping.year);
              setSemester(mapping.semLabel);
            }
          }
        }
      } catch (err) {
        console.warn("Failed to initialize course mapping defaults:", err);
      }
    };
    fetchProfileSemester();
  }, [userData?.uid]);

  // Get student name - fallback to collegeId if name not available
  const studentName = userData?.name || userData?.collegeId || "Student";

  // Determine section from roll number
  const getSectionFromRollNumber = (rollNo: string): string => {
    const upperRoll = rollNo.toUpperCase();
    let match = upperRoll.match(/22B81A05([0-9A-F]+)$/);
    if (!match) {
      match = upperRoll.match(/(\d{2})[A-Z].*?([0-9A-F]{2,3})$/);
      if (match) {
        const numPart = parseInt(match[2], 16);
        if (numPart >= 0x01 && numPart <= 0x64) return "A";
        if (numPart >= 0x65 && numPart <= 0xC8) return "B";
        return "B";
      }
      return "B";
    }
    const hexPart = match[1];
    const numPart = parseInt(hexPart, 16);
    if (numPart >= 0x01 && numPart <= 0x64) return "A";
    if (numPart >= 0x65 && numPart <= 0xC8) return "B";
    if (numPart >= 0xC9 && numPart <= 0x12C) return "C";
    if (numPart >= 0x12D && numPart <= 0x190) return "D";
    if (numPart >= 0x191 && numPart <= 0x1F4) return "E";
    if (numPart >= 0x1F5 && numPart <= 0x258) return "F";
    if (numPart >= 0x259 && numPart <= 0x2BC) return "G";
    return "B";
  };

  // Fetch assignments for the student based on their section + filters
  const fetchAssignments = async () => {
    try {
      setLoading(true);
      const studentId = userData?.collegeId || "";
      if (!studentId) {
        toast.error("Student ID not found");
        return;
      }

      const section = getSectionFromRollNumber(studentId);
      const data = await getStudentAssignments(section, studentId, {
        degree,
        semester,
        year,
      });
      setAssignments(data);
    } catch (error) {
      console.error("Error fetching assignments:", error);
      toast.error("Failed to load assignments");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (userData?.collegeId) {
      fetchAssignments();
    }
  }, [userData?.collegeId, degree, year, semester]);

  // All filtering is done server-side (degree + year + semester + section)
  const filteredAssignments = assignments;

  // Handle file selection and upload
  const handleFileSelection = async (
    assignmentId: string,
    event: ChangeEvent<HTMLInputElement>
  ) => {
    const file = event.target.files?.[0];
    if (!file) return;

    // Validate file type (PDF only)
    if (file.type !== "application/pdf") {
      toast.error("Only PDF files are allowed");
      event.target.value = "";
      return;
    }

    // Validate file size (max 10MB)
    if (file.size > 10 * 1024 * 1024) {
      toast.error("File size must be less than 10MB");
      event.target.value = "";
      return;
    }

    try {
      setUploading(assignmentId);

      // Convert file to base64
      const base64Data = await fileToBase64(file);

      // Submit to backend
      await submitAssignment(assignmentId, {
        studentId: userData?.collegeId || "",
        studentName: studentName,
        fileName: file.name,
        fileType: file.type,
        fileSize: file.size,
        fileData: base64Data,
      });

      toast.success("Assignment submitted successfully!", {
        description: `File: ${file.name}`,
      });

      // Refresh assignments to update status
      fetchAssignments();
    } catch (error) {
      console.error("Error submitting assignment:", error);
      toast.error("Failed to submit assignment");
    } finally {
      setUploading(null);
      event.target.value = "";
    }
  };

  // View own submission
  const handleViewSubmission = async (assignmentId: string, title: string) => {
    try {
      setViewingSubmission(assignmentId);
      const studentId = userData?.collegeId || "";
      const submission = await getStudentSubmission(assignmentId, studentId);

      if (submission && submission.fileData) {
        openPdfInNewTab(submission.fileData, submission.fileName);
      } else {
        toast.error("No submission found");
      }
    } catch (error) {
      console.error("Error viewing submission:", error);
      toast.error("Failed to view submission");
    } finally {
      setViewingSubmission(null);
    }
  };

  // Get status badge component
  const getStatusBadge = (assignment: Assignment) => {
    if (assignment.hasSubmitted) {
      if (assignment.grade !== null) {
        return (
          <Badge className="bg-green-500/20 text-green-400 border-green-500/30">
            <CheckCircle2 className="w-3 h-3 mr-1" />
            Graded: {assignment.grade}/{assignment.maxMarks}
          </Badge>
        );
      }
      return (
        <Badge className="bg-blue-500/20 text-blue-400 border-blue-500/30">
          <CheckCircle2 className="w-3 h-3 mr-1" />
          Submitted
        </Badge>
      );
    }
    if (isOverdue(assignment.dueDate)) {
      return (
        <Badge className="bg-red-500/20 text-red-400 border-red-500/30">
          <AlertCircle className="w-3 h-3 mr-1" />
          Overdue
        </Badge>
      );
    }
    return (
      <Badge className="bg-yellow-500/20 text-yellow-400 border-yellow-500/30">
        <Clock className="w-3 h-3 mr-1" />
        Pending
      </Badge>
    );
  };

  return (
    <StudentLayout>
      <div className="max-w-7xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
              <FileText className="w-8 h-8 text-primary" />
              Assignments
            </h1>
            <p className="text-muted-foreground mt-1">
              Submit your assignments and track your progress
            </p>
          </div>
        </div>

        {/* Top Filters — matching /student/results exactly */}
        <div className="flex flex-col sm:flex-row gap-4">
          <Select name="degree" value={degree} onValueChange={setDegree}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Degree" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="Major">Major</SelectItem>
              <SelectItem value="Minor">Minor</SelectItem>
            </SelectContent>
          </Select>

          <Select name="year" value={year} onValueChange={setYear}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Year" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="I Year">I Year</SelectItem>
              <SelectItem value="II Year">II Year</SelectItem>
              <SelectItem value="III Year">III Year</SelectItem>
              <SelectItem value="IV Year">IV Year</SelectItem>
            </SelectContent>
          </Select>

          <Select name="semester" value={semester} onValueChange={setSemester}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Semester" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="Semester-I">Semester-I</SelectItem>
              <SelectItem value="Semester-II">Semester-II</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {loading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="w-8 h-8 animate-spin text-primary" />
          </div>
        ) : filteredAssignments.length === 0 ? (
          <Card className="border shadow-none bg-card/50">
            <CardContent className="py-12 text-center">
              <FileText className="w-12 h-12 mx-auto text-muted-foreground/50 mb-4" />
              <h3 className="text-lg font-medium mb-2">No Assignments Found</h3>
              <p className="text-muted-foreground text-sm">
                No assignments match your selected Degree, Year, and Semester combination.
              </p>
            </CardContent>
          </Card>
        ) : (
          <div className="space-y-4">
            {filteredAssignments.map((assignment) => (
              <Card
                key={assignment._id}
                className="hover:shadow-md transition-shadow border-border/50"
              >
                <CardContent className="p-6">
                  <div className="flex flex-col gap-4 md:flex-row md:items-start md:justify-between">
                    {/* Assignment Info */}
                    <div className="flex-1">
                      <div className="flex items-start justify-between mb-2">
                        <h3 className="text-lg font-semibold text-foreground">
                          {assignment.title}
                        </h3>
                        {getStatusBadge(assignment)}
                      </div>

                      <p className="text-sm text-primary mb-3">
                        {assignment.course}
                        {assignment.courseCode && ` (${assignment.courseCode})`}
                      </p>


                      <div className="flex flex-wrap items-center gap-4 text-sm text-muted-foreground">
                        <div className="flex items-center gap-1">
                          <Calendar className="w-4 h-4" />
                          <span>Due: {formatDate(assignment.dueDate)}</span>
                        </div>
                        <div className="flex items-center gap-1">
                          <FileText className="w-4 h-4" />
                          <span>Max Marks: {assignment.maxMarks}</span>
                        </div>
                        {assignment.hasSubmitted && assignment.submittedAt && (
                          <div className="flex items-center gap-1 text-green-500">
                            <CheckCircle2 className="w-4 h-4" />
                            <span>Submitted: {formatDate(assignment.submittedAt)}</span>
                          </div>
                        )}
                      </div>

                      {/* Feedback */}
                      {assignment.feedback && (
                        <div className="mt-4 p-3 bg-muted/30 rounded-lg">
                          <p className="text-sm font-medium text-foreground mb-1">
                            Faculty Feedback:
                          </p>
                          <p className="text-sm text-muted-foreground">
                            {assignment.feedback}
                          </p>
                        </div>
                      )}
                    </div>

                    {/* Actions */}
                    <div className="flex flex-col items-stretch space-y-2 md:w-48">
                      {/* Hidden file input */}
                      <input
                        ref={(el) => (fileInputRefs.current[assignment._id] = el)}
                        type="file"
                        accept=".pdf"
                        className="hidden"
                        onChange={(e) => handleFileSelection(assignment._id, e)}
                      />

                      {/* View Button — opens description modal */}
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => {
                          setViewAssignment(assignment);
                          setViewModalOpen(true);
                        }}
                      >
                        <Eye className="w-4 h-4 mr-2" />
                        View
                      </Button>

                      {/* Submit/Resubmit Button */}
                      <Button
                        size="sm"
                        onClick={() => fileInputRefs.current[assignment._id]?.click()}
                        disabled={uploading === assignment._id}
                        className={
                          assignment.hasSubmitted
                            ? "bg-blue-600 hover:bg-blue-700"
                            : "bg-primary hover:bg-primary/90"
                        }
                      >
                        {uploading === assignment._id ? (
                          <>
                            <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                            Uploading...
                          </>
                        ) : (
                          <>
                            <Upload className="w-4 h-4 mr-2" />
                            {assignment.hasSubmitted ? "Resubmit" : "Submit PDF"}
                          </>
                        )}
                      </Button>

                      {/* View Submission Button (if submitted) */}
                      {assignment.hasSubmitted && (
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() =>
                            handleViewSubmission(assignment._id, assignment.title)
                          }
                          disabled={viewingSubmission === assignment._id}
                        >
                          {viewingSubmission === assignment._id ? (
                            <>
                              <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                              Loading...
                            </>
                          ) : (
                            <>
                              <Eye className="w-4 h-4 mr-2" />
                              View My Submission
                            </>
                          )}
                        </Button>
                      )}
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}

        {/* View Assignment Modal */}
        <Dialog open={viewModalOpen} onOpenChange={setViewModalOpen}>
          <DialogContent className="sm:max-w-[550px]">
            <DialogHeader>
              <DialogTitle className="text-xl font-semibold">
                {viewAssignment?.title}
              </DialogTitle>
            </DialogHeader>
            <div className="space-y-4 mt-2">
              <div className="flex items-center gap-2 text-sm text-primary">
                <FileText className="w-4 h-4" />
                {viewAssignment?.course}
                {viewAssignment?.courseCode && ` (${viewAssignment.courseCode})`}
              </div>

              <div className="p-4 rounded-lg bg-muted/30 border border-border/50">
                <h4 className="text-sm font-medium text-foreground mb-2">Description</h4>
                <p className="text-sm text-muted-foreground whitespace-pre-wrap">
                  {viewAssignment?.description || "No description provided."}
                </p>
              </div>

              <div className="grid grid-cols-2 gap-4 text-sm">
                <div className="flex items-center gap-2 text-muted-foreground">
                  <Calendar className="w-4 h-4" />
                  <span>Due: {viewAssignment?.dueDate ? formatDate(viewAssignment.dueDate) : '-'}</span>
                </div>
                <div className="flex items-center gap-2 text-muted-foreground">
                  <FileText className="w-4 h-4" />
                  <span>Max Marks: {viewAssignment?.maxMarks}</span>
                </div>
              </div>

              {viewAssignment?.feedback && (
                <div className="p-3 bg-muted/30 rounded-lg border border-border/50">
                  <p className="text-sm font-medium text-foreground mb-1">
                    Faculty Feedback:
                  </p>
                  <p className="text-sm text-muted-foreground">
                    {viewAssignment.feedback}
                  </p>
                </div>
              )}
            </div>
          </DialogContent>
        </Dialog>
      </div>
    </StudentLayout>
  );
};

export default StudentAssignments;

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Button } from "@/components/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import StudentLayout from "@/components/StudentLayout";
import { useAuth } from "@/contexts/AuthContext";
import {
  CheckCircle2,
  XCircle,
  Clock,
  AlertCircle,
  TrendingUp,
  TrendingDown,
  Calendar,
  BarChart3,
  RefreshCw,
  BookOpen,
  Trophy,
  Sparkles,
  Users,
} from "lucide-react";
import { useState, useEffect } from "react";
import {
  AttendanceStatus,
  SubjectAttendanceSummary,
  AttendanceCategory,
  ATTENDANCE_THRESHOLDS,
} from "@/types/attendance";
import {
  getServerTime,
  formatDate,
  getSubjectWiseAttendance,
  calculateFourWeekAttendance,
  subscribeToStudentAttendance,
} from "@/services/attendanceService";
import { cn } from "@/lib/utils";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell,
} from "recharts";

const StudentAttendance = () => {
  const { userData } = useAuth();
  const [activeTab, setActiveTab] = useState("academic");
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [serverTime, setServerTime] = useState<Date>(new Date());

  // Attendance Data
  const [subjectAttendance, setSubjectAttendance] = useState<SubjectAttendanceSummary[]>([]);
  const [overallSummary, setOverallSummary] = useState({
    academic: { totalClasses: 0, attended: 0, percentage: 0 },
    events: { totalSessions: 0, attended: 0, percentage: 0 },
    sports: { totalSessions: 0, attended: 0, percentage: 0 },
    clubs: { totalMeetings: 0, attended: 0, percentage: 0 },
  });

  // Sync server time
  useEffect(() => {
    const syncTime = async () => {
      const time = await getServerTime();
      setServerTime(time);
    };

    syncTime();
    const interval = setInterval(syncTime, 60000);
    return () => clearInterval(interval);
  }, []);

  // Load attendance data
  useEffect(() => {
    loadAttendanceData();
  }, [userData?.collegeId]);

  const getMappedYear = (collegeId: string) => {
    if (!collegeId) return "25";
    const yearCode = collegeId.substring(0, 2);
    if (!yearCode || !/^\d{2}$/.test(yearCode)) return "25";
    const admissionYear = parseInt("20" + yearCode);
    const now = new Date();
    const curYear = now.getFullYear();
    const academicStartYear = now.getMonth() >= 6 ? curYear : curYear - 1;
    const diff = Math.min(Math.max(academicStartYear - admissionYear, 0), 3);
    const map = ["22", "23", "24", "25"];
    return map[diff] || "25";
  };

  const getMappedBranch = (collegeId: string) => {
    if (!collegeId) return "05";
    const branchCode = collegeId.substring(6, 8);
    if (branchCode === "04") return "04";
    if (branchCode === "12") return "06";
    return "05";
  };

  const getMappedSection = (rollNo: string): string => {
    if (!rollNo) return "A";
    const lastTwo = rollNo.slice(-2).toUpperCase();
    if (lastTwo.length !== 2) return "A";

    let value = 0;
    const firstChar = lastTwo[0];
    const secondChar = lastTwo[1];

    if (firstChar >= '0' && firstChar <= '9') {
      value = parseInt(lastTwo, 10);
    } else if (firstChar >= 'A' && firstChar <= 'Z') {
      const letterVal = firstChar.charCodeAt(0) - 65;
      value = 100 + (letterVal * 10);
      if (secondChar >= '0' && secondChar <= '9') {
        value += parseInt(secondChar, 10);
      } else {
        value += (secondChar.charCodeAt(0) - 65 + 10);
      }
    }
    return value <= 64 ? "A" : "B";
  };

  const loadAttendanceData = async () => {
    if (!userData?.collegeId) return;

    setIsRefreshing(true);
    try {
      const section = getMappedSection(userData.collegeId);
      const branch = getMappedBranch(userData.collegeId);
      const year = getMappedYear(userData.collegeId);

      // Get subject-wise attendance
      const subjectData = await getSubjectWiseAttendance(
        userData.collegeId,
        year,
        branch,
        section
      );
      setSubjectAttendance(subjectData);

      // Calculate overall
      if (subjectData.length > 0) {
        const totalClasses = subjectData.reduce((sum, s) => sum + s.totalClasses, 0);
        const attended = subjectData.reduce((sum, s) => sum + s.attended, 0);
        const percentage = totalClasses > 0
          ? Math.round((attended / totalClasses) * 100)
          : 0;

        setOverallSummary(prev => ({
          ...prev,
          academic: { totalClasses, attended, percentage },
        }));
      }

      // Get 4-week summary
      const fourWeekSummary = await calculateFourWeekAttendance(
        userData.collegeId,
        year,
        branch,
        section
      );

      if (fourWeekSummary) {
        setOverallSummary(prev => ({
          ...prev,
          academic: {
            totalClasses: fourWeekSummary.totalClasses,
            attended: fourWeekSummary.attended,
            percentage: fourWeekSummary.percentage,
          },
        }));
      }
    } catch (error) {
      console.error("Error loading attendance:", error);
    } finally {
      setIsRefreshing(false);
    }
  };

  const refreshAttendance = async () => {
    await loadAttendanceData();
  };

  const getStatusColor = (percentage: number) => {
    if (percentage >= ATTENDANCE_THRESHOLDS.SATISFACTORY) return "text-green-500";
    if (percentage >= ATTENDANCE_THRESHOLDS.WARNING) return "text-yellow-500";
    return "text-red-500";
  };

  const getProgressColor = (percentage: number) => {
    if (percentage >= ATTENDANCE_THRESHOLDS.SATISFACTORY) return "bg-green-500";
    if (percentage >= ATTENDANCE_THRESHOLDS.WARNING) return "bg-yellow-500";
    return "bg-red-500";
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "SATISFACTORY":
        return <Badge className="bg-green-500/20 text-green-500 border-green-500/30">Satisfactory</Badge>;
      case "WARNING":
        return <Badge className="bg-yellow-500/20 text-yellow-500 border-yellow-500/30">Warning</Badge>;
      case "CRITICAL":
        return <Badge className="bg-red-500/20 text-red-500 border-red-500/30">Critical</Badge>;
      default:
        return <Badge variant="outline">Unknown</Badge>;
    }
  };

  // Mock chart data
  const monthlyData = [
    { month: "Oct", attendance: 85, average: 78 },
    { month: "Nov", attendance: 82, average: 76 },
    { month: "Dec", attendance: 88, average: 80 },
    { month: "Jan", attendance: 86, average: 79 },
    { month: "Feb", attendance: 84, average: 77 },
    { month: "Mar", attendance: 89, average: 81 },
  ];

  const pieData = [
    { name: "Present", value: overallSummary.academic.attended, color: "#22c55e" },
    { name: "Absent", value: overallSummary.academic.totalClasses - overallSummary.academic.attended, color: "#ef4444" },
  ];

  return (
    <StudentLayout>
          {/* Header */}
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold text-foreground">
                Attendance Summary
              </h1>
              <p className="text-muted-foreground">
                Track your attendance across all categories
              </p>
            </div>
            <Button
              variant="outline"
              onClick={refreshAttendance}
              disabled={isRefreshing}
              className="gap-2"
            >
              <RefreshCw className={cn("w-4 h-4", isRefreshing && "animate-spin")} />
              Refresh
            </Button>
          </div>

          {/* Overall Stats Cards */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <Card className="border-border/50 bg-gradient-to-br from-blue-500/10 to-transparent">
              <CardContent className="p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm text-muted-foreground">Academic</p>
                    <p className={cn("text-2xl font-bold", getStatusColor(overallSummary.academic.percentage))}>
                      {overallSummary.academic.percentage}%
                    </p>
                    <p className="text-xs text-muted-foreground">
                      {overallSummary.academic.attended}/{overallSummary.academic.totalClasses} classes
                    </p>
                  </div>
                  <BookOpen className="w-8 h-8 text-blue-500/50" />
                </div>
              </CardContent>
            </Card>

            <Card className="border-border/50 bg-gradient-to-br from-purple-500/10 to-transparent">
              <CardContent className="p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm text-muted-foreground">Events</p>
                    <p className="text-2xl font-bold text-purple-500">
                      {overallSummary.events.percentage}%
                    </p>
                    <p className="text-xs text-muted-foreground">
                      {overallSummary.events.attended}/{overallSummary.events.totalSessions} events
                    </p>
                  </div>
                  <Sparkles className="w-8 h-8 text-purple-500/50" />
                </div>
              </CardContent>
            </Card>

            <Card className="border-border/50 bg-gradient-to-br from-green-500/10 to-transparent">
              <CardContent className="p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm text-muted-foreground">Sports</p>
                    <p className="text-2xl font-bold text-green-500">
                      {overallSummary.sports.percentage}%
                    </p>
                    <p className="text-xs text-muted-foreground">
                      {overallSummary.sports.attended}/{overallSummary.sports.totalSessions} sessions
                    </p>
                  </div>
                  <Trophy className="w-8 h-8 text-green-500/50" />
                </div>
              </CardContent>
            </Card>

            <Card className="border-border/50 bg-gradient-to-br from-orange-500/10 to-transparent">
              <CardContent className="p-4">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm text-muted-foreground">Clubs</p>
                    <p className="text-2xl font-bold text-orange-500">
                      {overallSummary.clubs.percentage}%
                    </p>
                    <p className="text-xs text-muted-foreground">
                      {overallSummary.clubs.attended}/{overallSummary.clubs.totalMeetings} meetings
                    </p>
                  </div>
                  <Users className="w-8 h-8 text-orange-500/50" />
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Tabs for different views */}
          <Tabs value={activeTab} onValueChange={setActiveTab} className="space-y-6">
            <TabsList>
              <TabsTrigger value="academic">Academic</TabsTrigger>
              <TabsTrigger value="comparison">Comparison</TabsTrigger>
              <TabsTrigger value="calendar">Calendar View</TabsTrigger>
            </TabsList>

            {/* Academic Attendance Tab */}
            <TabsContent value="academic" className="space-y-6">
              <div className="grid lg:grid-cols-3 gap-6">
                {/* Subject-wise Attendance */}
                <Card className="lg:col-span-2 border-border/50 shadow-lg">
                  <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                      <BookOpen className="w-5 h-5 text-primary" />
                      Subject-wise Attendance
                    </CardTitle>
                    <CardDescription>
                      Your attendance breakdown by subject for the current semester
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="space-y-6">
                    {subjectAttendance.map((subject, index) => (
                      <div key={index} className="space-y-2">
                        <div className="flex items-center justify-between">
                          <div className="flex-1">
                            <div className="flex items-center justify-between">
                              <span className="font-medium text-foreground">
                                {subject.subjectName}
                              </span>
                              <div className="flex items-center gap-3">
                                <span className={cn(
                                  "text-lg font-bold",
                                  getStatusColor(subject.percentage)
                                )}>
                                  {subject.percentage}%
                                </span>
                                {getStatusBadge(subject.status)}
                              </div>
                            </div>
                            <div className="text-xs text-muted-foreground mt-1">
                              {subject.subjectCode} • {subject.attended}/{subject.totalClasses} classes
                            </div>
                          </div>
                        </div>
                        <div className="relative h-2 bg-muted rounded-full overflow-hidden">
                          <div
                            className={cn(
                              "absolute inset-y-0 left-0 rounded-full transition-all duration-500",
                              getProgressColor(subject.percentage)
                            )}
                            style={{ width: `${subject.percentage}%` }}
                          />
                        </div>
                      </div>
                    ))}
                  </CardContent>
                </Card>

                {/* Pie Chart */}
                <Card className="border-border/50 shadow-lg">
                  <CardHeader>
                    <CardTitle className="text-lg">Attendance Distribution</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="h-64">
                      <ResponsiveContainer width="100%" height="100%">
                        <PieChart>
                          <Pie
                            data={pieData}
                            cx="50%"
                            cy="50%"
                            innerRadius={60}
                            outerRadius={80}
                            paddingAngle={5}
                            dataKey="value"
                          >
                            {pieData.map((entry, index) => (
                              <Cell key={`cell-${index}`} fill={entry.color} />
                            ))}
                          </Pie>
                          <Tooltip />
                        </PieChart>
                      </ResponsiveContainer>
                    </div>
                    <div className="flex justify-center gap-6 mt-4">
                      <div className="flex items-center gap-2">
                        <div className="w-3 h-3 rounded-full bg-green-500" />
                        <span className="text-sm">Present</span>
                      </div>
                      <div className="flex items-center gap-2">
                        <div className="w-3 h-3 rounded-full bg-red-500" />
                        <span className="text-sm">Absent</span>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </div>
            </TabsContent>

            {/* Comparison Tab */}
            <TabsContent value="comparison" className="space-y-6">
              <Card className="border-border/50 shadow-lg">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <BarChart3 className="w-5 h-5 text-primary" />
                    Attendance Comparison
                  </CardTitle>
                  <CardDescription>
                    Your attendance vs class average over the past 6 months
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  <div className="h-80">
                    <ResponsiveContainer width="100%" height="100%">
                      <BarChart data={monthlyData} barGap={8}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} />
                        <XAxis dataKey="month" />
                        <YAxis domain={[0, 100]} />
                        <Tooltip />
                        <Bar dataKey="attendance" fill="#3b82f6" name="Your Attendance" radius={[4, 4, 0, 0]} />
                        <Bar dataKey="average" fill="#9ca3af" name="Class Average" radius={[4, 4, 0, 0]} />
                      </BarChart>
                    </ResponsiveContainer>
                  </div>
                  <div className="flex justify-center gap-6 mt-4">
                    <div className="flex items-center gap-2">
                      <div className="w-3 h-3 rounded-full bg-blue-500" />
                      <span className="text-sm">Your Attendance</span>
                    </div>
                    <div className="flex items-center gap-2">
                      <div className="w-3 h-3 rounded-full bg-gray-400" />
                      <span className="text-sm">Class Average</span>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </TabsContent>

            {/* Calendar View Tab */}
            <TabsContent value="calendar" className="space-y-6">
              <Card className="border-border/50 shadow-lg">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <Calendar className="w-5 h-5 text-primary" />
                    Calendar View
                  </CardTitle>
                  <CardDescription>
                    View your attendance history by date
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  <div className="text-center py-12 text-muted-foreground">
                    <Calendar className="w-16 h-16 mx-auto mb-4 opacity-50" />
                    <p>Calendar view coming soon</p>
                    <p className="text-sm mt-2">
                      You'll be able to view your attendance history on a calendar
                    </p>
                  </div>
                </CardContent>
              </Card>
            </TabsContent>
          </Tabs>

          {/* Warning Alert for Low Attendance */}
          {overallSummary.academic.percentage < ATTENDANCE_THRESHOLDS.SATISFACTORY && (
            <Card className="border-red-500/30 bg-red-500/5">
              <CardContent className="p-4">
                <div className="flex items-start gap-3">
                  <AlertCircle className="w-5 h-5 text-red-500 mt-0.5" />
                  <div>
                    <h4 className="font-medium text-red-500">Attendance Warning</h4>
                    <p className="text-sm text-muted-foreground mt-1">
                      Your attendance is below the minimum threshold of {ATTENDANCE_THRESHOLDS.SATISFACTORY}%.
                      Please ensure regular attendance to avoid detention.
                    </p>
                    <p className="text-xs text-muted-foreground mt-2">
                      Required: {ATTENDANCE_THRESHOLDS.SATISFACTORY}% |
                      Current: {overallSummary.academic.percentage}%
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>
          )}    </StudentLayout>  );
};

export default StudentAttendance;

import { useState, useEffect, useCallback } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { ScrollArea } from "@/components/ui/scroll-area";
import StudentLayout from "@/components/StudentLayout";
import { useAuth } from "@/contexts/AuthContext";
import { useToast } from "@/hooks/use-toast";
import { api } from "@/lib/api";
import {
  ArrowLeft,
  Calendar,
  MapPin,
  Users,
  Heart,
  MessageCircle,
  Share2,
  Bookmark,
  Send,
  Loader2,
  Star,
  ExternalLink,
  CheckCircle,
  XCircle,
  Trophy,
  DollarSign,
  UserPlus,
  UsersRound,
} from "lucide-react";

// ── Interfaces ──
interface ClubData {
  _id: string;
  club_id: string;
  name: string;
  description: string;
  category: string;
  foundedYear?: number;
  logo?: string;
  coverImage?: string;
  president?: { name: string; email: string; phone: string };
  faculty_advisor?: { name: string; email: string; department: string };
  memberCount: number;
  joinedStudents?: string[];
  maxMembers: number;
  meetingSchedule?: string;
  venue?: string;
  achievements?: string[];
  socialLinks?: { instagram?: string; linkedin?: string; twitter?: string; website?: string };
  recruitmentStatus: string;
  recruitmentDeadline?: string;
  eligibility: string;
  membershipFee: string;
  tags?: string[];
  featured: boolean;
  status: string;
  coordinatorRollNo?: string;
  postedBy?: { name: string; collegeId: string; email?: string };
  isRecruitmentOpen?: boolean;
  createdAt?: string;
}

interface PostComment {
  _id: string;
  user: { _id: string; name: string; collegeId: string };
  text: string;
  createdAt: string;
}

interface ClubPost {
  _id: string;
  clubId: string;
  content: string;
  image?: string;
  createdBy: { _id: string; name: string; collegeId: string; role: string };
  likes: string[];
  comments: PostComment[];
  createdAt: string;
}

// ── Component ──
const ClubDetail = () => {
  const { slug } = useParams<{ slug: string }>();
  const navigate = useNavigate();
  const { userData } = useAuth();
  const { toast } = useToast();

  const [club, setClub] = useState<ClubData | null>(null);
  const [posts, setPosts] = useState<ClubPost[]>([]);
  const [loadingClub, setLoadingClub] = useState(true);
  const [loadingPosts, setLoadingPosts] = useState(false);
  const [bookmarked, setBookmarked] = useState(false);
  const [processingJoin, setProcessingJoin] = useState(false);

  // Post creation
  const [newPostContent, setNewPostContent] = useState("");
  const [newPostImage, setNewPostImage] = useState("");
  const [submittingPost, setSubmittingPost] = useState(false);

  // Comment management
  const [commentTexts, setCommentTexts] = useState<Record<string, string>>({});
  const [expandedComments, setExpandedComments] = useState<Record<string, boolean>>({});
  const [submittingComment, setSubmittingComment] = useState<string | null>(null);

  // Coordinator check
  const isCoordinator = !!(club?.coordinatorRollNo && userData?.collegeId &&
    club.coordinatorRollNo.toUpperCase() === userData.collegeId.toUpperCase());

  // ── Data fetching ──
  const fetchClub = useCallback(async () => {
    if (!slug) return;
    setLoadingClub(true);
    try {
      const data = await api.get(`/clubs/slug/${slug}`);
      setClub(data);
    } catch (err: any) {
      console.error("Error fetching club:", err);
      toast({ title: "Error", description: "Club not found.", variant: "destructive" });
    } finally {
      setLoadingClub(false);
    }
  }, [slug]);

  const fetchPosts = useCallback(async (clubId: string) => {
    setLoadingPosts(true);
    try {
      const data = await api.get(`/clubs/${clubId}/posts`);
      setPosts(data.posts || []);
    } catch (err: any) {
      console.error("Error fetching posts:", err);
    } finally {
      setLoadingPosts(false);
    }
  }, []);

  useEffect(() => { fetchClub(); }, [fetchClub]);
  useEffect(() => { if (club?._id) fetchPosts(club._id); }, [club?._id, fetchPosts]);

  // ── Derived state ──
  const isJoined = club?.joinedStudents?.includes(userData?.collegeId || "") || false;
  const isPastDeadline = club?.recruitmentDeadline ? new Date(club.recruitmentDeadline) < new Date() : false;
  const canJoin = !isJoined && !isPastDeadline && club?.recruitmentStatus === "Open" &&
    (club?.maxMembers === 0 || club.memberCount < club.maxMembers);

  // ── Handlers ──
  const handleJoin = async () => {
    if (!club) return;
    setProcessingJoin(true);
    try {
      await api.post(`/clubs/${club._id}/join`, {});
      toast({ title: "Joined Successfully! ✅", description: `You are now a member of ${club.name}.` });
      fetchClub();
    } catch (err: any) {
      toast({ title: "Join Failed", description: err.message, variant: "destructive" });
    } finally {
      setProcessingJoin(false);
    }
  };

  const handleShare = async () => {
    const url = window.location.href;
    try {
      await navigator.clipboard.writeText(url);
      toast({ title: "Link Copied! 🔗", description: "Club link copied to clipboard." });
    } catch {
      toast({ title: "Share", description: url });
    }
  };

  const handleCreatePost = async () => {
    if (!club || !newPostContent.trim()) return;
    setSubmittingPost(true);
    try {
      await api.post(`/clubs/${club._id}/posts`, { content: newPostContent, image: newPostImage || undefined });
      setNewPostContent("");
      setNewPostImage("");
      fetchPosts(club._id);
      toast({ title: "Post Created ✅" });
    } catch (err: any) {
      toast({ title: "Error", description: err.message, variant: "destructive" });
    } finally {
      setSubmittingPost(false);
    }
  };

  const handleLike = async (postId: string) => {
    if (!club) return;
    try {
      const res = await api.post(`/clubs/${club._id}/posts/${postId}/like`, {});
      setPosts((prev) =>
        prev.map((p) => {
          if (p._id !== postId) return p;
          const userId = (userData as any)?._id || userData?.collegeId || "";
          return res.liked
            ? { ...p, likes: [...p.likes, userId] }
            : { ...p, likes: p.likes.filter((id) => id !== userId) };
        })
      );
    } catch (err: any) {
      console.error("Like error:", err);
    }
  };

  const handleComment = async (postId: string) => {
    if (!club) return;
    const text = commentTexts[postId]?.trim();
    if (!text) return;
    setSubmittingComment(postId);
    try {
      const res = await api.post(`/clubs/${club._id}/posts/${postId}/comment`, { text });
      setPosts((prev) =>
        prev.map((p) => p._id !== postId ? p : { ...p, comments: [...p.comments, res.comment] })
      );
      setCommentTexts((prev) => ({ ...prev, [postId]: "" }));
    } catch (err: any) {
      toast({ title: "Error", description: err.message, variant: "destructive" });
    } finally {
      setSubmittingComment(null);
    }
  };

  // ── Format helpers ──
  const formatDate = (d: string) =>
    new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" });
  const formatDateTime = (d: string) =>
    new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric", hour: "2-digit", minute: "2-digit", hour12: true });
  const timeAgo = (d: string) => {
    const diff = Date.now() - new Date(d).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return "Just now";
    if (mins < 60) return `${mins}m ago`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h ago`;
    const days = Math.floor(hrs / 24);
    if (days < 7) return `${days}d ago`;
    return formatDate(d);
  };

  // ── Loading / Error states ──
  if (loadingClub) {
    return (
      <StudentLayout>
        <div className="flex items-center justify-center min-h-[60vh]">
          <Loader2 className="w-10 h-10 animate-spin text-primary" />
        </div>
      </StudentLayout>
    );
  }

  if (!club) {
    return (
      <StudentLayout>
        <div className="py-16 text-center">
          <h2 className="text-2xl font-bold mb-4">Club Not Found</h2>
          <p className="text-muted-foreground mb-6">The club you're looking for doesn't exist or has been removed.</p>
          <Button onClick={() => navigate("/student/clubs")}>
            <ArrowLeft className="w-4 h-4 mr-2" /> Back to Clubs
          </Button>
        </div>
      </StudentLayout>
    );
  }

  // ── Main Render ──
  return (
    <StudentLayout>
      <div className="space-y-6">
        {/* ═══ BACK NAVIGATION ═══ */}
        <button
          onClick={() => navigate("/student/clubs")}
          className="flex items-center gap-2 text-muted-foreground hover:text-foreground transition-colors text-sm group"
        >
          <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
          Back to Clubs
        </button>

        {/* ═══ BANNER + HEADER ═══ */}
        <Card className="overflow-hidden">
          {club.coverImage && (
            <div className="relative h-[280px] overflow-hidden">
              <img src={club.coverImage} alt={club.name} className="w-full h-full object-cover" />
              <div
                className="absolute inset-0"
                style={{ background: "linear-gradient(to top, hsl(var(--card)) 5%, rgba(0,0,0,0.4) 50%, transparent 100%)" }}
              />
              {club.featured && (
                <Badge className="absolute top-4 right-4 bg-yellow-500/90 backdrop-blur-sm text-white shadow-lg">
                  <Star className="w-3 h-3 mr-1 fill-current" /> Featured
                </Badge>
              )}
            </div>
          )}

          <CardContent className={`${club.coverImage ? "-mt-20 relative z-10" : ""} px-8 py-6`}>
            <div className="flex flex-col lg:flex-row lg:items-end lg:justify-between gap-4">
              {/* Left: Title + Info */}
              <div className="space-y-2">
                <div className="flex flex-wrap items-center gap-2">
                  <Badge variant="outline" className="text-xs">{club.category}</Badge>
                  <Badge
                    variant="outline"
                    className={`text-xs ${club.recruitmentStatus === "Open" ? "bg-green-500/20 text-green-400 border-green-500/30" : "bg-red-500/20 text-red-400 border-red-500/30"}`}
                  >
                    {club.recruitmentStatus === "Open" ? "Recruiting" : club.recruitmentStatus}
                  </Badge>
                  {isJoined && (
                    <Badge variant="outline" className="bg-primary/20 text-primary border-primary/30 text-xs">
                      <CheckCircle className="w-3 h-3 mr-1" /> Member
                    </Badge>
                  )}
                </div>
                <h1 className="text-[28px] lg:text-[32px] font-bold text-foreground leading-tight">{club.name}</h1>
                <p className="text-muted-foreground text-sm">
                  {club.foundedYear ? `Est. ${club.foundedYear}` : club.club_id}
                  {club.president?.name && <> · Led by <span className="font-semibold text-foreground">{club.president.name}</span></>}
                </p>
              </div>

              {/* Right: Action buttons */}
              <div className="flex flex-wrap gap-3 shrink-0">
                {isJoined ? (
                  <Button className="bg-green-600 hover:bg-green-700 text-white cursor-default" disabled>
                    <CheckCircle className="w-4 h-4 mr-2" /> Joined
                  </Button>
                ) : isPastDeadline ? (
                  <Button variant="destructive" disabled className="cursor-default">
                    <XCircle className="w-4 h-4 mr-2" /> Joining Closed
                  </Button>
                ) : canJoin ? (
                  <Button className="bg-green-600 hover:bg-green-700 text-white" onClick={handleJoin} disabled={processingJoin}>
                    {processingJoin && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                    <UserPlus className="w-4 h-4 mr-2" /> Join Club
                  </Button>
                ) : null}
                <Button variant="outline" onClick={handleShare}>
                  <Share2 className="w-4 h-4 mr-2" /> Share
                </Button>
                <Button
                  variant="outline"
                  onClick={() => setBookmarked(!bookmarked)}
                  className={bookmarked ? "border-yellow-500 text-yellow-500" : ""}
                >
                  <Bookmark className={`w-4 h-4 mr-2 ${bookmarked ? "fill-current" : ""}`} />
                  {bookmarked ? "Saved" : "Save"}
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* ═══ MAIN 2-COLUMN LAYOUT ═══ */}
        <div className="grid grid-cols-1 lg:grid-cols-[1fr_340px] gap-6">

          {/* ── LEFT COLUMN ── */}
          <div className="space-y-6 min-w-0">

            {/* Description */}
            <Card>
              <CardContent className="p-7 space-y-5">
                <h2 className="text-xl font-bold">About This Club</h2>
                <p className="text-muted-foreground leading-relaxed whitespace-pre-wrap text-[15px]">{club.description}</p>

                {club.achievements && club.achievements.length > 0 && (
                  <div>
                    <h3 className="text-sm font-semibold mb-2 text-muted-foreground uppercase tracking-wide">Achievements</h3>
                    <div className="flex flex-wrap gap-2">
                      {club.achievements.map((a, i) => (
                        <Badge key={i} variant="secondary" className="text-xs px-3 py-1">
                          <Trophy className="w-3 h-3 mr-1" />{a}
                        </Badge>
                      ))}
                    </div>
                  </div>
                )}

                {club.tags && club.tags.length > 0 && (
                  <div>
                    <h3 className="text-sm font-semibold mb-2 text-muted-foreground uppercase tracking-wide">Tags</h3>
                    <div className="flex flex-wrap gap-2">
                      {club.tags.map((t, i) => (
                        <Badge key={i} variant="outline" className="text-xs">{t}</Badge>
                      ))}
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>

            {/* ═══ SOCIAL FEED ═══ */}
            <div className="space-y-5">
              <h2 className="text-xl font-bold flex items-center gap-2">
                <MessageCircle className="w-5 h-5 text-primary" />
                Club Feed
              </h2>

              {/* Create Post (Coordinator Only) */}
              {isCoordinator && (
                <Card className="border-primary/20">
                  <CardContent className="p-6 space-y-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center text-sm font-bold text-primary">
                        {userData?.name?.charAt(0) || "C"}
                      </div>
                      <div>
                        <p className="text-sm font-semibold">{userData?.name || "Coordinator"}</p>
                        <p className="text-xs text-muted-foreground">Club Coordinator</p>
                      </div>
                    </div>
                    <Textarea
                      placeholder="Share an update about this club..."
                      value={newPostContent}
                      onChange={(e) => setNewPostContent(e.target.value)}
                      rows={3}
                      className="resize-none"
                    />
                    {newPostImage && (
                      <div className="relative inline-block">
                        <img src={newPostImage} alt="Preview" className="rounded-lg max-h-40 object-cover" />
                        <button
                          onClick={() => setNewPostImage("")}
                          className="absolute top-2 right-2 bg-background/80 rounded-full w-6 h-6 flex items-center justify-center text-xs hover:bg-background"
                        >✕</button>
                      </div>
                    )}
                    <div className="flex items-center justify-between gap-4">
                      <Input
                        placeholder="Image URL (optional)"
                        value={newPostImage}
                        onChange={(e) => setNewPostImage(e.target.value)}
                        className="flex-1 text-xs h-9"
                      />
                      <Button onClick={handleCreatePost} disabled={!newPostContent.trim() || submittingPost}>
                        {submittingPost ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Send className="w-4 h-4 mr-2" />}
                        Post Update
                      </Button>
                    </div>
                  </CardContent>
                </Card>
              )}

              {/* Posts */}
              {loadingPosts ? (
                <div className="py-16 text-center">
                  <Loader2 className="w-8 h-8 animate-spin mx-auto text-primary" />
                  <p className="text-sm text-muted-foreground mt-3">Loading feed...</p>
                </div>
              ) : posts.length === 0 ? (
                <Card>
                  <CardContent className="py-16 text-center">
                    <MessageCircle className="w-12 h-12 mx-auto mb-3 text-muted-foreground/30" />
                    <p className="text-muted-foreground font-medium">No posts yet</p>
                    {isCoordinator && <p className="text-xs text-muted-foreground mt-1">Create a post to start the conversation!</p>}
                  </CardContent>
                </Card>
              ) : (
                <div className="space-y-5">
                  {posts.map((post) => {
                    const isLiked = post.likes.includes((userData as any)?._id || "");
                    const showComments = expandedComments[post._id] || false;

                    return (
                      <Card key={post._id} className="overflow-hidden hover:shadow-lg transition-all duration-200">
                        <CardContent className="p-0">
                          {/* Post Header */}
                          <div className="flex items-center gap-3 px-6 pt-5 pb-3">
                            <div className="w-11 h-11 rounded-full bg-primary/10 flex items-center justify-center text-sm font-bold text-primary">
                              {post.createdBy?.name?.charAt(0) || "?"}
                            </div>
                            <div className="flex-1">
                              <p className="text-sm font-semibold">{post.createdBy?.name || "Unknown"}</p>
                              <p className="text-xs text-muted-foreground">
                                Coordinator · {timeAgo(post.createdAt)}
                              </p>
                            </div>
                          </div>

                          {/* Post Content */}
                          <div className="px-6 pb-4">
                            <p className="text-[15px] leading-relaxed whitespace-pre-wrap">{post.content}</p>
                          </div>

                          {/* Post Image */}
                          {post.image && (
                            <div className="px-6 pb-4">
                              <img src={post.image} alt="Post" className="rounded-xl w-full max-h-[420px] object-cover border border-border" />
                            </div>
                          )}

                          {/* Engagement Stats */}
                          <div className="px-6 py-2.5 flex items-center justify-between text-xs text-muted-foreground border-t border-border/40">
                            <span>{post.likes.length} {post.likes.length === 1 ? "like" : "likes"}</span>
                            <span>{post.comments.length} {post.comments.length === 1 ? "comment" : "comments"}</span>
                          </div>

                          {/* Action Bar */}
                          <div className="flex border-t border-border/40">
                            <button
                              onClick={() => handleLike(post._id)}
                              className={`flex-1 flex items-center justify-center gap-2 py-3 text-sm font-medium transition-colors hover:bg-muted/50 ${isLiked ? "text-red-500" : "text-muted-foreground"}`}
                            >
                              <Heart className={`w-[18px] h-[18px] ${isLiked ? "fill-current" : ""}`} /> Like
                            </button>
                            <button
                              onClick={() => setExpandedComments((p) => ({ ...p, [post._id]: !p[post._id] }))}
                              className="flex-1 flex items-center justify-center gap-2 py-3 text-sm font-medium text-muted-foreground transition-colors hover:bg-muted/50"
                            >
                              <MessageCircle className="w-[18px] h-[18px]" /> Comment
                            </button>
                            <button
                              onClick={handleShare}
                              className="flex-1 flex items-center justify-center gap-2 py-3 text-sm font-medium text-muted-foreground transition-colors hover:bg-muted/50"
                            >
                              <Share2 className="w-[18px] h-[18px]" /> Share
                            </button>
                          </div>

                          {/* Comments */}
                          {showComments && (
                            <div className="border-t border-border/40 bg-muted/10">
                              {post.comments.length > 0 && (
                                <ScrollArea className={post.comments.length > 4 ? "max-h-64" : ""}>
                                  <div className="px-6 py-4 space-y-3">
                                    {post.comments.map((c) => (
                                      <div key={c._id} className="flex gap-2.5">
                                        <div className="w-8 h-8 rounded-full bg-muted flex items-center justify-center text-xs font-bold text-muted-foreground shrink-0">
                                          {c.user?.name?.charAt(0) || "?"}
                                        </div>
                                        <div className="flex-1">
                                          <div className="bg-muted/60 rounded-2xl px-4 py-2.5">
                                            <p className="text-xs font-semibold">{c.user?.name || "Unknown"}</p>
                                            <p className="text-xs text-muted-foreground leading-relaxed mt-0.5">{c.text}</p>
                                          </div>
                                          <p className="text-[10px] text-muted-foreground mt-1 ml-4">{timeAgo(c.createdAt)}</p>
                                        </div>
                                      </div>
                                    ))}
                                  </div>
                                </ScrollArea>
                              )}

                              {/* Comment Input */}
                              <div className="px-6 py-3 flex items-center gap-3 border-t border-border/30">
                                <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center text-xs font-bold text-primary shrink-0">
                                  {userData?.name?.charAt(0) || "?"}
                                </div>
                                <Input
                                  placeholder="Write a comment..."
                                  value={commentTexts[post._id] || ""}
                                  onChange={(e) => setCommentTexts((p) => ({ ...p, [post._id]: e.target.value }))}
                                  onKeyDown={(e) => {
                                    if (e.key === "Enter" && !e.shiftKey) {
                                      e.preventDefault();
                                      handleComment(post._id);
                                    }
                                  }}
                                  className="h-9 text-xs flex-1"
                                />
                                <Button
                                  size="sm"
                                  variant="ghost"
                                  className="h-9 w-9 p-0"
                                  onClick={() => handleComment(post._id)}
                                  disabled={submittingComment === post._id || !commentTexts[post._id]?.trim()}
                                >
                                  {submittingComment === post._id ? (
                                    <Loader2 className="w-4 h-4 animate-spin" />
                                  ) : (
                                    <Send className="w-4 h-4 text-primary" />
                                  )}
                                </Button>
                              </div>
                            </div>
                          )}
                        </CardContent>
                      </Card>
                    );
                  })}
                </div>
              )}
            </div>
          </div>

          {/* ── RIGHT COLUMN (Sticky Sidebar) ── */}
          <div className="space-y-5 lg:sticky lg:top-0 lg:self-start">

            {/* Quick Info */}
            <Card>
              <CardContent className="p-6 space-y-5">
                <h3 className="text-sm font-bold uppercase tracking-wide text-muted-foreground">Club Info</h3>
                <div className="space-y-4">
                  <div className="flex items-start gap-3">
                    <div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
                      <Users className="w-4 h-4 text-primary" />
                    </div>
                    <div>
                      <p className="text-xs text-muted-foreground">Members</p>
                      <p className="text-sm font-semibold">
                        {club.memberCount || 0}
                        {club.maxMembers > 0 ? ` / ${club.maxMembers}` : " members"}
                      </p>
                    </div>
                  </div>

                  {club.venue && (
                    <div className="flex items-start gap-3">
                      <div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
                        <MapPin className="w-4 h-4 text-primary" />
                      </div>
                      <div>
                        <p className="text-xs text-muted-foreground">Venue</p>
                        <p className="text-sm font-semibold">{club.venue}</p>
                      </div>
                    </div>
                  )}

                  {club.meetingSchedule && (
                    <div className="flex items-start gap-3">
                      <div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
                        <Calendar className="w-4 h-4 text-primary" />
                      </div>
                      <div>
                        <p className="text-xs text-muted-foreground">Meetings</p>
                        <p className="text-sm font-semibold">{club.meetingSchedule}</p>
                      </div>
                    </div>
                  )}

                  <div className="flex items-start gap-3">
                    <div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
                      <DollarSign className="w-4 h-4 text-primary" />
                    </div>
                    <div>
                      <p className="text-xs text-muted-foreground">Membership Fee</p>
                      <p className="text-sm font-semibold">{club.membershipFee || "Free"}</p>
                    </div>
                  </div>

                  <div className="flex items-start gap-3">
                    <div className="w-9 h-9 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
                      <UsersRound className="w-4 h-4 text-primary" />
                    </div>
                    <div>
                      <p className="text-xs text-muted-foreground">Eligibility</p>
                      <p className="text-sm font-semibold">{club.eligibility || "All Students"}</p>
                    </div>
                  </div>

                  {club.recruitmentDeadline && (
                    <div className="flex items-start gap-3">
                      <div className={`w-9 h-9 rounded-lg ${isPastDeadline ? "bg-red-500/10" : "bg-primary/10"} flex items-center justify-center shrink-0`}>
                        <Calendar className={`w-4 h-4 ${isPastDeadline ? "text-red-400" : "text-primary"}`} />
                      </div>
                      <div>
                        <p className="text-xs text-muted-foreground">Recruitment Deadline</p>
                        <p className={`text-sm font-semibold ${isPastDeadline ? "text-destructive" : ""}`}>
                          {formatDateTime(club.recruitmentDeadline)}
                        </p>
                      </div>
                    </div>
                  )}
                </div>
              </CardContent>
            </Card>

            {/* Contact / Advisors */}
            {(club.faculty_advisor?.name || club.president?.name || club.socialLinks) && (
              <Card>
                <CardContent className="p-6 space-y-4">
                  <h3 className="text-sm font-bold uppercase tracking-wide text-muted-foreground">People & Links</h3>
                  {club.president?.name && (
                    <div>
                      <p className="text-xs text-muted-foreground">President</p>
                      <p className="text-sm font-medium">{club.president.name}</p>
                      {club.president.email && <p className="text-xs text-muted-foreground">{club.president.email}</p>}
                    </div>
                  )}
                  {club.faculty_advisor?.name && (
                    <div>
                      <p className="text-xs text-muted-foreground">Faculty Advisor</p>
                      <p className="text-sm font-medium">{club.faculty_advisor.name}</p>
                      {club.faculty_advisor.department && <p className="text-xs text-muted-foreground">{club.faculty_advisor.department}</p>}
                    </div>
                  )}
                  {club.socialLinks && (
                    <div className="flex flex-wrap gap-2 pt-1">
                      {club.socialLinks.website && (
                        <a href={club.socialLinks.website} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1 text-xs text-primary hover:underline">
                          <ExternalLink className="w-3 h-3" /> Website
                        </a>
                      )}
                      {club.socialLinks.instagram && (
                        <a href={club.socialLinks.instagram} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1 text-xs text-primary hover:underline">
                          <ExternalLink className="w-3 h-3" /> Instagram
                        </a>
                      )}
                      {club.socialLinks.linkedin && (
                        <a href={club.socialLinks.linkedin} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1 text-xs text-primary hover:underline">
                          <ExternalLink className="w-3 h-3" /> LinkedIn
                        </a>
                      )}
                    </div>
                  )}
                </CardContent>
              </Card>
            )}
          </div>
        </div>
      </div>
    </StudentLayout>
  );
};

export default ClubDetail;

import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import StudentLayout from "@/components/StudentLayout";
import { useAuth } from "@/contexts/AuthContext";
import { useClubs } from "@/contexts/ClubContext";
import { useToast } from "@/hooks/use-toast";
import {
  Search,
  Users,
  Heart,
  Calendar,
  Trophy,
  Code,
  Palette,
  Camera,
  ExternalLink,
  UserPlus,
  Loader2,
  MapPin,
  Star,
  UsersRound,
  CheckCircle,
  XCircle,
} from "lucide-react";

const StudentClubs = () => {
  const { userData } = useAuth();
  const { clubs, loading, error, fetchClubs, joinClub } = useClubs();
  const { toast } = useToast();
  const navigate = useNavigate();
  const [searchTerm, setSearchTerm] = useState("");
  const [categoryFilter, setCategoryFilter] = useState("all");
  const [statusFilter, setStatusFilter] = useState("all");
  const [processingClubId, setProcessingClubId] = useState<string | null>(null);

  const isJoined = (club: any) => {
    if (!userData?.collegeId || !club.joinedStudents) return false;
    return club.joinedStudents.includes(userData.collegeId);
  };

  const [expandedCards, setExpandedCards] = useState<Record<string, boolean>>({});

  const toggleExpand = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setExpandedCards(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const isPastDeadline = (deadline?: string) => {
    if (!deadline) return false;
    return new Date(deadline) < new Date();
  };

  useEffect(() => {
    fetchClubs();
  }, []);

  const slugify = (text: string) =>
    text.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, "");

  const filteredClubs = clubs.filter((club) => {
    const matchesSearch =
      club.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      club.description?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      club.club_id.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory =
      categoryFilter === "all" ||
      club.category.toLowerCase() === categoryFilter.toLowerCase();
    const matchesStatus =
      statusFilter === "all" || club.recruitmentStatus === statusFilter;

    return matchesSearch && matchesCategory && matchesStatus;
  });

  const getCategoryIcon = (category: string) => {
    switch (category.toLowerCase()) {
      case "technical":
        return <Code className="w-4 h-4" />;
      case "cultural":
        return <Palette className="w-4 h-4" />;
      case "sports":
        return <Trophy className="w-4 h-4" />;
      case "literary":
        return <Camera className="w-4 h-4" />;
      default:
        return <Users className="w-4 h-4" />;
    }
  };

  const getCategoryBadge = (category: string) => {
    const colors: { [key: string]: string } = {
      Technical: "bg-blue-500",
      Cultural: "bg-purple-500",
      Sports: "bg-green-500",
      Literary: "bg-amber-500",
      Social: "bg-pink-500",
      Professional: "bg-cyan-500",
      Hobby: "bg-orange-500",
      Other: "bg-gray-500",
    };
    return <Badge className={colors[category] || "bg-gray-500"}>{category}</Badge>;
  };

  const getRecruitmentBadge = (status: string) => {
    switch (status) {
      case "Open":
        return <Badge className="bg-green-500">Recruiting</Badge>;
      case "Closed":
        return <Badge variant="secondary">Closed</Badge>;
      case "Coming Soon":
        return <Badge variant="outline">Coming Soon</Badge>;
      default:
        return <Badge variant="secondary">{status}</Badge>;
    }
  };

  const handleJoinClub = async (clubId: string) => {
    try {
      setProcessingClubId(clubId);
      await joinClub(clubId);
      toast({
        title: "Joined!",
        description: "You have successfully joined the club.",
      });
    } catch (err: any) {
      console.error("Error joining club:", err);
      toast({
        title: "Error",
        description: err.message || "Failed to join club.",
        variant: "destructive",
      });
    } finally {
      setProcessingClubId(null);
    }
  };

  return (
    <StudentLayout>
      <div className="max-w-7xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
              <UsersRound className="w-8 h-8 text-primary" />
              Student Clubs
            </h1>
            <p className="text-muted-foreground mt-1">
              Discover and join clubs that match your interests
            </p>
          </div>
        </div>

        {/* Filters */}
        <Card>
          <CardHeader>
            <CardTitle className="text-lg">Find Clubs</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="flex flex-col md:flex-row gap-4">
              <div className="flex-1">
                <div className="relative">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground w-4 h-4" />
                  <Input
                    placeholder="Search clubs..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10"
                  />
                </div>
              </div>
              <Select
                name="clubCategory"
                value={categoryFilter}
                onValueChange={setCategoryFilter}
              >
                <SelectTrigger className="w-full md:w-[200px]">
                  <SelectValue placeholder="Category" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Categories</SelectItem>
                  <SelectItem value="technical">Technical</SelectItem>
                  <SelectItem value="cultural">Cultural</SelectItem>
                  <SelectItem value="sports">Sports</SelectItem>
                  <SelectItem value="literary">Literary</SelectItem>
                  <SelectItem value="social">Social</SelectItem>
                  <SelectItem value="hobby">Hobby</SelectItem>
                </SelectContent>
              </Select>
              <Select
                name="clubStatus"
                value={statusFilter}
                onValueChange={setStatusFilter}
              >
                <SelectTrigger className="w-full md:w-[200px]">
                  <SelectValue placeholder="Recruitment" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Clubs</SelectItem>
                  <SelectItem value="Open">Recruiting</SelectItem>
                  <SelectItem value="Closed">Closed</SelectItem>
                  <SelectItem value="Coming Soon">Coming Soon</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </CardContent>
        </Card>



        {/* Loading State */}
        {loading && clubs.length === 0 && (
          <Card>
            <CardContent className="p-12 text-center">
              <Loader2 className="w-12 h-12 text-primary mx-auto mb-4 animate-spin" />
              <p className="text-muted-foreground">Loading clubs...</p>
            </CardContent>
          </Card>
        )}

        {/* Clubs Grid */}
        <div>
          <h2 className="text-xl font-semibold mb-4">All Clubs</h2>
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
            {!loading && filteredClubs.length === 0 ? (
              <div className="col-span-full">
                <Card>
                  <CardContent className="py-12 text-center">
                    <UsersRound className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                    <h3 className="text-lg font-medium text-foreground mb-2">
                      No clubs found
                    </h3>
                    <p className="text-muted-foreground">
                      {clubs.length === 0
                        ? "No clubs have been registered yet."
                        : "Try adjusting your filters to discover more clubs."}
                    </p>
                  </CardContent>
                </Card>
              </div>
            ) : (
              filteredClubs.map((club) => (
                <Card
                  key={club._id}
                  className="flex flex-col h-full min-h-[420px] hover:shadow-lg transition-all duration-300 hover:-translate-y-1"
                >
                  <CardHeader className="pb-3">
                    <div className="flex items-start justify-between">
                      <div className="flex items-center gap-3">
                        <div className="w-12 h-12 bg-primary rounded-lg flex items-center justify-center text-white">
                          <UsersRound className="w-6 h-6" />
                        </div>
                        <div>
                          <div className="flex items-center gap-2">
                            <h3 className="font-bold text-foreground hover:underline cursor-pointer" onClick={() => navigate(`/student/clubs/${slugify(club.name)}`)}>
                              {club.name}
                            </h3>
                            {club.featured && (
                              <Star className="w-4 h-4 text-yellow-500 fill-current" />
                            )}
                          </div>
                          <p className="text-xs text-muted-foreground">
                            {club.foundedYear ? `Est. ${club.foundedYear}` : club.club_id}
                          </p>
                        </div>
                      </div>
                      {isJoined(club) ? (
                        <Button size="sm" disabled className="bg-green-600 hover:bg-green-700 opacity-100 disabled:opacity-100 cursor-default text-white">
                          <CheckCircle className="w-4 h-4 mr-1" />
                          Joined
                        </Button>
                      ) : isPastDeadline(club.recruitmentDeadline) ? (
                        <Button size="sm" disabled className="bg-destructive hover:bg-destructive opacity-100 disabled:opacity-100 cursor-default text-destructive-foreground">
                          <XCircle className="w-4 h-4 mr-1" />
                          Joining Closed
                        </Button>
                      ) : club.recruitmentStatus === "Open" && (
                        <Button
                          size="sm"
                          onClick={() => handleJoinClub(club._id)}
                          disabled={processingClubId === club._id}
                        >
                          {processingClubId === club._id ? (
                            <><Loader2 className="w-4 h-4 mr-1 animate-spin" /> Joining...</>
                          ) : (
                            <><UserPlus className="w-4 h-4 mr-1" /> Join</>
                          )}
                        </Button>
                      )}
                    </div>
                    <div className="flex flex-wrap gap-1 mt-2">
                      {getCategoryBadge(club.category)}
                      {getRecruitmentBadge(club.recruitmentStatus)}
                    </div>
                  </CardHeader>
                  <CardContent className="space-y-4 flex-1 flex flex-col">
                    <div>
                      <p className={`text-sm text-muted-foreground ${expandedCards[club._id] ? '' : 'line-clamp-3'}`}>
                        {club.description}
                      </p>
                      {club.description && club.description.length > 100 && (
                        <button
                          onClick={(e) => toggleExpand(club._id, e)}
                          className="text-primary text-xs hover:underline mt-1 bg-transparent border-none p-0 cursor-pointer"
                        >
                          {expandedCards[club._id] ? 'Show less' : 'Read more'}
                        </button>
                      )}
                    </div>

                    {/* Stats */}
                    <div className="grid grid-cols-3 gap-4 py-3 border-y">
                      <div className="text-center">
                        <div className="text-lg font-bold text-foreground">
                          {club.memberCount || 0}
                        </div>
                        <div className="text-xs text-muted-foreground">
                          Members
                        </div>
                      </div>
                      <div className="text-center">
                        <div className="text-lg font-bold text-foreground">
                          {club.maxMembers || "∞"}
                        </div>
                        <div className="text-xs text-muted-foreground">
                          Max
                        </div>
                      </div>
                      <div className="text-center">
                        <div className="text-lg font-bold text-foreground">
                          {club.membershipFee || "Free"}
                        </div>
                        <div className="text-xs text-muted-foreground">
                          Fee
                        </div>
                      </div>
                    </div>

                    {/* Details */}
                    <div className="space-y-2 text-sm text-muted-foreground">
                      {club.venue && (
                        <div className="flex items-center gap-2">
                          <MapPin className="w-4 h-4" />
                          <span>{club.venue}</span>
                        </div>
                      )}
                      {club.meetingSchedule && (
                        <div className="flex items-center gap-2">
                          <Calendar className="w-4 h-4" />
                          <span>{club.meetingSchedule}</span>
                        </div>
                      )}
                      {club.president?.name && (
                        <div className="flex items-center gap-2">
                          <Users className="w-4 h-4" />
                          <span>President: {club.president.name}</span>
                        </div>
                      )}
                    </div>

                    {/* Achievements */}
                    {club.achievements && club.achievements.length > 0 && (
                      <div>
                        <h4 className="font-medium text-sm mb-2 flex items-center gap-1">
                          <Trophy className="w-4 h-4" />
                          Achievements
                        </h4>
                        <div className="flex flex-wrap gap-1">
                          {club.achievements.slice(0, 2).map((achievement, idx) => (
                            <Badge key={idx} variant="outline" className="text-xs">
                              {achievement}
                            </Badge>
                          ))}
                        </div>
                      </div>
                    )}

                    {/* Actions */}
                    <div className="flex gap-2 pt-4 border-t mt-auto">
                      <Button size="sm" className="flex-1" onClick={() => navigate(`/student/clubs/${slugify(club.name)}`)}>
                        View Details
                        <ExternalLink className="w-3 h-3 ml-1" />
                      </Button>
                    </div>
                  </CardContent>
                </Card>
              ))
            )}
          </div>
        </div>
      </div>
    </StudentLayout>
  );
};

export default StudentClubs;

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import StudentLayout from "@/components/StudentLayout";
import { useAuth } from "@/contexts/AuthContext";
import { User, FileText, BookOpen, Loader2, Download } from "lucide-react";

const API_BASE = import.meta.env.VITE_API_URL || "http://localhost:5000/api";

interface CourseResource {
  _id?: string;
  name: string;
  type: string;
  fileData?: string;
  fileName?: string;
  fileSize?: number;
}

interface SyllabusTopic {
  topic: string;
  duration: string;
}

interface Course {
  _id: string;
  courseCode: string;
  courseName: string;
  credits: number;
  maxStudents: number;
  description: string;
  objectives: string[];
  syllabus: SyllabusTopic[];
  resources: CourseResource[];
  facultyId: string;
  facultyName: string;
  status: string;
  color: string;
  department?: string;
  year?: string;
  semester?: string;
  classType?: string;
  sections?: string[];
  assignedStudents?: string[];
  createdAt: string;
}

const StudentCourses = () => {
  const { userData } = useAuth();
  const [courses, setCourses] = useState<Course[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedCourse, setSelectedCourse] = useState<Course | null>(null);
  // ── Compute student's current academic year from collegeId ──
  const getStudentCurrentYear = (): string => {
    const collegeId = userData?.collegeId || "";
    const yearCode = collegeId.substring(0, 2);
    if (!yearCode || !/^\d{2}$/.test(yearCode)) return "IV Year";
    const admissionYear = parseInt("20" + yearCode);
    const now = new Date();
    const curYear = now.getFullYear();
    const curMonth = now.getMonth();
    const academicStartYear = curMonth >= 6 ? curYear : curYear - 1;
    const yearNum = academicStartYear - admissionYear + 1;
    const yearLabels = ["I Year", "II Year", "III Year", "IV Year"];
    return yearLabels[Math.min(Math.max(yearNum - 1, 0), 3)];
  };

  const [degree, setDegree] = useState("Major");
  const [selectedYear, setSelectedYear] = useState(() => getStudentCurrentYear());
  const [selectedSemester, setSelectedSemester] = useState(() => {
    return userData?.collegeId?.startsWith('22') ? "Semester-II" : "Semester-I";
  });

  // Dynamically configure dropdown defaults mapping exactly to the backend student Current Semester logic
  useEffect(() => {
    if (!userData?.uid) return;
    const fetchProfileSemester = async () => {
      try {
        const apiBaseUrl = import.meta.env.VITE_API_URL || import.meta.env.VITE_API_BASE_URL || "http://localhost:5000/api";
        const res = await fetch(`${apiBaseUrl}/users/${userData.uid}`);
        if (res.ok) {
          const profile = await res.json();
          let currentSem = profile.academicInformation?.currentSemester || profile.semester;
          
          if (userData?.collegeId?.startsWith('22')) {
            currentSem = "VIII";
          }
          
          if (currentSem) {
            const romanMap: Record<string, { year: string; semLabel: string }> = {
              "I": { year: "I Year", semLabel: "Semester-I" },
              "II": { year: "I Year", semLabel: "Semester-II" },
              "III": { year: "II Year", semLabel: "Semester-I" },
              "IV": { year: "II Year", semLabel: "Semester-II" },
              "V": { year: "III Year", semLabel: "Semester-I" },
              "VI": { year: "III Year", semLabel: "Semester-II" },
              "VII": { year: "IV Year", semLabel: "Semester-I" },
              "VIII": { year: "IV Year", semLabel: "Semester-II" }
            };
            const mapping = romanMap[String(currentSem).toUpperCase()];
            if (mapping) {
              setDegree("Major");
              setSelectedYear(mapping.year);
              setSelectedSemester(mapping.semLabel);
            }
          }
        }
      } catch (err) {
        console.warn("Failed to initialize course mapping defaults:", err);
      }
    };
    fetchProfileSemester();
  }, [userData?.uid]);

  // Fetch courses relevant to this student
  useEffect(() => {
    const fetchCourses = async () => {
      try {
        setLoading(true);
        const studentSection = userData?.section || "";
        const studentId = userData?.collegeId || "";

        const params = new URLSearchParams();
        if (studentSection) params.append("section", studentSection);
        if (studentId) params.append("studentId", studentId);

        const res = await fetch(`${API_BASE}/courses?${params.toString()}`);
        if (res.ok) {
          const data = await res.json();
          const activeCourses = data.filter((c: Course) => c.status === "Active").reverse();
          setCourses(activeCourses);
        }
      } catch (error) {
        console.error("Error fetching courses:", error);
      } finally {
        setLoading(false);
      }
    };
    fetchCourses();
  }, [userData?.section, userData?.collegeId]);

  // Robust filtering to handle Faculty entering either relative ("Semester I") or absolute ("Semester VII") terms
  const filteredCourses = courses.filter((c) => {
    // Check Year
    const yearMatch = c.year === selectedYear || !c.year;
    
    // Check Semester
    let semesterMatch = false;
    const sem = c.semester || "";
    if (selectedSemester === "Semester-I") {
      semesterMatch = ["Semester-I", "Semester I", "Semester 1"].includes(sem);
      if (selectedYear === "I Year") semesterMatch = semesterMatch || sem === "Semester I";
      if (selectedYear === "II Year") semesterMatch = semesterMatch || sem === "Semester III";
      if (selectedYear === "III Year") semesterMatch = semesterMatch || sem === "Semester V";
      if (selectedYear === "IV Year") semesterMatch = semesterMatch || sem === "Semester VII";
    } else if (selectedSemester === "Semester-II") {
      semesterMatch = ["Semester-II", "Semester II", "Semester 2"].includes(sem);
      if (selectedYear === "I Year") semesterMatch = semesterMatch || sem === "Semester II";
      if (selectedYear === "II Year") semesterMatch = semesterMatch || sem === "Semester IV";
      if (selectedYear === "III Year") semesterMatch = semesterMatch || sem === "Semester VI";
      if (selectedYear === "IV Year") semesterMatch = semesterMatch || sem === "Semester VIII";
    }

    return yearMatch && semesterMatch;
  });

  // Download a resource
  const handleDownload = async (courseId: string, resource: CourseResource) => {
    try {
      if (!resource._id) {
        if (resource.fileData) {
          const link = document.createElement("a");
          link.href = resource.fileData;
          link.download = resource.fileName || resource.name;
          link.click();
        }
        return;
      }

      const res = await fetch(`${API_BASE}/courses/${courseId}/resources/${resource._id}/download`);
      if (res.ok) {
        const data = await res.json();
        const link = document.createElement("a");
        link.href = data.fileData;
        link.download = data.fileName || data.name || resource.name;
        link.click();
      } else {
        console.error("Failed to download resource");
      }
    } catch (error) {
      console.error("Error downloading resource:", error);
    }
  };

  return (
    <StudentLayout>
      <div className="max-w-7xl mx-auto space-y-6">
        {/* Header */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-3xl font-bold text-foreground flex items-center gap-2">
              <BookOpen className="w-8 h-8 text-primary" />
              My Courses
            </h1>
            <p className="text-muted-foreground mt-1">
              Explore and manage your enrolled academic courses and materials
            </p>
          </div>
        </div>

        {/* Top Filters — matching /student/assignments exactly */}
        <div className="flex flex-col sm:flex-row gap-4">
          <Select name="degree" value={degree} onValueChange={setDegree}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Degree" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="Major">Major</SelectItem>
              <SelectItem value="Minor">Minor</SelectItem>
            </SelectContent>
          </Select>

          <Select name="year" value={selectedYear} onValueChange={setSelectedYear}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Year" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="I Year">I Year</SelectItem>
              <SelectItem value="II Year">II Year</SelectItem>
              <SelectItem value="III Year">III Year</SelectItem>
              <SelectItem value="IV Year">IV Year</SelectItem>
            </SelectContent>
          </Select>

          <Select name="semester" value={selectedSemester} onValueChange={setSelectedSemester}>
            <SelectTrigger className="w-[180px]">
              <SelectValue placeholder="Semester" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="Semester-I">Semester-I</SelectItem>
              <SelectItem value="Semester-II">Semester-II</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Loading */}
        {loading ? (
          <div className="flex items-center justify-center py-24">
            <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
          </div>
        ) : filteredCourses.length === 0 ? (
          <div className="text-center py-24">
            <BookOpen className="w-16 h-16 mx-auto text-muted-foreground/30 mb-4" />
            <p className="text-lg font-medium text-muted-foreground">
              {courses.length > 0 ? "No courses available for this semester" : "No courses available yet"}
            </p>
            <p className="text-sm text-muted-foreground/60 mt-1">
              {courses.length > 0 ? "Select another semester to view your courses." : "Courses will appear here once your faculty adds them."}
            </p>
          </div>
        ) : (
          /* Courses Grid */
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredCourses.map((course) => (
              <Card key={course._id} className="hover:shadow-lg transition-shadow">
                <CardHeader className="pb-4">
                  <div
                    className={`w-full h-20 ${course.color || "bg-blue-500"} rounded-lg flex items-center justify-center text-white font-bold text-lg mb-4`}
                  >
                    {course.courseCode}
                  </div>
                  <div className="flex items-start justify-between gap-3">
                    <CardTitle className="text-lg leading-tight">{course.courseName}</CardTitle>
                    {course.classType && (
                      <Badge
                        variant="outline"
                        className={`text-[10px] px-2 py-0.5 rounded-full uppercase tracking-wider shrink-0 mt-0.5 ${
                          course.classType === "Theory"
                            ? "bg-orange-500/10 text-orange-500 border-orange-500/20"
                            : "bg-blue-500/10 text-blue-500 border-blue-500/20"
                        }`}
                      >
                        {course.classType}
                      </Badge>
                    )}
                  </div>
                  <div className="flex items-center space-x-1 text-sm text-muted-foreground mt-1.5">
                    <User className="w-4 h-4" />
                    <span>{course.facultyName}</span>
                  </div>
                </CardHeader>

                <CardContent className="space-y-4">
                  {/* Course Stats */}
                  <div className="grid grid-cols-2 gap-4 text-center">
                    <div>
                      <div className="text-2xl font-bold text-foreground">
                        {course.credits}
                      </div>
                      <div className="text-xs text-muted-foreground">Credits</div>
                    </div>
                    <div>
                      <div className="text-2xl font-bold text-foreground">
                        {course.maxStudents}
                      </div>
                      <div className="text-xs text-muted-foreground">Students</div>
                    </div>
                  </div>

                  {/* Details Button */}
                  <Dialog>
                    <DialogTrigger asChild>
                      <Button
                        variant="outline"
                        className="w-full"
                        onClick={() => setSelectedCourse(course)}
                      >
                        <FileText className="w-4 h-4 mr-2" />
                        Details
                      </Button>
                    </DialogTrigger>
                    <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
                      <DialogHeader>
                        <DialogTitle>
                          {course.courseCode} - {course.courseName}
                        </DialogTitle>
                      </DialogHeader>

                      <div className="space-y-6">
                        {/* Course Description */}
                        {course.description && (
                          <div>
                            <h4 className="font-semibold text-foreground mb-2">
                              Course Description
                            </h4>
                            <p className="text-muted-foreground">{course.description}</p>
                          </div>
                        )}

                        {/* Course Objectives */}
                        {course.objectives && course.objectives.length > 0 && (
                          <div>
                            <h4 className="font-semibold text-foreground mb-2">
                              Course Objectives
                            </h4>
                            <ul className="space-y-1">
                              {course.objectives.map((objective, index) => (
                                <li
                                  key={index}
                                  className="text-muted-foreground flex items-start"
                                >
                                  <span className="mr-2">•</span>
                                  {objective}
                                </li>
                              ))}
                            </ul>
                          </div>
                        )}

                        {/* Course Syllabus */}
                        {course.syllabus && course.syllabus.length > 0 && (
                          <div>
                            <h4 className="font-semibold text-foreground mb-2">
                              Course Syllabus
                            </h4>
                            <div className="space-y-2">
                              {course.syllabus.map((item, index) => (
                                <div
                                  key={index}
                                  className="flex justify-between items-center p-2 bg-muted/30 rounded"
                                >
                                  <span className="text-foreground">{item.topic}</span>
                                  {item.duration && (
                                    <span className="text-sm text-muted-foreground">
                                      {item.duration}
                                    </span>
                                  )}
                                </div>
                              ))}
                            </div>
                          </div>
                        )}

                        {/* Course Resources */}
                        {course.resources && course.resources.length > 0 && (
                          <div>
                            <h4 className="font-semibold text-foreground mb-2">
                              Course Resources
                            </h4>
                            <div className="grid grid-cols-2 gap-3">
                              {course.resources.map((resource, index) => (
                                <div
                                  key={index}
                                  className="flex items-center space-x-2 p-3 bg-primary/10 rounded-lg cursor-pointer hover:bg-primary/20 transition-colors"
                                  onClick={() => handleDownload(course._id, resource)}
                                >
                                  <FileText className="w-5 h-5 text-primary" />
                                  <div className="flex-1 min-w-0">
                                    <div className="font-medium text-primary text-sm truncate">
                                      {resource.name}
                                    </div>
                                    <div className="text-xs text-muted-foreground">
                                      {resource.type}
                                    </div>
                                  </div>
                                  <Download className="w-4 h-4 text-primary/60" />
                                </div>
                              ))}
                            </div>
                          </div>
                        )}

                      </div>
                    </DialogContent>
                  </Dialog>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>
    </StudentLayout>
  );
};

export default StudentCourses;

