                                  {subjectInfo[Object.keys(subjectInfo).find(k => subject.includes(k)) || '']?.instructor && (
                                    <div className="text-xs text-muted-foreground">{subjectInfo[Object.keys(subjectInfo).find(k => subject.includes(k)) || '']?.instructor}</div>
                                  )}
                                </div>
                              </TooltipContent>
                            </Tooltip>
                          </TooltipProvider>
                        )}
                      </td>
                    ))}
