/**
 * Calculate 4-week attendance
 */
export const calculateFourWeekAttendance = async (
    studentId: string,
    year: string,
    branch: string,
    section: string,
    category: AttendanceCategory = 'ACADEMIC'
): Promise<StudentAttendanceSummary> => {
    const endDate = new Date();
    const startDate = new Date();
    startDate.setDate(startDate.getDate() - 28); // 4 weeks

    const defaultSummary: StudentAttendanceSummary = {
        studentId,
        studentName: '',
        totalClasses: 0,
        attended: 0,
        absent: 0,
        late: 0,
        excused: 0,
        percentage: 0,
        category,
        period: {
            startDate: formatDate(startDate),
            endDate: formatDate(endDate),
            weeks: 4,
        },
    };

    if (!firebaseReady || !database) {
        // Mock data for development
        return {
            ...defaultSummary,
            totalClasses: 48,
            attended: 40,
            absent: 5,
            late: 3,
            percentage: 83,
        };
    }

    try {
        // Fetch records for the last 4 weeks
        let totalClasses = 0;
        let attended = 0;
        let absent = 0;
        let late = 0;
        let excused = 0;

        for (let i = 0; i < 28; i++) {
            const checkDate = new Date();
            checkDate.setDate(checkDate.getDate() - i);
            const dateStr = formatDate(checkDate);

            const records = await getStudentAttendanceForDate(
                studentId,
                dateStr,
                year,
                branch,
                section
            );

            const categoryRecords = records.filter(r => r.category === category);

            for (const record of categoryRecords) {
                totalClasses++;
                switch (record.status) {
                    case 'PRESENT':
                        attended++;
                        break;
                    case 'ABSENT':
                        absent++;
                        break;
                    case 'LATE':
                        late++;
                        break;
                    case 'EXCUSED':
                        excused++;
                        break;
                }
            }
        }

        const percentage = totalClasses > 0
            ? Math.round(((attended + late * 0.5) / totalClasses) * 100)
            : 0;

        return {
            ...defaultSummary,
            totalClasses,
            attended,
            absent,
            late,
            excused,
            percentage,
        };
    } catch (error) {
        console.error('Error calculating 4-week attendance:', error);
        return defaultSummary;
    }
};

/**
 * Get historical attendance per subject for ALL dates
 * Returns per-subject metrics for performance tracking
 */
export const getHistoricalSubjectAttendance = async (
    studentId: string,
    year: string,
    branch: string,
    section: string,
    subjects: { subjectCode: string; subjectName: string }[]
): Promise<SubjectAttendanceSummary[]> => {
        const emptyResult = subjects.map(s => ({
            subjectCode: s.subjectCode,
            subjectName: s.subjectName,
            totalClasses: 0,
            attended: 0,
            absent: 0,
            notMarked: 0,
            percentage: 0,
            status: 'CRITICAL' as const
        }));

    if (!database) {
        console.log('[getHistoricalSubjectAttendance] Firebase not ready');
        return emptyResult;
    }

    try {
        // Get all attendance records for this section
        const recordsPath = `${ATTENDANCE_PATHS.RECORDS}/${year}/${branch}/${section}`;
        const recordsRef = ref(database, recordsPath);
        const snapshot = await get(recordsRef);

        if (!snapshot.exists()) {
            console.log('[getHistoricalSubjectAttendance] No records found');
            return emptyResult;
        }

        // Parse all records across all dates
        const dateRecords = snapshot.val();
        const subjectStats: Record<string, { total: number; attended: number; absent: number; notMarked: number; }> = {};

        // Initialize stats for each subject
        subjects.forEach(s => {
            subjectStats[s.subjectCode] = { total: 0, attended: 0, absent: 0, notMarked: 0 };
        });

        // Iterate over all dates
        for (const dateKey in dateRecords) {
            const dayRecords = dateRecords[dateKey];

            // Iterate over all records for this date
            for (const recordKey in dayRecords) {
                const record = dayRecords[recordKey];

                // Only count records for this student
                if (record.studentId === studentId) {
                    const subjectCode = record.subjectCode;

                    if (subjectStats[subjectCode]) {
                        subjectStats[subjectCode].total++;
                        if (record.status === 'PRESENT' || record.status === 'LATE') {
                            subjectStats[subjectCode].attended++;
                        } else if (record.status === 'ABSENT') {
                            subjectStats[subjectCode].absent++;
                        } else if (record.status === 'NOT_MARKED') {
                            subjectStats[subjectCode].notMarked++;
                        }
                    }
                }
            }
        }

        // Build summary for each subject
        const result: SubjectAttendanceSummary[] = subjects.map(s => {
            const stats = subjectStats[s.subjectCode] || { total: 0, attended: 0, absent: 0, notMarked: 0 };
            const percentage = stats.total > 0
                ? Math.round((stats.attended / stats.total) * 100)
                : 0;

            let status: 'SATISFACTORY' | 'WARNING' | 'CRITICAL' = 'WARNING';
            if (percentage >= 75) status = 'SATISFACTORY';
            else if (percentage < 50) status = 'CRITICAL';

            return {
                subjectCode: s.subjectCode,
                subjectName: s.subjectName,
                totalClasses: stats.total,
                attended: stats.attended,
                absent: stats.absent,
                notMarked: stats.notMarked,
                percentage,
                status,
            };
        });

        console.log('[getHistoricalSubjectAttendance] Results:', result);
        return result;

    } catch (error) {
        console.error('[getHistoricalSubjectAttendance] Error:', error);
        return emptyResult;
    }
};

